type PrewarmResult struct {
	Kind       string `json:"kind"`
	TargetID   string `json:"target_id"`
	Mode       string `json:"mode"`
	Model      string `json:"model"`
	BaseURL    string `json:"base_url"`
	OK         bool   `json:"ok"`
	DurationMS int64  `json:"duration_ms"`
	Error      string `json:"error,omitempty"`
}

func PrewarmChatTargets(ctx context.Context) ([]PrewarmResult, error) {
	store, err := ListTargets()
	if err != nil {
		return nil, err
	}
	results := []PrewarmResult{}
	for _, target := range store.Targets {
		mode := strings.ToLower(strings.TrimSpace(target.Mode))
		if mode != "chat" && mode != "briefing" && mode != "assistant" {
			continue
		}
		if strings.TrimSpace(target.Model) == "" && strings.TrimSpace(target.BaseURL) == "" {
			continue
		}
		results = append(results, prewarmChatTarget(ctx, target))
	}
	return results, nil
}

func prewarmChatTarget(ctx context.Context, target Target) PrewarmResult {
	cfg, _, err := aichat.LoadConfig()
	if err != nil {
		cfg = aichat.DefaultConfig()
	}
	if target.Model != "" {
		cfg.Model = target.Model
	}
	if target.BaseURL != "" {
		cfg.BaseURL = target.BaseURL
	}
	cfg.SystemPrompt = "Return a final answer with exactly: ready"
	cfg.MaxTokens = 64
	cfg.Temperature = 0
	result := PrewarmResult{
		Kind:     "meshclaw_signal_chat_prewarm",
		TargetID: target.ID,
		Mode:     target.Mode,
		Model:    cfg.Model,
		BaseURL:  cfg.BaseURL,
	}
	started := time.Now()
	_, err = aichat.NewClient(cfg).Chat(ctx, nil, "ready")
	result.DurationMS = time.Since(started).Milliseconds()
	if err != nil {
		if strings.Contains(err.Error(), "reasoning but no final answer") {
			result.OK = true
			result.Error = "backend reached and model warmed, but no final answer was returned"
			return result
		}
		result.Error = err.Error()
		return result
	}
	result.OK = true
	return result
}

func ListenAll(opts ListenOptions) (ListenResult, error) {
	store, err := ListTargets()
	if err != nil {
		return ListenResult{}, err
	}
	timeout := opts.Timeout
	if timeout <= 0 {
		timeout = 10
	}
	maxMessages := opts.MaxMessages
	if maxMessages <= 0 {
		maxMessages = 10
	}
	command := signalReceiveCommand(timeout, maxMessages)
	result := ListenResult{
		Kind:      "meshclaw_signal_dispatch_listen",
		Mode:      "dry-run",
		Command:   command,
		Messages:  []IncomingMessage{},
		RawStored: false,
	}
	if opts.Execute {
		result.Mode = "execute"
	}
	completed := exec.Command(command[0], command[1:]...)
	completed.Dir = signalAttachmentDir()
	out, err := completed.Output()
	if err != nil {
		result.Error = err.Error()
		return result, err
	}
	events := parseSignalReceive(out, Target{})
	for _, event := range events {
		started := time.Now()
		if isStaleIncoming(event, opts.MaxAgeSeconds) {
			continue
		}
		if isSignalSelfEcho(event) {
			continue
		}
		target, ok := matchSignalTarget(store.Targets, event)
		if !ok {
			continue
		}
		replyOpts := opts
		replyOpts.TargetID = target.ID
		replyOpts.Source = strings.TrimSpace(event.Source)
		if replyOpts.Mode == "" {
			replyOpts.Mode = target.Mode
		}
		if replyOpts.Model == "" {
			replyOpts.Model = target.Model
		}
		if replyOpts.BaseURL == "" {
			replyOpts.BaseURL = target.BaseURL
		}
		oneWayReport := isOneWayReportTarget(replyOpts, target, replyOpts.Mode)
		if opts.Execute && !oneWayReport {
			maybeSendChatAck(target, replyOpts, &event)
		}
		if !oneWayReport {
			storeLatestSignalAttachmentContext(replyOpts.TargetID, event)
		}
		replyStarted := time.Now()
		reply := guardReply(replyOpts, target, event)
		event.ReplyDurationMS = time.Since(replyStarted).Milliseconds()
		event.Reply = signalReplyLogText(reply)
		event.ReplyAttachmentCount = len(signalReplyAttachments(reply))
		if opts.Execute && reply != "" {
			sendStarted := time.Now()
			event.Sent, event.SendError = sendSignalReply(target, reply)
			event.SendDurationMS = time.Since(sendStarted).Milliseconds()
		}
		event.TotalDurationMS = time.Since(started).Milliseconds()
		result.Messages = append(result.Messages, event)
	}
	return result, nil
}

func Listen(opts ListenOptions) (ListenResult, error) {
	target, err := findTarget(opts.TargetID)
	if err != nil {
		return ListenResult{}, err
	}
	if opts.Mode == "" {
		opts.Mode = target.Mode
	}
	if opts.Model == "" {
		opts.Model = target.Model
	}
	if opts.BaseURL == "" {
		opts.BaseURL = target.BaseURL
	}
	timeout := opts.Timeout
	if timeout <= 0 {
		timeout = 10
	}
	maxMessages := opts.MaxMessages
	if maxMessages <= 0 {
		maxMessages = 10
	}
	command := signalReceiveCommand(timeout, maxMessages)
	result := ListenResult{
		Kind:      "meshclaw_signal_guard_listen",
		Mode:      "dry-run",
		Target:    target,
		Command:   command,
		Messages:  []IncomingMessage{},
		RawStored: false,
	}
	if opts.Execute {
		result.Mode = "execute"
	}
	completed := exec.Command(command[0], command[1:]...)
	completed.Dir = signalAttachmentDir()
	out, err := completed.Output()
	if err != nil {
		result.Error = err.Error()
		return result, err
	}
	events := parseSignalReceive(out, target)
	for _, event := range events {
		started := time.Now()
		if isStaleIncoming(event, opts.MaxAgeSeconds) {
			continue
		}
		if isSignalSelfEcho(event) {
			continue
		}
		oneWayReport := isOneWayReportTarget(opts, target, opts.Mode)
		if opts.Execute && !oneWayReport {
			maybeSendChatAck(target, opts, &event)
		}
		if !oneWayReport {
			storeLatestSignalAttachmentContext(opts.TargetID, event)
		}
		replyStarted := time.Now()
		reply := guardReply(opts, target, event)
		event.ReplyDurationMS = time.Since(replyStarted).Milliseconds()
		event.Reply = signalReplyLogText(reply)
		event.ReplyAttachmentCount = len(signalReplyAttachments(reply))
		if opts.Execute && reply != "" {
			sendStarted := time.Now()
			event.Sent, event.SendError = sendSignalReply(target, reply)
			event.SendDurationMS = time.Since(sendStarted).Milliseconds()
		}
		event.TotalDurationMS = time.Since(started).Milliseconds()
		result.Messages = append(result.Messages, event)
	}
	return result, nil
}

func isSignalSelfEcho(event IncomingMessage) bool {
	name := strings.ToLower(strings.TrimSpace(event.Name))
	source := strings.TrimSpace(event.Source)
	if event.SelfSync && signalSingleAccountConsoleEnabled() && isSignalConsoleCommand(event.Redacted) {
		return false
	}
	if name == "argos" {
		return true
	}
	for _, value := range []string{
		os.Getenv("MESHCLAW_SIGNAL_SELF_NUMBER"),
		os.Getenv("MESHCLAW_SIGNAL_BOT_NUMBER"),
		os.Getenv("ARGOS_SIGNAL_ACCOUNT"),
	} {
		if strings.TrimSpace(value) != "" && source == strings.TrimSpace(value) {
			return true
		}
	}
	lower := strings.ToLower(strings.TrimSpace(event.Redacted))
	selfPrefixes := []string{
		"승인 기록에 실패했습니다:",
		"argos assistant에서 바로 해볼 수 있는 예시입니다.",
		"argos assistant 방에서 바로 할 수 있는 일입니다.",
		"argos 기능 쇼케이스입니다.",
		"argos 기능 쇼케이스를 보고방에 보냈습니다.",
		"주차 정보 확인 링크입니다.",
		"지도에서 주차/영업정보/후기를 확인하고",
		"[argos hourly development report]",
	}
	for _, prefix := range selfPrefixes {
		if strings.HasPrefix(lower, strings.ToLower(prefix)) {
			return true
		}
	}
	return false
}

func signalSingleAccountConsoleEnabled() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_SINGLE_ACCOUNT_CONSOLE")))
	return value == "1" || value == "true" || value == "on" || value == "yes"
}

func isSignalConsoleCommand(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return false
	}
	for _, prefix := range []string{"/", "!", "argos", "아르고스", "@argos"} {
		if strings.HasPrefix(lower, prefix) {
			return true
		}
	}
	return false
}

func sendSignalReply(target Target, reply string) (bool, string) {
	attachments := signalReplyAttachments(reply)
	send := signalCLICommand(target, signalReplyVisibleText(reply), attachments, signalReplyVoiceNote(attachments))
	timeout := signalSendTimeout(0)
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()
	sent := exec.CommandContext(ctx, send[0], send[1:]...)
	if sendOut, sendErr := sent.CombinedOutput(); sendErr != nil {
		if ctx.Err() == context.DeadlineExceeded {
			return false, fmt.Sprintf("signal-cli send timed out after %d seconds", int(timeout.Seconds()))
		}
		return false, strings.TrimSpace(string(sendOut) + "\n" + sendErr.Error())
	}
	cleanupSignalReplyAttachments(attachments)
	return true, ""
}

func signalReplyVisibleText(reply string) string {
	lines := strings.Split(reply, "\n")
	visible := make([]string, 0, len(lines))
	for _, line := range lines {
		if _, ok := signalReplyAttachmentPath(line); ok {
			continue
		}
		visible = append(visible, line)
	}
	return sanitizeSignalUserVisibleText(strings.Join(visible, "\n"))
}

func signalReplyLogText(reply string) string {
	lines := strings.Split(reply, "\n")
	visible := make([]string, 0, len(lines))
	for _, line := range lines {
		if strings.HasPrefix(strings.TrimSpace(line), "meshclaw-attachment:") {
			continue
		}
		visible = append(visible, line)
	}
	return strings.TrimSpace(redactLocalPathsForSignal(strings.Join(visible, "\n")))
}

func sanitizeSignalUserVisibleText(value string) string {
	lines := strings.Split(value, "\n")
	visible := make([]string, 0, len(lines))
	for _, line := range lines {
		if signalReplyInternalDiagnosticLine(line) {
			continue
		}
		visible = append(visible, line)
	}
	return strings.TrimSpace(strings.Join(visible, "\n"))
}

var signalEvidenceIDLineRE = regexp.MustCompile(`\b\d{8}T\d{6}Z-\d{6,}-[A-Za-z0-9_-]+\b`)

func signalReplyInternalDiagnosticLine(line string) bool {
	trimmed := strings.TrimSpace(line)
	if trimmed == "" {
		return false
	}
	lower := strings.ToLower(trimmed)
	for _, marker := range []string{
		"/users/",
		"/private/var/",
		"/var/",
		"/tmp/",
		"/volumes/",
		"/.meshclaw/",
		"~/.meshclaw/",
		"evidence id",
		"evidence_id",
		"stored_at",
		"store_error",
		"exit status",
		"router",
		"raw log",
		"debug:",
	} {
		if strings.Contains(lower, marker) {
			return true
		}
	}
	for _, marker := range []string{"증거 ID", "진행 증거:", "원시 로그", "디버그:", "라우터"} {
		if strings.Contains(trimmed, marker) {
			return true
		}
	}
	return signalEvidenceIDLineRE.MatchString(trimmed)
}

func signalReplyAttachments(reply string) []string {
	lines := strings.Split(reply, "\n")
	seen := map[string]bool{}
	attachments := []string{}
	for _, line := range lines {
		line = strings.TrimSpace(line)
		path, ok := signalReplyAttachmentPath(line)
		if !ok || path == "" || seen[path] {
			continue
		}
		for _, attachment := range signalFriendlyReplyAttachments(path) {
			if attachment == "" || seen[attachment] {
				continue
			}
			if strings.HasPrefix(attachment, "data:") {
				seen[attachment] = true
				attachments = append(attachments, attachment)
				continue
			}
			if st, err := os.Stat(attachment); err == nil && !st.IsDir() && st.Size() > 0 {
				seen[attachment] = true
				attachments = append(attachments, attachment)
			}
		}
	}
	return attachments
}

func signalReplyVoiceNote(attachments []string) bool {
	if len(attachments) != 1 {
		return false
	}
	switch strings.ToLower(filepath.Ext(strings.TrimSpace(attachments[0]))) {
	case ".aac", ".aiff", ".aif", ".m4a", ".mp3", ".ogg", ".opus", ".wav":
		return true
	default:
		return false
	}
}

func signalReplyAttachmentPath(line string) (string, bool) {
	line = strings.TrimSpace(line)
	for _, prefix := range []string{"meshclaw-attachment:", "작업 화면 기록:", "작업 문서:", "문서 미리보기 이미지:", "Signal 읽기용 문서:", "Obsidian 편집 문서:", "Pages/Word 편집용 문서:", "Pages 편집용 Word 문서:", "screen recording:", "recording:", "document:"} {
		path, ok := strings.CutPrefix(line, prefix)
		if ok {
			return strings.TrimSpace(path), true
		}
	}
	return "", false
}

func signalFriendlyReplyAttachments(path string) []string {
	ext := strings.ToLower(filepath.Ext(path))
	switch ext {
	case ".mov":
		return []string{signalFriendlyReplyVideo(path)}
	case ".pages":
		out := []string{}
		if dataURI := signalPagesDataURI(path); dataURI != "" {
			out = append(out, dataURI)
		} else {
			out = append(out, path)
		}
		return out
	case ".pdf", ".jpg", ".jpeg", ".png":
		return []string{path}
	case ".md", ".txt":
		out := []string{}
		if preview := signalReplyDocumentPreviewImage(path); preview != "" {
			out = append(out, preview)
		}
		out = append(out, path)
		if preview := strings.TrimSuffix(path, filepath.Ext(path)) + ".html"; attachRawSignalReplyDocuments() && fileNonEmptyLocal(preview) {
			out = append(out, preview)
		}
		return out
	default:
		return []string{path}
	}
}

func signalPagesDataURI(path string) string {
	data, err := os.ReadFile(path)
	if err != nil || len(data) == 0 {
		return ""
	}
	name := strings.TrimSuffix(filepath.Base(path), filepath.Ext(path))
	name = publish.SanitizePublicBase(name)
	if name == "" {
		name = "argos-document"
	}
	return "data:application/vnd.apple.pages;filename=" + name + ".pages;base64," + base64.StdEncoding.EncodeToString(data)
}

func signalReplyDocumentPreviewImage(path string) string {
	return publish.DocumentPreviewImage(path)
}

func signalReplyDocumentLink(path string) string {
	links := signalReplyDocumentLinks(path)
	if len(links) == 0 {
		return ""
	}
	return links[0]
}

func signalReplyDocumentLinks(path string) []string {
	return publish.DocumentLinks(path)
}

func attachRawSignalReplyDocuments() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_ARGOS_ATTACH_RAW_DOCS")))
	return value == "1" || value == "true" || value == "yes"
}

func signalFriendlyReplyVideo(path string) string {
	out := strings.TrimSuffix(path, filepath.Ext(path)) + ".m4v"
	if fileNonEmptyLocal(out) {
		return out
	}
	cmd := exec.Command("avconvert", "--source", path, "--preset", "PresetAppleM4V720pHD", "--output", out, "--replace")
	if err := cmd.Run(); err == nil && fileNonEmptyLocal(out) {
		return out
	}
	return path
}

func fileNonEmptyLocal(path string) bool {
	st, err := os.Stat(path)
	return err == nil && !st.IsDir() && st.Size() > 0
}

func cleanupSignalReplyAttachments(paths []string) {
	if keepSignalRecordings() {
		return
	}
	for _, path := range paths {
		if isEphemeralArgosRecording(path) {
			_ = os.Remove(path)
		}
	}
}

func keepSignalRecordings() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_ARGOS_KEEP_RECORDINGS")))
	return value == "1" || value == "true" || value == "yes"
}

func isEphemeralArgosRecording(path string) bool {
	path = strings.TrimSpace(path)
	if path == "" {
		return false
	}
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return false
	}
	root := filepath.Join(home, ".meshclaw", "recordings")
	abs, err := filepath.Abs(path)
	if err != nil {
		return false
	}
	rootAbs, err := filepath.Abs(root)
	if err != nil {
		return false
	}
	rel, err := filepath.Rel(rootAbs, abs)
	if err != nil {
		return false
	}
	return rel != "." && rel != ".." && !strings.HasPrefix(rel, ".."+string(os.PathSeparator))
}

func maybeSendChatAck(target Target, opts ListenOptions, event *IncomingMessage) {
	if strings.ToLower(strings.TrimSpace(opts.Mode)) != "chat" || !signalChatAckEnabled() {
		return
	}
	ack := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_CHAT_ACK_TEXT"))
	if ack == "" {
		ack = "받았습니다. 답변 작성 중입니다."
	}
	event.Ack = ack
	send := signalCLICommand(target, ack, nil, false)
	sent := exec.Command(send[0], send[1:]...)
	if sendOut, sendErr := sent.CombinedOutput(); sendErr != nil {
		event.AckError = strings.TrimSpace(string(sendOut) + "\n" + sendErr.Error())
		return
	}
	event.AckSent = true
}

func signalChatAckEnabled() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_CHAT_ACK")))
	return value == "1" || value == "true" || value == "on" || value == "yes"
}

func signalAttachmentDir() string {
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return filepath.Join(os.TempDir(), "meshclaw-signal-attachments")
	}
	dir := filepath.Join(home, ".meshclaw", "signal-attachments")
	_ = os.MkdirAll(dir, 0700)
	return dir
}

func isStaleIncoming(event IncomingMessage, maxAgeSeconds int) bool {
	if maxAgeSeconds <= 0 || event.Timestamp <= 0 {
		return false
	}
	age := time.Since(time.UnixMilli(event.Timestamp))
	return age > time.Duration(maxAgeSeconds)*time.Second
}

func signalReceiveCommand(timeout, maxMessages int) []string {
	binary := signalCLIBinary()
	args := []string{binary, "-o", "json"}
	if account := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_ACCOUNT")); account != "" {
		args = append(args, "-a", account)
	}
	return append(args, "receive", "--timeout", strconv.Itoa(timeout), "--max-messages", strconv.Itoa(maxMessages), "--ignore-stories", "--ignore-avatars", "--ignore-stickers")
}

func parseSignalReceive(data []byte, target Target) []IncomingMessage {
	var events []IncomingMessage
	scanner := bufio.NewScanner(strings.NewReader(string(data)))
	scanner.Buffer(make([]byte, 0, 1024*1024), 16*1024*1024)
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" || !strings.HasPrefix(line, "{") {
			continue
		}
		var payload struct {
			Envelope struct {
				Source       string `json:"source"`
				SourceNumber string `json:"sourceNumber"`
				SourceName   string `json:"sourceName"`
				Timestamp    int64  `json:"timestamp"`
				DataMessage  struct {
					Message     string                `json:"message"`
					Attachments []signalRawAttachment `json:"attachments"`
					GroupInfo   struct {
						GroupID string `json:"groupId"`
					} `json:"groupInfo"`
				} `json:"dataMessage"`
				SyncMessage struct {
					SentMessage struct {
						Message     string                `json:"message"`
						Attachments []signalRawAttachment `json:"attachments"`
						Timestamp   int64                 `json:"timestamp"`
						GroupInfo   struct {
							GroupID string `json:"groupId"`
						} `json:"groupInfo"`
					} `json:"sentMessage"`
				} `json:"syncMessage"`
			} `json:"envelope"`
		}
		if err := json.Unmarshal([]byte(line), &payload); err != nil {
			continue
		}
		message := strings.TrimSpace(payload.Envelope.DataMessage.Message)
		attachments := signalIncomingAttachments(payload.Envelope.DataMessage.Attachments, payload.Envelope.Timestamp)
		selfSync := false
		eventTimestamp := payload.Envelope.Timestamp
		groupID := strings.TrimSpace(payload.Envelope.DataMessage.GroupInfo.GroupID)
		if message == "" && len(attachments) == 0 {
			sent := payload.Envelope.SyncMessage.SentMessage
			message = strings.TrimSpace(sent.Message)
			eventTimestamp = firstNonZeroInt64(sent.Timestamp, payload.Envelope.Timestamp)
			attachments = signalIncomingAttachments(sent.Attachments, eventTimestamp)
			groupID = strings.TrimSpace(sent.GroupInfo.GroupID)
			selfSync = message != "" || len(attachments) > 0
		}
		if message == "" && len(attachments) == 0 {
			continue
		}
		if target.GroupID != "" && groupID != "" && groupID != target.GroupID {
			continue
		}
		report := guard.Detect("signal-guard", message)
		intent := guard.ParseIntent(report.Redacted)
		redacted := report.Redacted
		if strings.TrimSpace(redacted) == "" && len(attachments) > 0 {
			redacted = signalAttachmentOnlyText(attachments)
		}
		events = append(events, IncomingMessage{
			Source:         firstNonEmpty(payload.Envelope.SourceNumber, payload.Envelope.Source),
			Name:           strings.TrimSpace(payload.Envelope.SourceName),
			GroupID:        groupID,
			Timestamp:      eventTimestamp,
			Attachments:    attachments,
			Redacted:       redacted,
			raw:            message,
			SelfSync:       selfSync,
			SecretDetected: len(report.Findings) > 0,
			Intent:         intent.Intent,
		})
	}
	return events
}

func signalIncomingAttachments(raw []signalRawAttachment, timestamp int64) []SignalAttachment {
	out := []SignalAttachment{}
	for _, item := range raw {
		path := resolveSignalIncomingAttachmentPath(firstNonEmpty(item.StoredFilename, item.Path, item.Filename, item.ID), item.Size, timestamp)
		attachment := SignalAttachment{
			ContentType: strings.TrimSpace(item.ContentType),
			Filename:    strings.TrimSpace(firstNonEmpty(item.Filename, filepath.Base(path))),
			Path:        path,
			Size:        item.Size,
		}
		if signalAttachmentIsImage(attachment) {
			attachment.Text, attachment.Error = recognizeSignalImageText(path)
			attachment.Description, attachment.VisionError = describeSignalImage(path, attachment.Text)
		} else if signalAttachmentIsReadableText(attachment) {
			attachment.Text, attachment.Error = readSignalTextAttachment(path)
		} else if signalAttachmentIsReadableDocument(attachment) {
			attachment.Text, attachment.Error = readSignalDocumentAttachment(path)
		} else if path != "" {
			if st, err := os.Stat(path); err != nil || st.IsDir() || st.Size() == 0 {
				if err != nil {
					attachment.Error = err.Error()
				} else if st != nil && st.IsDir() {
					attachment.Error = "attachment path is a directory"
				} else {
					attachment.Error = "attachment file is empty"
				}
			}
		}
		out = append(out, attachment)
	}
	return out
}

func resolveSignalIncomingAttachmentPath(name string, size int64, timestamp int64) string {
	name = strings.TrimSpace(name)
	if name == "" {
		return ""
	}
	if filepath.IsAbs(name) {
		return name
	}
	candidates := []string{
		filepath.Join(signalAttachmentDir(), name),
		filepath.Join(signalCLIAttachmentDir(), name),
	}
	for _, candidate := range candidates {
		if st, err := os.Stat(candidate); err == nil && !st.IsDir() {
			return candidate
		}
	}
	if candidate := resolveSignalCLIAttachmentBySize(name, size, timestamp); candidate != "" {
		return candidate
	}
	return candidates[0]
}

func resolveSignalCLIAttachmentBySize(name string, size int64, timestamp int64) string {
	dir := signalCLIAttachmentDir()
	entries, err := os.ReadDir(dir)
	if err != nil {
		return ""
	}
	ext := strings.ToLower(filepath.Ext(name))
	type candidate struct {
		path      string
		modTime   time.Time
		distance  time.Duration
		exactSize bool
	}
	matches := []candidate{}
	eventTime := time.Time{}
	if timestamp > 0 {
		eventTime = time.UnixMilli(timestamp)
	}
	for _, entry := range entries {
		if entry.IsDir() {
			continue
		}
		if ext != "" && strings.ToLower(filepath.Ext(entry.Name())) != ext {
			continue
		}
		info, err := entry.Info()
		if err != nil {
			continue
		}
		exactSize := size > 0 && info.Size() == size
		if size > 0 && !exactSize {
			continue
		}
		if size <= 0 && !attachmentModTimeNearEvent(info.ModTime(), eventTime) {
			continue
		}
		matches = append(matches, candidate{
			path:      filepath.Join(dir, entry.Name()),
			modTime:   info.ModTime(),
			distance:  attachmentTimeDistance(info.ModTime(), eventTime),
			exactSize: exactSize,
		})
	}
	if len(matches) == 1 {
		return matches[0].path
	}
	if len(matches) > 1 {
		sort.Slice(matches, func(i, j int) bool {
			if matches[i].exactSize != matches[j].exactSize {
				return matches[i].exactSize
			}
			if matches[i].distance != matches[j].distance {
				return matches[i].distance < matches[j].distance
			}
			return matches[i].modTime.After(matches[j].modTime)
		})
		if matches[0].distance == 0 || matches[0].distance < matches[1].distance || matches[0].modTime.After(matches[1].modTime) {
			return matches[0].path
		}
	}
	return ""
}

func attachmentModTimeNearEvent(modTime, eventTime time.Time) bool {
	if eventTime.IsZero() {
		return time.Since(modTime) <= 10*time.Minute
	}
	return attachmentTimeDistance(modTime, eventTime) <= 10*time.Minute
}

func attachmentTimeDistance(modTime, eventTime time.Time) time.Duration {
	if eventTime.IsZero() {
		return 0
	}
	if modTime.After(eventTime) {
		return modTime.Sub(eventTime)
	}
	return eventTime.Sub(modTime)
}

func signalCLIAttachmentDir() string {
	if dir := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_CLI_ATTACHMENT_DIR")); dir != "" {
		return dir
	}
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return filepath.Join(os.TempDir(), "signal-cli", "attachments")
	}
	return filepath.Join(home, ".local", "share", "signal-cli", "attachments")
}

func signalAttachmentOnlyText(attachments []SignalAttachment) string {
	images := 0
	for _, attachment := range attachments {
		if signalAttachmentIsImage(attachment) {
			images++
		}
	}
	if images > 0 {
		return "이미지 첨부를 받았습니다. 이 이미지에 대해 질문하면 방금 이미지 분석 내용을 기준으로 답하세요."
	}
	return "첨부 파일을 받았습니다."
}

func signalAttachmentIsImage(attachment SignalAttachment) bool {
	contentType := strings.ToLower(strings.TrimSpace(attachment.ContentType))
	if strings.HasPrefix(contentType, "image/") {
		return true
	}
	ext := strings.ToLower(filepath.Ext(firstNonEmpty(attachment.Path, attachment.Filename)))
	switch ext {
	case ".png", ".jpg", ".jpeg", ".heic", ".webp", ".gif", ".tif", ".tiff":
		return true
	default:
		return false
	}
}

func signalAttachmentImageMIME(attachment SignalAttachment) string {
	contentType := strings.ToLower(strings.TrimSpace(attachment.ContentType))
	if strings.HasPrefix(contentType, "image/") {
		return contentType
	}
	ext := strings.ToLower(filepath.Ext(firstNonEmpty(attachment.Path, attachment.Filename)))
	switch ext {
	case ".jpg", ".jpeg":
		return "image/jpeg"
	case ".png":
		return "image/png"
	case ".gif":
		return "image/gif"
	case ".webp":
		return "image/webp"
	case ".heic":
		return "image/heic"
	case ".tif", ".tiff":
		return "image/tiff"
	default:
		return "image/png"
	}
}

func signalAttachmentIsReadableText(attachment SignalAttachment) bool {
	contentType := strings.ToLower(strings.TrimSpace(attachment.ContentType))
	if strings.HasPrefix(contentType, "text/") {
		return true
	}
	switch contentType {
	case "application/json", "application/x-ndjson", "application/xml", "application/javascript":
		return true
	}
	ext := strings.ToLower(filepath.Ext(firstNonEmpty(attachment.Path, attachment.Filename)))
	switch ext {
	case ".txt", ".md", ".markdown", ".csv", ".tsv", ".json", ".jsonl", ".xml", ".html", ".htm", ".log", ".yaml", ".yml":
		return true
	default:
		return false
	}
}

func signalAttachmentIsReadableDocument(attachment SignalAttachment) bool {
	contentType := strings.ToLower(strings.TrimSpace(attachment.ContentType))
	switch contentType {
	case "application/pdf",
		"application/rtf",
		"text/rtf",
		"application/msword",
		"application/vnd.openxmlformats-officedocument.wordprocessingml.document":
		return true
	}
	ext := strings.ToLower(filepath.Ext(firstNonEmpty(attachment.Path, attachment.Filename)))
	switch ext {
	case ".pdf", ".docx", ".doc", ".rtf":
		return true
	default:
		return false
	}
}

func readSignalTextAttachment(path string) (string, string) {
	path = strings.TrimSpace(path)
	if path == "" {
		return "", "attachment path is empty"
	}
	st, err := os.Stat(path)
	if err != nil {
		return "", err.Error()
	}
	if st.IsDir() {
		return "", "attachment path is a directory"
	}
	if st.Size() == 0 {
		return "", "attachment file is empty"
	}
	const maxTextAttachmentBytes = 128 * 1024
	data, err := os.ReadFile(path)
	if err != nil {
		return "", err.Error()
	}
	truncated := false
	if len(data) > maxTextAttachmentBytes {
		data = data[:maxTextAttachmentBytes]
		truncated = true
	}
	text := strings.TrimSpace(strings.ToValidUTF8(string(data), ""))
	if text == "" {
		return "", "attachment did not contain readable UTF-8 text"
	}
	if truncated {
		text += "\n\n[첨부 텍스트가 길어서 앞부분만 읽었습니다.]"
	}
	return text, ""
}

func readSignalDocumentAttachment(path string) (string, string) {
	if errText := validateSignalAttachmentFile(path); errText != "" {
		return "", errText
	}
	ext := strings.ToLower(filepath.Ext(path))
	var (
		text string
		err  error
	)
	switch ext {
	case ".docx":
		text, err = readSignalDocxAttachment(path)
	case ".pdf":
		text, err = readSignalPDFAttachment(path)
	case ".doc", ".rtf":
		text, err = readSignalTextutilAttachment(path)
	default:
		err = fmt.Errorf("unsupported document attachment type: %s", ext)
	}
	if err != nil {
		return "", err.Error()
	}
	text = normalizeSignalAttachmentText(text)
	if text == "" {
		return "", "document did not contain readable text"
	}
	return trimSignalAttachmentText(text), ""
}

func validateSignalAttachmentFile(path string) string {
	path = strings.TrimSpace(path)
	if path == "" {
		return "attachment path is empty"
	}
	st, err := os.Stat(path)
	if err != nil {
		return err.Error()
	}
	if st.IsDir() {
		return "attachment path is a directory"
	}
	if st.Size() == 0 {
		return "attachment file is empty"
	}
	return ""
}

func readSignalDocxAttachment(path string) (string, error) {
	reader, err := zip.OpenReader(path)
	if err != nil {
		return "", err
	}
	defer reader.Close()
	parts := []string{}
	for _, file := range reader.File {
		name := strings.ToLower(file.Name)
		if name != "word/document.xml" && !strings.HasPrefix(name, "word/header") && !strings.HasPrefix(name, "word/footer") {
			continue
		}
		rc, err := file.Open()
		if err != nil {
			continue
		}
		data, readErr := io.ReadAll(io.LimitReader(rc, 2*1024*1024))
		_ = rc.Close()
		if readErr != nil {
			continue
		}
		if text := textFromOfficeXML(data); text != "" {
			parts = append(parts, text)
		}
	}
	if len(parts) == 0 {
		return "", fmt.Errorf("docx did not contain word/document.xml text")
	}
	return strings.Join(parts, "\n"), nil
}

func textFromOfficeXML(data []byte) string {
	text := string(data)
	replacements := []struct {
		old string
		new string
	}{
		{`<w:tab/>`, "\t"},
		{`<w:br/>`, "\n"},
		{`</w:p>`, "\n"},
		{`</w:tr>`, "\n"},
		{`</w:tc>`, "\t"},
	}
	for _, replacement := range replacements {
		text = strings.ReplaceAll(text, replacement.old, replacement.new)
	}
	text = regexp.MustCompile(`<[^>]+>`).ReplaceAllString(text, " ")
	return normalizeSignalAttachmentText(html.UnescapeString(text))
}

func readSignalPDFAttachment(path string) (string, error) {
	if text, err := runSignalAttachmentTextCommand("mdls", "-raw", "-name", "kMDItemTextContent", path); err == nil && usableExtractedDocumentText(text) {
		return text, nil
	}
	if text, err := runSignalAttachmentTextCommand("pdftotext", "-layout", path, "-"); err == nil && usableExtractedDocumentText(text) {
		return text, nil
	}
	if text, err := readSignalPDFViaQuickLookOCR(path); err == nil && usableExtractedDocumentText(text) {
		return text + "\n\n[PDF 첫 페이지를 QuickLook 이미지 OCR로 읽었습니다.]", nil
	}
	return "", fmt.Errorf("pdf text extraction unavailable; install pdftotext, let Spotlight index the file, or enable QuickLook/macOS Vision OCR")
}

func readSignalPDFViaQuickLookOCR(path string) (string, error) {
	if !commandAvailable("qlmanage") {
		return "", fmt.Errorf("qlmanage is not available")
	}
	if !commandAvailable("swift") {
		return "", fmt.Errorf("swift is not available for macOS Vision OCR")
	}
	tmp, err := os.MkdirTemp("", "meshclaw-pdf-ocr-*")
	if err != nil {
		return "", err
	}
	defer os.RemoveAll(tmp)

	ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
	defer cancel()
	cmd := exec.CommandContext(ctx, "qlmanage", "-t", "-s", "1800", "-o", tmp, path)
	if out, err := cmd.CombinedOutput(); err != nil {
		if ctx.Err() != nil {
			return "", ctx.Err()
		}
		return "", fmt.Errorf("qlmanage thumbnail failed: %v: %s", err, strings.TrimSpace(string(out)))
	}
	candidates, err := signalPDFThumbnailCandidates(tmp)
	if err != nil {
		return "", err
	}
	for _, candidate := range candidates {
		text, errText := recognizeSignalImageText(candidate)
		if usableExtractedDocumentText(text) {
			return text, nil
		}
		if errText != "" {
			err = fmt.Errorf("%s", errText)
		}
	}
	if err != nil {
		return "", err
	}
	return "", fmt.Errorf("quicklook thumbnail OCR did not find readable text")
}

func signalPDFThumbnailCandidates(dir string) ([]string, error) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		return nil, err
	}
	type candidate struct {
		path string
		size int64
	}
	candidates := []candidate{}
	for _, entry := range entries {
		if entry.IsDir() {
			continue
		}
		ext := strings.ToLower(filepath.Ext(entry.Name()))
		if ext != ".png" && ext != ".jpg" && ext != ".jpeg" && ext != ".tif" && ext != ".tiff" {
			continue
		}
		info, err := entry.Info()
		if err != nil || info.Size() == 0 {
			continue
		}
		candidates = append(candidates, candidate{
			path: filepath.Join(dir, entry.Name()),
			size: info.Size(),
		})
	}
	sort.Slice(candidates, func(i, j int) bool {
		return candidates[i].size > candidates[j].size
	})
	out := make([]string, 0, len(candidates))
	for _, candidate := range candidates {
		out = append(out, candidate.path)
	}
	if len(out) == 0 {
		return nil, fmt.Errorf("quicklook did not create an image thumbnail")
	}
	return out, nil
}

func readSignalTextutilAttachment(path string) (string, error) {
	if text, err := runSignalAttachmentTextCommand("textutil", "-convert", "txt", "-stdout", path); err == nil && usableExtractedDocumentText(text) {
		return text, nil
	}
	return "", fmt.Errorf("document text extraction failed")
}

func runSignalAttachmentTextCommand(name string, args ...string) (string, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()
	cmd := exec.CommandContext(ctx, name, args...)
	out, err := cmd.Output()
	if ctx.Err() != nil {
		return "", ctx.Err()
	}
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(strings.ToValidUTF8(string(out), "")), nil
}

func usableExtractedDocumentText(text string) bool {
	text = normalizeSignalAttachmentText(text)
	if text == "" || text == "(null)" {
		return false
	}
	return len([]rune(text)) >= 3
}

func normalizeSignalAttachmentText(text string) string {
	text = strings.ReplaceAll(text, "\r\n", "\n")
	text = strings.ReplaceAll(text, "\r", "\n")
	lines := strings.Split(text, "\n")
	out := make([]string, 0, len(lines))
	blank := false
	for _, line := range lines {
		line = strings.Join(strings.Fields(line), " ")
		if line == "" {
			if blank {
				continue
			}
			blank = true
			out = append(out, "")
			continue
		}
		blank = false
		out = append(out, line)
	}
	return strings.TrimSpace(strings.Join(out, "\n"))
}

func trimSignalAttachmentText(text string) string {
	const maxTextAttachmentBytes = 128 * 1024
	if len(text) <= maxTextAttachmentBytes {
		return text
	}
	return text[:maxTextAttachmentBytes] + "\n\n[첨부 텍스트가 길어서 앞부분만 읽었습니다.]"
}

func recognizeSignalImageText(path string) (string, string) {
	path = strings.TrimSpace(path)
	if path == "" {
		return "", "image path is empty"
	}
	if st, err := os.Stat(path); err != nil || st.IsDir() || st.Size() == 0 {
		if err != nil {
			return "", err.Error()
		}
		return "", "image file is empty"
	}
	script, err := ensureSignalVisionOCRScript()
	if err != nil {
		return "", err.Error()
	}
	ctx, cancel := context.WithTimeout(context.Background(), signalVisionOCRTimeout())
	defer cancel()
	cmd := exec.CommandContext(ctx, "/usr/bin/swift", script, path)
	out, err := cmd.CombinedOutput()
	text := strings.TrimSpace(string(out))
	if ctx.Err() == context.DeadlineExceeded {
		return "", "image text recognition timed out"
	}
	if err != nil {
		return "", strings.TrimSpace(text + "\n" + err.Error())
	}
	return text, ""
}

func describeSignalImage(path string, ocrText string) (string, string) {
	path = strings.TrimSpace(path)
	if path == "" {
		return "", "image path is empty"
	}
	st, err := os.Stat(path)
	if err != nil {
		return "", err.Error()
	}
	if st.IsDir() || st.Size() == 0 {
		return "", "image file is empty"
	}
	model := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_MODEL"))
	if model == "" {
		return fallbackSignalImageDescription(path, st.Size(), ocrText), ""
	}
	description, err := callSignalVisionModel(path, model, ocrText)
	if err != nil {
		return fallbackSignalImageDescription(path, st.Size(), ocrText), err.Error()
	}
	description = strings.TrimSpace(description)
	if description == "" {
		return fallbackSignalImageDescription(path, st.Size(), ocrText), "vision model returned empty description"
	}
	return description, ""
}

func fallbackSignalImageDescription(path string, size int64, ocrText string) string {
	parts := []string{fmt.Sprintf("이미지 파일입니다. 파일명: %s, 크기: %d bytes.", filepath.Base(path), size)}
	ocrText = strings.TrimSpace(ocrText)
	if ocrText != "" {
		parts = append(parts, "이미지 안에서 읽은 텍스트를 기준으로 내용을 추정할 수 있습니다.")
	} else {
		parts = append(parts, "현재 비전 모델이 연결되지 않아 사물/장면 설명은 하지 못했고, OCR 텍스트도 찾지 못했습니다.")
	}
	return strings.Join(parts, " ")
}

func callSignalVisionModel(path string, model string, ocrText string) (string, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return "", err
	}
	const maxVisionImageBytes = 12 * 1024 * 1024
	if len(data) > maxVisionImageBytes {
		return "", fmt.Errorf("image is too large for vision model: %d bytes", len(data))
	}
	baseURL := strings.TrimRight(strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_BASE_URL")), "/")
	apiKey := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_API_KEY"))
	if baseURL == "" {
		cfg, _, err := aichat.LoadConfig()
		if err == nil {
			baseURL = strings.TrimRight(strings.TrimSpace(cfg.BaseURL), "/")
			apiKey = strings.TrimSpace(cfg.APIKey)
		}
	}
	if baseURL == "" {
		baseURL = strings.TrimRight(strings.TrimSpace(aichat.DefaultConfig().BaseURL), "/")
	}
	if apiKey == "" {
		apiKey = strings.TrimSpace(aichat.DefaultConfig().APIKey)
	}
	mime := signalAttachmentImageMIME(SignalAttachment{Path: path})
	prompt := strings.Join([]string{
		"이 이미지를 한국어로 간결하게 설명하세요.",
		"스크린샷이면 앱/화면/보이는 메시지/사용자가 물을 만한 핵심을 설명하세요.",
		"추측이 필요한 부분은 추측이라고 말하고, 보이지 않는 내용은 만들지 마세요.",
		"이미 OCR로 읽은 텍스트가 있으면 시각 설명과 함께 반영하세요.",
		"OCR 텍스트:",
		firstNonEmpty(strings.TrimSpace(ocrText), "(없음)"),
	}, "\n")
	payload := map[string]interface{}{
		"model": model,
		"messages": []map[string]interface{}{
			{
				"role": "user",
				"content": []map[string]interface{}{
					{"type": "text", "text": prompt},
					{"type": "image_url", "image_url": map[string]interface{}{"url": "data:" + mime + ";base64," + base64.StdEncoding.EncodeToString(data)}},
				},
			},
		},
		"stream":      false,
		"max_tokens":  700,
		"temperature": 0.2,
	}
	body, err := json.Marshal(payload)
	if err != nil {
		return "", err
	}
	timeout := signalVisionModelTimeout()
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, baseURL+"/chat/completions", bytes.NewReader(body))
	if err != nil {
		return "", err
	}
	req.Header.Set("Content-Type", "application/json")
	if apiKey != "" {
		req.Header.Set("Authorization", "Bearer "+apiKey)
	}
	resp, err := (&http.Client{Timeout: timeout}).Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()
	var decoded struct {
		Choices []struct {
			Message struct {
				Content string `json:"content"`
			} `json:"message"`
		} `json:"choices"`
		Error interface{} `json:"error,omitempty"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&decoded); err != nil {
		return "", err
	}
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return "", fmt.Errorf("vision backend returned %s: %v", resp.Status, decoded.Error)
	}
	if len(decoded.Choices) == 0 {
		return "", fmt.Errorf("vision backend returned no choices")
	}
	return strings.TrimSpace(decoded.Choices[0].Message.Content), nil
}

func ensureSignalVisionOCRScript() (string, error) {
	dir := filepath.Join(signalAttachmentDir(), "bin")
	if err := os.MkdirAll(dir, 0700); err != nil {
		return "", err
	}
	path := filepath.Join(dir, "argos-vision-ocr.swift")
	if fileNonEmptyLocal(path) {
		return path, nil
	}
	source := `import Foundation
import AppKit
import Vision

if CommandLine.arguments.count < 2 {
    FileHandle.standardError.write(Data("image path required\n".utf8))
    exit(2)
}

let url = URL(fileURLWithPath: CommandLine.arguments[1])
guard let image = NSImage(contentsOf: url) else {
    FileHandle.standardError.write(Data("cannot open image\n".utf8))
    exit(3)
}
var rect = CGRect(origin: .zero, size: image.size)
guard let cgImage = image.cgImage(forProposedRect: &rect, context: nil, hints: nil) else {
    FileHandle.standardError.write(Data("cannot create cg image\n".utf8))
    exit(4)
}

var recognized: [String] = []
let request = VNRecognizeTextRequest { request, error in
    if let error = error {
        FileHandle.standardError.write(Data(error.localizedDescription.utf8))
        return
    }
    let observations = request.results as? [VNRecognizedTextObservation] ?? []
    for observation in observations {
        if let candidate = observation.topCandidates(1).first {
            recognized.append(candidate.string)
        }
    }
}
request.recognitionLevel = .accurate
request.usesLanguageCorrection = true
request.recognitionLanguages = ["ko-KR", "en-US"]

let handler = VNImageRequestHandler(cgImage: cgImage, options: [:])
do {
    try handler.perform([request])
    print(recognized.joined(separator: "\n"))
} catch {
    FileHandle.standardError.write(Data(error.localizedDescription.utf8))
    exit(5)
}
`
	if err := os.WriteFile(path, []byte(source), 0600); err != nil {
		return "", err
	}
	return path, nil
}

func signalVisionOCRTimeout() time.Duration {
	raw := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_IMAGE_OCR_TIMEOUT"))
	if raw == "" {
		return 30 * time.Second
	}
	if d, err := time.ParseDuration(raw); err == nil && d > 0 {
		return d
	}
	if seconds, err := strconv.ParseFloat(raw, 64); err == nil && seconds > 0 {
		return time.Duration(seconds * float64(time.Second))
	}
	return 30 * time.Second
}

func signalVisionModelTimeout() time.Duration {
	raw := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_TIMEOUT"))
	if raw == "" {
		return 45 * time.Second
	}
	if d, err := time.ParseDuration(raw); err == nil && d > 0 {
		return d
	}
	if seconds, err := strconv.ParseFloat(raw, 64); err == nil && seconds > 0 {
		return time.Duration(seconds * float64(time.Second))
	}
	return 45 * time.Second
}

func matchSignalTarget(targets []Target, event IncomingMessage) (Target, bool) {
	for _, target := range targets {
		if target.Channel != "signal" {
			continue
		}
		if target.GroupID != "" && event.GroupID == target.GroupID {
			return target, true
		}
		if target.Recipient != "" && event.GroupID == "" && event.Source == target.Recipient {
			return target, true
		}
	}
	return Target{}, false
}

type signalAttachmentContext struct {
	TargetID    string             `json:"target_id"`
	CreatedAt   time.Time          `json:"created_at"`
	MessageText string             `json:"message_text,omitempty"`
	Attachments []SignalAttachment `json:"attachments,omitempty"`
}

func storeLatestSignalAttachmentContext(targetID string, event IncomingMessage) {
	if strings.TrimSpace(targetID) == "" || len(event.Attachments) == 0 {
		return
	}
	ctx := signalAttachmentContext{
		TargetID:    targetID,
		CreatedAt:   time.Now().UTC(),
		MessageText: event.Redacted,
		Attachments: event.Attachments,
	}
	data, err := json.MarshalIndent(ctx, "", "  ")
	if err != nil {
		return
	}
	path := signalAttachmentContextPath(targetID)
	_ = os.MkdirAll(filepath.Dir(path), 0700)
	_ = os.WriteFile(path, append(data, '\n'), 0600)
}

func latestSignalAttachmentContext(targetID string) string {
	ctx, ok := latestSignalAttachmentContextData(targetID)
	if !ok {
		return ""
	}
	lines := []string{"최근 Signal 이미지/첨부 컨텍스트입니다. 사용자가 '위 이미지', '방금 이미지', '사진'이라고 말하면 이 내용을 기준으로 답하세요."}
	if ctx.MessageText != "" {
		lines = append(lines, "첨부와 함께 온 메시지: "+ctx.MessageText)
	}
	for i, attachment := range ctx.Attachments {
		label := fmt.Sprintf("첨부 %d", i+1)
		if attachment.Filename != "" {
			label += " (" + attachment.Filename + ")"
		}
		lines = append(lines, label+": "+firstNonEmpty(attachment.ContentType, "unknown"))
		if attachment.Description != "" {
			lines = append(lines, "이미지 설명: "+trimForContext(attachment.Description, 1200))
		}
		if attachment.Text != "" {
			lines = append(lines, "인식된 텍스트: "+trimForContext(attachment.Text, 1800))
		} else if attachment.Error != "" {
			lines = append(lines, "이미지 분석 오류: "+attachment.Error)
		} else if signalAttachmentIsImage(attachment) {
			lines = append(lines, "이미지 텍스트를 찾지 못했습니다.")
		}
		if attachment.VisionError != "" {
			lines = append(lines, "이미지 설명 오류: "+attachment.VisionError)
		}
	}
	return strings.Join(lines, "\n")
}

func latestSignalAttachmentContextData(targetID string) (signalAttachmentContext, bool) {
	path := signalAttachmentContextPath(targetID)
	data, err := os.ReadFile(path)
	if err != nil {
		return signalAttachmentContext{}, false
	}
	var ctx signalAttachmentContext
	if err := json.Unmarshal(data, &ctx); err != nil {
		return signalAttachmentContext{}, false
	}
	if ctx.CreatedAt.IsZero() || time.Since(ctx.CreatedAt) > signalAttachmentContextTTL() || len(ctx.Attachments) == 0 {
		return signalAttachmentContext{}, false
	}
	return ctx, true
}

func signalAttachmentContextPath(targetID string) string {
	safe := strings.NewReplacer("/", "_", "\\", "_", ":", "_").Replace(strings.TrimSpace(targetID))
	if safe == "" {
		safe = "unknown"
	}
	return filepath.Join(signalAttachmentDir(), safe+".context.json")
}

func signalAttachmentContextTTL() time.Duration {
	raw := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_ATTACHMENT_CONTEXT_TTL"))
	if raw == "" {
		return 30 * time.Minute
	}
	if d, err := time.ParseDuration(raw); err == nil && d > 0 {
		return d
	}
	if seconds, err := strconv.ParseFloat(raw, 64); err == nil && seconds > 0 {
		return time.Duration(seconds * float64(time.Second))
	}
	return 30 * time.Minute
}

func directSignalAttachmentReply(event IncomingMessage) string {
	if len(event.Attachments) == 0 || !signalTextAsksAboutAttachment(event.Redacted) {
		return ""
	}
	recognized := []string{}
	descriptions := []string{}
	errors := []string{}
	for _, attachment := range event.Attachments {
		if description := strings.TrimSpace(attachment.Description); description != "" {
			descriptions = append(descriptions, description)
		}
		if text := strings.TrimSpace(attachment.Text); text != "" {
			recognized = append(recognized, text)
		} else if errText := strings.TrimSpace(attachment.Error); errText != "" {
			errors = append(errors, errText)
		}
	}
	if len(recognized) > 0 {
		text := strings.Join(recognized, "\n")
		if signalTextAsksForCode(event.Redacted) {
			if code := firstSignalImageCode(text); code != "" {
				return code
			}
		}
		if signalTextAsksForVisualDescription(event.Redacted) && len(descriptions) > 0 {
			return formatSignalImageUnderstanding(descriptions, text)
		}
		if signalTextAsksForSummary(event.Redacted) {
			if len(descriptions) > 0 {
				return formatSignalImageUnderstanding(descriptions, text)
			}
			return summarizeSignalAttachmentText(text)
		}
		if len(descriptions) > 0 {
			return formatSignalImageUnderstanding(descriptions, text)
		}
		return "첨부에서 읽은 텍스트입니다.\n" + trimForContext(text, 1200)
	}
	if len(descriptions) > 0 {
		return formatSignalImageUnderstanding(descriptions, "")
	}
	if len(errors) > 0 {
		return "첨부는 받았지만 내용을 읽지 못했습니다: " + strings.Join(errors, "; ")
	}
	return ""
}

func directLatestSignalAttachmentReply(targetID, text string) string {
	if !signalTextAsksAboutPreviousAttachment(text) {
		return ""
	}
	ctx, ok := latestSignalAttachmentContextData(targetID)
	if !ok {
		return ""
	}
	return directSignalAttachmentReply(IncomingMessage{
		Redacted:    text,
		Attachments: ctx.Attachments,
	})
}

func signalTextAsksAboutAttachment(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return true
	}
	keywords := []string{"attachment", "file", "image", "photo", "picture", "screenshot", "ocr", "code", "text", "summary", "summarize", "첨부", "파일", "이미지", "사진", "스크린샷", "캡처", "코드", "텍스트", "요약", "내용", "무슨", "뭐", "읽", "위"}
	for _, keyword := range keywords {
		if strings.Contains(lower, keyword) {
			return true
		}
	}
	return false
}

func signalTextAsksAboutPreviousAttachment(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return false
	}
	if containsAny(lower, "previous image", "last image", "above image", "that image", "that screenshot", "previous attachment", "last attachment") {
		return true
	}
	if containsAny(lower, "위 이미지", "위 사진", "위 스크린샷", "위 캡처", "방금 이미지", "방금 사진", "아까 이미지", "아까 사진", "최근 이미지", "최근 사진", "저 이미지", "그 이미지", "저 사진", "그 사진", "첨부") {
		return true
	}
	if containsAny(lower, "이미지", "사진", "스크린샷", "캡처") {
		return containsAny(lower, "위", "방금", "아까", "최근", "저", "그", "읽", "봐", "설명", "분석", "내용", "뭐", "무슨")
	}
	if containsAny(lower, "위", "방금", "아까", "최근", "저거", "그거") {
		return containsAny(lower, "읽", "봐", "설명", "분석", "내용", "뭐", "무슨")
	}
	return false
}

func signalTextAsksForCode(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	return strings.Contains(lower, "code") || strings.Contains(lower, "코드")
}

func signalTextAsksForSummary(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	return containsAny(lower, "summary", "summarize", "summarise", "요약", "정리", "내용", "무슨", "뭐야", "뭔지")
}

func signalTextAsksForVisualDescription(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	return containsAny(lower, "what is in", "describe", "look at", "understand", "screen", "image", "photo", "picture", "screenshot", "뭐가", "무슨", "설명", "이해", "화면", "이미지", "사진", "스크린샷", "봐줘")
}

func formatSignalImageUnderstanding(descriptions []string, ocrText string) string {
	lines := []string{"이미지 분석입니다."}
	for _, description := range descriptions {
		description = strings.TrimSpace(description)
		if description == "" {
			continue
		}
		lines = append(lines, "- "+trimForContext(description, 900))
	}
	ocrText = strings.TrimSpace(ocrText)
	if ocrText != "" {
		lines = append(lines, "읽은 텍스트:")
		lines = append(lines, trimForContext(ocrText, 1200))
	}
	return strings.Join(lines, "\n")
}

func summarizeSignalAttachmentText(text string) string {
	lines := strings.Split(strings.TrimSpace(text), "\n")
	summary := []string{}
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		summary = append(summary, line)
		if len(summary) >= 5 {
			break
		}
	}
	if len(summary) == 0 {
		return "첨부에서 읽을 수 있는 텍스트가 거의 없습니다."
	}
	return "첨부 내용 요약입니다.\n- " + strings.Join(summary, "\n- ")
}

func firstSignalImageCode(text string) string {
	re := regexp.MustCompile(`\b[A-Z][A-Z0-9]+-[0-9]{3,}\b`)
	return re.FindString(strings.ToUpper(text))
}

func guardReply(opts ListenOptions, target Target, event IncomingMessage) string {
	redacted := event.Redacted
	if strings.TrimSpace(redacted) == "" {
		return ""
	}
	mode := strings.ToLower(strings.TrimSpace(opts.Mode))
	if mode == "" {
		mode = "guard"
	}
	if isOneWayReportTarget(opts, target, mode) {
		return ""
	}
	workText := redacted
	if mode == "assistant" && signalLocalRawIngressEnabled() && strings.TrimSpace(event.raw) != "" {
		workText = event.raw
		opts.EvidenceText = redacted
	}
	opts.Source = strings.TrimSpace(event.Source)
	if reply, handled := maybeUpdateRoomModel(target, event, redacted); handled {
		return reply
	}
	if reply, handled := maybeClearRoomHistory(target, event, redacted); handled {
		return reply
	}
	if reply, handled := maybeSignalAttachmentStatusReply(redacted); handled {
		return reply
	}
	if reply, handled := maybeSignalImageStatusReply(redacted); handled {
		return reply
	}
	if reply, handled := signalCapabilityReply(mode, redacted); handled {
		return reply
	}
	if reply, handled := prepareSignalMailFromLatestAttachment(opts, redacted); handled {
		return reply
	}
	if reply := directSignalAttachmentReply(event); reply != "" {
		return reply
	}
	if reply := directLatestSignalAttachmentReply(opts.TargetID, redacted); reply != "" {
		return reply
	}
	if mode == "assistant" && signalAssistantVaultCommandsEnabled() && isAssistantVaultSignalFlow(target, event) {
		if reply, handled := guardVaultSignalReply(target, event); handled {
			return assistantVaultSignalReply(reply)
		}
	}
	if mode == "guard" {
		if reply, handled := guardVaultSignalReply(target, event); handled {
			return reply
		}
	}
	if mode == "assistant" {
		return assistantReply(opts, workText)
	}
	if reply, handled := maybeStartAsyncPreparedNewsReply(opts, target, redacted); handled {
		return reply
	}
	if mode == "assistant" {
		if reply, handled := assistantMemoryIntentReply(opts, redacted); handled {
			return reply
		}
		if isFreshSpreadsheetCreationRequest(redacted) {
			if reply, handled := assistantRequiredToolFallbackReply(opts, redacted); handled {
				return reply
			}
		}
		if reply, handled := assistantRecentArtifactFallbackReply(opts, redacted); handled {
			return reply
		}
		if intent, handled := fallbackAssistantToolIntent(redacted); handled {
			return replyFromMailToolIntent(opts, redacted, intent)
		}
		if reply, handled := replyFromRecentSignalMailContext(opts, redacted); handled {
			return reply
		}
	}
	if reply, handled := assistantScenarioReply(opts, workText); handled {
		return reply
	}
	if mode == "guard" {
		if isArgosApprovalText(strings.ToLower(strings.TrimSpace(redacted))) {
			if reply, ok := approvePendingArgosAction(opts, isArgosAlwaysAllowText(strings.ToLower(strings.TrimSpace(redacted)))); ok {
				return reply
			}
		}
		if isMailApprovalText(strings.ToLower(strings.TrimSpace(redacted))) {
			if reply, ok := approvePendingMailSend(opts); ok {
				return reply
			}
		}
	}
	if asksForExternalAI(redacted) {
		return strings.Join([]string{
			"Argos는 Signal 방의 mode를 보고 직접 처리합니다.",
			"Claude, Codex, GPT 웹/앱에 물어보는 handoff는 토큰이나 세션을 추출하지 않는 visible handoff 작업으로만 다룹니다.",
			"개발 작업 자체는 Claude/Codex 앱에서 MeshClaw MCP를 호출하는 흐름이 기본입니다.",
		}, "\n")
	}
	if mode == "guard" && isSignalPersonalAssistantAction(redacted) {
		assistantOpts := opts
		assistantOpts.Mode = "assistant"
		return assistantReply(assistantOpts, redacted)
	}
	if mode == "ops" {
		return opsReply(redacted)
	}
	if mode == "briefing" {
		return briefingReply(opts, redacted)
	}
	if mode == "assistant" {
		return assistantReply(opts, redacted)
	}
	if mode != "chat" && !isGuardScope(redacted, event.Intent) {
		return strings.Join([]string{
			"이 방은 MeshClaw Guard 채널입니다. Argos는 배달부이고, Guard 채널은 비밀번호, 토큰, 키, vault handle, 승인, 로컬 AI 기록 정리 같은 민감정보 작업 전용입니다.",
			"일반 질문이나 서버 운영 판단은 Codex/Claude/Cursor에서 MeshClaw MCP로 진행하는 편이 맞습니다.",
		}, "\n")
	}
	if strings.Contains(redacted, "[REDACTED:") {
		return strings.Join([]string{
			"Argos가 받았습니다.",
			"비밀값처럼 보이는 내용은 원문을 저장하지 않고 가렸습니다.",
			"아직 Signal 대화에서 자동 vault 저장은 켜지지 않았습니다. 지금은 로컬 Guard/Vault 명령으로 handle을 만든 뒤 Codex/Claude에는 handle만 넘기는 구조가 안전합니다.",
		}, "\n")
	}
	cfg, _, err := aichat.LoadConfig()
	if err != nil {
		cfg = aichat.DefaultConfig()
	}
	if opts.Model != "" {
		cfg.Model = opts.Model
	}
	cfg.MaxTokens = signalMaxTokens(mode, cfg.MaxTokens)
	if opts.BaseURL != "" {
		cfg.BaseURL = opts.BaseURL
	}
	if baseURL := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_GUARD_BASE_URL")); baseURL != "" {
		cfg.BaseURL = baseURL
	}
	if model := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_GUARD_MODEL")); model != "" {
		cfg.Model = model
	}
	cfg.SystemPrompt = signalSystemPrompt(mode, event.Intent)
	history := []aichat.Message(nil)
	if mode == "chat" || mode == "briefing" || mode == "assistant" {
		history = loadSignalHistory(opts.TargetID, 12)
		if contextText := latestSignalAttachmentContext(opts.TargetID); contextText != "" {
			history = append([]aichat.Message{{Role: "system", Content: contextText}}, history...)
		}
		if mode == "chat" || mode == "assistant" {
			history = append(assistantPersonalizationModelContextMessages(), history...)
		}
	}
	if mode == "briefing" {
		if contextText := latestNewsBriefingContext(); contextText != "" {
			history = append([]aichat.Message{{Role: "system", Content: contextText}}, history...)
		}
	}
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
	defer cancel()
	reply, err := aichat.NewClient(cfg).Chat(ctx, history, redacted)
	if err != nil {
		return "Argos가 받았습니다. 로컬 모델 응답은 아직 실패했습니다: " + err.Error()
	}
	if mode == "chat" || mode == "briefing" || mode == "assistant" {
		_ = appendSignalHistory(opts.TargetID, redacted, reply)
	}
	return reply
}

func isOneWayReportTarget(opts ListenOptions, target Target, mode string) bool {
	id := sanitizeID(firstNonEmpty(opts.TargetID, target.ID))
	if id == "argos-briefing" || id == "argos-ops" || id == "report-room" {
		return true
	}
	if OneWayReportTarget(target) {
		return true
	}
	switch strings.ToLower(strings.TrimSpace(firstNonEmpty(mode, opts.Mode))) {
	case "briefing", "ops":
		return true
	default:
		return false
	}
}

func signalLocalRawIngressEnabled() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_LOCAL_RAW_INGRESS")))
	return value == "" || value == "1" || value == "true" || value == "on" || value == "yes"
}

