func isSignalCapabilityQuestion(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "").Replace(lower)
	if compact == "?" || compact == "도움" || compact == "도움말" || compact == "사용법" || compact == "help" || compact == "/help" {
		return true
	}
	if containsAny(lower, "what can you do", "what do you do", "who are you", "help", "usage", "빠른 예시", "바로 해볼 명령", "예문 보여", "기능 보여") {
		return true
	}
	return containsAny(compact,
		"넌누구", "너는누구", "정체성", "뭐하는", "뭐할수", "뭘할수", "무엇을할수", "어떤일을할수", "기능뭐", "기능목록", "기능보여", "할수있는일", "사용방법", "빠른예시", "바로해볼명령",
	)
}

func isSignalPersonalAssistantAction(text string) bool {
	action := osauto.ClassifyArgosAction(text)
	return action.Action != "none" && action.Error == ""
}

func maybeClearRoomHistory(target Target, event IncomingMessage, text string) (string, bool) {
	if !isClearHistoryCommand(text) {
		return "", false
	}
	mode := strings.ToLower(strings.TrimSpace(target.Mode))
	if mode != "chat" && mode != "briefing" && mode != "assistant" && mode != "guard" {
		return "이 방은 대화 기록 정리 대상이 아닙니다.", true
	}
	if target.GroupID != "" && !signalRoomAdmin(target, event.Source) {
		return "대화 기록 정리는 이 Signal 방의 관리자만 할 수 있습니다.", true
	}
	path := signalHistoryPath(target.ID)
	if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
		return "대화 기록 삭제에 실패했습니다: " + err.Error(), true
	}
	return strings.Join([]string{
		"이 방의 MeshClaw 로컬 대화 기록을 삭제했습니다.",
		"삭제 대상: " + path,
		"주의: Signal 앱 자체의 메시지 기록과 Claude/Codex 자체 앱 기록은 별도로 관리됩니다.",
	}, "\n"), true
}

func isClearHistoryCommand(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return false
	}
	if lower == "/clear" || lower == "/reset" || lower == "clear history" || lower == "reset memory" {
		return true
	}
	return containsAny(lower,
		"기억 지워", "기억 삭제", "기록 지워", "기록 삭제", "대화기록 삭제", "대화 기록 삭제",
		"메모리 지워", "메모리 삭제", "memory clear", "history clear",
	)
}

