type signalAttachmentStatusReport struct {
	Image          signalImageStatusReport `json:"image"`
	TextReadable   bool                    `json:"text_readable"`
	DocxReadable   bool                    `json:"docx_readable"`
	TextutilReady  bool                    `json:"textutil_ready"`
	SpotlightReady bool                    `json:"spotlight_ready"`
	PDFToTextReady bool                    `json:"pdftotext_ready"`
	QuickLookReady bool                    `json:"quicklook_ready"`
	SwiftReady     bool                    `json:"swift_ready"`
}

func signalAttachmentStatus() signalAttachmentStatusReport {
	return signalAttachmentStatusReport{
		Image:          signalImageStatus(),
		TextReadable:   true,
		DocxReadable:   true,
		TextutilReady:  commandAvailable("textutil"),
		SpotlightReady: commandAvailable("mdls"),
		PDFToTextReady: commandAvailable("pdftotext"),
		QuickLookReady: commandAvailable("qlmanage"),
		SwiftReady:     commandAvailable("swift"),
	}
}

func formatSignalAttachmentStatus(report signalAttachmentStatusReport) string {
	lines := []string{"Signal 첨부 이해 상태입니다."}
	image := "가능"
	if !report.Image.OCRAvailable {
		image = "점검 필요"
	}
	lines = append(lines, "- 이미지: "+image+" (macOS Vision OCR")
	if report.Image.VisionConfigured {
		model := "설정됨"
		if report.Image.VisionModel != "" {
			model = report.Image.VisionModel
		}
		lines[len(lines)-1] += " + " + model + " 설명 모델"
	}
	lines[len(lines)-1] += ")"
	lines = append(lines, "- 텍스트/Markdown/JSON/CSV: 가능")
	lines = append(lines, "- DOCX: 가능 (내장 파서)")
	docRTF := "가능"
	if !report.TextutilReady {
		docRTF = "제한"
	}
	lines = append(lines, "- DOC/RTF: "+docRTF+" (textutil)")
	pdfText := "제한"
	pdfParts := []string{}
	if report.SpotlightReady {
		pdfParts = append(pdfParts, "mdls")
	}
	if report.PDFToTextReady {
		pdfParts = append(pdfParts, "pdftotext")
	}
	if len(pdfParts) > 0 {
		pdfText = "가능"
	} else {
		pdfParts = append(pdfParts, "mdls/pdftotext 없음")
	}
	lines = append(lines, "- PDF 텍스트: "+pdfText+" ("+strings.Join(pdfParts, ", ")+")")
	pdfOCR := "가능"
	if !report.QuickLookReady || !report.SwiftReady || !report.Image.OCRAvailable {
		pdfOCR = "제한"
	}
	lines = append(lines, "- PDF 이미지 OCR fallback: "+pdfOCR+" (QuickLook + macOS Vision, 첫 페이지 중심)")
	if report.Image.Problem != "" {
		lines = append(lines, "문제: "+report.Image.Problem)
	}
	if report.Image.NextAction != "" {
		lines = append(lines, "다음 조치: "+report.Image.NextAction)
	}
	return strings.Join(lines, "\n")
}

func commandAvailable(name string) bool {
	_, err := exec.LookPath(name)
	return err == nil
}

type signalImageStatusReport struct {
	OCRBackend       string `json:"ocr_backend"`
	OCRAvailable     bool   `json:"ocr_available"`
	OCRScriptReady   bool   `json:"ocr_script_ready"`
	VisionConfigured bool   `json:"vision_configured"`
	VisionModel      string `json:"vision_model,omitempty"`
	VisionBaseURL    string `json:"vision_base_url,omitempty"`
	VisionSource     string `json:"vision_source,omitempty"`
	VisionReachable  bool   `json:"vision_reachable"`
	VisionStatus     string `json:"vision_status,omitempty"`
	Problem          string `json:"problem,omitempty"`
	NextAction       string `json:"next_action,omitempty"`
}

func signalImageStatus() signalImageStatusReport {
	report := signalImageStatusReport{
		OCRBackend:     "macos_vision",
		OCRAvailable:   fileNonEmptyLocal("/usr/bin/swift"),
		OCRScriptReady: fileNonEmptyLocal(filepath.Join(signalAttachmentDir(), "bin", "argos-vision-ocr.swift")),
	}
	model := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_MODEL"))
	baseURL := strings.TrimRight(strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_BASE_URL")), "/")
	apiKey := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_VISION_API_KEY"))
	source := "environment"
	if model == "" {
		model = signalDispatcherPlistEnvValue("MESHCLAW_SIGNAL_VISION_MODEL")
		if model != "" {
			source = "signal-dispatcher-plist"
		}
	}
	if baseURL == "" {
		baseURL = strings.TrimRight(signalDispatcherPlistEnvValue("MESHCLAW_SIGNAL_VISION_BASE_URL"), "/")
		if baseURL != "" {
			source = "signal-dispatcher-plist"
		}
	}
	if apiKey == "" {
		apiKey = signalDispatcherPlistEnvValue("MESHCLAW_SIGNAL_VISION_API_KEY")
	}
	if baseURL == "" {
		if cfg, _, err := aichat.LoadConfig(); err == nil {
			baseURL = strings.TrimRight(strings.TrimSpace(cfg.BaseURL), "/")
			if apiKey == "" {
				apiKey = strings.TrimSpace(cfg.APIKey)
			}
			source = "aichat-config"
		}
	}
	if baseURL == "" {
		baseURL = strings.TrimRight(strings.TrimSpace(aichat.DefaultConfig().BaseURL), "/")
		if apiKey == "" {
			apiKey = strings.TrimSpace(aichat.DefaultConfig().APIKey)
		}
		source = "default"
	}
	report.VisionModel = model
	report.VisionBaseURL = baseURL
	report.VisionSource = source
	report.VisionConfigured = model != "" && baseURL != ""
	if !report.OCRAvailable {
		report.Problem = "macOS Vision OCR을 실행할 Swift 런타임을 찾지 못했습니다."
		report.NextAction = "Signal dispatcher를 macOS 사용자 세션에서 실행하고 /usr/bin/swift를 확인하세요."
	}
	if !report.VisionConfigured {
		if report.Problem == "" {
			report.Problem = "이미지 설명용 비전 모델이 설정되지 않아 OCR fallback만 사용합니다."
		}
		report.NextAction = "MESHCLAW_SIGNAL_VISION_MODEL과 MESHCLAW_SIGNAL_VISION_BASE_URL을 설정한 뒤 signal-dispatcher를 재설치/재시작하세요."
		return report
	}
	endpoint := strings.TrimRight(baseURL, "/") + "/models"
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, endpoint, nil)
	if err != nil {
		report.Problem = "비전 모델 endpoint 요청을 만들 수 없습니다: " + err.Error()
		report.NextAction = "비전 모델 base_url 설정을 확인하세요."
		return report
	}
	if apiKey != "" {
		req.Header.Set("Authorization", "Bearer "+apiKey)
	}
	resp, err := (&http.Client{Timeout: 3 * time.Second}).Do(req)
	if err != nil {
		report.Problem = "비전 모델 endpoint에 연결할 수 없습니다: " + err.Error()
		report.NextAction = "모델 서버가 켜져 있고 dispatcher Mac에서 접근 가능한지 확인하세요."
		return report
	}
	defer resp.Body.Close()
	report.VisionStatus = resp.Status
	report.VisionReachable = resp.StatusCode >= 200 && resp.StatusCode < 300
	if !report.VisionReachable {
		report.Problem = "비전 모델 endpoint가 정상 응답하지 않습니다: " + resp.Status
		report.NextAction = "OpenAI-compatible /models endpoint와 API key 설정을 확인하세요."
	}
	return report
}

func formatSignalImageStatus(report signalImageStatusReport) string {
	lines := []string{"Signal 이미지 이해 상태입니다."}
	ocr := "가능"
	if !report.OCRAvailable {
		ocr = "점검 필요"
	}
	lines = append(lines, "- OCR: "+ocr+" ("+report.OCRBackend+", dispatcher Mac에서 실행)")
	if report.OCRScriptReady {
		lines = append(lines, "- OCR 스크립트: 준비됨")
	} else {
		lines = append(lines, "- OCR 스크립트: 첫 이미지 수신 시 자동 생성")
	}
	if report.VisionConfigured {
		reachable := "점검 필요"
		if report.VisionReachable {
			reachable = "연결됨"
		}
		lines = append(lines, "- 이미지 설명 모델: "+reachable+" ("+report.VisionModel+" @ "+report.VisionBaseURL+")")
		if report.VisionSource != "" {
			lines = append(lines, "- 모델 설정 출처: "+report.VisionSource)
		}
	} else {
		lines = append(lines, "- 이미지 설명 모델: 미설정, OCR fallback만 사용")
	}
	if report.Problem != "" {
		lines = append(lines, "문제: "+report.Problem)
	}
	if report.NextAction != "" {
		lines = append(lines, "다음 조치: "+report.NextAction)
	}
	return strings.Join(lines, "\n")
}

func signalDispatcherPlistEnvValue(key string) string {
	key = strings.TrimSpace(key)
	if key == "" {
		return ""
	}
	home, err := os.UserHomeDir()
	if err != nil || strings.TrimSpace(home) == "" {
		return ""
	}
	path := filepath.Join(home, "Library", "LaunchAgents", "ai.meshclaw.argos-signal-dispatcher.plist")
	data, err := os.ReadFile(path)
	if err != nil {
		return ""
	}
	text := string(data)
	marker := "<key>" + xmlEscapeSignalPlist(key) + "</key>"
	idx := strings.Index(text, marker)
	if idx < 0 {
		return ""
	}
	rest := text[idx+len(marker):]
	start := strings.Index(rest, "<string>")
	if start < 0 {
		return ""
	}
	rest = rest[start+len("<string>"):]
	end := strings.Index(rest, "</string>")
	if end < 0 {
		return ""
	}
	return strings.TrimSpace(xmlUnescapeSignalPlist(rest[:end]))
}

func xmlEscapeSignalPlist(value string) string {
	replacer := strings.NewReplacer("&", "&amp;", "<", "&lt;", ">", "&gt;", `"`, "&quot;", "'", "&apos;")
	return replacer.Replace(value)
}

func xmlUnescapeSignalPlist(value string) string {
	replacer := strings.NewReplacer("&apos;", "'", "&quot;", `"`, "&gt;", ">", "&lt;", "<", "&amp;", "&")
	return replacer.Replace(value)
}

func maybeUpdateRoomModel(target Target, event IncomingMessage, text string) (string, bool) {
	if isRoomModelUsageCommand(text) {
		return strings.Join([]string{
			"모델을 바꾸려면 이렇게 보내세요.",
			"/model gemma4:e4b",
			"/model gpt-oss:20b http://g4:11434/v1",
		}, "\n"), true
	}
	model, baseURL, ok := parseRoomModelCommand(text)
	if !ok {
		return "", false
	}
	mode := strings.ToLower(strings.TrimSpace(target.Mode))
	if mode != "chat" && mode != "briefing" && mode != "assistant" {
		return "이 방은 모델 교체 대상이 아닙니다. 모델 교체는 chat, briefing, assistant 방에서만 허용합니다.", true
	}
	if !signalRoomAdmin(target, event.Source) {
		return "모델 교체는 이 Signal 방의 관리자만 할 수 있습니다.", true
	}
	if isBlockedRoomModel(model) {
		return "이 방은 로컬/OpenAI 호환 모델만 지원합니다. Claude/Codex는 각 앱과 MeshClaw MCP에서 직접 사용하세요.", true
	}
	target.Model = model
	if baseURL != "" {
		target.BaseURL = baseURL
	} else if isLocalOllamaRoomModel(model) {
		target.BaseURL = "http://localhost:11434/v1"
	}
	_, saved, err := UpsertTarget(target)
	if err != nil {
		return "모델 설정 저장에 실패했습니다: " + err.Error(), true
	}
	lines := []string{
		"모델 설정을 변경했습니다.",
		"target: " + saved.ID,
		"mode: " + saved.Mode,
		"model: " + saved.Model,
	}
	if saved.BaseURL != "" {
		lines = append(lines, "base_url: "+saved.BaseURL)
	}
	return strings.Join(lines, "\n"), true
}

func parseRoomModelCommand(text string) (model string, baseURL string, ok bool) {
	fields := strings.Fields(strings.TrimSpace(text))
	if len(fields) < 2 {
		return "", "", false
	}
	verb := strings.ToLower(strings.Trim(fields[0], " :：,，.。"))
	if verb != "model" && verb != "모델" && verb != "/model" {
		return "", "", false
	}
	model = strings.TrimSpace(fields[1])
	if model == "" {
		return "", "", false
	}
	if len(fields) >= 3 {
		baseURL = strings.TrimSpace(fields[2])
	}
	return model, baseURL, true
}

func isRoomModelUsageCommand(text string) bool {
	verb := strings.ToLower(strings.Trim(strings.TrimSpace(text), " :：,，.。"))
	return verb == "model" || verb == "모델" || verb == "/model"
}

func signalRoomAdmin(target Target, source string) bool {
	source = strings.TrimSpace(source)
	if source == "" {
		return false
	}
	if target.GroupID == "" {
		return target.Recipient != "" && source == target.Recipient
	}
	rooms, _, err := listSignalRooms("", 10*time.Second)
	if err != nil {
		return false
	}
	for _, room := range rooms {
		if room.ID != target.GroupID {
			continue
		}
		for _, admin := range room.Admins {
			if strings.TrimSpace(admin) == source {
				return true
			}
		}
		return false
	}
	return false
}

func guardVaultSignalReply(target Target, event IncomingMessage) (string, bool) {
	key := guardPendingKey(target, event)
	if command, ok := parseGuardCaptureCommand(event.Redacted); ok {
		ttl := guardSignalSecretTTL()
		now := time.Now().UTC()
		rememberPendingGuardCapture(key, pendingGuardCapture{
			Command:   command,
			CreatedAt: now,
			ExpiresAt: now.Add(ttl),
			Source:    event.Source,
			GroupID:   event.GroupID,
		})
		return strings.Join([]string{
			"Guard secret capture armed.",
			fmt.Sprintf("다음 %s 안에 비밀값만 보내세요.", guardSignalSecretTTLText(ttl)),
			"다음 메시지는 모델, MCP evidence, 대화기록으로 보내지 않고 바로 vault에 저장합니다.",
			"주의: Signal 앱 자체에는 자동삭제 전까지 원문 메시지가 남을 수 있습니다.",
			"저장 대상: " + command.Scope + "/" + command.Name,
			"backend: " + command.Backend,
		}, "\n"), true
	}
	if capture, found := takePendingGuardCapture(key); found {
		return storeSignalGuardSecret(capture.Command, []byte(event.raw), target, event, false), true
	}
	command, ok := parseGuardStoreCommand(event.Redacted)
	if ok {
		pending, found := takePendingGuardSecret(key)
		if !found {
			return strings.Join([]string{
				"저장할 비밀값을 찾지 못했습니다.",
				fmt.Sprintf("먼저 `비밀 입력 operator-example api-key keychain`이라고 보낸 뒤 %s 안에 비밀값만 보내세요.", guardSignalSecretTTLText(guardSignalSecretTTL())),
				"또는 API 키나 비밀번호를 먼저 보낸 뒤 `저장 operator-example api-key keychain` 형식으로 답하세요.",
				"원문 비밀은 모델이나 evidence에 저장하지 않습니다.",
			}, "\n"), true
		}
		return storeSignalGuardSecret(command, pending.Value, target, event, true), true
	}
	if event.SecretDetected {
		now := time.Now().UTC()
		ttl := guardSignalSecretTTL()
		rememberPendingGuardSecret(key, pendingGuardSecret{
			Value:     []byte(event.raw),
			Redacted:  event.Redacted,
			CreatedAt: now,
			ExpiresAt: now.Add(ttl),
			Source:    event.Source,
			GroupID:   event.GroupID,
		})
		return strings.Join([]string{
			"비밀값을 감지했습니다.",
			fmt.Sprintf("원문은 모델로 보내지 않고 %s 동안 이 로컬 Guard 프로세스 메모리에만 보관합니다.", guardSignalSecretTTLText(ttl)),
			"저장하려면 이렇게 답하세요:",
			"`저장 operator-example api-key keychain`",
			"",
			"형식:",
			"`저장 <scope> <name> [local|keychain|pass]`",
			"예: `저장 cloudflare dns-token keychain`",
			"",
			"더 안전한 흐름:",
			"`비밀 입력 cloudflare dns-token keychain`을 먼저 보낸 뒤 다음 메시지에 비밀값만 보내세요.",
			"주의: Signal 앱 자체에는 자동삭제 전까지 원문 메시지가 남을 수 있습니다.",
		}, "\n"), true
	}
	return "", false
}

