func assistantVaultSignalReply(reply string) string {
	replacements := []struct {
		old string
		new string
	}{
		{"Guard secret capture armed.", "비밀값 저장 준비 완료."},
		{"로컬 Guard 프로세스", "로컬 비밀 저장 프로세스"},
		{"Signal Guard", "Signal"},
		{"Guard/Vault", "로컬 vault"},
		{"Guard", "로컬 vault"},
	}
	for _, replacement := range replacements {
		reply = strings.ReplaceAll(reply, replacement.old, replacement.new)
	}
	lines := []string{}
	for _, line := range strings.Split(reply, "\n") {
		if strings.HasPrefix(line, "주의:") || strings.HasPrefix(line, "Signal 앱에 남은 원문 메시지는") {
			continue
		}
		lines = append(lines, line)
	}
	return strings.Join(lines, "\n")
}

func storeSignalGuardSecret(command guardStoreCommand, value []byte, target Target, event IncomingMessage, keepOnFailure bool) string {
	entry, err := guardvault.Put(guardvault.PutOptions{
		Scope:       command.Scope,
		Name:        command.Name,
		Kind:        command.Kind,
		Description: command.Description,
		Backend:     command.Backend,
		Value:       value,
	})
	if err != nil {
		if keepOnFailure {
			key := guardPendingKey(target, event)
			now := time.Now().UTC()
			rememberPendingGuardSecret(key, pendingGuardSecret{
				Value:     value,
				Redacted:  event.Redacted,
				CreatedAt: now,
				ExpiresAt: now.Add(guardSignalSecretTTL()),
				Source:    event.Source,
				GroupID:   event.GroupID,
			})
		}
		return "저장 실패: " + err.Error()
	}
	record, storeErr := evidence.Store("signal-guard-vault-put", entry.Scope, "stored "+entry.Handle, entry)
	lines := []string{
		"저장 완료.",
		"handle: " + entry.Handle,
		"backend: " + entry.Backend,
		"fingerprint: " + entry.Fingerprint,
		"원문 비밀은 모델/MCP/evidence 답변에 포함하지 않았습니다.",
		"Signal 앱에 남은 원문 메시지는 자동삭제를 기다리거나 직접 삭제하세요.",
	}
	if record.StoredAt != "" {
		lines = append(lines, "작업 기록도 저장했습니다.")
	}
	if storeErr != nil {
		lines = append(lines, "작업 기록 저장 경고: "+storeErr.Error())
	}
	return strings.Join(lines, "\n")
}

type guardStoreCommand struct {
	Scope       string
	Name        string
	Backend     string
	Kind        string
	Description string
}

func parseGuardStoreCommand(text string) (guardStoreCommand, bool) {
	fields := strings.Fields(strings.TrimSpace(text))
	if len(fields) < 3 {
		return guardStoreCommand{}, false
	}
	verb := strings.ToLower(strings.Trim(fields[0], " :：,，.。"))
	if verb != "저장" && verb != "store" && verb != "save" {
		return guardStoreCommand{}, false
	}
	cmd := guardStoreCommand{Scope: fields[1], Name: fields[2], Backend: defaultGuardSignalBackend(), Kind: "secret", Description: "Imported from Signal Guard"}
	if len(fields) >= 4 {
		candidate := strings.ToLower(strings.Trim(fields[3], " :：,，.。"))
		switch candidate {
		case "local", "meshclaw", "aes", "keychain", "apple-keychain", "pass", "ubuntu-pass":
			cmd.Backend = candidate
		default:
			cmd.Kind = candidate
		}
	}
	if len(fields) >= 5 {
		cmd.Description = strings.Join(fields[4:], " ")
	}
	return cmd, true
}

func parseGuardCaptureCommand(text string) (guardStoreCommand, bool) {
	if cmd, ok := parseNaturalGuardCaptureCommand(text); ok {
		return cmd, true
	}
	fields := strings.Fields(strings.TrimSpace(text))
	if len(fields) < 3 {
		return guardStoreCommand{}, false
	}
	first := strings.ToLower(strings.Trim(fields[0], " :：,，.。"))
	second := strings.ToLower(strings.Trim(fields[1], " :：,，.。"))
	offset := -1
	switch first {
	case "비밀", "토큰", "패스워드", "비밀번호":
		switch second {
		case "입력", "캡처", "capture", "import":
			offset = 2
		}
	case "secret", "capture", "import", "token", "password":
		offset = 1
		if second == "input" || second == "capture" || second == "import" {
			offset = 2
		}
	}
	if offset < 0 || len(fields) < offset+2 {
		return guardStoreCommand{}, false
	}
	cmd := guardStoreCommand{Scope: fields[offset], Name: fields[offset+1], Backend: defaultGuardSignalBackend(), Kind: "secret", Description: "Imported from Signal vault capture"}
	if len(fields) >= offset+3 {
		candidate := strings.ToLower(strings.Trim(fields[offset+2], " :：,，.。"))
		switch candidate {
		case "local", "meshclaw", "aes", "keychain", "apple-keychain", "pass", "ubuntu-pass":
			cmd.Backend = candidate
		default:
			cmd.Kind = candidate
		}
	}
	if len(fields) >= offset+4 {
		cmd.Description = strings.Join(fields[offset+3:], " ")
	}
	return cmd, true
}

func parseNaturalGuardCaptureCommand(text string) (guardStoreCommand, bool) {
	trimmed := strings.TrimSpace(text)
	lower := strings.ToLower(trimmed)
	if !containsAny(lower, "비밀", "토큰", "token", "secret", "패스워드", "비밀번호", "api key", "api키") {
		return guardStoreCommand{}, false
	}
	if !containsAny(trimmed, "저장", "넣어", "보관", "save", "store") {
		return guardStoreCommand{}, false
	}
	if !containsAny(trimmed, "다음 메시지", "다음메시지", "값만", "비밀값", "secret value", "next message") {
		return guardStoreCommand{}, false
	}
	backend := defaultGuardSignalBackend()
	switch {
	case containsAny(lower, "로컬", "local", "meshclaw"):
		backend = "local"
	case containsAny(lower, "키체인", "keychain", "apple-keychain"):
		backend = "keychain"
	case containsAny(lower, "pass", "ubuntu-pass"):
		backend = "pass"
	}
	scope, name := "", ""
	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?i)([a-z0-9][a-z0-9._-]*)\s+([a-z0-9][a-z0-9._-]*)\s*(?:에|으로|로)\s*(?:로컬|local|키체인|keychain|pass|저장|보관|넣어)`),
		regexp.MustCompile(`(?i)(?:scope|스코프)\s*[:= ]\s*([a-z0-9][a-z0-9._-]*)\s+(?:name|이름)\s*[:= ]\s*([a-z0-9][a-z0-9._-]*)`),
	}
	for _, pattern := range patterns {
		if match := pattern.FindStringSubmatch(trimmed); len(match) >= 3 {
			scope = strings.Trim(match[1], " :：,，.。")
			name = strings.Trim(match[2], " :：,，.。")
			break
		}
	}
	if scope == "" || name == "" {
		return guardStoreCommand{}, false
	}
	return guardStoreCommand{
		Scope:       scope,
		Name:        name,
		Backend:     backend,
		Kind:        "secret",
		Description: "Imported from Signal natural vault capture",
	}, true
}

func guardSignalSecretTTL() time.Duration {
	seconds := 300
	if raw := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_GUARD_SECRET_TTL_SECONDS")); raw != "" {
		parsed, err := strconv.Atoi(raw)
		if err == nil && parsed > 0 {
			seconds = parsed
		}
	}
	if seconds > 600 {
		seconds = 600
	}
	return time.Duration(seconds) * time.Second
}

func guardSignalSecretTTLText(ttl time.Duration) string {
	seconds := int(ttl.Seconds())
	if seconds <= 120 || seconds%60 != 0 {
		return fmt.Sprintf("%d초", seconds)
	}
	minutes := seconds / 60
	return fmt.Sprintf("%d분", minutes)
}

func defaultGuardSignalBackend() string {
	if backend := strings.TrimSpace(os.Getenv("MESHCLAW_SIGNAL_GUARD_BACKEND")); backend != "" {
		return backend
	}
	if _, err := exec.LookPath("security"); err == nil {
		return "keychain"
	}
	if _, err := exec.LookPath("pass"); err == nil {
		return "pass"
	}
	return "local"
}

