func rememberPendingAssistantMemory(key string, pending pendingAssistantMemory) {
	assistantMemoryPending.Lock()
	defer assistantMemoryPending.Unlock()
	prunePendingAssistantMemoryLocked(time.Now().UTC())
	assistantMemoryPending.items[key] = pending
}

func takePendingAssistantMemory(key string, remove bool) (pendingAssistantMemory, bool) {
	assistantMemoryPending.Lock()
	defer assistantMemoryPending.Unlock()
	now := time.Now().UTC()
	prunePendingAssistantMemoryLocked(now)
	pending, ok := assistantMemoryPending.items[key]
	if !ok || now.After(pending.ExpiresAt) {
		delete(assistantMemoryPending.items, key)
		return pendingAssistantMemory{}, false
	}
	if remove {
		delete(assistantMemoryPending.items, key)
	}
	return pending, true
}

func prunePendingAssistantMemoryLocked(now time.Time) {
	for key, pending := range assistantMemoryPending.items {
		if now.After(pending.ExpiresAt) {
			delete(assistantMemoryPending.items, key)
		}
	}
}

