func rememberPendingAssistantConversation(key string, pending pendingAssistantConversation) {
	assistantConversationPending.Lock()
	defer assistantConversationPending.Unlock()
	now := time.Now().UTC()
	_ = loadPendingAssistantConversationsLocked(now)
	prunePendingAssistantConversationsLocked(now)
	assistantConversationPending.items[key] = pending
	_ = persistPendingAssistantConversationsLocked()
}

func takePendingAssistantConversation(key string, remove bool) (pendingAssistantConversation, bool) {
	assistantConversationPending.Lock()
	defer assistantConversationPending.Unlock()
	now := time.Now().UTC()
	_ = loadPendingAssistantConversationsLocked(now)
	changed := prunePendingAssistantConversationsLocked(now)
	pending, ok := assistantConversationPending.items[key]
	if !ok || now.After(pending.ExpiresAt) {
		delete(assistantConversationPending.items, key)
		_ = persistPendingAssistantConversationsLocked()
		return pendingAssistantConversation{}, false
	}
	if remove {
		delete(assistantConversationPending.items, key)
		changed = true
	}
	if changed {
		_ = persistPendingAssistantConversationsLocked()
	}
	return pending, true
}

func prunePendingAssistantConversationsLocked(now time.Time) bool {
	changed := false
	for key, pending := range assistantConversationPending.items {
		if now.After(pending.ExpiresAt) {
			delete(assistantConversationPending.items, key)
			changed = true
		}
	}
	return changed
}

func pendingAssistantConversationStorePath() string {
	if path := strings.TrimSpace(os.Getenv("MESHCLAW_PENDING_ASSISTANT_CONVERSATIONS")); path != "" {
		return path
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return filepath.Join(".meshclaw", "pending-assistant-conversations.json")
	}
	return filepath.Join(home, ".meshclaw", "pending-assistant-conversations.json")
}

func loadPendingAssistantConversationsLocked(now time.Time) error {
	if assistantConversationPending.items == nil {
		assistantConversationPending.items = map[string]pendingAssistantConversation{}
	}
	path := pendingAssistantConversationStorePath()
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}
	var store pendingAssistantConversationStore
	if err := json.Unmarshal(data, &store); err != nil {
		return err
	}
	for key, pending := range store.Items {
		key = strings.TrimSpace(key)
		if key == "" || pending.Kind != "shopping_direct_purchase" || strings.TrimSpace(pending.Intent.Query) == "" || now.After(pending.ExpiresAt) {
			continue
		}
		assistantConversationPending.items[key] = pending
	}
	return nil
}

func persistPendingAssistantConversationsLocked() error {
	path := pendingAssistantConversationStorePath()
	now := time.Now().UTC()
	items := map[string]pendingAssistantConversation{}
	for key, pending := range assistantConversationPending.items {
		key = strings.TrimSpace(key)
		if key == "" || pending.Kind != "shopping_direct_purchase" || strings.TrimSpace(pending.Intent.Query) == "" || now.After(pending.ExpiresAt) {
			continue
		}
		items[key] = pending
	}
	store := pendingAssistantConversationStore{
		Kind:      "meshclaw_pending_assistant_conversations",
		UpdatedAt: now,
		Items:     items,
	}
	data, err := json.MarshalIndent(store, "", "  ")
	if err != nil {
		return err
	}
	if err := os.MkdirAll(filepath.Dir(path), 0700); err != nil {
		return err
	}
	tmp := path + ".tmp"
	if err := os.WriteFile(tmp, append(data, '\n'), 0600); err != nil {
		return err
	}
	return os.Rename(tmp, path)
}

