func rememberRecentSignalMailContext(key string, ctx recentSignalMailContext) {
	if strings.TrimSpace(key) == "" || len(ctx.Items) == 0 {
		return
	}
	now := time.Now().UTC()
	ctx.CreatedAt = now
	if ctx.ExpiresAt.IsZero() {
		ctx.ExpiresAt = now.Add(mailSignalApprovalTTL())
	}
	recentSignalMailContexts.Lock()
	defer recentSignalMailContexts.Unlock()
	pruneRecentSignalMailContextsLocked(now)
	recentSignalMailContexts.items[key] = ctx
	if key != signalMailDefaultPendingKey {
		recentSignalMailContexts.items[signalMailDefaultPendingKey] = ctx
	}
	_ = persistRecentSignalMailContextsLocked()
}

func takeRecentSignalMailContext(key string, remove bool) (recentSignalMailContext, bool) {
	recentSignalMailContexts.Lock()
	defer recentSignalMailContexts.Unlock()
	now := time.Now().UTC()
	_ = loadRecentSignalMailContextsLocked(now)
	changed := pruneRecentSignalMailContextsLocked(now)
	ctx, foundKey, ok := recentSignalMailContextForKeyLocked(key)
	if !ok || now.After(ctx.ExpiresAt) {
		delete(recentSignalMailContexts.items, foundKey)
		_ = persistRecentSignalMailContextsLocked()
		return recentSignalMailContext{}, false
	}
	if remove {
		delete(recentSignalMailContexts.items, foundKey)
		changed = true
	}
	if changed {
		_ = persistRecentSignalMailContextsLocked()
	}
	return ctx, true
}

func recentSignalMailContextForKeyLocked(key string) (recentSignalMailContext, string, bool) {
	if ctx, ok := recentSignalMailContexts.items[key]; ok {
		return ctx, key, true
	}
	if key != signalMailDefaultPendingKey {
		if ctx, ok := recentSignalMailContexts.items[signalMailDefaultPendingKey]; ok {
			return ctx, signalMailDefaultPendingKey, true
		}
	}
	return recentSignalMailContext{}, key, false
}

func pruneRecentSignalMailContextsLocked(now time.Time) bool {
	changed := false
	for key, ctx := range recentSignalMailContexts.items {
		if now.After(ctx.ExpiresAt) {
			delete(recentSignalMailContexts.items, key)
			changed = true
		}
	}
	return changed
}

