func signalMaxTokens(mode string, configured int) int {
	if configured <= 0 {
		configured = 1024
	}
	switch mode {
	case "guard":
		if configured > 512 {
			return 512
		}
	case "ops":
		if configured > 1200 {
			return 1200
		}
	case "chat":
		if configured < 2048 {
			return 2048
		}
		if configured > 3072 {
			return 3072
		}
	case "briefing":
		if configured < 2048 {
			return 2048
		}
		if configured > 3072 {
			return 3072
		}
	case "assistant":
		if configured < 1536 {
			return 1536
		}
		if configured > 3072 {
			return 3072
		}
	default:
		if configured > 768 {
			return 768
		}
	}
	return configured
}

func opsReply(text string) string {
	lower := strings.ToLower(strings.TrimSpace(text))
	switch strings.TrimSpace(lower) {
	case "1", "뉴스", "news", "주요뉴스", "오늘의 주요뉴스", "오늘 주요뉴스", "주요 뉴스", "오늘의 주요 뉴스", "오늘 주요 뉴스":
		ctx, cancel := context.WithTimeout(context.Background(), 45*time.Second)
		defer cancel()
		return assistantbrief.News(ctx, assistantbrief.Options{Location: "Seoul", NewsLimit: assistantbrief.NewsLimitFromText(text, 8)}).Text
	case "2", "날씨", "weather":
		ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
		defer cancel()
		return assistantbrief.Morning(ctx, assistantbrief.Options{Location: "Seoul", NoNews: true}).Text
	case "3", "일정", "메일", "mail", "calendar":
		return strings.Join([]string{
			"개인 일정/메일 정리는 owner 전용 target으로만 보내는 것이 안전합니다.",
			"아직 Gmail/Calendar adapter 권한이 연결되지 않았습니다.",
			"구조는 준비 가능합니다: 개인 메일 요약 -> redaction -> owner-signal 전송 -> 답장/삭제/전달은 승인 필요.",
		}, "\n")
	case "4", "저녁", "evening":
		ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
		defer cancel()
		return assistantbrief.Evening(ctx, assistantbrief.Options{Location: "Seoul"}).Text
	case "5", "콘텐츠", "영상", "youtube", "rss":
		return strings.Join([]string{
			"콘텐츠/RSS 브리핑은 RSS가 있는 채널부터 안전하게 붙일 수 있습니다.",
			"가능한 것: YouTube channel RSS, 블로그 RSS, 뉴스 RSS, 공개 팟캐스트 RSS.",
			"주의할 것: Instagram/TikTok 인기 밈은 공식 RSS가 약해서 브라우저/검색 adapter와 출처 기록이 필요합니다.",
		}, "\n")
	}
	if step, ok := extractApprovalStep(text); ok {
		record, err := runtimeflow.GrantApproval("latest", step, "signal-ops", "approved from MeshClaw Ops Signal room", "signal")
		if err != nil {
			return "승인 기록에 실패했습니다: " + err.Error()
		}
		return fmt.Sprintf("승인 기록 완료: step=%s bundle=%s\n이 승인은 실행이 아니라 approval evidence 기록입니다. 실제 실행은 Codex/Claude 또는 MeshClaw workflow execute가 정책을 다시 확인해야 합니다.", step, record.Bundle)
	}
	if containsAny(lower, "상태", "보고", "리포트", "report", "status", "latest") {
		report, err := BuildReport(ReportOptions{Ref: "latest", Channel: "signal", Audience: "ops"})
		if err != nil {
			return "최신 MeshClaw 보고서를 만들지 못했습니다: " + err.Error()
		}
		return report.Text
	}
	if containsAny(lower, "도움", "help", "사용법") {
		return strings.Join([]string{
			"MeshClaw Ops 방입니다. Argos는 배달부이고, MeshClaw가 DevOps 런타임입니다.",
			"가능한 말:",
			"- 상태",
			"- 보고",
			"- 승인 <step-id>",
			"실제 서버 조치/실행은 Codex/Claude가 MeshClaw MCP로 수행하는 흐름이 안전합니다.",
		}, "\n")
	}
	return strings.Join([]string{
		"MeshClaw Ops 방입니다.",
		"여기서는 상태/보고/승인 기록만 처리합니다.",
		"예: 상태, 보고, 승인 send-approval",
	}, "\n")
}

func briefingReply(opts ListenOptions, text string) string {
	lower := strings.ToLower(strings.TrimSpace(text))
	switch strings.TrimSpace(lower) {
	case "1":
		ctx, cancel := context.WithTimeout(context.Background(), 45*time.Second)
		defer cancel()
		return assistantbrief.News(ctx, assistantbrief.Options{Location: "Seoul", NewsLimit: assistantbrief.NewsLimitFromText(text, 10)}).Text
	case "2":
		ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
		defer cancel()
		return assistantbrief.WeatherNow(ctx, assistantbrief.Options{Location: "Seoul"}).Text
	case "4":
		ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
		defer cancel()
		return assistantbrief.Evening(ctx, assistantbrief.Options{Location: "Seoul"}).Text
	}

	intent, ok := classifyBriefingIntent(opts, text)
	if ok && intent.Confidence >= 0.65 {
		switch intent.Intent {
		case "weather_current":
			ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
			defer cancel()
			return assistantbrief.WeatherNow(ctx, assistantbrief.Options{Location: firstNonEmpty(intent.Location, "Seoul")}).Text
		case "news_brief":
			ctx, cancel := context.WithTimeout(context.Background(), 45*time.Second)
			defer cancel()
			return assistantbrief.News(ctx, assistantbrief.Options{Location: firstNonEmpty(intent.Location, "Seoul"), NewsLimit: assistantbrief.NewsLimitFromText(text, 10)}).Text
		case "evening_brief":
			ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
			defer cancel()
			return assistantbrief.Evening(ctx, assistantbrief.Options{Location: firstNonEmpty(intent.Location, "Seoul")}).Text
		case "source_links":
			if sourceText := latestNewsSourcesReply(); sourceText != "" {
				return sourceText
			}
			return "최근 브리핑 evidence를 찾지 못했습니다."
		case "news_detail":
			if detail := latestNewsDetailReply(intent.Index); detail != "" {
				return detail
			}
			return "최근 주요뉴스 자료에서 해당 번호를 찾지 못했습니다."
		}
	}

	if reply, handled := assistantToolReply(opts, text); handled {
		return reply
	}

	return modelRoomReply(opts, text, "briefing")
}

type briefingIntent struct {
	Intent     string  `json:"intent"`
	Location   string  `json:"location,omitempty"`
	Index      int     `json:"index,omitempty"`
	Confidence float64 `json:"confidence,omitempty"`
	Reason     string  `json:"reason,omitempty"`
}

func classifyBriefingIntent(opts ListenOptions, text string) (briefingIntent, bool) {
	cfg, _, err := aichat.LoadConfig()
	if err != nil {
		cfg = aichat.DefaultConfig()
	}
	if opts.Model != "" {
		cfg.Model = opts.Model
	}
	if opts.BaseURL != "" {
		cfg.BaseURL = opts.BaseURL
	}
	cfg.MaxTokens = 192
	cfg.SystemPrompt = strings.Join([]string{
		"You classify the latest Signal room message for MeshClaw Argos Briefing.",
		"Return JSON only. No markdown. No explanation outside JSON.",
		"Valid intents: weather_current, news_brief, news_detail, evening_brief, source_links, meta_or_conversation.",
		"weather_current means the user is directly asking for current weather or forecast now.",
		"news_brief means the user asks to generate or refresh today's main news, news summary, or morning news briefing.",
		"news_detail means the user asks to explain one numbered news item in more detail. Extract the number into index.",
		"evening_brief means the user asks for an evening reminder or prayer briefing.",
		"source_links means the user explicitly asks for source links, original links, URLs, evidence, or Korean 출처/원문/링크 from the latest briefing.",
		"Do not classify fresh sources, current sources, or today's sources as source_links when the user is asking for a news brief.",
		"meta_or_conversation means corrections, complaints, questions about how the system works, date/API/source questions, or normal conversation.",
		"Do not classify as weather_current just because the message contains the word weather. If the user says the bot does not know weather, asks why a date was wrong, asks where weather is fetched from, or asks browser vs API, classify as meta_or_conversation.",
		"If location is omitted, use Seoul only for direct weather/news/evening requests.",
		`Examples:
{"message":"서울 오늘 날씨 알려줘","intent":"weather_current","location":"Seoul","confidence":0.95}
{"message":"비 와?","intent":"weather_current","location":"Seoul","confidence":0.8}
{"message":"오늘날씨는 모르네","intent":"meta_or_conversation","confidence":0.95}
{"message":"오늘 날짜를 왜 22일이라고 답했어?","intent":"meta_or_conversation","confidence":0.95}
{"message":"최신 기상 예보를 어디서 조회해?","intent":"meta_or_conversation","confidence":0.95}
{"message":"너가 브라우저로 찾아보는거야? 아니면 api 로?","intent":"meta_or_conversation","confidence":0.95}
{"message":"브리핑해줘","intent":"news_brief","location":"Seoul","confidence":0.85}
{"message":"오늘의 주요뉴스","intent":"news_brief","location":"Seoul","confidence":0.95}
{"message":"오늘 주요 뉴스 정리해줘","intent":"news_brief","location":"Seoul","confidence":0.95}
{"message":"한글로 주여뉴스 알려달라고","intent":"news_brief","location":"Seoul","confidence":0.9}
{"message":"give me five important news items using fresh sources","intent":"news_brief","location":"Seoul","confidence":0.9}
{"message":"3번 자세히 설명해줘","intent":"news_detail","index":3,"confidence":0.9}
{"message":"출처 보여줘","intent":"source_links","confidence":0.9}`,
		`Schema: {"intent":"...","location":"...","confidence":0.0,"reason":"..."}`,
	}, "\n")
	history := loadSignalHistory(opts.TargetID, 6)
	ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
	defer cancel()
	reply, err := aichat.NewClient(cfg).Chat(ctx, history, text)
	if err != nil {
		if strings.Contains(err.Error(), "reasoning but no final answer") {
			cfg.MaxTokens = 768
			cfg.SystemPrompt += "\nIf you cannot decide, return {\"intent\":\"meta_or_conversation\",\"confidence\":0.5}. Do not return reasoning."
			retryCtx, retryCancel := context.WithTimeout(context.Background(), 20*time.Second)
			defer retryCancel()
			reply, err = aichat.NewClient(cfg).Chat(retryCtx, nil, text)
			if err == nil {
				return parseBriefingIntentJSON(reply)
			}
		}
		return briefingIntent{}, false
	}
	return parseBriefingIntentJSON(reply)
}

func parseBriefingIntentJSON(reply string) (briefingIntent, bool) {
	reply = strings.TrimSpace(reply)
	if reply == "" {
		return briefingIntent{}, false
	}
	if start := strings.Index(reply, "{"); start >= 0 {
		if end := strings.LastIndex(reply, "}"); end >= start {
			reply = reply[start : end+1]
		}
	}
	var out briefingIntent
	if err := json.Unmarshal([]byte(reply), &out); err != nil {
		return briefingIntent{}, false
	}
	out.Intent = strings.ToLower(strings.TrimSpace(out.Intent))
	out.Location = normalizeBriefingLocation(out.Location)
	switch out.Intent {
	case "weather_current", "news_brief", "news_detail", "evening_brief", "source_links", "meta_or_conversation":
	default:
		return briefingIntent{}, false
	}
	if out.Confidence < 0 || out.Confidence > 1 {
		out.Confidence = 0
	}
	return out, true
}

func normalizeBriefingLocation(location string) string {
	normalized := strings.TrimSpace(location)
	switch strings.ToLower(normalized) {
	case "", "seoul", "서울", "서울시":
		return "Seoul"
	case "hanoi", "하노이":
		return "Hanoi"
	case "tokyo", "도쿄":
		return "Tokyo"
	case "bangkok", "방콕":
		return "Bangkok"
	case "beijing", "베이징":
		return "Beijing"
	case "new york", "뉴욕":
		return "New York"
	default:
		return normalized
	}
}

