func pendingShoppingDirectPurchaseApprovalReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !isShoppingDirectPurchaseApprovalFollowUp(lower) {
		return "", false
	}
	pending, ok := takePendingAssistantConversation(assistantPendingKey(opts.TargetID), false)
	if !ok || pending.Kind != "shopping_direct_purchase" {
		return "", false
	}
	if recentShoppingCheckoutDecisionReady(opts.TargetID) &&
		(isPurchaseFinalApprovalText(lower) || isPurchaseShortFinalGoAheadFollowUp(lower) || isPurchaseNaturalFinalGoAheadFollowUp(lower)) {
		locale, explicit := purchaseApprovalLocaleWithEvidence(text)
		return purchaseFinalGoAheadReplyForRequest(opts, locale, explicit, purchaseFinalConfirmationTextFromRequest(lower, text)), true
	}
	return continueShoppingDirectPurchase(opts, pending, text), true
}

func shoppingDirectPurchaseRetryHelpReply(opts ListenOptions, text string) (string, bool) {
	pending, hasPending := takePendingAssistantConversation(assistantPendingKey(opts.TargetID), false)
	if hasPending && pending.Kind != "shopping_direct_purchase" {
		hasPending = false
	}
	lower := strings.ToLower(strings.TrimSpace(text))
	if !isShoppingDirectPurchaseRetryHelpRequest(lower, hasPending) {
		return "", false
	}
	locale := shoppingDirectPurchaseRetryHelpLocale(text, pending.Request)
	if hasPending {
		return formatShoppingDirectPurchaseRetryHelpFor(locale, pending), true
	}
	return strings.Join([]string{
		lang.TF(locale, "assistant.shopping.direct_purchase.retry_help.empty.title"),
		lang.TF(locale, "assistant.shopping.direct_purchase.retry_help.empty.start"),
		lang.TF(locale, "assistant.shopping.direct_purchase.retry_help.empty.queue"),
	}, "\n"), true
}

func isShoppingDirectPurchaseRetryHelpRequest(lower string, hasPending bool) bool {
	lower = strings.TrimSpace(lower)
	if lower == "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", "-", "", "_", "", ".", "", "?", "", "!", "").Replace(lower)
	if containsAny(lower,
		"purchase retry help",
		"purchase help",
		"retry purchase",
		"resume purchase",
		"purchase stuck",
		"purchase blocked",
		"why did the purchase stop",
		"why did it stop buying",
		"automatic purchase help",
	) || containsAny(compact,
		"구매재시도",
		"구매도움말",
		"구매도움",
		"구매막힘",
		"구매멈춤",
		"구매왜멈",
		"구매어떻게",
		"주문재시도",
		"주문도움말",
		"주문막힘",
		"주문멈춤",
	) {
		return true
	}
	if !hasPending {
		return false
	}
	purchaseContext := containsAny(compact, "구매", "주문", "쿠팡", "쇼핑", "사줘", "사지", "안사") ||
		containsAny(lower, "purchase", "order", "coupang", "shopping", "buy")
	stuckContext := containsAny(compact, "막혔", "막힘", "멈췄", "멈춤", "안돼", "안되", "안사", "사지않", "왜멈", "왜막") ||
		containsAny(lower, "stuck", "blocked", "stopped", "not buying", "won't buy", "doesn't buy")
	return purchaseContext && stuckContext
}

func shoppingDirectPurchaseRetryHelpLocale(text, pendingRequest string) string {
	lower := strings.ToLower(strings.TrimSpace(text))
	if assistantCheckoutPrepContainsHangul(text) || containsAny(text, "구매", "주문", "쿠팡", "쇼핑", "재시도", "멈", "막") {
		return "ko"
	}
	if containsAny(lower, "purchase", "order", "retry", "resume", "stuck", "blocked", "current screen", "coupang", "shopping", "buy") {
		return "en"
	}
	if locale, explicit := shoppingSearchLocaleWithEvidence(pendingRequest); explicit {
		return locale
	}
	return lang.Current()
}

func formatShoppingDirectPurchaseRetryHelpFor(locale string, pending pendingAssistantConversation) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	query := strings.TrimSpace(firstNonEmpty(pending.Intent.Query, coupangShoppingQuery(pending.Request), pending.Request))
	displayQuery := directPurchaseDisplayQueryFor(locale, query)
	if displayQuery == "" {
		displayQuery = directPurchaseDisplayQueryFor(locale, directPurchaseCurrentVisibleProductSentinel)
	}
	lines := []string{
		t("assistant.shopping.direct_purchase.retry_help.title"),
		t("assistant.shopping.direct_purchase.retry_help.item", displayQuery),
	}
	if productURL := strings.TrimSpace(pending.Intent.URL); isCoupangProductURL(productURL) {
		lines = append(lines, t("assistant.shopping.direct_purchase.retry_help.link", productURL))
	}
	lines = append(lines, t("assistant.shopping.direct_purchase.retry_help.expires", pending.ExpiresAt.Local().Format("2006-01-02 15:04")))
	if blocker := pendingShoppingDirectPurchaseBlocker(pending); strings.TrimSpace(blocker) != "" {
		lines = append(lines, t("assistant.shopping.direct_purchase.retry_help.blocker", firstNonEmpty(directPurchaseBlockerDisplayFor(locale, blocker), blocker)))
		if hint := directPurchaseBlockerUserHintFor(locale, blocker); hint != "" {
			lines = append(lines, t("assistant.shopping.direct_purchase.blocked.user_hint", hint))
		}
	}
	lines = append(lines,
		"",
		t("assistant.shopping.direct_purchase.retry_help.resume"),
		t("assistant.shopping.direct_purchase.retry_help.current_screen"),
		t("assistant.shopping.direct_purchase.retry_help.stop"),
		t("assistant.shopping.direct_purchase.retry_help.readonly"),
	)
	return strings.Join(lines, "\n")
}

func pendingShoppingDirectPurchaseCandidateSearchReply(opts ListenOptions, text string) (string, bool) {
	pending, ok := takePendingAssistantConversation(assistantPendingKey(opts.TargetID), false)
	if !ok || pending.Kind != "shopping_direct_purchase" {
		return "", false
	}
	lower := strings.ToLower(strings.TrimSpace(text))
	if !isPendingShoppingDirectPurchaseCandidateSearchRequest(lower) {
		return "", false
	}
	if recentShoppingCandidateContextExists(opts.TargetID) {
		return "", false
	}
	query := strings.TrimSpace(firstNonEmpty(pending.Intent.Query, coupangShoppingQuery(pending.Request)))
	if query == "" || isDirectPurchaseCurrentVisibleProductQuery(query) {
		return "", false
	}
	locale := shoppingDirectPurchaseRetryHelpLocale(text, pending.Request)
	searchURL := coupangSearchURL(query)
	_ = cleanupCoupangTabsForNewWork(opts)
	actionReply, handled := runSignalArgosAction(opts, searchURL+" 열어줘", 0)
	if !handled {
		return "", false
	}
	candidates := coupangShoppingCandidates(context.Background(), query, 3)
	prepared := coupangShoppingPrepReplyFor(locale, localizeCoupangOpenURLActionReply(locale, actionReply, searchURL), query, candidates...)
	prepared = strings.TrimSpace(prepared) + "\n\n" + lang.TF(locale, "assistant.shopping.direct_purchase.candidate_search.pending_kept")
	return scenarioReplyWithEvidence(opts, "pending_direct_purchase_candidate_search", text, prepared, []string{searchURL}), true
}

func isPendingShoppingDirectPurchaseCandidateSearchRequest(lower string) bool {
	lower = strings.TrimSpace(lower)
	if lower == "" || isShoppingDirectPurchaseApprovalFollowUp(lower) {
		return false
	}
	if directPurchaseKoreanImperativeQuery(lower) != "" || directPurchaseEnglishImperativeQuery(lower) != "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", "-", "", "_", "", ".", "", "?", "", "!", "").Replace(lower)
	if containsAny(lower,
		"candidate",
		"candidates",
		"compare",
		"comparison",
		"recommend",
		"recommendation",
		"which product",
		"which item",
		"what should i buy",
		"best option",
		"good option",
		"prepare cart",
		"add to cart",
		"cart prep",
	) {
		return true
	}
	return containsAny(compact,
		"후보",
		"비교",
		"비교표",
		"추천",
		"뭐사",
		"무엇사",
		"어떤상품",
		"어떤제품",
		"어떤걸",
		"골라",
		"고르",
		"장바구니",
		"담아",
		"담기",
		"넣어",
	)
}

func recentShoppingCandidateContextExists(targetID string) bool {
	if _, candidates, _, ok := latestShoppingCandidatesFromHistoryWithLocale(targetID); ok && len(candidates) > 0 {
		return true
	}
	if candidate, _, ok := latestShoppingDetailFromHistoryWithLocale(targetID); ok && strings.TrimSpace(candidate.URL) != "" {
		return true
	}
	if candidate, _, ok := latestShoppingSelectionFromHistoryWithLocale(targetID); ok && strings.TrimSpace(candidate.URL) != "" {
		return true
	}
	return false
}

func assistantHermesParityReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return "", false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(lower)
	hasHermesSignal := containsAny(lower, "hermes", "헤르메스", "openclaw", "오픈클로")
	axisSignals := 0
	for _, markers := range [][]string{
		{"장기 기억", "long-term memory", "long term memory"},
		{"skill 자동", "skill auto", "스킬 자동"},
		{"작업 학습", "작업 재사용", "work reuse", "task reuse"},
		{"natural scheduling", "자연어 스케줄링", "자연어 예약", "스케줄을 자연어", "workflow scheduling"},
	} {
		if containsAny(lower, markers...) {
			axisSignals++
		}
	}
	hasAxisQuestion := axisSignals >= 1 && containsAny(lower, "설명", "어디서", "작동", "흐름", "overview", "explain", "how")
	hasFourAxis := axisSignals >= 2 || hasAxisQuestion || containsAny(compact, "4가지", "네가지", "네축", "4축", "기억스킬작업스케줄", "메모리스킬작업스케줄")
	if hasHermesSignal && isAssistantHomeRequest(lower) {
		return "", false
	}
	if hasHermesSignal && axisSignals == 0 && !hasFourAxis && containsAny(lower, "브라우저", "검색", "search", "browser", "웹에서", "웹 검색") {
		return "", false
	}
	if !hasHermesSignal && !hasFourAxis {
		return "", false
	}
	lines := []string{
		lang.T("assistant.hermes.title"),
		lang.T("assistant.hermes.intro"),
		"",
		lang.T("assistant.hermes.axis.memory"),
		lang.T("assistant.hermes.axis.skill"),
		lang.T("assistant.hermes.axis.reuse"),
		lang.T("assistant.hermes.axis.schedule"),
		"",
		lang.T("assistant.hermes.next_title"),
		lang.T("assistant.hermes.next.memory"),
		lang.T("assistant.hermes.next.skill"),
		lang.T("assistant.hermes.next.reuse"),
		lang.T("assistant.hermes.next.schedule"),
		"",
		lang.T("assistant.hermes.boundary"),
	}
	if reply, handled := assistantWorkReuseReply(text); handled && strings.TrimSpace(reply) != "" {
		lines = append(lines, "", reply)
	}
	_ = opts
	return strings.Join(lines, "\n"), true
}

func assistantWorkReuseReply(text string) (string, bool) {
	request, ok := parseAssistantWorkReuseRequest(text)
	if !ok {
		return "", false
	}
	t := lang.T
	lines := []string{t("assistant.work_reuse.title")}
	if strings.TrimSpace(request) != "" {
		lines = append(lines, t("assistant.work_reuse.request", request))
	} else {
		lines = append(lines, t("assistant.work_reuse.no_request"))
	}
	if profile, err := assistantprofile.Inspect(time.Now().UTC(), ""); err == nil {
		active := []assistantprofile.SkillInfo{}
		for _, skill := range profile.Skills.Items {
			if skill.Activation == "active_policy_gated" {
				active = append(active, skill)
			}
		}
		lines = append(lines, t("assistant.work_reuse.status", profile.Skills.Count, len(active)))
		if len(active) > 0 {
			lines = append(lines, "", t("assistant.work_reuse.active_title"))
			for i, skill := range active {
				if i >= 3 {
					lines = append(lines, t("assistant.work_reuse.active_more", len(active)-i))
					break
				}
				lines = append(lines, t("assistant.work_reuse.active_line", firstNonEmpty(skill.Title, skill.Name), firstNonEmpty(skill.Name, skill.Title)))
			}
		}
	}
	matches := assistantSkillTemplateSearch(firstNonEmpty(request, "work reuse routine workflow skill"), 3)
	if len(matches) == 0 {
		if tmpl, found := assistantSkillTemplateByQuery("work-reuse"); found {
			matches = append(matches, tmpl)
		}
	}
	if len(matches) > 0 {
		lines = append(lines, "", t("assistant.work_reuse.templates_title"))
		for _, tmpl := range matches {
			lines = append(lines, t("assistant.work_reuse.template_line", tmpl.ID, trimSignalSelfTestDetail(tmpl.Summary, 160)))
		}
	}
	shortRequest := trimSignalSelfTestDetail(firstNonEmpty(request, t("assistant.work_reuse.example_request")), 90)
	lines = append(lines,
		"",
		t("assistant.work_reuse.next_title"),
		t("assistant.work_reuse.next.save_skill", shortRequest),
		t("assistant.work_reuse.next.skill_next", shortRequest),
		t("assistant.work_reuse.next.preview", shortRequest),
		t("assistant.work_reuse.next.schedule"),
		"",
		t("assistant.work_reuse.boundary"),
		t("assistant.work_reuse.read_only"),
	)
	return strings.Join(lines, "\n"), true
}

