func parseAssistantPersonalizationPreviewRequest(text string) (string, bool) {
	trimmed := strings.TrimSpace(text)
	if trimmed == "" {
		return "", false
	}
	lower := strings.ToLower(trimmed)
	if !containsAny(lower, "개인화 미리보기", "개인화 프리뷰", "개인화 보여", "개인화 확인", "개인화 상태", "메모리와 스킬 반영", "어떤 기억", "무슨 기억", "적용되는 기억", "적용될 기억", "memory applies", "personalization preview", "personalisation preview") {
		return "", false
	}
	request := trimmed
	markers := []string{
		"개인화 미리보기", "개인화 프리뷰", "개인화 보여줘", "개인화 확인", "개인화 상태", "현재 적용된", "메모리와 스킬 반영 확인", "이 요청에", "어떤 기억이 적용돼", "어떤 기억 적용돼", "무슨 기억이 적용돼", "무슨 기억 적용돼",
		"적용되는 기억", "적용될 기억", "memory applies", "what memory applies", "personalization preview", "personalisation preview",
	}
	for _, marker := range markers {
		request = strings.ReplaceAll(request, marker, " ")
	}
	request = strings.Trim(strings.Join(strings.Fields(request), " "), " .。:：-")
	return request, true
}

func assistantMemoryRecallReply() string {
	ctx, err := assistantprofile.LoadMemoryContext(time.Now().UTC(), "", 2200)
	if err != nil {
		return "메모리 확인에 실패했습니다: " + err.Error()
	}
	if strings.TrimSpace(ctx.Text) == "" {
		return strings.Join([]string{
			"아직 승인된 assistant memory가 없습니다.",
			"`meshclaw assistant memory add --text ... --approve`로 승인된 항목만 저장됩니다.",
			"비밀번호나 토큰처럼 보이는 값은 memory에 저장하지 않습니다.",
		}, "\n")
	}
	lines := []string{
		"현재 승인된 Argos memory입니다.",
		"비밀번호/토큰 원문은 저장하지 않는 정책입니다.",
		"",
		trimSignalSelfTestDetail(ctx.Text, 1600),
	}
	return strings.Join(lines, "\n")
}

func assistantMemoryPlanFromIntent(opts ListenOptions, intent assistantMemoryIntent) string {
	scope := strings.TrimSpace(intent.Scope)
	if scope != "assistant" && scope != "user" {
		scope = "user"
	}
	memoryText := strings.TrimSpace(intent.MemoryText)
	plan, err := assistantprofile.AddMemory(time.Now().UTC(), "", scope, memoryText, false)
	if err != nil {
		return lang.T("assistant.memory_save.plan_fail", err.Error())
	}
	if plan.Rejected {
		return strings.Join([]string{
			lang.T("assistant.memory_save.reject_title"),
			lang.T("assistant.memory_save.reason", plan.Message),
			lang.T("assistant.memory_save.secret_hint"),
		}, "\n")
	}
	pending := pendingAssistantMemory{
		Scope:     plan.Scope,
		Text:      memoryText,
		CreatedAt: time.Now().UTC(),
		ExpiresAt: time.Now().UTC().Add(10 * time.Minute),
	}
	rememberPendingAssistantMemory(assistantMemoryPendingKey(opts.TargetID), pending)
	return strings.Join([]string{
		lang.T("assistant.memory_save.draft_title"),
		lang.T("assistant.memory_save.scope", plan.Scope),
		lang.T("assistant.memory_save.content", trimSignalSelfTestDetail(memoryText, 260)),
		"",
		lang.T("assistant.memory_save.approval_hint"),
		lang.T("assistant.memory_save.cancel_hint"),
	}, "\n")
}

func assistantMemoryMutationIntentReply(intent assistantMemoryIntent) string {
	t := lang.T
	action := t("assistant.memory_mutation.update_action")
	if intent.Kind == assistantMemoryIntentDelete {
		action = t("assistant.memory_mutation.delete_action")
	}
	target := strings.TrimSpace(intent.Target)
	if target == "" {
		target = strings.TrimSpace(intent.MemoryText)
	}
	if target == "" {
		target = t("assistant.memory_mutation.unknown_target")
	}
	return strings.Join([]string{
		t("assistant.memory_mutation.title", action),
		t("assistant.memory_mutation.target", trimSignalSelfTestDetail(target, 180)),
		"",
		t("assistant.memory_mutation.not_applied", action),
		t("assistant.memory_mutation.next"),
		t("assistant.memory_mutation.check"),
	}, "\n")
}

