func assistantSkillPlanReply(opts ListenOptions, text string) (string, bool) {
	name, summary, ok := parseAssistantSkillRequest(text)
	if !ok {
		return "", false
	}
	if normalizedName, normalizedSummary, normalized := assistantIndustrySkillDraftNameSummary(text, name, summary); normalized {
		name, summary = normalizedName, normalizedSummary
	}
	plan, err := assistantprofile.InstallSkill(time.Now().UTC(), "", name, summary, false)
	if err != nil {
		return lang.T("assistant.skill_install.plan_fail", err.Error()), true
	}
	if plan.Rejected {
		return strings.Join([]string{
			lang.T("assistant.skill_install.reject_title"),
			lang.T("assistant.skill_install.reason", plan.Message),
			lang.T("assistant.skill_install.secret_hint"),
			"",
			lang.T("assistant.skill_install.safe_rewrite_title"),
			lang.T("assistant.skill_install.safe_rewrite_example"),
			lang.T("assistant.skill_install.guard_boundary"),
			lang.T("assistant.skill_install.market_next"),
		}, "\n"), true
	}
	rememberPendingAssistantSkill(assistantSkillPendingKey(opts.TargetID), pendingAssistantSkill{
		Name:      plan.Name,
		Summary:   plan.Summary,
		CreatedAt: time.Now().UTC(),
		ExpiresAt: time.Now().UTC().Add(10 * time.Minute),
	})
	lines := []string{
		lang.T("assistant.skill_install.draft_title"),
		lang.T("assistant.skill_install.name", plan.Name),
		lang.T("assistant.skill_install.slug", plan.Slug),
		lang.T("assistant.skill_install.path", assistantSkillUserFacingLocation(plan.Slug)),
		lang.T("assistant.skill_install.summary", trimSignalSelfTestDetail(plan.Summary, 300)),
		"",
		lang.T("assistant.skill_install.not_written"),
		lang.T("assistant.skill_install.approval_hint"),
	}
	lines = append(lines, "")
	lines = append(lines, assistantSkillInstallAfterSaveLines(plan.Slug)...)
	lines = append(lines,
		"",
		lang.T("assistant.skill_install.boundary"),
	)
	return strings.Join(lines, "\n"), true
}

