func assistantSkillUserFacingLocation(slug string) string {
	slug = strings.Trim(strings.TrimSpace(slug), "/")
	base := "개인 스킬 저장소"
	if lang.Normalize(lang.Current()) == "en" {
		base = "Personal skill store"
	}
	if slug == "" {
		return base
	}
	return base + "/" + slug
}

func assistantSkillRevisionPlanReply(opts ListenOptions, text string) (string, bool) {
	query, summary, ok := parseAssistantSkillRevisionRequest(text)
	if !ok {
		return "", false
	}
	if strings.TrimSpace(query) == "" || strings.TrimSpace(summary) == "" {
		return strings.Join([]string{
			lang.T("assistant.skill_revision.need_detail"),
			lang.T("assistant.skill_revision.example"),
		}, "\n"), true
	}
	plan, err := assistantprofile.ReviseSkill(time.Now().UTC(), "", query, summary, false)
	if err != nil {
		return lang.T("assistant.skill_revision.plan_fail", err.Error()), true
	}
	if plan.Status == "not_found" || plan.Status == "needs_skill" {
		return strings.Join([]string{
			lang.T("assistant.skill_revision.not_found"),
			lang.T("assistant.skill_revision.request", strings.TrimSpace(query)),
			lang.T("assistant.skill_revision.install_hint"),
		}, "\n"), true
	}
	if plan.Rejected {
		lines := []string{
			lang.T("assistant.skill_revision.reject_title"),
			lang.T("assistant.skill_revision.reason", plan.Message),
		}
		if len(plan.GuardFindings) > 0 {
			lines = append(lines, lang.T("assistant.skill_install.secret_hint"))
		}
		return strings.Join(lines, "\n"), true
	}
	rememberPendingAssistantSkillRevision(assistantSkillPendingKey(opts.TargetID), pendingAssistantSkillRevision{
		Query:     plan.Query,
		Summary:   plan.Summary,
		CreatedAt: time.Now().UTC(),
		ExpiresAt: time.Now().UTC().Add(10 * time.Minute),
	})
	name := firstNonEmpty(plan.Skill.Name, plan.Name, plan.Query)
	title := firstNonEmpty(plan.Skill.Title, plan.Skill.Name, plan.Query)
	before := strings.TrimSpace(plan.Skill.Summary)
	if before == "" {
		before = lang.T("assistant.skill_revision.preview_before_empty")
	} else {
		before = trimSignalSelfTestDetail(before, 180)
	}
	lines := []string{
		lang.T("assistant.skill_revision.draft_title"),
		lang.T("assistant.skill_revision.skill", title),
		lang.T("assistant.skill_revision.status", plan.Skill.Status, plan.Skill.Activation),
		lang.T("assistant.skill_revision.preview_title"),
		lang.T("assistant.skill_revision.preview_before", before),
		lang.T("assistant.skill_revision.preview_after", trimSignalSelfTestDetail(plan.Summary, 180)),
		lang.T("assistant.skill_revision.summary", trimSignalSelfTestDetail(plan.Summary, 300)),
		lang.T("assistant.skill_revision.files"),
		"",
		lang.T("assistant.skill_revision.not_written"),
		lang.T("assistant.skill_revision.approval_hint"),
	}
	if strings.TrimSpace(name) != "" {
		lines = append(lines,
			"",
			lang.T("assistant.skill_revision.next_title"),
			lang.T("assistant.skill_revision.test_command", name),
			lang.T("assistant.skill_revision.result_command", name),
			lang.T("assistant.skill_test.review_command", name),
		)
	}
	lines = append(lines, "", lang.T("assistant.skill_revision.boundary"))
	return strings.Join(lines, "\n"), true
}

func approvePendingAssistantSkillRevision(opts ListenOptions) (string, bool) {
	pending, ok := takePendingAssistantSkillRevision(assistantSkillPendingKey(opts.TargetID), true)
	if !ok {
		return "", false
	}
	report, err := assistantprofile.ReviseSkill(time.Now().UTC(), "", pending.Query, pending.Summary, true)
	if err != nil {
		return lang.T("assistant.skill_revision.apply_fail", err.Error()), true
	}
	if report.Rejected {
		lines := []string{
			lang.T("assistant.skill_revision.not_revised"),
			lang.T("assistant.skill_revision.reason", report.Message),
		}
		if len(report.GuardFindings) > 0 {
			lines = append(lines, lang.T("assistant.skill_install.secret_hint"))
		}
		return strings.Join(lines, "\n"), true
	}
	name := firstNonEmpty(report.Skill.Name, report.Name, report.Query)
	title := firstNonEmpty(report.Skill.Title, report.Skill.Name, report.Query)
	lines := []string{
		lang.T("assistant.skill_revision.success_title"),
		lang.T("assistant.skill_revision.skill", title),
		lang.T("assistant.skill_revision.status_value", report.Status),
	}
	if strings.TrimSpace(report.Summary) != "" {
		lines = append(lines, lang.T("assistant.skill_revision.applied_summary", trimSignalSelfTestDetail(report.Summary, 220)))
	}
	lines = append(lines,
		"",
		lang.T("assistant.skill_revision.next_title"),
		lang.T("assistant.skill_revision.status_command"),
	)
	if strings.TrimSpace(name) != "" {
		lines = append(lines,
			lang.T("assistant.skill_revision.test_command", name),
			lang.T("assistant.skill_revision.result_command", name),
			lang.T("assistant.skill_test.review_command", name),
		)
		if report.Status == "active_policy_gated" {
			lines = append(lines, lang.T("assistant.skill_test.deactivate_command", name))
		} else {
			lines = append(lines, lang.T("assistant.skill_test.activate_command", name))
		}
	}
	lines = append(lines, "", lang.T("assistant.skill_revision.boundary"))
	return strings.Join(lines, "\n"), true
}

func assistantSkillActivationPlanReply(opts ListenOptions, text string) (string, bool) {
	query, active, ok := parseAssistantSkillActivationRequest(text)
	if !ok {
		return "", false
	}
	plan, err := assistantprofile.SetSkillActivation(time.Now().UTC(), "", query, active, false)
	if err != nil {
		return lang.T("assistant.skill_activation.plan_fail", err.Error()), true
	}
	if plan.Status == "not_found" {
		return strings.Join([]string{
			lang.T("assistant.skill_activation.not_found"),
			lang.T("assistant.skill_activation.request", strings.TrimSpace(query)),
			lang.T("assistant.skill_activation.status_hint"),
		}, "\n"), true
	}
	if plan.Rejected {
		return strings.Join([]string{
			lang.T("assistant.skill_activation.reject_title"),
			lang.T("assistant.skill_activation.reason", plan.Message),
		}, "\n"), true
	}
	if plan.Status == "already_active" || plan.Status == "already_inactive" {
		return strings.Join([]string{
			lang.T("assistant.skill_activation.no_change"),
			lang.T("assistant.skill_activation.skill", firstNonEmpty(plan.Skill.Title, plan.Skill.Name)),
			lang.T("assistant.skill_activation.status", plan.Message),
		}, "\n"), true
	}
	rememberPendingAssistantSkillActivation(assistantSkillPendingKey(opts.TargetID), pendingAssistantSkillActivation{
		Query:     query,
		Active:    active,
		CreatedAt: time.Now().UTC(),
		ExpiresAt: time.Now().UTC().Add(10 * time.Minute),
	})
	title := lang.T("assistant.skill_activation.inactive_title")
	approval := lang.T("assistant.skill_activation.inactive_approval")
	if active {
		title = lang.T("assistant.skill_activation.active_title")
		approval = lang.T("assistant.skill_activation.active_approval")
	}
	return strings.Join([]string{
		title,
		lang.T("assistant.skill_activation.skill", firstNonEmpty(plan.Skill.Title, plan.Skill.Name)),
		lang.T("assistant.skill_activation.current_status", plan.Skill.Status, plan.Skill.Activation),
		lang.T("assistant.skill_activation.file", plan.ActivePath),
		"",
		lang.T("assistant.skill_activation.not_written"),
		approval,
		lang.T("assistant.skill_activation.marker_only"),
	}, "\n"), true
}

func approvePendingAssistantSkillActivation(opts ListenOptions) (string, bool) {
	pending, ok := takePendingAssistantSkillActivation(assistantSkillPendingKey(opts.TargetID), true)
	if !ok {
		return "", false
	}
	report, err := assistantprofile.SetSkillActivation(time.Now().UTC(), "", pending.Query, pending.Active, true)
	if err != nil {
		return lang.T("assistant.skill_activation.apply_fail", err.Error()), true
	}
	if report.Rejected {
		return strings.Join([]string{
			lang.T("assistant.skill_activation.not_changed"),
			lang.T("assistant.skill_activation.reason", report.Message),
		}, "\n"), true
	}
	title := lang.T("assistant.skill_activation.inactive_success")
	if pending.Active {
		title = lang.T("assistant.skill_activation.active_success")
	}
	display := firstNonEmpty(report.Skill.Title, report.Skill.Name)
	name := firstNonEmpty(report.Skill.Name, report.Skill.Title)
	lines := []string{
		title,
		lang.T("assistant.skill_activation.skill", display),
		lang.T("assistant.skill_activation.status", report.Status),
		"",
		lang.T("assistant.skill_activation.next_title"),
		lang.T("assistant.skill_activation.status_command"),
	}
	if strings.TrimSpace(name) != "" {
		if pending.Active {
			lines = append(lines,
				lang.T("assistant.skill_activation.next_test", name),
				lang.T("assistant.skill_activation.next_use", display),
			)
		}
		lines = append(lines,
			lang.T("assistant.skill_test.detail_command", name),
			lang.T("assistant.skill_test.review_command", name),
		)
		if pending.Active {
			lines = append(lines, lang.T("assistant.skill_test.deactivate_command", name))
		} else {
			lines = append(lines, lang.T("assistant.skill_test.activate_command", name))
		}
	}
	return strings.Join(lines, "\n"), true
}

func assistantSkillReviewReply(text string) (string, bool) {
	query, ok := parseAssistantSkillReviewRequest(text)
	if !ok {
		return "", false
	}
	t := lang.T
	if strings.TrimSpace(query) == "" {
		return strings.Join([]string{
			t("assistant.skill_review.title"),
			t("assistant.skill_review.need_query"),
			"",
			t("assistant.skill_review.read_only"),
		}, "\n"), true
	}
	report, err := assistantprofile.TestSkill(time.Now().UTC(), "", query)
	if err != nil {
		return t("assistant.skill_detail.fail", err.Error()), true
	}
	if strings.TrimSpace(report.Skill.Name) == "" || report.Status == "not_found" || report.Status == "needs_skill" {
		return strings.Join([]string{
			t("assistant.skill_review.title"),
			t("assistant.skill_review.not_found"),
			t("assistant.skill_detail.query", strings.TrimSpace(query)),
			"",
			t("assistant.skill_detail.market_command"),
			t("assistant.skill_review.read_only"),
		}, "\n"), true
	}
	return assistantInstalledSkillReviewCard(report), true
}

func assistantInstalledSkillReviewCard(report assistantprofile.SkillTestReport) string {
	t := lang.T
	skill := report.Skill
	name := firstNonEmpty(skill.Name, skill.Title)
	title := firstNonEmpty(skill.Title, skill.Name)
	testState := t("assistant.skill_review.test_ready")
	if report.Status == "missing_test" {
		testState = t("assistant.skill_review.test_missing")
	}
	lines := []string{
		t("assistant.skill_review.title"),
		t("assistant.skill_review.skill", title),
		t("assistant.skill_detail.status", skill.Status),
		t("assistant.skill_detail.activation", skill.Activation),
		t("assistant.skill_review.review", skill.Review),
		t("assistant.skill_review.source", skill.Source),
	}
	if updated := assistantSkillUpdatedAtText(skill.UpdatedAt); updated != "" {
		lines = append(lines, t("assistant.skill_market.updated", updated))
	}
	lines = append(lines,
		"",
		t("assistant.skill_review.checklist"),
		t("assistant.skill_review.check_review", skill.Review),
		t("assistant.skill_review.check_activation", skill.Activation),
		t("assistant.skill_review.check_test", testState),
		t("assistant.skill_review.check_boundary"),
		"",
		t("assistant.skill_review.next"),
		t("assistant.skill_detail.test_command", name),
		t("assistant.skill_search.detail", name),
	)
	if skill.Activation == "active_policy_gated" {
		lines = append(lines, t("assistant.skill_detail.deactivate_command", name))
	} else {
		lines = append(lines, t("assistant.skill_detail.activate_command", name))
	}
	lines = append(lines,
		"",
		t("assistant.skill_review.boundary"),
		t("assistant.skill_review.read_only"),
	)
	return strings.Join(lines, "\n")
}

func parseAssistantSkillReviewRequest(text string) (string, bool) {
	trimmed := strings.TrimSpace(text)
	if trimmed == "" {
		return "", false
	}
	lower := strings.ToLower(trimmed)
	if !containsAny(lower, "스킬 검토", "스킬 안전 검토", "스킬 리뷰", "skill review", "review skill", "skill safety") {
		return "", false
	}
	query := trimmed
	replacements := []string{
		"스킬 안전 검토", "스킬 검토해줘", "스킬 검토", "스킬 리뷰",
		"skill safety review", "skill review", "review skill", "skill safety",
	}
	for _, marker := range replacements {
		query = strings.ReplaceAll(query, marker, " ")
	}
	query = strings.Trim(strings.Join(strings.Fields(query), " "), " .。:：-")
	return query, true
}

func assistantSkillRecommendationReply(text string) (string, bool) {
	request, ok := parseAssistantSkillRecommendationRequest(text)
	if !ok {
		return "", false
	}
	t := lang.T
	if strings.TrimSpace(request) == "" {
		return strings.Join([]string{
			t("assistant.skill_recommend.title"),
			t("assistant.skill_recommend.need_request"),
			"",
			t("assistant.skill_recommend.read_only"),
		}, "\n"), true
	}
	profile, err := assistantprofile.Inspect(time.Now().UTC(), "")
	if err != nil {
		return t("assistant.skill_detail.fail", err.Error()), true
	}
	installedMatches := assistantInstalledSkillSearch(profile.Skills.Items, request, 3)
	templateMatches := assistantSkillTemplateSearch(request, 3)
	lines := []string{
		t("assistant.skill_recommend.title"),
		t("assistant.skill_recommend.request", strings.TrimSpace(request)),
	}
	if len(installedMatches) > 0 {
		lines = append(lines, "", t("assistant.skill_recommend.installed"))
		for _, skill := range installedMatches {
			name := firstNonEmpty(skill.Name, skill.Title)
			lines = append(lines, t("assistant.skill_search.installed_line", firstNonEmpty(skill.Title, skill.Name), skill.Status, skill.Activation))
			if updated := assistantSkillUpdatedAtText(skill.UpdatedAt); updated != "" {
				lines = append(lines, t("assistant.skill_market.updated", updated))
			}
			if strings.TrimSpace(skill.Summary) != "" {
				lines = append(lines, "  "+trimSignalSelfTestDetail(skill.Summary, 180))
			}
			lines = append(lines, t("assistant.skill_recommend.detail", name))
			lines = append(lines, t("assistant.skill_recommend.test", name))
			lines = append(lines, t("assistant.skill_recommend.revise", name))
		}
	}
	if len(templateMatches) > 0 {
		lines = append(lines, "", t("assistant.skill_recommend.templates"))
		for _, tmpl := range templateMatches {
			lines = append(lines, t("assistant.skill_search.template_line", tmpl.ID, trimSignalSelfTestDetail(tmpl.Summary, 180)))
			lines = append(lines, t("assistant.skill_recommend.install", tmpl.ID))
			lines = append(lines, t("assistant.skill_recommend.detail", tmpl.ID))
		}
	}
	if len(installedMatches) == 0 && len(templateMatches) == 0 {
		lines = append(lines,
			"",
			t("assistant.skill_recommend.none"),
			t("assistant.skill_recommend.search", trimSignalSelfTestDetail(request, 60)),
			t("assistant.skill_recommend.create"),
		)
	}
	lines = append(lines,
		"",
		t("assistant.skill_recommend.boundary"),
		t("assistant.skill_recommend.read_only"),
	)
	return strings.Join(lines, "\n"), true
}

