func assistantSkillTemplateSearch(query string, limit int) []assistantprofile.SkillTemplate {
	if limit <= 0 {
		limit = 4
	}
	out := []assistantprofile.SkillTemplate{}
	for _, tmpl := range assistantprofile.SkillTemplates() {
		if !assistantSkillSearchMatches(query, tmpl.ID, tmpl.Title, tmpl.Summary, tmpl.Example, tmpl.Status) {
			continue
		}
		out = append(out, tmpl)
		if len(out) >= limit {
			break
		}
	}
	return out
}

func assistantInstalledSkillSearch(skills []assistantprofile.SkillInfo, query string, limit int) []assistantprofile.SkillInfo {
	if limit <= 0 {
		limit = 5
	}
	out := []assistantprofile.SkillInfo{}
	for _, skill := range skills {
		if !assistantSkillSearchMatches(query, skill.Name, skill.Title, skill.Summary, skill.Status, skill.Activation) {
			continue
		}
		out = append(out, skill)
		if len(out) >= limit {
			break
		}
	}
	return out
}

func assistantSkillSearchMatches(query string, values ...string) bool {
	needles := assistantSkillSearchNeedles(query)
	if len(needles) == 0 {
		return false
	}
	for _, value := range values {
		haystack := normalizeAssistantSkillTemplateQuery(value)
		if haystack == "" {
			continue
		}
		for _, needle := range needles {
			if haystack == needle || strings.Contains(haystack, needle) || strings.Contains(needle, haystack) {
				return true
			}
		}
	}
	return false
}

func assistantSkillSearchNeedles(query string) []string {
	seen := map[string]bool{}
	add := func(values ...string) {
		for _, value := range values {
			norm := normalizeAssistantSkillTemplateQuery(value)
			if norm == "" || seen[norm] {
				continue
			}
			seen[norm] = true
		}
	}
	add(query)
	for _, field := range strings.Fields(strings.ToLower(query)) {
		if assistantSkillSearchFieldNeedle(field) {
			add(field)
		}
	}
	lower := strings.ToLower(query)
	switch {
	case containsAny(lower, "작업 재사용", "작업 학습", "반복 작업", "루틴", "워크플로우", "workflow", "routine", "reuse", "repeatable"):
		add("work-reuse", "work", "reuse", "workflow", "routine", "repeatable")
	}
	switch {
	case containsAny(lower, "여행", "출장", "항공", "비행기", "호텔", "숙소", "여정", "동선", "예약", "travel", "trip", "flight", "hotel", "itinerary", "booking"):
		add("travel-prep", "travel", "trip", "flight", "hotel", "itinerary", "booking")
	}
	switch {
	case containsAny(lower, "쿠팡", "쇼핑", "구매", "상품", "장바구니", "결제", "shopping", "product", "purchase", "checkout", "cart"):
		add("shopping-prep", "shopping", "product", "purchase", "checkout")
	}
	switch {
	case containsAny(lower, "회의록", "회의", "미팅", "meeting", "minutes"):
		add("meeting-minutes", "meeting", "minutes")
	}
	switch {
	case containsAny(lower, "메일", "이메일", "답장", "회신", "mail", "email", "reply"):
		add("mail-priority", "mail", "email", "reply")
	}
	switch {
	case containsAny(lower, "캘린더", "일정", "리마인더", "알림", "초대", "calendar", "schedule", "reminder", "event", "invite"):
		add("calendar-reminder", "calendar", "schedule", "reminder", "event", "invite")
	}
	switch {
	case containsAny(lower, "아침", "하루", "오늘", "데일리", "브리핑", "날씨", "daily", "morning", "today", "briefing", "weather"):
		add("daily-briefing", "daily", "morning", "today", "briefing", "weather")
	}
	switch {
	case containsAny(lower, "음성", "보이스", "낭독", "읽어줘", "mp3", "tts", "voice", "audio", "spoken", "read aloud"):
		add("voice-briefing", "voice", "audio", "spoken", "tts", "mp3")
	}
	switch {
	case containsAny(lower, "시장분석", "시장 분석", "전망", "유가", "환율", "금리", "주식", "경쟁사", "원자재", "market analysis", "market outlook", "forecast", "commodity", "commodities", "fx", "oil", "equity", "competitor"):
		add("market-analysis", "market", "analysis", "outlook", "forecast", "commodity", "fx", "oil", "equity", "competitor")
	}
	switch {
	case containsAny(lower, "조사", "리서치", "보고서", "출처", "뉴스", "research", "report", "source", "sources"):
		add("research-report", "research", "report", "source", "sources")
	}
	out := make([]string, 0, len(seen))
	for value := range seen {
		out = append(out, value)
	}
	sort.Strings(out)
	return out
}

func assistantSkillSearchFieldNeedle(field string) bool {
	field = normalizeAssistantSkillTemplateQuery(field)
	if len([]rune(field)) < 3 {
		return false
	}
	switch field {
	case "and", "the", "for", "with", "without", "from", "into", "onto", "that", "this", "what", "which", "whose", "when", "where", "before", "after":
		return false
	case "후보", "비교", "요약", "정리", "작성", "확인", "만들기", "멈추기":
		return false
	}
	return true
}

func assistantSkillDetailReply(text string) (string, bool) {
	query, ok := parseAssistantSkillDetailRequest(text)
	if !ok {
		return "", false
	}
	t := lang.T
	if strings.TrimSpace(query) == "" {
		return strings.Join([]string{
			t("assistant.skill_detail.title"),
			t("assistant.skill_detail.need_query"),
			"",
			t("assistant.skill_detail.read_only"),
		}, "\n"), true
	}
	report, err := assistantprofile.TestSkill(time.Now().UTC(), "", query)
	if err != nil {
		return t("assistant.skill_detail.fail", err.Error()), true
	}
	if strings.TrimSpace(report.Skill.Name) != "" && report.Status != "not_found" && report.Status != "needs_skill" {
		return assistantInstalledSkillDetailCard(report), true
	}
	if tmpl, found := assistantSkillTemplateByQuery(query); found {
		return assistantSkillTemplateDetailCard(tmpl), true
	}
	lines := []string{
		t("assistant.skill_detail.title"),
		t("assistant.skill_detail.not_found"),
		t("assistant.skill_detail.query", strings.TrimSpace(query)),
		"",
		t("assistant.skill_detail.next_title"),
		t("assistant.skill_detail.market_command"),
		"",
		t("assistant.skill_detail.read_only"),
	}
	return strings.Join(lines, "\n"), true
}

func assistantInstalledSkillDetailCard(report assistantprofile.SkillTestReport) string {
	t := lang.T
	skill := report.Skill
	title := firstNonEmpty(skill.Title, skill.Name)
	name := firstNonEmpty(skill.Name, title)
	lines := []string{
		t("assistant.skill_detail.title"),
		t("assistant.skill_detail.skill", title),
		t("assistant.skill_detail.status", skill.Status),
		t("assistant.skill_detail.activation", skill.Activation),
	}
	if strings.TrimSpace(skill.Summary) != "" {
		lines = append(lines, t("assistant.skill_detail.summary", trimSignalSelfTestDetail(skill.Summary, 360)))
	}
	if updated := assistantSkillUpdatedAtText(skill.UpdatedAt); updated != "" {
		lines = append(lines, t("assistant.skill_market.updated", updated))
	}
	if strings.TrimSpace(report.TestPath) != "" {
		lines = append(lines, t("assistant.skill_detail.test_file", report.TestPath))
	}
	lines = append(lines,
		"",
		t("assistant.skill_detail.next_title"),
		t("assistant.skill_detail.test_command", name),
		t("assistant.skill_detail.revise_command", name),
	)
	if skill.Activation == "active_policy_gated" {
		lines = append(lines, t("assistant.skill_detail.deactivate_command", name))
	} else {
		lines = append(lines, t("assistant.skill_detail.activate_command", name))
	}
	lines = append(lines,
		t("assistant.skill_detail.market_command"),
		"",
		t("assistant.skill_detail.boundary"),
		t("assistant.skill_detail.read_only"),
	)
	return strings.Join(lines, "\n")
}

