	if !containsAny(lower, "스킬 상세", "스킬 정보", "템플릿 상세", "템플릿 정보", "skill detail", "skill details", "skill info", "template detail", "template info") {
		return "", false
	}
	query := trimmed
	replacements := []string{
		"스킬 상세", "스킬 정보", "템플릿 상세", "템플릿 정보",
		"skill details", "skill detail", "skill info", "template detail", "template info",
	}
