func assistantSkillTemplateByQuery(query string) (assistantprofile.SkillTemplate, bool) {
	normalized := normalizeAssistantSkillTemplateQuery(query)
	if normalized == "" {
		return assistantprofile.SkillTemplate{}, false
	}
	for _, tmpl := range assistantprofile.SkillTemplates() {
		id := normalizeAssistantSkillTemplateQuery(tmpl.ID)
		title := normalizeAssistantSkillTemplateQuery(tmpl.Title)
		if normalized == id || normalized == title || strings.Contains(normalized, id) || strings.Contains(id, normalized) || strings.Contains(normalized, title) {
			return tmpl, true
		}
	}
	return assistantprofile.SkillTemplate{}, false
}

func normalizeAssistantSkillTemplateQuery(value string) string {
	value = strings.ToLower(strings.TrimSpace(value))
	value = strings.NewReplacer("_", "-", " ", "-", "\t", "-", "\n", "-", ".", "", ":", "", "：", "").Replace(value)
	value = strings.Trim(value, "-")
	for strings.Contains(value, "--") {
		value = strings.ReplaceAll(value, "--", "-")
	}
	return value
}

func assistantSkillTemplatePlanReply(opts ListenOptions, text string) (string, bool) {
	tmpl, ok := parseAssistantSkillTemplateInstallRequest(text)
	if !ok {
		return "", false
	}
	plan, err := assistantprofile.InstallSkill(time.Now().UTC(), "", tmpl.Title, tmpl.Summary, false)
	if err != nil {
		return lang.T("assistant.skill_install.template_plan_fail", err.Error()), true
	}
	if plan.Rejected {
		return strings.Join([]string{
			lang.T("assistant.skill_install.template_reject_title"),
			lang.T("assistant.skill_install.reason", plan.Message),
		}, "\n"), true
	}
	rememberPendingAssistantSkill(assistantSkillPendingKey(opts.TargetID), pendingAssistantSkill{
		Name:      plan.Name,
		Summary:   plan.Summary,
		CreatedAt: time.Now().UTC(),
		ExpiresAt: time.Now().UTC().Add(10 * time.Minute),
	})
	lines := []string{
		lang.T("assistant.skill_install.template_draft_title"),
		lang.T("assistant.skill_install.template", tmpl.ID),
		lang.T("assistant.skill_install.name", plan.Name),
		lang.T("assistant.skill_install.description", trimSignalSelfTestDetail(plan.Summary, 300)),
	}
	if strings.TrimSpace(tmpl.Example) != "" && (lang.Current() == "ko" || !assistantCheckoutPrepContainsHangul(tmpl.Example)) {
		lines = append(lines, lang.T("assistant.skill_install.example", tmpl.Example))
	}
	lines = append(lines,
		"",
		lang.T("assistant.skill_install.not_written"),
		lang.T("assistant.skill_install.template_approval_hint"),
	)
	lines = append(lines, "")
	lines = append(lines, assistantSkillInstallAfterSaveLines(plan.Slug)...)
	lines = append(lines, "", lang.T("assistant.skill_install.template_boundary"))
	return strings.Join(lines, "\n"), true
}

func parseAssistantSkillTemplateInstallRequest(text string) (assistantprofile.SkillTemplate, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return assistantprofile.SkillTemplate{}, false
	}
	if !containsAny(lower, "스킬 설치", "install skill", "skill install") {
		return assistantprofile.SkillTemplate{}, false
	}
	for _, tmpl := range assistantprofile.SkillTemplates() {
		id := strings.ToLower(strings.TrimSpace(tmpl.ID))
		title := strings.ToLower(strings.TrimSpace(tmpl.Title))
		if id != "" && containsAny(lower, id, strings.ReplaceAll(id, "-", " ")) {
			return tmpl, true
		}
		if title != "" && containsAny(lower, title) {
			return tmpl, true
		}
	}
	return assistantprofile.SkillTemplate{}, false
}

func parseAssistantSkillActivationRequest(text string) (query string, active bool, ok bool) {
	trimmed := strings.TrimSpace(text)
	if trimmed == "" {
		return "", false, false
	}
	lower := strings.ToLower(trimmed)
	deactivate := containsAny(lower, "스킬 비활성화", "스킬 끄기", "스킬 꺼", "disable skill", "deactivate skill", "turn off skill")
	activate := containsAny(lower, "스킬 활성화", "스킬 켜기", "스킬 켜", "스킬 재활성화", "activate skill", "enable skill", "turn on skill")
	if !deactivate && !activate {
		return "", false, false
	}
	active = activate && !deactivate
	query = trimmed
	replacements := []string{
		"스킬 비활성화해줘", "스킬 비활성화해", "스킬 비활성화", "스킬 끄기", "스킬 꺼줘", "스킬 꺼",
		"스킬 활성화해줘", "스킬 활성화해", "스킬 활성화", "스킬 재활성화", "스킬 켜기", "스킬 켜줘", "스킬 켜",
		"disable skill", "deactivate skill", "turn off skill", "activate skill", "enable skill", "turn on skill",
	}
	for _, marker := range replacements {
		query = strings.ReplaceAll(query, marker, " ")
	}
	query = strings.Trim(strings.Join(strings.Fields(query), " "), " .。:：-")
	return query, active, true
}

