func parseAssistantSkillRevisionRequest(text string) (query, summary string, ok bool) {
	trimmed := strings.TrimSpace(text)
	if trimmed == "" {
		return "", "", false
	}
	lower := strings.ToLower(trimmed)
	if !containsAny(lower, "스킬 수정", "스킬 고쳐", "스킬 업데이트", "revise skill", "edit skill", "update skill") {
		return "", "", false
	}
	if containsAny(lower, "승인", "approve") && !strings.Contains(lower, ":") && !strings.Contains(lower, "：") {
		return "", "", false
	}
	body := trimmed
	replacements := []string{
		"스킬 수정해줘", "스킬 수정", "스킬 고쳐줘", "스킬 고쳐", "스킬 업데이트해줘", "스킬 업데이트",
		"revise skill", "edit skill", "update skill",
	}
	for _, marker := range replacements {
		body = strings.ReplaceAll(body, marker, " ")
	}
	body = strings.Trim(strings.Join(strings.Fields(body), " "), " .。:：-")
	if body == "" {
		return "", "", true
	}
	query, summary = splitAssistantSkillNameSummary(body)
	query = strings.TrimSpace(query)
	summary = strings.TrimSpace(summary)
	return query, summary, true
}

func parseAssistantSkillRequest(text string) (name, summary string, ok bool) {
	trimmed := strings.TrimSpace(text)
	if trimmed == "" {
		return "", "", false
	}
	lower := strings.ToLower(trimmed)
	if !containsAny(lower,
		"스킬 만들어", "스킬 생성", "스킬 등록", "스킬로 저장", "스킬 설치 초안",
		"스킬로 만들어", "스킬로 만들어줘",
		"작업 스킬로", "작업을 스킬로", "이 작업 스킬", "이 작업을 스킬", "방금 작업 스킬", "방금 작업을 스킬",
		"create skill", "new skill", "register skill", "save as skill", "save this task as skill", "turn this task into a skill",
	) {
		return "", "", false
	}
	if containsAny(lower, "현황", "상태", "어디까지", "몇개", "뭐됨", "status") {
		return "", "", false
	}
	summary = trimmed
	replacements := []string{
		"이 작업을 스킬로 만들어줘", "이 작업 스킬로 만들어줘", "방금 작업을 스킬로 만들어줘", "방금 작업 스킬로 만들어줘",
		"작업을 스킬로 만들어줘", "작업 스킬로 만들어줘", "작업을 스킬로 저장해줘", "작업 스킬로 저장해줘",
		"스킬 만들어줘", "스킬 만들어", "스킬 생성해줘", "스킬 생성", "스킬 등록해줘", "스킬 등록",
		"스킬로 저장해줘", "스킬로 저장", "스킬 설치 초안 만들어줘", "스킬 설치 초안",
		"스킬로 만들어줘", "스킬로 만들어",
		"create skill", "new skill", "register skill", "save as skill", "save this task as skill", "turn this task into a skill",
	}
	for _, marker := range replacements {
		summary = strings.ReplaceAll(summary, marker, " ")
	}
	summary = strings.Trim(strings.Join(strings.Fields(summary), " "), " .。:：-")
	if summary == "" {
		return "", "", false
	}
	name, summary = splitAssistantSkillNameSummary(summary)
	name = strings.TrimSuffix(name, "스킬")
	name = strings.TrimSuffix(name, "를")
	name = strings.TrimSuffix(name, "을")
	name = strings.TrimSpace(name)
	if len([]rune(name)) > 32 {
		runes := []rune(name)
		name = strings.TrimSpace(string(runes[:32]))
	}
	if name == "" {
		name = "Custom Assistant Skill"
	}
	return name, summary, true
}

func splitAssistantSkillNameSummary(text string) (string, string) {
	text = strings.TrimSpace(text)
	if text == "" {
		return "", ""
	}
	for _, sep := range []string{" - ", " — ", " – ", ":", "：", "-", "—", "–"} {
		before, after, ok := strings.Cut(text, sep)
		if !ok {
			continue
		}
		name := strings.TrimSpace(before)
		summary := strings.TrimSpace(after)
		if name == "" || summary == "" || len([]rune(name)) > 40 {
			continue
		}
		return name, summary
	}
	return text, text
}

