type assistantReportRoomQuietPolicy struct {
	Kind               string    `json:"kind"`
	QuietMode          bool      `json:"quiet_mode"`
	NewsMaxPerDay      int       `json:"news_max_per_day"`
	MailPriorityOnly   bool      `json:"mail_priority_only"`
	HealthFailuresOnly bool      `json:"health_failures_only"`
	HidePaths          bool      `json:"hide_paths"`
	UpdatedAt          time.Time `json:"updated_at"`
	UpdatedBy          string    `json:"updated_by"`
}

func assistantReportRoomQuietPolicyPath() string {
	if path := strings.TrimSpace(os.Getenv("MESHCLAW_REPORT_ROOM_POLICY")); path != "" {
		return path
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return filepath.Join(".meshclaw", "report-room-policy.json")
	}
	return filepath.Join(home, ".meshclaw", "report-room-policy.json")
}

func assistantDefaultReportRoomQuietPolicy(updatedBy string) assistantReportRoomQuietPolicy {
	return assistantReportRoomQuietPolicy{
		Kind:               "meshclaw_report_room_policy",
		QuietMode:          true,
		NewsMaxPerDay:      2,
		MailPriorityOnly:   true,
		HealthFailuresOnly: true,
		HidePaths:          true,
		UpdatedAt:          time.Now().UTC(),
		UpdatedBy:          firstNonEmpty(strings.TrimSpace(updatedBy), "assistant"),
	}
}

func readAssistantReportRoomQuietPolicy() (assistantReportRoomQuietPolicy, bool) {
	data, err := os.ReadFile(assistantReportRoomQuietPolicyPath())
	if err != nil {
		return assistantReportRoomQuietPolicy{}, false
	}
	var policy assistantReportRoomQuietPolicy
	if err := json.Unmarshal(data, &policy); err != nil {
		return assistantReportRoomQuietPolicy{}, false
	}
	return policy, strings.TrimSpace(policy.Kind) == "meshclaw_report_room_policy"
}

func writeAssistantReportRoomQuietPolicy(policy assistantReportRoomQuietPolicy) error {
	path := assistantReportRoomQuietPolicyPath()
	if err := os.MkdirAll(filepath.Dir(path), 0700); err != nil {
		return err
	}
	data, err := json.MarshalIndent(policy, "", "  ")
	if err != nil {
		return err
	}
	tmp := path + ".tmp"
	if err := os.WriteFile(tmp, append(data, '\n'), 0600); err != nil {
		return err
	}
	return os.Rename(tmp, path)
}

