func assistantReportRoomNoiseJobLines() []string {
	watched := map[string]bool{
		"local-ai-briefing": true,
		"mail-watch":        true,
		"assistant-watch":   true,
		"argos-health":      true,
	}
	order := []string{"local-ai-briefing", "mail-watch", "assistant-watch", "argos-health"}
	liveByID := map[string]assistantScheduleLiveJob{}
	if live, ok := readAssistantScheduleLiveStatus(); ok {
		for _, job := range live.Jobs {
			if watched[job.ID] {
				liveByID[job.ID] = job
			}
		}
	}
	lines := []string{}
	for _, id := range order {
		if live, ok := liveByID[id]; ok {
			lines = append(lines, assistantAutomationConciseLiveScheduleLine(live))
			continue
		}
		known, ok := assistantScheduleKnownJobByID(id)
		if !ok {
			continue
		}
		parts := []string{firstNonEmpty(known.Cadence, known.Interval.String()), assistantScheduleLocalizedTarget(known.TargetID, known.TargetLabel)}
		if known.Purpose != "" {
			parts = append(parts, known.Purpose)
		}
		lines = append(lines, fmt.Sprintf("%s (%s): %s", assistantScheduleLocalizedLabel(known, id), id, strings.Join(parts, " · ")))
	}
	return lines
}

