type assistantSkillCounts struct {
	total       int
	implemented int
	partial     int
	planned     int
}

func assistantSkillStatusCounts() assistantSkillCounts {
	var counts assistantSkillCounts
	for _, scenario := range assistantcatalog.Catalog() {
		counts.total++
		switch strings.TrimSpace(scenario.Status) {
		case "implemented":
			counts.implemented++
		case "partial":
			counts.partial++
		case "planned":
			counts.planned++
		}
	}
	return counts
}

func assistantChannelSummary() string {
	store, err := ListTargets()
	if err != nil {
		return lang.T("assistant.channel.need_check")
	}
	interactive := 0
	oneWay := 0
	for _, target := range store.Targets {
		if OneWayReportTarget(target) {
			oneWay++
		} else if isInteractiveTargetMode(target.Mode) {
			interactive++
		}
	}
	return lang.T("assistant.channel.summary", len(store.Targets), interactive, oneWay)
}

func assistantControlAutomationSummary() string {
	parts := []string{}
	if summary, ok := readAssistantScheduleStateSummary(); ok {
		parts = append(parts, lang.T("assistant.automation.schedule_prefix", summary))
	} else {
		parts = append(parts, lang.T("assistant.automation.schedule_unknown"))
	}
	if watches, err := assistantwatch.ListWatches("", false); err == nil {
		parts = append(parts, lang.T("assistant.automation.watch_count", len(watches)))
	}
	if store, err := LoadScheduledDeliveryStore(); err == nil {
		enabled := 0
		for _, job := range store.Jobs {
			if job.Enabled {
				enabled++
			}
		}
		parts = append(parts, lang.T("assistant.automation.delivery_count", enabled))
	}
	return strings.Join(parts, ", ")
}

func assistantControlNextRunSummary() string {
	if live, ok := readAssistantScheduleLiveStatus(); ok {
		if live.NextDueJob != "" && !live.NextDue.IsZero() {
			return fmt.Sprintf("%s at %s (%s)",
				assistantScheduleJobDisplayName(live.NextDueJob),
				live.NextDue.Local().Format("15:04"),
				assistantScheduleDueInText(time.Until(live.NextDue)),
			)
		}
		return fmt.Sprintf("대기 중, due=%d, status=%s", live.DueCount, firstNonEmpty(live.Status, "unknown"))
	}
	if lastRun, ok := readAssistantScheduleLastRun(); ok {
		if nextJob, nextDue, found := assistantNextScheduleDue(lastRun, time.Now().UTC()); found {
			return fmt.Sprintf("%s at %s (%s)",
				assistantScheduleJobDisplayName(nextJob),
				nextDue.Local().Format("15:04"),
				assistantScheduleDueInText(time.Until(nextDue)),
			)
		}
	}
	return "schedule 상태 확인 필요"
}

func assistantControlApprovalSummary() string {
	plan, err := runtimeflow.PlanExecute("latest")
	if err != nil {
		return lang.T("assistant.approval.need_check")
	}
	attention := plan.Counts.Failed + plan.Counts.RepairNeeded + plan.Counts.RetryableFailed + plan.Counts.VaultMissing
	return lang.T("assistant.approval.summary", plan.Counts.ApprovalPending, plan.Counts.Ready, attention)
}

