func isAssistantAutomationStopRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	if containsAny(lower, "가격 알림", "가격알림", "price alert", "price watch") {
		return false
	}
	if containsAny(lower, "stop automation", "disable automation", "pause automation", "stop schedule", "disable schedule", "pause schedule", "stop job", "disable job", "pause job") {
		return true
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(lower)
	if containsAny(compact, "자동화중지", "자동화멈춰", "자동화꺼줘", "자동화끄기", "자동화정지", "스케줄중지", "스케줄멈춰", "스케줄꺼줘", "잡중지", "예약발송중지", "예약발송꺼줘") {
		return true
	}
	if containsAny(lower, "멈춰", "중지", "꺼줘", "끄기", "정지", "disable", "pause", "stop") && assistantAutomationStopTarget(lower) != "" {
		return true
	}
	return containsAny(lower, "dev loop 멈춰", "dev-loop 멈춰", "dev worker 멈춰", "dev-worker 멈춰", "mail-watch 멈춰", "assistant-auto-check 멈춰", "local-ai-briefing 멈춰")
}

func assistantAutomationStopReply(text string) string {
	target := assistantAutomationStopTarget(text)
	lines := []string{lang.T("assistant.automation_stop.title")}
	if target == "" {
		lines = append(lines, lang.T("assistant.automation_stop.need_target"))
	} else {
		lines = append(lines, lang.T("assistant.automation_stop.target", target))
		contextLines := assistantApprovalDraftContext(target)
		if lang.Current() != "ko" {
			contextLines = []string{lang.T("assistant.automation_stop.context", target)}
		}
		if len(contextLines) > 0 {
			lines = append(lines, contextLines[0])
		}
		lines = append(lines,
			lang.T("assistant.automation_stop.approval_required"),
			lang.T("assistant.automation_stop.next_draft", lang.T("assistant.approval_queue.draft.stop_command", target)),
		)
	}
	lines = append(lines,
		lang.T("assistant.automation_stop.read_only"),
		lang.T("assistant.automation_stop.next"),
		lang.T("assistant.automation_stop.dashboard", assistantDashboardURL()),
	)
	return strings.Join(lines, "\n")
}

func assistantAutomationStopTarget(text string) string {
	lower := strings.ToLower(strings.TrimSpace(text))
	for _, candidate := range []string{
		"serverops-quickcheck",
		"local-ai-briefing",
		"morning-briefing",
		"mail-watch",
		"assistant-watch",
		"argos-health",
		"assistant-auto-check",
		"local-hygiene",
		"data-doctor",
		"daily-expert-audit",
		"dev-loop",
		"dev-worker",
	} {
		if strings.Contains(lower, strings.ToLower(candidate)) {
			return candidate
		}
	}
	if containsAny(lower, "메일", "mail") {
		return "mail-watch"
	}
	if containsAny(lower, "비서 자동 점검", "assistant auto", "auto-check") {
		return "assistant-auto-check"
	}
	if containsAny(lower, "뉴스", "브리핑", "local ai", "local-ai") {
		return "local-ai-briefing"
	}
	if containsAny(lower, "개발 루프", "dev loop", "dev worker") {
		return "dev-loop"
	}
	return ""
}

