func assistantDashboardEvidenceURL(evidenceID string) string {
	evidenceID = assistantRecentReportsRequestedEvidenceID(evidenceID)
	if evidenceID == "" {
		return assistantDashboardURL()
	}
	base := assistantDashboardURL()
	parsed, err := url.Parse(base)
	if err != nil {
		sep := "?"
		if strings.Contains(base, "?") {
			sep = "&"
		}
		return base + sep + "evidence=" + url.QueryEscape(evidenceID) + "#evidence"
	}
	q := parsed.Query()
	q.Set("evidence", evidenceID)
	parsed.RawQuery = q.Encode()
	parsed.Fragment = "evidence"
	return parsed.String()
}

