func assistantRecentReportsReply() string {
	return assistantRecentReportsReplyFor(lang.Current())
}

func assistantRecentReportsReplyFor(locale string) string {
	return assistantRecentReportsReplyForRequest(locale, "")
}

func assistantRecentReportsReplyForRequest(locale, request string) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	filterID := assistantRecentReportsRequestedEvidenceID(request)
	limit := 5
	if filterID != "" {
		limit = 25
	}
	items, err := evidence.List(limit)
	lines := []string{t("assistant.recent_reports.title")}
	if err != nil {
		lines = append(lines,
			t("assistant.recent_reports.error", err.Error()),
			t("assistant.recent_reports.readonly"),
		)
		return strings.Join(lines, "\n")
	}
	if len(items) == 0 {
		lines = append(lines,
			t("assistant.recent_reports.empty"),
			t("assistant.recent_reports.dashboard", assistantDashboardURL()),
			t("assistant.recent_reports.readonly"),
		)
		return strings.Join(lines, "\n")
	}
	if filterID != "" {
		filtered := make([]evidence.Summary, 0, 1)
		for _, item := range items {
			if assistantEvidenceDisplayID(item.ID) == filterID {
				filtered = append(filtered, item)
				break
			}
		}
		items = filtered
		if len(items) == 0 {
			lines = append(lines,
				t("assistant.recent_reports.filter_empty", filterID),
				t("assistant.recent_reports.dashboard", assistantDashboardURL()),
				t("assistant.recent_reports.readonly"),
			)
			return strings.Join(lines, "\n")
		}
		lines = append(lines, t("assistant.recent_reports.filter", filterID))
	}
	lines = append(lines, assistantRecentReportsOverviewFor(locale, items))
	for i, item := range items {
		lines = append(lines, fmt.Sprintf("%d. %s · %s", i+1, item.Time.Local().Format("01/02 15:04"), assistantEvidenceDisplayKindFor(locale, item.Kind)))
		if id := assistantEvidenceDisplayID(item.ID); id != "" {
			lines = append(lines, t("assistant.recent_reports.evidence_id", id))
		}
		lines = append(lines, t("assistant.recent_reports.result", assistantEvidenceDisplaySummaryFor(locale, item.Summary, item.Kind, item.ID)))
	}
	if filterID != "" {
		lines = append(lines, t("assistant.recent_reports.dashboard_evidence", assistantDashboardEvidenceURL(filterID)))
	}
	lines = append(lines,
		t("assistant.recent_reports.dashboard", assistantDashboardURL()),
		t("assistant.recent_reports.readonly"),
	)
	return strings.Join(lines, "\n")
}

var assistantEvidenceDisplayIDPattern = regexp.MustCompile(`\b\d{8}[Tt]\d{6}[Zz]-\d{1,9}\b`)

func assistantRecentReportsRequestedEvidenceID(request string) string {
	return strings.ToUpper(assistantEvidenceDisplayIDPattern.FindString(strings.TrimSpace(request)))
}

func assistantRecentReportsOverview(items []evidence.Summary) string {
	return assistantRecentReportsOverviewFor(lang.Current(), items)
}

func assistantRecentReportsOverviewFor(locale string, items []evidence.Summary) string {
	if len(items) == 0 {
		return lang.TF(locale, "assistant.recent_reports.overview_zero")
	}
	type kindCount struct {
		label string
		count int
	}
	counts := []kindCount{}
	for _, item := range items {
		label := assistantEvidenceDisplayKindFor(locale, item.Kind)
		found := false
		for i := range counts {
			if counts[i].label == label {
				counts[i].count++
				found = true
				break
			}
		}
		if !found {
			counts = append(counts, kindCount{label: label, count: 1})
		}
	}
	parts := []string{}
	for i, entry := range counts {
		if i >= 4 {
			parts = append(parts, lang.TF(locale, "assistant.recent_reports.overview_more_types", len(counts)-i))
			break
		}
		parts = append(parts, fmt.Sprintf("%s %d", entry.label, entry.count))
	}
	latest := assistantEvidenceDisplayKindFor(locale, items[0].Kind)
	return lang.TF(locale, "assistant.recent_reports.overview", len(items), latest, strings.Join(parts, ", "))
}

