func assistantEvidenceDisplaySummary(summary, kind, fallback string) string {
	return assistantEvidenceDisplaySummaryFor(lang.Current(), summary, kind, fallback)
}

func assistantEvidenceDisplaySummaryFor(locale, summary, kind, fallback string) string {
	text := strings.TrimSpace(summary)
	if text == "" {
		text = strings.TrimSpace(fallback)
	}
	lowerKind := strings.ToLower(strings.TrimSpace(kind))
	if lowerKind == "open_url" || strings.Contains(text, "http://") || strings.Contains(text, "https://") {
		if host := firstURLHost(text); host != "" {
			return lang.TF(locale, "assistant.recent_reports.summary.url", host)
		}
		return lang.TF(locale, "assistant.recent_reports.kind.open_url")
	}
	text = strings.Join(strings.Fields(text), " ")
	return trimSignalListLine(text, 96)
}

func assistantEvidenceDisplayID(id string) string {
	id = strings.TrimSpace(id)
	if id == "" {
		return ""
	}
	parts := strings.Split(id, "-")
	if len(parts) >= 2 && strings.HasSuffix(parts[0], "Z") {
		return parts[0] + "-" + parts[1]
	}
	return trimSignalListLine(id, 48)
}

func signalEvidenceRef(record evidence.Record) string {
	if id := strings.TrimSpace(record.ID); id != "" {
		return assistantEvidenceDisplayID(id)
	}
	stored := strings.TrimSpace(record.StoredAt)
	if stored == "" {
		return ""
	}
	base := filepath.Base(stored)
	return strings.TrimSuffix(base, filepath.Ext(base))
}

func firstURLHost(text string) string {
	match := regexp.MustCompile(`https?://\S+`).FindString(text)
	if match == "" {
		return ""
	}
	parsed, err := url.Parse(match)
	if err != nil {
		return ""
	}
	return parsed.Host
}

