func assistantChannelStatusReply() string {
	store, err := ListTargets()
	if err != nil {
		return strings.Join([]string{
			"Argos 채널 상태입니다.",
			"Signal target store를 읽지 못했습니다: " + err.Error(),
			"읽기 전용 조회입니다. 채널을 만들거나 바꾸지 않았습니다.",
		}, "\n")
	}
	interactive := []string{}
	oneWay := []string{}
	other := []string{}
	for _, target := range store.Targets {
		id := strings.TrimSpace(target.ID)
		if id == "" {
			id = "-"
		}
		mode := strings.TrimSpace(target.Mode)
		if mode == "" {
			mode = "default"
		}
		label := id + " (" + mode + ")"
		if OneWayReportTarget(target) {
			oneWay = append(oneWay, label)
		} else if isInteractiveTargetMode(target.Mode) {
			interactive = append(interactive, label)
		} else {
			other = append(other, label)
		}
	}
	sort.Strings(interactive)
	sort.Strings(oneWay)
	sort.Strings(other)
	lines := []string{
		"Argos 채널 상태입니다.",
		fmt.Sprintf("Signal targets: 전체 %d개, interactive %d개, one-way/no-reply %d개", len(store.Targets), len(interactive), len(oneWay)),
	}
	if len(interactive) > 0 {
		lines = append(lines, "- 대화형: "+strings.Join(limitStrings(interactive, 3), ", "))
	}
	if len(oneWay) > 0 {
		lines = append(lines, "- 보고 전용: "+strings.Join(limitStrings(oneWay, 3), ", "))
	}
	if len(other) > 0 {
		lines = append(lines, "- 기타: "+strings.Join(limitStrings(other, 3), ", "))
	}
	lines = append(lines,
		"- Gateway: Signal은 열림, Webhook 상태: 닫힘. 공개 수신 endpoint는 아직 열지 않았습니다.",
		"- 열기 전 조건: `/argos/webhook/events`, 허용 출처, HMAC 서명, rate limit, payload 최대 크기, 기본 dry-run.",
		"- 예시 이벤트: 메일 초안, 일정 후보, 알림/감시 결과, 서버 조치 요청. 모두 승인 초안으로만 들어옵니다.",
		"- 수신 흐름: 외부 도구 -> Webhook -> 승인 초안 -> Signal 승인 -> 별도 실행.",
		"- 보안/경계: raw token/password 금지, Guard/vault handle만 사용. Dashboard는 관찰, Signal은 승인, Webhook은 외부 이벤트 수신입니다.",
		"- 금지: 수신만으로 메일 발송, 삭제, 결제, 예약 확정, 서버 조치를 하지 않습니다.",
		"- 열려면: `webhook receiver 열기 승인 요청 만들어줘`",
		"관제센터: "+assistantDashboardURL()+" · 읽기 전용 조회입니다. 채널을 만들거나 바꾸지 않았습니다.",
	)
	return strings.Join(lines, "\n")
}

func limitStrings(items []string, max int) []string {
	if max <= 0 || len(items) <= max {
		return items
	}
	out := append([]string{}, items[:max]...)
	out = append(out, fmt.Sprintf("외 %d개", len(items)-max))
	return out
}

func isAssistantScheduledDeliveryStatusRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	if containsAny(lower, "scheduled delivery status", "scheduled delivery runner", "delivery runner", "recurring delivery") {
		return true
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(lower)
	return containsAny(compact,
		"예약발송상태", "예약발송현황", "예약발송러너", "예약전송상태", "예약전송현황",
		"정기발송상태", "정기발송현황",
	)
}

func assistantScheduledDeliveryStatusReply() string {
	store, err := LoadScheduledDeliveryStore()
	if err != nil {
		return strings.Join([]string{
			"Argos 예약 발송 상태입니다.",
			"예약 발송 저장소를 읽지 못했습니다: " + err.Error(),
			"읽기 전용 조회입니다. 예약 등록, 발송, 중지는 하지 않았습니다.",
		}, "\n")
	}
	enabled := []ScheduledDeliveryJob{}
	disabled := 0
	for _, job := range store.Jobs {
		if job.Enabled {
			enabled = append(enabled, job)
		} else {
			disabled++
		}
	}
	lines := []string{
		"Argos 예약 발송 상태입니다.",
		fmt.Sprintf("등록 %d개: 활성 %d개, 비활성 %d개", len(store.Jobs), len(enabled), disabled),
	}
	now := time.Now()
	if job, next, ok := assistantScheduledDeliveryNextCandidate(enabled, now); ok {
		target := firstNonEmpty(job.TargetLabel, job.TargetID, "대상 미정")
		lines = append(lines, fmt.Sprintf("다음 발송 후보: %s -> %s, %s (%s)",
			firstNonEmpty(job.ID, job.Schedule, "예약"),
			target,
			next.Local().Format("01-02 15:04"),
			assistantScheduleDueInText(next.Sub(now)),
		))
	}
	if len(enabled) == 0 {
		lines = append(lines,
			"- 활성 예약 발송이 없습니다.",
			"- 새 예약은 요청을 계획/미리보기로 만든 뒤 승인 전에는 등록하거나 발송하지 않습니다.",
		)
	} else {
		for i, job := range enabled {
			if i >= 5 {
				lines = append(lines, fmt.Sprintf("- 외 %d개 더 있음", len(enabled)-i))
				break
			}
			target := firstNonEmpty(job.TargetLabel, job.TargetID, "대상 미정")
			last := "아직 실행 없음"
			if !job.LastRunAt.IsZero() {
				last = job.LastRunAt.Local().Format("01-02 15:04")
			}
			next := assistantScheduledDeliveryNextText(job, now)
			lines = append(lines, fmt.Sprintf("- %s · %s -> %s: %s · 상태=%s · 방식=%s · 최근=%s · 다음=%s",
				firstNonEmpty(job.ID, "예약"),
				job.Schedule,
				target,
				trimSignalListLine(job.Content, 34),
				assistantScheduledDeliveryStatusLabel(firstNonEmpty(job.Status, "registered")),
				assistantScheduledDeliveryMethodLabel(firstNonEmpty(job.Delivery, "signal")),
				last,
				next,
			))
		}
	}
	lines = append(lines,
		"작동 방식: 승인된 예약만 저장되고, 실제 발송은 정해진 시간에 예약 실행기가 처리합니다.",
		"변경/중지: `<ID> 예약 발송 중지 승인 요청 만들어줘`로 승인 초안을 먼저 만듭니다.",
		"읽기 전용 조회입니다. 예약 등록, 발송, 중지는 하지 않았습니다.",
	)
	return strings.Join(lines, "\n")
}

func assistantScheduledDeliveryNextCandidate(jobs []ScheduledDeliveryJob, now time.Time) (ScheduledDeliveryJob, time.Time, bool) {
	var selected ScheduledDeliveryJob
	var selectedNext time.Time
	for _, job := range jobs {
		next, ok := assistantScheduledDeliveryNextRun(job, now)
		if !ok || next.IsZero() {
			continue
		}
		if selectedNext.IsZero() || next.Before(selectedNext) {
			selected = job
			selectedNext = next
		}
	}
	return selected, selectedNext, !selectedNext.IsZero()
}

func assistantScheduledDeliveryStatusLabel(status string) string {
	switch strings.ToLower(strings.TrimSpace(status)) {
	case "", "registered", "ready", "active":
		return "등록됨"
	case "disabled", "paused", "stopped":
		return "꺼짐"
	case "sent", "done", "completed":
		return "완료"
	case "failed", "error":
		return "실패"
	default:
		return strings.TrimSpace(status)
	}
}

func assistantScheduledDeliveryMethodLabel(method string) string {
	switch strings.ToLower(strings.TrimSpace(method)) {
	case "", "signal":
		return "Signal"
	case "voice_note", "voice", "audio":
		return "음성"
	case "call":
		return "전화"
	default:
		return strings.TrimSpace(method)
	}
}

func assistantScheduledDeliveryNextText(job ScheduledDeliveryJob, now time.Time) string {
	next, ok := assistantScheduledDeliveryNextRun(job, now)
	if !ok {
		return "수동 확인"
	}
	if !job.LastRunAt.IsZero() && !job.LastRunAt.Before(next) {
		if assistantScheduledDeliveryIsWeekly(job.Schedule) {
			next = next.AddDate(0, 0, 7)
		} else {
			next = next.Add(24 * time.Hour)
		}
	}
	if !next.After(now) {
		return "지금 실행 대상"
	}
	return fmt.Sprintf("%s (%s)", next.Local().Format("01-02 15:04"), assistantScheduleDueInText(next.Sub(now)))
}

func assistantScheduledDeliveryNextRun(job ScheduledDeliveryJob, now time.Time) (time.Time, bool) {
	schedule := assistantScheduledDeliveryNormalizeSchedule(job.Schedule)
	if schedule == "" {
		return time.Time{}, false
	}
	local := now.Local()
	if assistantScheduledDeliveryIsDaily(schedule) {
		hour, ok := assistantScheduledDeliveryHour(schedule)
		if !ok {
			return time.Time{}, false
		}
		next := time.Date(local.Year(), local.Month(), local.Day(), hour, 0, 0, 0, local.Location())
		if next.Before(local) || next.Equal(local) {
			next = next.Add(24 * time.Hour)
		}
		return next, true
	}
	weekday, ok := assistantScheduledDeliveryWeekday(schedule)
	if !ok {
		return time.Time{}, false
	}
	hour, ok := assistantScheduledDeliveryHour(schedule)
	if !ok {
		return time.Time{}, false
	}
	days := (int(weekday) - int(local.Weekday()) + 7) % 7
	nextDay := local.AddDate(0, 0, days)
	next := time.Date(nextDay.Year(), nextDay.Month(), nextDay.Day(), hour, 0, 0, 0, local.Location())
	if !next.After(local) {
		next = next.AddDate(0, 0, 7)
	}
	return next, true
}

func assistantScheduledDeliveryDailyHour(schedule string) (int, bool) {
	schedule = assistantScheduledDeliveryNormalizeSchedule(schedule)
	if !assistantScheduledDeliveryIsDaily(schedule) {
		return 0, false
	}
	return assistantScheduledDeliveryHour(schedule)
}

func assistantScheduledDeliveryNormalizeSchedule(schedule string) string {
	schedule = strings.ToLower(strings.TrimSpace(schedule))
	return strings.NewReplacer(
		"월욜", "월요일",
		"화욜", "화요일",
		"수욜", "수요일",
		"목욜", "목요일",
		"금욜", "금요일",
		"토욜", "토요일",
		"일욜", "일요일",
	).Replace(schedule)
}

func assistantScheduledDeliveryIsDaily(schedule string) bool {
	return containsAny(assistantScheduledDeliveryNormalizeSchedule(schedule), "매일", "daily", "every day")
}

func assistantScheduledDeliveryIsWeekly(schedule string) bool {
	schedule = assistantScheduledDeliveryNormalizeSchedule(schedule)
	return containsAny(schedule, "매주", "weekly", "every week") || strings.Contains(schedule, "요일")
}

func assistantScheduledDeliveryHour(schedule string) (int, bool) {
	re := regexp.MustCompile(`(\d{1,2})\s*시`)
	match := re.FindStringSubmatch(schedule)
	if len(match) < 2 {
		re = regexp.MustCompile(`\b(\d{1,2})\s*(am|pm)\b`)
		match = re.FindStringSubmatch(schedule)
		if len(match) < 2 {
			return 0, false
		}
	}
	hour, err := strconv.Atoi(match[1])
	if err != nil || hour < 0 || hour > 23 {
		return 0, false
	}
	if containsAny(schedule, "오후", "pm") && hour < 12 {
		hour += 12
	}
	if containsAny(schedule, "오전", "am") && hour == 12 {
		hour = 0
	}
	return hour, true
}

func assistantScheduledDeliveryWeekday(schedule string) (time.Weekday, bool) {
	schedule = assistantScheduledDeliveryNormalizeSchedule(schedule)
	switch {
	case containsAny(schedule, "일요일", "sunday", "sun"):
		return time.Sunday, true
	case containsAny(schedule, "월요일", "monday", "mon"):
		return time.Monday, true
	case containsAny(schedule, "화요일", "tuesday", "tue"):
		return time.Tuesday, true
	case containsAny(schedule, "수요일", "wednesday", "wed"):
		return time.Wednesday, true
	case containsAny(schedule, "목요일", "thursday", "thu"):
		return time.Thursday, true
	case containsAny(schedule, "금요일", "friday", "fri"):
		return time.Friday, true
	case containsAny(schedule, "토요일", "saturday", "sat"):
		return time.Saturday, true
	default:
		return time.Sunday, false
	}
}

