func assistantApprovalQueueReply(opts ListenOptions) string {
	return assistantApprovalQueueReplyFor(opts, lang.Current())
}

func assistantApprovalQueueLocale(text string) string {
	lower := strings.ToLower(text)
	if containsAny(lower, "approval queue", "approval list", "pending approval", "pending approvals") {
		return "en"
	}
	if assistantCheckoutPrepContainsHangul(text) ||
		containsAny(text, "승인 대기열", "승인 목록", "승인 리스트", "대기 승인", "승인 대기") {
		return "ko"
	}
	return lang.Current()
}

func assistantApprovalQueueReplyFor(opts ListenOptions, locale string) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	resume, resumeErr := runtimeflow.Resume("latest")
	plan, err := runtimeflow.PlanExecute("latest")
	lines := []string{
		t("assistant.approval_queue.title"),
		t("assistant.approval_queue.dashboard", assistantDashboardURL()),
	}
	lines = append(lines, assistantApprovalQueueQuickActionLinesFor(locale, opts.TargetID)...)
	if err != nil {
		lines = append(lines,
			t("assistant.approval_queue.no_pending"),
			t("assistant.approval_queue.no_recent_bundle"),
			t("assistant.approval_queue.record_none"),
			t("assistant.approval_queue.candidate_hint"),
		)
	} else {
		lines = append(lines,
			t("assistant.approval_queue.recent_bundle", firstNonEmpty(plan.Workflow, t("assistant.approval_queue.unnamed"))),
			t("assistant.approval_queue.counts", plan.Counts.ApprovalPending, plan.Counts.Ready, plan.Counts.Failed+plan.Counts.RepairNeeded),
		)
		if len(plan.ApprovalPending) == 0 {
			lines = append(lines, t("assistant.approval_queue.none_ready"))
		} else {
			for i, item := range plan.ApprovalPending {
				if i >= 5 {
					lines = append(lines, t("assistant.approval_queue.more", len(plan.ApprovalPending)-i))
					break
				}
				level := t("assistant.approval_queue.level.normal")
				if item.StrongApproval {
					level = t("assistant.approval_queue.level.strong")
				}
				lines = append(lines, t("assistant.approval_queue.pending_item", item.Step, level, firstNonEmpty(item.Node, "-"), firstNonEmpty(item.Transport, "-")))
			}
		}
		if resumeErr == nil && len(resume.Approvals) > 0 {
			lines = append(lines, t("assistant.approval_queue.record_remaining", len(resume.Approvals)))
		} else {
			lines = append(lines, t("assistant.approval_queue.record_none_recent"))
		}
	}
	lines = appendAssistantApprovalQueueMailCandidateFor(locale, lines, opts.TargetID)
	lines = appendAssistantApprovalQueueMacActionCandidateFor(locale, lines, opts.TargetID)
	lines = appendAssistantApprovalQueueDirectPurchaseCandidateFor(locale, lines, opts.TargetID)
	lines = appendAssistantApprovalQueuePurchaseCandidateFor(locale, lines, opts.TargetID)
	lines = append(lines, "", t("assistant.approval_queue.drafts_title"))
	lines = append(lines, assistantApprovalCandidateLinesFor(locale)...)
	lines = append(lines,
		"",
		t("assistant.approval_queue.examples"),
		t("assistant.approval_queue.boundary"),
		t("assistant.approval_queue.separation"),
		t("assistant.approval_queue.read_only"),
	)
	return strings.Join(lines, "\n")
}

func assistantApprovalQueueQuickActionLinesFor(locale, targetID string) []string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	var actions []string
	if pending, ok := peekPendingMailSend(mailPendingKey(targetID)); ok && strings.TrimSpace(pending.Draft.ID) != "" {
		actions = append(actions, t("assistant.approval_queue.quick.mail"))
	}
	if pending, ok := peekPendingArgosAction(argosPendingKey(targetID)); ok && strings.TrimSpace(pending.Action.Action) != "" {
		actions = append(actions, t("assistant.approval_queue.quick.mac"))
		if pending.Decision.Grantable {
			actions = append(actions, t("assistant.approval_queue.quick.mac_always"))
		}
	}
	if !assistantPurchaseAutomationDisabled() {
		if pending, ok := takePendingAssistantConversation(assistantPendingKey(targetID), false); ok && pending.Kind == "shopping_direct_purchase" {
			actions = append(actions, t("assistant.approval_queue.quick.direct_purchase"))
		}
		if _, ok := latestPurchaseFinalExecutionCandidateFromHistory(targetID); ok {
			actions = append(actions, t("assistant.approval_queue.quick.purchase_final"))
		}
	}
	if len(actions) == 0 {
		return nil
	}
	lines := []string{"", t("assistant.approval_queue.quick.title")}
	lines = append(lines, actions...)
	lines = append(lines, t("assistant.approval_queue.quick.readonly"))
	return lines
}

type assistantPurchaseApprovalCandidate struct {
	Item  string
	Total string
	Tool  string
}

func appendAssistantApprovalQueueMailCandidateFor(locale string, lines []string, targetID string) []string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	pending, ok := peekPendingMailSend(mailPendingKey(targetID))
	if !ok || strings.TrimSpace(pending.Draft.ID) == "" {
		return lines
	}
	to := cleanSignalMailDraftRecipientsForDisplay(pending.Draft.To)
	if to == "" {
		to = lang.TF(locale, "assistant.mail_draft.to_unknown")
	}
	subject := cleanSignalMailHeaderForDisplay(pending.Draft.Subject, lang.TF(locale, "assistant.mail_draft.subject_unknown"))
	draftID := firstNonEmpty(pending.Draft.ID, "-")
	return append(lines,
		"",
		t("assistant.approval_queue.mail_pending_title"),
		t("assistant.approval_queue.mail_pending.item", to, subject, draftID),
		t("assistant.approval_queue.mail_pending.expires", pending.ExpiresAt.Local().Format("2006-01-02 15:04 MST")),
		t("assistant.approval_queue.mail_pending.action.approve"),
		t("assistant.approval_queue.mail_pending.action.revise"),
		t("assistant.approval_queue.mail_pending.action.stop"),
		t("assistant.approval_queue.mail_pending.action.readonly"),
	)
}

func appendAssistantApprovalQueueMacActionCandidateFor(locale string, lines []string, targetID string) []string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	pending, ok := peekPendingArgosAction(argosPendingKey(targetID))
	if !ok || strings.TrimSpace(pending.Action.Action) == "" {
		return lines
	}
	actionLabel := assistantApprovalQueueMacActionLabel(locale, pending.Action)
	target := firstNonEmpty(assistantApprovalQueueMacActionTarget(pending.Action), "-")
	scope := firstNonEmpty(pending.Decision.Label, pending.Decision.Scope, pending.Action.Action, "-")
	out := append(lines,
		"",
		t("assistant.approval_queue.mac_pending_title"),
		t("assistant.approval_queue.mac_pending.item", actionLabel, target, scope),
		t("assistant.approval_queue.mac_pending.expires", pending.ExpiresAt.Local().Format("2006-01-02 15:04 MST")),
		t("assistant.approval_queue.mac_pending.action.execute"),
	)
	if pending.Decision.Grantable {
		out = append(out, t("assistant.approval_queue.mac_pending.action.always"))
	} else {
		out = append(out, t("assistant.approval_queue.mac_pending.action.once_only"))
	}
	return append(out, t("assistant.approval_queue.mac_pending.action.readonly"))
}

func appendAssistantApprovalQueueDirectPurchaseCandidateFor(locale string, lines []string, targetID string) []string {
	if assistantPurchaseAutomationDisabled() {
		return lines
	}
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	pending, ok := takePendingAssistantConversation(assistantPendingKey(targetID), false)
	if !ok || pending.Kind != "shopping_direct_purchase" {
		return lines
	}
	query := strings.TrimSpace(firstNonEmpty(pending.Intent.Query, coupangShoppingQuery(pending.Request)))
	if query == "" {
		return lines
	}
	item := directPurchaseDisplayQueryFor(locale, query)
	out := append(lines,
		"",
		t("assistant.approval_queue.direct_purchase_pending_title"),
		t("assistant.approval_queue.direct_purchase_pending.item", item),
	)
	if productURL := strings.TrimSpace(pending.Intent.URL); isCoupangProductURL(productURL) {
		out = append(out, t("assistant.approval_queue.direct_purchase_pending.link", productURL))
	}
	out = append(out, t("assistant.approval_queue.direct_purchase_pending.expires", pending.ExpiresAt.Local().Format("2006-01-02 15:04 MST")))
	out = append(out, t("assistant.approval_queue.direct_purchase_pending.one_approval"))
	if evidenceID := pendingShoppingDirectPurchaseEvidenceID(pending); evidenceID != "" {
		out = append(out, t("assistant.approval_queue.direct_purchase_pending.evidence_id", evidenceID, evidenceID))
		out = append(out, t("assistant.approval_queue.direct_purchase_pending.dashboard", assistantDashboardEvidenceURL(evidenceID)))
	} else {
		out = append(out, t("assistant.approval_queue.direct_purchase_pending.evidence_check"))
	}
	if blocker := pendingShoppingDirectPurchaseBlocker(pending); blocker != "" {
		out = append(out, t("assistant.approval_queue.direct_purchase_pending.blocker", directPurchaseBlockerDisplayFor(locale, blocker)))
		if hint := directPurchaseBlockerUserHintFor(locale, blocker); hint != "" {
			out = append(out, t("assistant.approval_queue.direct_purchase_pending.user_hint", hint))
		}
	}
	return append(out,
		t("assistant.approval_queue.direct_purchase_pending.action.continue"),
		t("assistant.approval_queue.direct_purchase_pending.action.stop"),
		t("assistant.approval_queue.direct_purchase_pending.action.readonly"),
	)
}

