func assistantApprovalQueueMacActionTarget(action osauto.ArgosAction) string {
	switch action.Action {
	case "open_app":
		return action.App
	case "open_url", "browser_fetch":
		return action.URL
	case "browser_search", "visible_browser_search", "work_demo":
		return action.Query
	case "note_create":
		return action.NoteTitle
	case "reminder_create":
		return firstNonEmpty(action.ReminderTitle, action.ReminderQuery)
	case "reminders_list":
		return firstNonEmpty(action.ReminderQuery, assistantApprovalQueueRange(action.ReminderStart, action.ReminderEnd))
	case "reminder_complete", "reminder_delete":
		return firstNonEmpty(action.ReminderQuery, action.ReminderID)
	case "calendar_event_create":
		return firstNonEmpty(action.CalendarTitle, assistantApprovalQueueRange(action.CalendarStart, action.CalendarEnd))
	case "calendar_events_list":
		return firstNonEmpty(action.CalendarQuery, assistantApprovalQueueRange(action.CalendarStart, action.CalendarEnd))
	case "calendar_event_delete":
		return firstNonEmpty(action.CalendarTitle, action.CalendarQuery, action.CalendarID)
	case "contacts_search":
		return action.ContactQuery
	case "shortcut_run":
		return action.Shortcut
	case "mac_runner_command":
		return action.Input
	case "ai_handoff":
		return action.Provider
	default:
		return firstNonEmpty(action.Text, action.Action)
	}
}

func assistantApprovalQueueRange(start, end string) string {
	start = strings.TrimSpace(start)
	end = strings.TrimSpace(end)
	if start != "" && end != "" {
		return start + " ~ " + end
	}
	return firstNonEmpty(start, end)
}

func appendAssistantApprovalQueuePurchaseCandidate(lines []string, targetID string) []string {
	return appendAssistantApprovalQueuePurchaseCandidateFor(lang.Current(), lines, targetID)
}

func appendAssistantApprovalQueuePurchaseCandidateFor(locale string, lines []string, targetID string) []string {
	if assistantPurchaseAutomationDisabled() {
		return lines
	}
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	candidate, ok := latestPurchaseFinalExecutionCandidateFromHistory(targetID)
	if !ok {
		return lines
	}
	item := firstNonEmpty(candidate.Item, "-")
	total := firstNonEmpty(candidate.Total, "-")
	tool := firstNonEmpty(candidate.Tool, "`meshclaw_purchase_click`")
	return append(lines,
		"",
		t("assistant.approval_queue.purchase_pending_title"),
		t("assistant.approval_queue.purchase_pending.item", item, total, tool),
		t("assistant.approval_queue.purchase_pending.next"),
		t("assistant.approval_queue.purchase_pending.action.approve"),
		t("assistant.approval_queue.purchase_pending.action.stop"),
		t("assistant.approval_queue.purchase_pending.action.readonly"),
	)
}

func latestPurchaseFinalExecutionCandidateFromHistory(targetID string) (assistantPurchaseApprovalCandidate, bool) {
	targetID = strings.TrimSpace(targetID)
	if targetID == "" {
		return assistantPurchaseApprovalCandidate{}, false
	}
	history := loadSignalHistory(targetID, 20)
	for i := len(history) - 1; i >= 0; i-- {
		msg := history[i]
		if looksLikePurchaseFlowStopMarker(msg) {
			return assistantPurchaseApprovalCandidate{}, false
		}
		if msg.Role != "assistant" {
			continue
		}
		visible := signalReplyVisibleText(msg.Content)
		if !looksLikePurchaseFinalExecutionReadyReply(visible) || looksLikeCompletedPurchaseReply(visible) {
			continue
		}
		candidate := parsePurchaseFinalExecutionCandidate(visible)
		if candidate.Tool == "" {
			candidate.Tool = "`meshclaw_purchase_click`"
		}
		return candidate, true
	}
	return assistantPurchaseApprovalCandidate{}, false
}

func looksLikePurchaseFlowStopMarker(msg aichat.Message) bool {
	visible := signalReplyVisibleText(msg.Content)
	lower := strings.ToLower(strings.TrimSpace(visible))
	if lower == "" {
		return false
	}
	if msg.Role == "user" && isShoppingPurchaseStopRequest(lower) {
		return true
	}
	return containsAny(visible,
		lang.T("assistant.shopping.stop.title"),
		"구매 플로우를 중지했습니다.",
		"Purchase flow stopped.",
	)
}

func looksLikePurchaseFinalExecutionReadyReply(text string) bool {
	return containsAny(text,
		lang.T("assistant.shopping.final_execution.ready.title"),
		"최종 구매 클릭 실행값이 준비되었습니다.",
		"Final purchase-click execution values are ready.",
	)
}

func looksLikeCompletedPurchaseReply(text string) bool {
	lower := strings.ToLower(text)
	return containsAny(text, "구매 완료", "주문 완료", "최종 주문 버튼을 눌렀습니다") ||
		containsAny(lower, "purchase completed", "order completed", "clicked the final")
}

func parsePurchaseFinalExecutionCandidate(text string) assistantPurchaseApprovalCandidate {
	candidate := assistantPurchaseApprovalCandidate{}
	for _, rawLine := range strings.Split(text, "\n") {
		line := strings.TrimSpace(rawLine)
		if value, ok := approvalQueueValueAfterLabels(line, "상품명:", "Item:"); ok {
			candidate.Item = value
			continue
		}
		if value, ok := approvalQueueValueAfterLabels(line, "총액:", "Total:"); ok {
			candidate.Total = value
			continue
		}
		if value, ok := approvalQueueValueAfterLabels(line, "실제 클릭 도구:", "Actual click tool:"); ok {
			candidate.Tool = cleanApprovalQueueToolName(value)
			continue
		}
	}
	return candidate
}

func approvalQueueValueAfterLabels(line string, labels ...string) (string, bool) {
	line = strings.TrimSpace(strings.TrimPrefix(strings.TrimSpace(line), "-"))
	for _, label := range labels {
		if strings.HasPrefix(line, label) {
			value := strings.TrimSpace(strings.TrimPrefix(line, label))
			return strings.TrimSpace(value), strings.TrimSpace(value) != ""
		}
	}
	return "", false
}

func cleanApprovalQueueToolName(value string) string {
	value = strings.TrimSpace(value)
	if value == "" {
		return ""
	}
	if strings.HasPrefix(value, "`") && strings.HasSuffix(value, "`") {
		return value
	}
	return "`" + strings.Trim(value, "`") + "`"
}

func assistantApprovalCandidateLines() []string {
	return assistantApprovalCandidateLinesFor(lang.Current())
}

func assistantApprovalCandidateLinesFor(locale string) []string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	lines := []string{
		t("assistant.approval_queue.draft.auto_stop"),
		assistantApprovalCandidateCommandLineFor(locale, "mail-watch"),
		assistantApprovalCandidateCommandLineFor(locale, "assistant-auto-check"),
		t("assistant.approval_queue.draft.server"),
		t("assistant.approval_queue.draft.webhook"),
		t("assistant.approval_queue.draft.mail_payment_delete"),
	}
	if store, err := LoadScheduledDeliveryStore(); err == nil {
		enabled := []ScheduledDeliveryJob{}
		for _, job := range store.Jobs {
			if job.Enabled {
				enabled = append(enabled, job)
			}
		}
		if len(enabled) > 0 {
			lines = append(lines, t("assistant.approval_queue.draft.scheduled_delivery"))
			for i, job := range enabled {
				if i >= 3 {
					lines = append(lines, t("assistant.approval_queue.more", len(enabled)-i))
					break
				}
				target := firstNonEmpty(assistantScheduleLocalizedTarget(job.TargetID, job.TargetLabel), job.TargetID, t("assistant.automation_list.target_unknown"))
				lines = append(lines, t("assistant.approval_queue.draft.scheduled_delivery_line", firstNonEmpty(job.ID, job.Schedule), job.Schedule, target))
			}
		}
	}
	return lines
}

func assistantApprovalCandidateCommandLine(target string) string {
	return assistantApprovalCandidateCommandLineFor(lang.Current(), target)
}

func assistantApprovalCandidateCommandLineFor(locale, target string) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	command := t("assistant.approval_queue.draft.stop_command", target)
	if lang.Normalize(locale) != "ko" {
		return t("assistant.approval_queue.draft.stop_plain", command)
	}
	if contextLines := assistantApprovalDraftContext(target); len(contextLines) > 0 {
		state := strings.TrimSpace(strings.TrimPrefix(contextLines[0], "현재 상태:"))
		if state != "" {
			return t("assistant.approval_queue.draft.stop_state", command, trimSignalListLine(state, 84))
		}
	}
	return t("assistant.approval_queue.draft.stop_plain", command)
}

func assistantGenericFinalApprovalReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return "", false
	}
	if !containsAny(lower,
		"최종 승인", "실행 승인", "예약 승인", "발송 승인", "구매 승인", "결제 승인",
		"final approval", "execution approval", "send approved", "booking approved", "purchase approved",
	) {
		return "", false
	}
	if containsAny(lower, "승인 대기열", "approval queue", "승인 요청 초안", "approval request draft") {
		return "", false
	}
	locale := assistantGenericFinalApprovalLocale(text)
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	target := firstNonEmpty(opts.TargetID, "assistant")
	lines := []string{
		t("assistant.final_approval.title"),
		t("assistant.final_approval.hold"),
		"",
		t("assistant.final_approval.required_title"),
		t("assistant.final_approval.kind"),
		t("assistant.final_approval.target"),
		t("assistant.final_approval.final_value"),
		t("assistant.final_approval.evidence"),
		t("assistant.final_approval.phrase"),
		"",
		t("assistant.final_approval.room", target),
		t("assistant.final_approval.boundary"),
		t("assistant.final_approval.missing_evidence"),
	}
	if pending, ok := peekPendingMailSend(mailPendingKey(opts.TargetID)); ok && strings.TrimSpace(pending.Draft.ID) != "" {
		to := cleanSignalMailDraftRecipientsForDisplay(pending.Draft.To)
		if to == "" {
			to = lang.TF(locale, "assistant.mail_draft.to_unknown")
		}
		subject := cleanSignalMailHeaderForDisplay(pending.Draft.Subject, lang.TF(locale, "assistant.mail_draft.subject_unknown"))
		lines = append(lines,
			"",
			t("assistant.final_approval.mail_title"),
			t("assistant.final_approval.mail_to", to),
			t("assistant.final_approval.mail_subject", subject),
			t("assistant.final_approval.mail_draft", pending.Draft.ID),
			t("assistant.final_approval.mail_command"),
		)
	}
	if pending, ok := peekPendingArgosAction(argosPendingKey(opts.TargetID)); ok && strings.TrimSpace(pending.Action.Action) != "" {
		switch pending.Action.Action {
		case "reminder_create", "calendar_event_create":
			lines = append(lines,
				"",
				t("assistant.final_approval.mac_title"),
				t("assistant.final_approval.mac_action", assistantApprovalQueueMacActionLabel(locale, pending.Action)),
				t("assistant.final_approval.mac_target", firstNonEmpty(assistantApprovalQueueMacActionTarget(pending.Action), "-")),
				t("assistant.final_approval.mac_scope", firstNonEmpty(pending.Decision.Label, pending.Decision.Scope, pending.Action.Action, "-")),
				t("assistant.final_approval.mac_command"),
			)
			if pending.Decision.Grantable {
				lines = append(lines, t("assistant.final_approval.mac_always"))
			}
		}
	}
	if candidate, ok := latestPurchaseFinalExecutionCandidateFromHistory(opts.TargetID); ok && !assistantPurchaseAutomationDisabled() {
		lines = append(lines,
			"",
			t("assistant.final_approval.purchase_title"),
			t("assistant.final_approval.purchase_item", firstNonEmpty(candidate.Item, "-")),
			t("assistant.final_approval.purchase_total", firstNonEmpty(candidate.Total, "-")),
			t("assistant.final_approval.purchase_tool", firstNonEmpty(candidate.Tool, "`meshclaw_purchase_click`")),
		)
	}
	lines = append(lines, assistantFinalApprovalPreflightPacketFor(locale, opts, text)...)
	return strings.Join(lines, "\n"), true
}

func assistantGenericFinalApprovalLocale(text string) string {
	lower := strings.ToLower(text)
	if containsAny(lower, "final approval", "execution approval", "send approved", "booking approved", "purchase approved") {
		return "en"
	}
	if assistantCheckoutPrepContainsHangul(text) || containsAny(text, "최종 승인", "실행 승인", "예약 승인", "발송 승인", "구매 승인", "결제 승인") {
		return "ko"
	}
	return lang.Current()
}

func assistantFinalApprovalPreflightPacketFor(locale string, opts ListenOptions, text string) []string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	kind, target, evidence := assistantFinalApprovalPreflightValues(opts, text)
	missing := []string{}
	if kind == "" {
		kind = t("assistant.final_approval.value.unknown")
		missing = append(missing, "action_kind")
	}
	if target == "" {
		target = t("assistant.final_approval.value.unknown")
		missing = append(missing, "target")
	}
	if evidence == "" {
		evidence = t("assistant.final_approval.value.none")
		missing = append(missing, "evidence_source")
	}
	missing = append(missing, "explicit_final_approval_phrase")
	return []string{
		"",
		t("assistant.final_approval.packet_title"),
		t("assistant.final_approval.packet.kind", kind),
		t("assistant.final_approval.packet.target", target),
		t("assistant.final_approval.packet.evidence", evidence),
		t("assistant.final_approval.packet.missing", strings.Join(missing, ", ")),
		t("assistant.final_approval.packet.status"),
		t("assistant.final_approval.packet.execute"),
		t("assistant.final_approval.packet.noop"),
	}
}

func assistantFinalApprovalPreflightValues(opts ListenOptions, text string) (string, string, string) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if pending, ok := peekPendingMailSend(mailPendingKey(opts.TargetID)); ok && strings.TrimSpace(pending.Draft.ID) != "" {
		to := cleanSignalMailDraftRecipientsForDisplay(pending.Draft.To)
		subject := cleanSignalMailHeaderForDisplay(pending.Draft.Subject, "")
		target := strings.TrimSpace(strings.Join(nonEmptyStrings(to, subject), " / "))
		return "mail_send", firstNonEmpty(target, pending.Draft.ID), "pending_mail_draft"
	}
	if candidate, ok := latestPurchaseFinalExecutionCandidateFromHistory(opts.TargetID); ok && !assistantPurchaseAutomationDisabled() {
		target := strings.TrimSpace(strings.Join(nonEmptyStrings(candidate.Item, candidate.Total), " / "))
		return "purchase_click", firstNonEmpty(target, candidate.Tool), "final_purchase_screen_candidate"
	}
	if pending, ok := peekPendingArgosAction(argosPendingKey(opts.TargetID)); ok {
		switch pending.Action.Action {
		case "reminder_create":
			return "reminder_create", firstNonEmpty(pending.Action.ReminderTitle, pending.Decision.Scope), "pending_argos_action"
		case "calendar_event_create":
			return "calendar_event_create", firstNonEmpty(pending.Action.CalendarTitle, pending.Decision.Scope), "pending_argos_action"
		}
	}
	switch {
	case containsAny(lower, "메일", "발송", "mail", "send"):
		return "mail_send", "", ""
	case containsAny(lower, "구매", "purchase", "order"):
		return "purchase_click", "", ""
	case containsAny(lower, "예약", "booking", "reservation"):
		return "booking_confirm", "", "draft_only"
	case containsAny(lower, "리마인더", "reminder"):
		return "reminder_create", "", ""
	case containsAny(lower, "일정", "calendar"):
		return "calendar_event_create", "", ""
	case containsAny(lower, "결제", "payment"):
		return "payment", "", ""
	case containsAny(lower, "삭제", "delete"):
		return "delete", "", ""
	default:
		return "", "", ""
	}
}

func nonEmptyStrings(values ...string) []string {
	out := []string{}
	for _, value := range values {
		if trimmed := strings.TrimSpace(value); trimmed != "" {
			out = append(out, trimmed)
		}
	}
	return out
}

func isAssistantApprovalRequestDraftRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	if containsAny(lower, "approval request draft", "create approval request", "make approval request", "draft approval") {
		return true
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(lower)
	return containsAny(compact,
		"승인요청만들", "승인요청작성", "승인요청초안", "승인요청정리",
		"승인초안", "승인받게정리", "승인받도록정리",
	)
}

func assistantApprovalRequestDraftReply(text string) string {
	subject := assistantApprovalDraftSubject(text)
	lines := []string{lang.T("assistant.approval_request.title")}
	if subject == "" {
		lines = append(lines, lang.T("assistant.approval_request.subject_unknown"))
	} else {
		lines = append(lines, lang.T("assistant.approval_request.subject", subject))
	}
	lines = append(lines, assistantApprovalDraftContextForLocale(subject)...)
	if strings.Contains(strings.ToLower(subject), "webhook") || strings.Contains(subject, "웹훅") {
		lines = append(lines,
			lang.T("assistant.approval_request.webhook.conditions_title"),
			lang.T("assistant.approval_request.webhook.endpoint"),
			lang.T("assistant.approval_request.webhook.sources"),
			lang.T("assistant.approval_request.webhook.auth"),
			lang.T("assistant.approval_request.webhook.protection"),
			lang.T("assistant.approval_request.webhook.default"),
		)
	}
	lines = append(lines,
		lang.T("assistant.approval_request.required_title"),
		lang.T("assistant.approval_request.required.change"),
		lang.T("assistant.approval_request.required.why"),
		lang.T("assistant.approval_request.required.rollback"),
		lang.T("assistant.approval_request.required.impact"),
		lang.T("assistant.approval_request.required.result"),
		"",
		lang.T("assistant.approval_request.draft_only"),
		lang.T("assistant.approval_request.explicit_approval"),
	)
	return strings.Join(lines, "\n")
}

func assistantApprovalDraftContextForLocale(subject string) []string {
	if lang.Current() == "ko" {
		return assistantApprovalDraftContext(subject)
	}
	subject = strings.TrimSpace(subject)
	if subject == "" {
		return nil
	}
	return []string{lang.T("assistant.approval_request.generic_change", subject)}
}

func assistantApprovalDraftContext(subject string) []string {
	subject = strings.TrimSpace(subject)
	if subject == "" {
		return nil
	}
	if strings.Contains(strings.ToLower(subject), "webhook") || strings.Contains(subject, "웹훅") {
		return assistantWebhookApprovalDraftContext()
	}
	if job, ok := assistantScheduleKnownJobByID(subject); ok {
		lines := []string{}
		if live, ok := readAssistantScheduleLiveStatus(); ok {
			if liveJob, found := assistantScheduleLiveJobByID(live, subject); found {
				lines = append(lines, "현재 상태: "+assistantApprovalDraftScheduleState(job, liveJob))
			}
		}
		if len(lines) == 0 {
			lines = append(lines, fmt.Sprintf("현재 상태: %s 자동화입니다. 주기=%s, 방=%s.", assistantScheduleJobLabel(job), firstNonEmpty(job.Cadence, job.Interval.String()), firstNonEmpty(job.TargetLabel, job.TargetID, "-")))
		}
		lines = append(lines,
			"변경 내용: 이 자동화를 비활성화해서 정기 실행과 자동 보고를 멈춥니다.",
			"되돌리는 방법: 같은 자동화를 다시 활성화하고 `자동화 상태`에서 due_count와 다음 실행 시간을 확인합니다.",
			"확인할 결과: `자동화 목록`에서 상태=disabled로 보이고, 의도하지 않은 보고방 발송이 없어야 합니다.",
		)
		return lines
	}
	if job, ok := assistantScheduledDeliveryJobByID(subject); ok {
		lines := []string{
			"현재 예약: " + assistantApprovalDraftScheduledDeliveryState(job),
			"변경 내용: 이 예약 발송을 비활성화해서 정해진 시간의 자동 Signal 발송을 멈춥니다.",
			"되돌리는 방법: 같은 예약 발송을 다시 활성화하고 `예약 발송 상태`에서 다음 실행 시간을 확인합니다.",
			"확인할 결과: `예약 발송 상태`에서 상태=꺼짐으로 보이고, 해당 내용이 보고방에 자동 발송되지 않아야 합니다.",
		}
		return lines
	}
	return nil
}

func assistantWebhookApprovalDraftContext() []string {
	total, interactive, oneWay := assistantSignalChannelCounts()
	current := "현재 상태: Webhook 공개 수신 endpoint는 닫힘. 아직 외부 이벤트로 자동 실행되는 경로가 없습니다."
	if total > 0 {
		current = fmt.Sprintf("현재 상태: Signal targets %d개, 대화형 %d개, 보고 전용 %d개. Webhook 공개 수신 endpoint는 닫힘.", total, interactive, oneWay)
	}
	return []string{
		current,
		"변경 내용: `/argos/webhook/events` 수신기를 열되 기본 동작은 수신 기록 저장과 승인 초안 생성입니다. execute=false가 기본입니다.",
		"되돌리는 방법: webhook receiver와 public route를 닫고 `웹훅 상태`에서 Webhook 상태: 닫힘을 확인합니다.",
		"확인할 결과: 서명 없는 요청은 거부되고, 정상 서명 요청도 메일 발송, 삭제, 결제, 예약 확정, 서버 조치를 바로 실행하지 않아야 합니다.",
	}
}

func assistantSignalChannelCounts() (int, int, int) {
	store, err := ListTargets()
	if err != nil {
		return 0, 0, 0
	}
	interactive := 0
	oneWay := 0
	for _, target := range store.Targets {
		if OneWayReportTarget(target) {
			oneWay++
		} else if isInteractiveTargetMode(target.Mode) {
			interactive++
		}
	}
	return len(store.Targets), interactive, oneWay
}

func assistantScheduledDeliveryJobByID(id string) (ScheduledDeliveryJob, bool) {
	id = strings.TrimSpace(id)
	if id == "" {
		return ScheduledDeliveryJob{}, false
	}
	store, err := LoadScheduledDeliveryStore()
	if err != nil {
		return ScheduledDeliveryJob{}, false
	}
	for _, job := range store.Jobs {
		if strings.EqualFold(strings.TrimSpace(job.ID), id) {
			return job, true
		}
	}
	return ScheduledDeliveryJob{}, false
}

func assistantApprovalDraftScheduledDeliveryState(job ScheduledDeliveryJob) string {
	target := firstNonEmpty(job.TargetLabel, job.TargetID, "대상 미정")
	status := assistantScheduledDeliveryStatusLabel(firstNonEmpty(job.Status, "registered"))
	method := assistantScheduledDeliveryMethodLabel(firstNonEmpty(job.Delivery, "signal"))
	last := "아직 실행 없음"
	if !job.LastRunAt.IsZero() {
		last = job.LastRunAt.Local().Format("01/02 15:04")
	}
	next := assistantScheduledDeliveryNextText(job, time.Now())
	return fmt.Sprintf("%s -> %s, 상태=%s, 방식=%s, 최근=%s, 다음=%s, 내용=%s.",
		firstNonEmpty(job.Schedule, "일정 미정"),
		target,
		status,
		method,
		last,
		next,
		trimSignalListLine(job.Content, 38),
	)
}

