func readAssistantScheduleStateSummary() (string, bool) {
	if live, ok := readAssistantScheduleLiveStatus(); ok {
		latestJob := ""
		var latest time.Time
		for _, job := range live.Jobs {
			if job.LastRun.After(latest) {
				latest = job.LastRun
				latestJob = job.ID
			}
		}
		summary := fmt.Sprintf("jobs=%d, due=%d, status=%s", len(live.Jobs), live.DueCount, firstNonEmpty(live.Status, "unknown"))
		if latestJob != "" && !latest.IsZero() {
			summary += fmt.Sprintf(", latest=%s at %s", assistantScheduleJobDisplayName(latestJob), latest.Local().Format("01/02 15:04"))
		}
		if live.NextDueJob != "" && !live.NextDue.IsZero() {
			summary += fmt.Sprintf(", next=%s at %s (%s)", assistantScheduleJobDisplayName(live.NextDueJob), live.NextDue.Local().Format("15:04"), assistantScheduleDueInText(time.Until(live.NextDue)))
		}
		return summary, true
	}
	path := strings.TrimSpace(os.Getenv("MESHCLAW_SCHEDULE_STATE"))
	if path == "" {
		home, err := os.UserHomeDir()
		if err != nil || home == "" {
			return "", false
		}
		path = filepath.Join(home, ".meshclaw", "schedule-state.json")
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return "", false
	}
	var state struct {
		LastRun map[string]time.Time `json:"last_run"`
	}
	if err := json.Unmarshal(data, &state); err != nil {
		return "state JSON 확인 필요", true
	}
	if len(state.LastRun) == 0 {
		return "기록된 실행 이력이 아직 없습니다.", true
	}
	latestJob := ""
	var latest time.Time
	for job, runAt := range state.LastRun {
		if runAt.After(latest) {
			latest = runAt
			latestJob = job
		}
	}
	if latestJob == "" || latest.IsZero() {
		return fmt.Sprintf("jobs=%d, 최근 실행 시간은 아직 없습니다.", len(state.LastRun)), true
	}
	now := time.Now().UTC()
	dueCount := assistantScheduleDueCount(state.LastRun, now)
	summary := fmt.Sprintf("jobs=%d, due=%d, latest=%s at %s", len(state.LastRun), dueCount, assistantScheduleJobDisplayName(latestJob), latest.Local().Format("01/02 15:04"))
	if nextJob, nextDue, ok := assistantNextScheduleDue(state.LastRun, now); ok {
		summary += fmt.Sprintf(", next=%s at %s (%s)", assistantScheduleJobDisplayName(nextJob), nextDue.Local().Format("15:04"), assistantScheduleDueInText(time.Until(nextDue)))
	}
	return summary, true
}

func assistantScheduleDueInText(d time.Duration) string {
	if d <= 0 {
		return "in now"
	}
	minutes := int(d.Round(time.Minute).Minutes())
	if minutes <= 0 {
		return "in <1m"
	}
	if minutes < 60 {
		return fmt.Sprintf("in %dm", minutes)
	}
	hours := minutes / 60
	rest := minutes % 60
	if rest == 0 {
		return fmt.Sprintf("in %dh", hours)
	}
	return fmt.Sprintf("in %dh%02dm", hours, rest)
}

func assistantNextScheduleDue(lastRun map[string]time.Time, now time.Time) (string, time.Time, bool) {
	nextJob := ""
	var nextDue time.Time
	for _, job := range assistantScheduleKnownJobs() {
		jobNextDue := assistantScheduleJobNextDue(job.ID, job.Interval, lastRun[job.ID], now)
		if jobNextDue.IsZero() {
			continue
		}
		if nextDue.IsZero() || jobNextDue.Before(nextDue) {
			nextJob = job.ID
			nextDue = jobNextDue
		}
	}
	return nextJob, nextDue, nextJob != "" && !nextDue.IsZero()
}

func assistantScheduleDueCount(lastRun map[string]time.Time, now time.Time) int {
	count := 0
	for _, job := range assistantScheduleKnownJobs() {
		next := assistantScheduleJobNextDue(job.ID, job.Interval, lastRun[job.ID], now)
		if next.IsZero() || !next.After(now) {
			count++
		}
	}
	return count
}

func assistantScheduleJobNextDue(id string, interval time.Duration, last, now time.Time) time.Time {
	if id == "local-ai-briefing" {
		next := time.Date(now.Year(), now.Month(), now.Day(), now.Hour(), 7, 0, 0, time.UTC)
		if next.Before(now) {
			next = next.Add(time.Hour)
		}
		if !last.IsZero() && !last.Before(next) {
			next = next.Add(time.Hour)
		}
		return next
	}
	if last.IsZero() {
		return now
	}
	next := last.Add(interval)
	if next.Before(now) {
		return now
	}
	return next
}

