func readAssistantDevWorkerSummary() (string, bool) {
	path := strings.TrimSpace(os.Getenv("MESHCLAW_DEV_WORKER_LATEST_JSON"))
	if path == "" {
		path = filepath.Join(".meshclaw-dev-loop", "dev-worker-latest.json")
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return "", false
	}
	var payload struct {
		OK                    bool                   `json:"ok"`
		StampUTC              string                 `json:"stamp_utc"`
		RawProfilelessMCP     map[string]interface{} `json:"raw_profileless_mcp"`
		LocalLiteSmoke        map[string]interface{} `json:"local_lite_smoke"`
		RawProfilelessMCPKill bool                   `json:"raw_profileless_mcp_kill_enabled"`
	}
	if err := json.Unmarshal(data, &payload); err != nil {
		return "latest JSON 확인 필요", true
	}
	status := "FAIL"
	if payload.OK {
		status = "PASS"
	}
	rawCount := intFromInterface(payload.RawProfilelessMCP["raw_profileless_mcp_count"])
	if after := intFromInterface(payload.RawProfilelessMCP["post_count"]); after >= 0 {
		rawCount = after
	}
	tools := intFromInterface(payload.LocalLiteSmoke["tool_count"])
	return fmt.Sprintf("%s at %s, raw MCP=%d, local-lite tools=%d", status, firstNonEmpty(payload.StampUTC, "-"), rawCount, tools), true
}

func intFromInterface(value interface{}) int {
	switch v := value.(type) {
	case int:
		return v
	case int64:
		return int(v)
	case float64:
		return int(v)
	case json.Number:
		n, _ := v.Int64()
		return int(n)
	default:
		return -1
	}
}

