func assistantCapabilitiesPersonalizationLines(locale string) []string {
	normalized := lang.Normalize(locale)
	var detail []string
	if memoryLine := assistantCapabilitiesMemoryLine(normalized); memoryLine != "" {
		detail = append(detail, lang.TF(locale, "assistant.capabilities.personalization_memory", memoryLine))
	}
	if skillLine := assistantCapabilitiesActiveSkillLine(normalized); skillLine != "" {
		detail = append(detail, lang.TF(locale, "assistant.capabilities.personalization_skill", skillLine))
	}
	if len(detail) == 0 {
		return nil
	}
	lines := []string{lang.TF(locale, "assistant.capabilities.personalization_title")}
	lines = append(lines, detail...)
	lines = append(lines, lang.TF(locale, "assistant.capabilities.personalization_boundary"))
	return lines
}

func assistantCapabilitiesMemoryLine(locale string) string {
	memoryContext, err := assistantprofile.LoadMemoryContext(time.Now().UTC(), "", 700)
	if err != nil || strings.TrimSpace(memoryContext.Text) == "" {
		return ""
	}
	excerpt := assistantFirstMemoryListItem(memoryContext.Text)
	if excerpt == "" {
		return ""
	}
	if locale == "en" && assistantCheckoutPrepContainsHangul(excerpt) {
		return ""
	}
	return trimSignalSelfTestDetail(excerpt, 120)
}

func assistantCapabilitiesActiveSkillLine(locale string) string {
	profile, err := assistantprofile.Inspect(time.Now().UTC(), "")
	if err != nil {
		return ""
	}
	for _, skill := range profile.Skills.Items {
		if skill.Activation != "active_policy_gated" {
			continue
		}
		name := strings.TrimSpace(firstNonEmpty(skill.Title, skill.Name))
		if name == "" {
			continue
		}
		if locale == "en" && assistantCheckoutPrepContainsHangul(name) {
			continue
		}
		return trimSignalSelfTestDetail(name, 80)
	}
	return ""
}

func isAssistantStarterRecommendationRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "", "요", "").Replace(lower)
	switch compact {
	case "뭐부터해볼까", "뭐부터하면돼", "뭐부터하면좋아", "뭐부터시켜", "뭘먼저할까", "뭘먼저하면돼",
		"다음은", "다음뭐하면좋아", "다음뭐하지", "추천해줘", "추천명령", "스타터", "스타터명령", "시작명령":
		return true
	}
	if containsAny(lower, "뭐부터", "뭘 먼저", "다음 뭐", "처음 뭐", "시작하려면") &&
		containsAny(lower, "해볼", "하면", "좋", "시켜", "추천", "하지") {
		return true
	}
	if containsAny(lower, "오늘 바로 테스트할 명령", "바로 테스트할 명령", "테스트할 명령 추천", "오늘 바로 해볼 명령") {
		return true
	}
	return containsAny(lower, "starter command", "starter commands", "what should i try first", "what should i do first")
}

