type assistantPersonalizationStyle struct {
	Excerpt         string
	QuietReportRoom bool
	HidePaths       bool
	Concise         bool
	ConclusionFirst bool
}

func assistantCurrentPersonalizationStyle(locale string) assistantPersonalizationStyle {
	memoryContext, err := assistantprofile.LoadMemoryContext(time.Now().UTC(), "", 900)
	if err != nil || strings.TrimSpace(memoryContext.Text) == "" {
		return assistantPersonalizationStyle{}
	}
	text := strings.TrimSpace(memoryContext.Text)
	lower := strings.ToLower(text)
	excerpt := assistantFirstMemoryListItem(text)
	if lang.Normalize(locale) == "en" && assistantCheckoutPrepContainsHangul(excerpt) {
		excerpt = ""
	}
	return assistantPersonalizationStyle{
		Excerpt: excerpt,
		QuietReportRoom: (containsAny(lower, "보고방", "브리핑방", "briefing room", "report room") &&
			containsAny(lower, "줄", "조용", "소음", "노이즈", "자주", "시끄", "quiet", "mute", "reduce", "noise", "too often")),
		HidePaths:       containsAny(lower, "경로", "파일 경로", "증거 경로", "path", "file path", "evidence path", "hide paths", "no paths"),
		Concise:         containsAny(lower, "짧게", "간단", "요약", "concise", "brief", "short"),
		ConclusionFirst: containsAny(lower, "결론부터", "결론 먼저", "conclusion first", "bottom line first"),
	}
}

func assistantFirstMemoryListItem(text string) string {
	for _, line := range strings.Split(text, "\n") {
		line = strings.TrimSpace(line)
		if !strings.HasPrefix(line, "- ") {
			continue
		}
		line = strings.TrimSpace(strings.TrimPrefix(line, "- "))
		if line == "" || strings.Contains(strings.ToLower(line), "no approved memory entries") {
			continue
		}
		if before, after, ok := strings.Cut(line, ": "); ok && regexp.MustCompile(`^\d{4}-\d{2}-\d{2}$`).MatchString(strings.TrimSpace(before)) {
			line = strings.TrimSpace(after)
		}
		if line != "" {
			return line
		}
	}
	return ""
}

