func assistantSkillMarketReply() string {
	t := lang.T
	profile, profileErr := assistantprofile.Inspect(time.Now().UTC(), "")
	lines := []string{t("assistant.skill_market.title")}
	if profileErr == nil {
		active := 0
		for _, item := range profile.Skills.Items {
			if item.Activation == "active_policy_gated" {
				active++
			}
		}
		lines = append(lines, t("assistant.skill_market.personal_status", profile.Skills.Count, active))
		if len(profile.Skills.Items) > 0 {
			lines = append(lines, assistantSkillMarketStatusLanes(profile.Skills.Items)...)
		}
	} else {
		lines = append(lines, t("assistant.skill_market.profile_fail", profileErr.Error()))
	}
	lines = append(lines,
		"",
		t("assistant.skill_market.quick_title"),
		t("assistant.skill_market.quick_next"),
		t("assistant.skill_market.quick_search"),
		"",
		t("assistant.skill_market.palette_title"),
	)
	for _, tmpl := range assistantprofile.SkillTemplates() {
		lines = append(lines, lang.TF(lang.Current(), "assistant.skill_market.palette_template", tmpl.ID, tmpl.ID, tmpl.ID))
	}
	if profileErr == nil && len(profile.Skills.Items) > 0 {
		lines = append(lines, t("assistant.skill_market.palette_installed_title"))
		for i, skill := range profile.Skills.Items {
			if i >= 4 {
				lines = append(lines, t("assistant.skill_market.installed_more", len(profile.Skills.Items)-i))
				break
			}
			name := firstNonEmpty(skill.Name, skill.Title)
			lines = append(lines, lang.TF(lang.Current(), "assistant.skill_market.palette_installed", name, name, name, name))
			lines = append(lines, lang.TF(lang.Current(), "assistant.skill_market.palette_revise", name))
			if skill.Activation == "active_policy_gated" {
				lines = append(lines, lang.TF(lang.Current(), "assistant.skill_market.palette_deactivate", name))
			} else {
				lines = append(lines, lang.TF(lang.Current(), "assistant.skill_market.palette_activate", name))
			}
		}
	}
	lines = append(lines,
		"",
		t("assistant.skill_market.templates"),
	)
	for _, tmpl := range assistantprofile.SkillTemplates() {
		lines = append(lines, t("assistant.skill_market.template_line", tmpl.ID, trimSignalSelfTestDetail(tmpl.Summary, 180)))
		lines = append(lines, t("assistant.skill_market.install", tmpl.ID))
		lines = append(lines, t("assistant.skill_market.detail", tmpl.ID))
		lines = append(lines, t("assistant.skill_market.test_after_install", tmpl.ID))
	}
	if profileErr == nil && len(profile.Skills.Items) > 0 {
		lines = append(lines, "", t("assistant.skill_market.installed"))
		for i, skill := range profile.Skills.Items {
			if i >= 4 {
				lines = append(lines, t("assistant.skill_market.installed_more", len(profile.Skills.Items)-i))
				break
			}
			name := firstNonEmpty(skill.Name, skill.Title)
			lines = append(lines, t("assistant.skill_market.installed_line", firstNonEmpty(skill.Title, skill.Name), skill.Status, skill.Activation))
			if updated := assistantSkillUpdatedAtText(skill.UpdatedAt); updated != "" {
				lines = append(lines, t("assistant.skill_market.updated", updated))
			}
			lines = append(lines, t("assistant.skill_search.detail", name))
			lines = append(lines, t("assistant.skill_search.test", name))
			lines = append(lines, t("assistant.skill_market.review", name))
			lines = append(lines, t("assistant.skill_market.revise", name))
			if skill.Activation == "active_policy_gated" {
				lines = append(lines, t("assistant.skill_detail.deactivate_command", name))
			} else {
				lines = append(lines, t("assistant.skill_detail.activate_command", name))
			}
		}
	}
	lines = append(lines,
		"",
		t("assistant.skill_market.one_approval"),
		t("assistant.skill_search.create"),
		t("assistant.skill_market.read_only"),
		t("assistant.skill_search.boundary"),
	)
	return strings.Join(lines, "\n")
}

func assistantSkillMarketStatusLanes(skills []assistantprofile.SkillInfo) []string {
	if len(skills) == 0 {
		return nil
	}
	locale := lang.Current()
	lines := []string{lang.TF(locale, "assistant.skill_market.status_lanes_title")}
	for i, skill := range skills {
		if i >= 3 {
			lines = append(lines, lang.TF(locale, "assistant.skill_market.status_lanes_more", len(skills)-i))
			break
		}
		name := firstNonEmpty(skill.Name, skill.Title)
		display := firstNonEmpty(skill.Title, skill.Name)
		switch {
		case skill.Activation == "active_policy_gated":
			lines = append(lines, lang.TF(locale, "assistant.skill_market.status_lane_active", display, name))
		case skill.Review == "reviewed" || strings.Contains(skill.Status, "reviewed"):
			lines = append(lines, lang.TF(locale, "assistant.skill_market.status_lane_reviewed", display, name))
		default:
			lines = append(lines, lang.TF(locale, "assistant.skill_market.status_lane_review_needed", display, name))
		}
	}
	return lines
}

func assistantSkillTestReply(text string) (string, bool) {
	t := lang.T
	query, ok := parseAssistantSkillTestRequest(text)
	if !ok {
		return "", false
	}
	report, err := assistantprofile.TestSkill(time.Now().UTC(), "", query)
	if err != nil {
		return lang.TF(lang.Current(), "assistant.skill_test.fail", err.Error()), true
	}
	if report.Status == "needs_skill" {
		return strings.Join([]string{
			t("assistant.skill_test.need_query"),
			t("assistant.skill_test.example"),
			t("assistant.skill_test.find_names"),
		}, "\n"), true
	}
	if report.Status == "not_found" {
		return strings.Join([]string{
			t("assistant.skill_test.not_found"),
			lang.TF(lang.Current(), "assistant.skill_test.request", strings.TrimSpace(query)),
			t("assistant.skill_test.install_hint"),
		}, "\n"), true
	}
	title := firstNonEmpty(report.Skill.Title, report.Skill.Name)
	lines := []string{
		t("assistant.skill_test.title"),
		lang.TF(lang.Current(), "assistant.skill_test.skill", title),
		lang.TF(lang.Current(), "assistant.skill_test.status", report.Skill.Status, report.Skill.Activation),
		lang.TF(lang.Current(), "assistant.skill_test.test_file", report.TestPath),
		"",
		t("assistant.skill_test.prompt_title"),
		"`" + trimSignalSelfTestDetail(report.Prompt, 360) + "`",
		"",
		t("assistant.skill_test.expected_title"),
	}
	for _, item := range report.Expected {
		lines = append(lines, "- "+item)
	}
	lines = append(lines, "", t("assistant.skill_test.safety_title"))
	for _, item := range report.Safety {
		lines = append(lines, "- "+item)
	}
	name := firstNonEmpty(report.Skill.Name, report.Skill.Title)
	if strings.TrimSpace(name) != "" {
		lines = append(lines,
			"",
			t("assistant.skill_test.next_title"),
			lang.TF(lang.Current(), "assistant.skill_test.detail_command", name),
			lang.TF(lang.Current(), "assistant.skill_test.review_command", name),
		)
		if report.Skill.Activation == "active_policy_gated" {
			lines = append(lines, lang.TF(lang.Current(), "assistant.skill_test.deactivate_command", name))
		} else {
			lines = append(lines, lang.TF(lang.Current(), "assistant.skill_test.activate_command", name))
		}
		lines = append(lines, t("assistant.skill_test.dry_run_command"))
	}
	lines = append(lines,
		"",
		t("assistant.skill_test.read_only"),
	)
	return strings.Join(lines, "\n"), true
}

func assistantSkillTestResultReviewReply(opts ListenOptions, text string) (string, bool) {
	query, result, ok := parseAssistantSkillTestResultReviewRequest(text)
	if !ok {
		return "", false
	}
	now := time.Now().UTC()
	t := lang.T
	if strings.TrimSpace(query) == "" || strings.TrimSpace(result) == "" {
		return strings.Join([]string{
			t("assistant.skill_test_result.need_result"),
			t("assistant.skill_test_result.example"),
			t("assistant.skill_test_result.read_only"),
		}, "\n"), true
	}
	report, err := assistantprofile.TestSkill(now, "", query)
	if err != nil {
		return lang.TF(lang.Current(), "assistant.skill_test.fail", err.Error()), true
	}
	if strings.TrimSpace(report.Skill.Name) == "" || report.Status == "not_found" || report.Status == "needs_skill" {
		return strings.Join([]string{
			t("assistant.skill_test.not_found"),
			lang.TF(lang.Current(), "assistant.skill_test.request", strings.TrimSpace(query)),
			t("assistant.skill_test.install_hint"),
			t("assistant.skill_test_result.read_only"),
		}, "\n"), true
	}
	name := firstNonEmpty(report.Skill.Name, report.Skill.Title)
	title := firstNonEmpty(report.Skill.Title, report.Skill.Name)
	lines := []string{
		t("assistant.skill_test_result.title"),
		lang.TF(lang.Current(), "assistant.skill_test.skill", title),
		lang.TF(lang.Current(), "assistant.skill_test.status", report.Skill.Status, report.Skill.Activation),
		"",
		t("assistant.skill_test_result.result_title"),
		"`" + trimSignalSelfTestDetail(result, 420) + "`",
		"",
		t("assistant.skill_test_result.expected_title"),
	}
	for _, item := range report.Expected {
		lines = append(lines, "- "+item)
	}
	lines = append(lines, "", t("assistant.skill_test_result.boundary_title"))
	executionClaim := skillTestResultClaimsIrreversibleExecution(result)
	activationPrepared := false
	if executionClaim {
		lines = append(lines, t("assistant.skill_test_result.boundary_warning"))
		lines = append(lines,
			t("assistant.skill_test_result.recommended_title"),
			lang.TF(lang.Current(), "assistant.skill_test_result.next_action_review", name),
			lang.TF(lang.Current(), "assistant.skill_test_result.next_action_revise", name),
		)
	} else {
		lines = append(lines, t("assistant.skill_test_result.boundary_ok"))
		if report.Skill.Activation != "active_policy_gated" {
			if plan, err := assistantprofile.SetSkillActivation(now, "", name, true, false); err == nil && plan.Status == "planned" && !plan.Rejected {
				rememberPendingAssistantSkillActivation(assistantSkillPendingKey(opts.TargetID), pendingAssistantSkillActivation{
					Query:     name,
					Active:    true,
					CreatedAt: now,
					ExpiresAt: now.Add(10 * time.Minute),
				})
				activationPrepared = true
				lines = append(lines,
					t("assistant.skill_test_result.activation_pending"),
					t("assistant.skill_test_result.recommended_title"),
					t("assistant.skill_test_result.next_action_approve"),
				)
			}
		}
	}
	lines = append(lines,
		"",
		t("assistant.skill_test.next_title"),
		lang.TF(lang.Current(), "assistant.skill_test.review_command", name),
	)
	if executionClaim {
		lines = append(lines, lang.TF(lang.Current(), "assistant.skill_test_result.next_action_revise", name))
	}
	if report.Skill.Activation == "active_policy_gated" {
		lines = append(lines, lang.TF(lang.Current(), "assistant.skill_test.deactivate_command", name))
	} else {
		lines = append(lines, lang.TF(lang.Current(), "assistant.skill_test.activate_command", name))
		if activationPrepared {
			lines = append(lines, t("assistant.skill_activation.active_approval"))
		}
	}
	lines = append(lines,
		"",
		t("assistant.skill_test_result.read_only"),
	)
	return strings.Join(lines, "\n"), true
}

func parseAssistantSkillTestResultReviewRequest(text string) (string, string, bool) {
	trimmed := strings.TrimSpace(text)
	if trimmed == "" {
		return "", "", false
	}
	lower := strings.ToLower(trimmed)
	markers := []string{
		"스킬 테스트 결과",
		"스킬 시험 결과",
		"스킬 검증 결과",
		"skill test result",
		"test result for skill",
		"skill validation result",
	}
	marker := ""
	for _, candidate := range markers {
		if strings.Contains(lower, candidate) {
			marker = candidate
			break
		}
	}
	if marker == "" {
		return "", "", false
	}
	queryAndResult := strings.TrimSpace(strings.Replace(strings.Replace(lower, marker, "", 1), "\t", " ", -1))
	if idx := strings.Index(lower, marker); idx >= 0 {
		queryAndResult = strings.TrimSpace(trimmed[:idx] + trimmed[idx+len(marker):])
	}
	queryAndResult = strings.Trim(queryAndResult, " .。-")
	if queryAndResult == "" {
		return "", "", true
	}
	for _, sep := range []string{":", "：", "\n"} {
		if before, after, ok := strings.Cut(queryAndResult, sep); ok {
			return strings.Trim(strings.Join(strings.Fields(before), " "), " .。:-"), strings.TrimSpace(after), true
		}
	}
	fields := strings.Fields(queryAndResult)
	if len(fields) < 2 {
		return strings.Trim(strings.Join(fields, " "), " .。:-"), "", true
	}
	return strings.Trim(strings.Join(fields[:1], " "), " .。:-"), strings.TrimSpace(strings.Join(fields[1:], " ")), true
}

func skillTestResultClaimsIrreversibleExecution(result string) bool {
	lower := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(result)), " "))
	return containsAny(lower,
		"발송했습니다", "보냈습니다", "메일 전송", "구매 완료", "주문 완료", "예약 완료", "결제 완료", "삭제했습니다",
		"sent the email", "email sent", "purchase completed", "order completed", "booking confirmed", "payment completed", "deleted",
	)
}

func parseAssistantSkillTestRequest(text string) (string, bool) {
	trimmed := strings.TrimSpace(text)
	if trimmed == "" {
		return "", false
	}
	lower := strings.ToLower(trimmed)
	if !containsAny(lower, "스킬 테스트", "스킬 검증", "스킬 시험", "test skill", "skill test", "validate skill") {
		return "", false
	}
	query := trimmed
	replacements := []string{"스킬 테스트", "스킬 검증", "스킬 시험", "test skill", "skill test", "validate skill"}
	for _, marker := range replacements {
		query = strings.ReplaceAll(query, marker, " ")
	}
	query = strings.Trim(strings.Join(strings.Fields(query), " "), " .。:：-")
	return query, true
}

func isAssistantSkillStatusRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(lower)
	if containsAny(lower, "skill status", "skills status", "capability status", "implemented skills", "implemented features") {
		return true
	}
	return containsAny(compact,
		"스킬현황", "스킬상태", "기능현황", "기능상태", "구현된기능", "구현기능",
		"기능몇개", "스킬몇개", "무엇이구현", "어디까지구현", "오픈클로처럼뭐됨",
	)
}

func assistantSkillStatusReply() string {
	scenarios := assistantcatalog.Catalog()
	statusCounts := map[string]int{}
	categoryCounts := map[string]map[string]int{}
	implementedExamples := map[string][]string{}
	for _, scenario := range scenarios {
		status := strings.TrimSpace(scenario.Status)
		if status == "" {
			status = "unknown"
		}
		statusCounts[status]++
		category := strings.TrimSpace(scenario.Category)
		if category == "" {
			category = "other"
		}
		if categoryCounts[category] == nil {
			categoryCounts[category] = map[string]int{}
		}
		categoryCounts[category][status]++
		if status == "implemented" && strings.TrimSpace(scenario.Example) != "" && len(implementedExamples[category]) < 2 {
			implementedExamples[category] = append(implementedExamples[category], strings.TrimSpace(scenario.Example))
		}
	}
	categories := make([]string, 0, len(categoryCounts))
	for category := range categoryCounts {
		categories = append(categories, category)
	}
	sort.Slice(categories, func(i, j int) bool {
		left := categoryCounts[categories[i]]["implemented"] + categoryCounts[categories[i]]["partial"]
		right := categoryCounts[categories[j]]["implemented"] + categoryCounts[categories[j]]["partial"]
		if left == right {
			return categories[i] < categories[j]
		}
		return left > right
	})
	profile, profileErr := assistantprofile.Inspect(time.Now().UTC(), "")
	lines := []string{
		"Argos 스킬 현황입니다.",
		fmt.Sprintf("전체 스킬/시나리오 %d개 중 지금 작동 가능한 것은 %d개입니다.", len(scenarios), statusCounts["implemented"]+statusCounts["partial"]),
		fmt.Sprintf("완성 %d개, 보강 중 %d개, 준비 중 %d개입니다.", statusCounts["implemented"], statusCounts["partial"], statusCounts["planned"]),
		"",
	}
	if profileErr == nil {
		active := 0
		reviewed := 0
		for _, item := range profile.Skills.Items {
			if item.Activation == "active_policy_gated" {
				active++
			}
			if item.Review == "reviewed" {
				reviewed++
			}
		}
		lines = append(lines, fmt.Sprintf("개인 스킬 마켓: %d개 등록, %d개 검토됨, %d개 활성.", profile.Skills.Count, reviewed, active))
		for i, item := range profile.Skills.Items {
			if i >= 3 {
				break
			}
			line := fmt.Sprintf("- %s: %s · %s", firstNonEmpty(item.Title, item.Name), item.Status, item.Activation)
			if updated := assistantSkillUpdatedAtText(item.UpdatedAt); updated != "" {
				line += " · " + lang.T("assistant.skill_status.updated_short", updated)
			}
			lines = append(lines, line)
		}
		lines = append(lines, "")
	}
	lines = append(lines, "Signal에서 바로 맡길 수 있는 묶음:")
	shownCategories := 0
	for _, category := range categories {
		counts := categoryCounts[category]
		active := counts["implemented"] + counts["partial"]
		if active == 0 {
			continue
		}
		label := assistantSkillCategoryLabel(category)
		line := fmt.Sprintf("- %s: 구현 %d, 부분 %d", label, counts["implemented"], counts["partial"])
		if examples := implementedExamples[category]; len(examples) > 0 {
			line += " 예: `" + strings.Join(examples, "`, `") + "`"
		}
		lines = append(lines, line)
		shownCategories++
		if shownCategories >= 7 {
			break
		}
	}
	lines = append(lines,
		"",
		"대표 결과물: 메일 요약/답장 초안, 회의록, 시장조사, PPTX, XLSX, 뉴스/날씨, 지도, TTS 음성, 운영 보고.",
		"위험 작업만 확인 후 실행합니다. 예: 실제 발송, 삭제, 결제, 예약 확정, 서버 재시작.",
	)
	return strings.Join(lines, "\n")
}

func assistantSkillUpdatedAtText(value time.Time) string {
	if value.IsZero() {
		return ""
	}
	return value.Local().Format("01/02 15:04")
}

func assistantSkillCategoryLabel(category string) string {
	switch category {
	case "daily":
		return "생활/브리핑"
	case "time":
		return "일정/할 일"
	case "mail":
		return "메일"
	case "research":
		return "뉴스/검색"
	case "maps":
		return "지도/장소"
	case "mac":
		return "Mac 제어"
	case "ops":
		return "서버/보안"
	case "voice":
		return "음성/TTS"
	case "contacts":
		return "연락처/메시지"
	case "shopping":
		return "쇼핑"
	case "files":
		return "파일/문서"
	case "identity":
		return "정체성/도움말"
	case "approval":
		return "승인"
	default:
		return category
	}
}

type assistantTodayBriefing struct {
	Generated time.Time
	Plan      bool
	Weather   string
	Agenda    assistantDailyAgendaData
	News      []string
	Notes     []string
}

func isAssistantTodayBriefingRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(lower)
	if containsAny(lower, "today briefing", "daily briefing", "morning briefing", "start my day", "what should i check today", "daily plan", "plan my day") {
		return true
	}
	if containsAny(lower, "하루 계획", "오늘 계획") && containsAny(lower, "일정", "할 일", "할일", "메일", "날씨", "뉴스") {
		return true
	}
	return containsAny(compact,
		"오늘뭐챙", "오늘챙길것", "오늘챙길거", "오늘뭘챙", "오늘무엇챙",
		"오늘봐야할것", "오늘봐야할거", "오늘할일일정메일뉴스", "오늘일정할일메일날씨", "오늘일정할일메일날씨하루계획", "오늘하루계획", "오늘브리핑", "하루계획으로묶",
		"아침브리핑", "모닝브리핑", "하루브리핑", "하루시작", "하루시작브리핑",
	)
}

func assistantTodayBriefingReply(opts ListenOptions, text string) string {
	brief := collectAssistantTodayBriefing(opts, text)
	return formatAssistantTodayBriefing(brief)
}

func collectAssistantTodayBriefing(opts ListenOptions, text string) assistantTodayBriefing {
	brief := assistantTodayBriefing{Generated: time.Now()}
	lower := strings.ToLower(strings.TrimSpace(text))
	brief.Plan = containsAny(lower, "하루 계획", "오늘 계획", "daily plan", "plan my day")
	if brief.Plan {
		ctx, cancel := context.WithTimeout(context.Background(), 12*time.Second)
		defer cancel()
		brief.Agenda = collectAssistantDailyAgendaData(ctx, text)
	}
	if !assistantTrueEnv("MESHCLAW_ASSISTANT_TODAY_BRIEFING_NO_FETCH") {
		ctx, cancel := context.WithTimeout(context.Background(), 4*time.Second)
		defer cancel()
		location := resolveWeatherLocation(ctx, opts, text)
		weather := assistantbrief.WeatherNow(ctx, assistantbrief.Options{Location: location})
		if weather.Weather != nil {
			brief.Weather = formatAssistantTodayWeatherLine(*weather.Weather)
		} else if len(weather.Errors) > 0 {
			brief.Notes = append(brief.Notes, "날씨 확인이 지연됐습니다. `지금 날씨 어때?`로 다시 확인할 수 있습니다.")
		}
	}
	if news, _, ok := assistantbrief.RecentNews(6 * time.Hour); ok {
		for i, item := range news.News {
			if i >= 3 {
				break
			}
			title := strings.TrimSpace(item.Title)
			if title == "" {
				continue
			}
			source := cleanVoiceNewsSource(firstNonEmpty(item.FeedTitle, item.FeedID))
			if source != "" {
				title += " (" + source + ")"
			}
			brief.News = append(brief.News, title)
		}
	}
	return brief
}

func assistantTrueEnv(name string) bool {
	switch strings.ToLower(strings.TrimSpace(os.Getenv(name))) {
	case "1", "true", "yes", "on":
		return true
	default:
		return false
	}
}

func formatAssistantTodayWeatherLine(weather assistantbrief.Weather) string {
	parts := []string{}
	if weather.Location != "" {
		parts = append(parts, weather.Location)
	}
	if weather.Condition != "" {
		parts = append(parts, weather.Condition)
	}
	if weather.TempC != "" {
		parts = append(parts, weather.TempC+"도")
	}
	if weather.FeelsLikeC != "" && weather.FeelsLikeC != weather.TempC {
		parts = append(parts, "체감 "+weather.FeelsLikeC+"도")
	}
	if weather.PrecipMM != "" {
		parts = append(parts, "강수 "+weather.PrecipMM+"mm")
	}
	if len(parts) == 0 {
		return ""
	}
	return strings.Join(parts, ", ")
}

func formatAssistantTodayBriefing(brief assistantTodayBriefing) string {
	lines := []string{"오늘 챙길 것 요약입니다."}
	if brief.Plan {
		return formatAssistantTodayPlanCard(brief)
	}
	if !brief.Generated.IsZero() {
		lines = append(lines, "기준: "+brief.Generated.In(time.Local).Format("15:04"))
	}
	lines = append(lines, "")
	if brief.Weather != "" {
		lines = append(lines, "날씨: "+brief.Weather)
	} else {
		lines = append(lines, "날씨: 바로 확인하려면 `지금 날씨 어때?`라고 보내세요.")
	}
	lines = append(lines,
		"일정: `오늘 일정 뭐 있어?`라고 보내면 Calendar를 읽어 정리합니다.",
		"할 일: `오늘 할 일 뭐 있어?`라고 보내면 Reminders를 읽어 정리합니다.",
		"메일: `최근 메일 요약해줘`라고 보내면 중요한 메일을 먼저 추립니다.",
	)
	if len(brief.News) > 0 {
		lines = append(lines, "뉴스: 최근 수집 기준으로 볼 만한 흐름입니다.")
		for i, item := range brief.News {
			lines = append(lines, fmt.Sprintf("%d. %s", i+1, item))
		}
	} else {
		lines = append(lines, "뉴스: `오늘 주요뉴스 알려줘`라고 보내면 최신 기사 기준으로 새로 정리합니다.")
	}
	if len(brief.Notes) > 0 {
		lines = append(lines, "")
		lines = append(lines, brief.Notes...)
	}
	lines = append(lines, "", "이 요약은 읽기 전용입니다. 삭제, 결제, 메일/Signal 발송, 서버 재시작은 하지 않았습니다.")
	return strings.Join(lines, "\n")
}

func formatAssistantTodayPlanCard(brief assistantTodayBriefing) string {
	data := brief.Agenda
	lines := []string{
		"오늘 하루 계획 요약입니다.",
		"일정, 할 일, 메일, 날씨를 한 카드로 묶었습니다.",
	}
	if !brief.Generated.IsZero() {
		lines = append(lines, "기준: "+brief.Generated.In(time.Local).Format("15:04"))
	}
	lines = append(lines, "")
	lines = append(lines, "날씨: "+assistantTodayPlanWeatherLine(brief))
	lines = append(lines, "일정: "+assistantTodayPlanEventsLine(data))
	lines = append(lines, "할 일: "+assistantTodayPlanTasksLine(data))
	lines = append(lines, "메일: "+assistantTodayPlanMailLine(data))
	lines = append(lines, "뉴스: "+assistantTodayPlanNewsLine(brief))
	lines = append(lines, "", "추천 순서:")
	lines = append(lines, assistantTodayPlanPriorityLines(data)...)
	lines = append(lines,
		"",
		"다음 행동: `가장 중요한 3개만 오전/오후로 다시 배치해줘`",
		"이 요약은 읽기 전용입니다. 일정 수정, 할 일 완료, 메일/Signal 발송, 삭제, 결제는 하지 않았습니다.",
	)
	if len(brief.Notes) > 0 {
		lines = append(lines, "")
		lines = append(lines, brief.Notes...)
	}
	return strings.Join(compactBlankLines(lines), "\n")
}

func assistantTodayPlanWeatherLine(brief assistantTodayBriefing) string {
	if strings.TrimSpace(brief.Weather) != "" {
		return brief.Weather
	}
	return "지금 확인하지 못했습니다. `지금 날씨 어때?`로 다시 확인할 수 있습니다."
}

func assistantTodayPlanEventsLine(data assistantDailyAgendaData) string {
	if len(data.Events) > 0 {
		return assistantDailyAgendaEventLine(data.Events[0])
	}
	if strings.TrimSpace(data.CalendarResult.Error) != "" {
		return "Calendar를 지금 읽을 수 없습니다. `오늘 일정 뭐 있어?`로 다시 확인하세요."
	}
	return "확인된 일정이 없습니다. Calendar 연결 전이면 `오늘 일정 뭐 있어?`로 따로 조회하세요."
}

func assistantTodayPlanTasksLine(data assistantDailyAgendaData) string {
	if len(data.Reminders) > 0 {
		return assistantDailyAgendaReminderLine(data.Reminders[0])
	}
	if strings.TrimSpace(data.ReminderResult.Error) != "" {
		return "Reminders를 지금 읽을 수 없습니다. `오늘 할 일 뭐 있어?`로 다시 확인하세요."
	}
	return "확인된 할 일이 없습니다. Reminders 연결 전이면 `오늘 할 일 뭐 있어?`로 따로 조회하세요."
}

func assistantTodayPlanMailLine(data assistantDailyAgendaData) string {
	if mailItem, ok := assistantDailyAgendaFirstMailItem(data.MailItems); ok {
		return assistantDailyAgendaMailLine(mailItem)
	}
	if len(data.MailErrors) > 0 {
		return "확인할 메일 계정을 찾지 못했거나 읽기에 실패했습니다. `최근 메일 요약해줘`로 계정 상태를 먼저 확인하세요."
	}
	if data.MailRequested {
		return "오늘 바로 처리할 메일 후보가 없습니다."
	}
	return "`최근 메일 요약해줘`라고 보내면 중요한 메일을 먼저 추립니다."
}

func assistantTodayPlanNewsLine(brief assistantTodayBriefing) string {
	if len(brief.News) > 0 {
		return brief.News[0]
	}
	return "`오늘 주요뉴스 알려줘`라고 보내면 최신 기사 기준으로 새로 정리합니다."
}

func assistantTodayPlanPriorityLines(data assistantDailyAgendaData) []string {
	lines := []string{}
	if len(data.Events) > 0 {
		lines = append(lines, "1. 고정 일정 보호: "+assistantDailyAgendaEventLine(data.Events[0]))
	}
	if len(data.Reminders) > 0 {
		lines = append(lines, fmt.Sprintf("%d. 먼저 끝낼 할 일: %s", len(lines)+1, assistantDailyAgendaReminderLine(data.Reminders[0])))
	}
	if mailItem, ok := assistantDailyAgendaFirstMailItem(data.MailItems); ok {
		lines = append(lines, fmt.Sprintf("%d. 짧은 메일 처리 블록: %s", len(lines)+1, assistantDailyAgendaMailLine(mailItem)))
	}
	if len(lines) == 0 {
		lines = append(lines, "1. 오전에는 가장 중요한 일 1개를 먼저 정하고, 오후에는 메일/정리 시간을 따로 두세요.")
	}
	return lines
}

func assistantRequiredToolFallbackReply(opts ListenOptions, text string) (string, bool) {
	if !assistantRequiresToolCall(text) {
		return "", false
	}
	lower := strings.ToLower(strings.TrimSpace(text))
	title := inferredArtifactTitle(text)
	body := strings.TrimSpace(text)
	switch {
	case looksLikeAssistantScheduledDeliveryRequest(lower):
		args := map[string]interface{}{
			"content": firstNonEmpty(inferAssistantScheduledDeliveryContent(text), body),
		}
		if target := inferAssistantSignalTargetRef(text); target != "" {
			args["target"] = target
		}
		if schedule := inferAssistantScheduledDeliverySchedule(text); schedule != "" {
			args["schedule"] = schedule
		}
		argsJSON, _ := json.Marshal(args)
		return executeAssistantToolCall(opts, text, "scheduled_delivery_plan", string(argsJSON)), true
	case looksLikeMeetingMaterialsRequest(lower) && !looksLikeMarketResearchReportRequest(lower):
		args := map[string]interface{}{
			"title":       firstNonEmpty(title, "회의 자료"),
			"body":        body,
			"audience":    "",
			"slide_count": inferSlideCount(text, 6),
		}
		if target := inferAssistantSignalTargetRef(text); target != "" {
			args["target"] = target
		}
		argsJSON, _ := json.Marshal(args)
		return executeAssistantToolCall(opts, text, "prepare_meeting_materials", string(argsJSON)), true
	case shouldRouteAsMeetingMinutes(lower):
		args := map[string]interface{}{
			"title": firstNonEmpty(title, "Argos 회의록"),
			"body":  meetingMinutesDocumentBody(text, firstNonEmpty(title, "Argos 회의록")),
		}
		if target := inferAssistantSignalTargetRef(text); target != "" {
			args["target"] = target
		}
		argsJSON, _ := json.Marshal(args)
		return executeAssistantToolCall(opts, text, "create_document", string(argsJSON)), true
	case looksLikeMarketResearchReportRequest(lower):
		query := assistantMarketResearchQuery(text)
		report := assistantMarketResearchReport(context.Background(), query)
		reportTitle := assistantMarketResearchTitle(text, query)
		reportBody := assistantMarketResearchReportBody(text, query, report)
		if containsAny(lower, "화학회사", "화학 회사", "화학업계", "화학 업계", "chemical company", "chemical industry") {
			reportTitle = "화학회사 민감 뉴스 분석 보고서"
			reportBody = assistantChemicalNewsReportBody(query, report)
		}
		toolName := "create_document"
		if wantsResearchPresentationPackage(lower) {
			toolName = "prepare_meeting_materials"
			reportTitle = assistantResearchMeetingMaterialsTitle(reportTitle)
		}
		args := map[string]interface{}{
			"title": reportTitle,
			"body":  reportBody,
		}
		if toolName == "prepare_meeting_materials" {
			args["audience"] = ""
			args["slide_count"] = inferSlideCount(text, 6)
		}
		if target := inferAssistantSignalTargetRef(text); target != "" {
			args["target"] = target
		}
		argsJSON, _ := json.Marshal(args)
		return executeAssistantToolCall(opts, text, toolName, string(argsJSON)), true
	case containsAny(lower, "발표자료", "발표 자료", "슬라이드", "ppt", "pptx", "deck", "presentation"):
		args, _ := json.Marshal(map[string]interface{}{
			"title":       firstNonEmpty(title, "Argos 발표자료"),
			"body":        body,
			"audience":    "",
			"slide_count": inferSlideCount(text, 6),
		})
		return executeAssistantToolCall(opts, text, "create_presentation", string(args)), true
	case looksLikeMailSpreadsheetArtifactRequest(lower):
		query, ok := extractSignalMailSearchQuery(text)
		if !ok || strings.TrimSpace(query) == "" {
			return "어떤 메일을 표로 정리할까요? 예: `메일에서 Google Workspace 찾아서 엑셀 표로 정리해줘`", true
		}
		return createMailSearchSpreadsheetArtifact(opts, text, query), true
	case looksLikeBrowserSpreadsheetArtifactRequest(lower):
		query, ok := extractBrowserSearchSpreadsheetQuery(text)
		if !ok || strings.TrimSpace(query) == "" {
			return "어떤 웹 검색 결과를 표로 정리할까요? 예: `브라우저로 Argos 검색해서 엑셀 표로 정리해줘`", true
		}
		return createBrowserSearchSpreadsheetArtifact(opts, text, query), true
	case looksLikeBrowserReportArtifactRequest(lower):
		query, ok := extractBrowserSearchReportQuery(text)
		if !ok || strings.TrimSpace(query) == "" {
			return "어떤 주제를 검색해서 보고서로 정리할까요? 예: `브라우저로 Argos 검색해서 보고서로 정리해줘`", true
		}
		reply, handled := runSignalArgosAction(opts, query+" 웹에서 검색해줘", 0)
		if !handled {
			return "브라우저 검색 보고서를 만들지 못했습니다.", true
		}
		return reply, true
	case looksLikeSpreadsheetArtifactRequest(lower):
		args, _ := json.Marshal(map[string]interface{}{
			"title": firstNonEmpty(title, "Argos 표"),
			"body":  body,
		})
		return executeAssistantToolCall(opts, text, "create_spreadsheet", string(args)), true
	default:
		args, _ := json.Marshal(map[string]interface{}{
			"title": firstNonEmpty(title, "Argos 문서"),
			"body":  body,
		})
		return executeAssistantToolCall(opts, text, "create_document", string(args)), true
	}
}

func looksLikeMeetingMinutesRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	return containsAny(lower, "회의록", "회의 기록", "회의 메모", "회의메모", "회의 노트", "회의노트", "미팅 기록", "미팅 노트", "meeting minutes", "meeting notes", "minutes")
}

func shouldRouteAsMeetingMinutes(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if !looksLikeMeetingMinutesRequest(lower) {
		return false
	}
	if containsAny(lower, "결정:", "결정：", "결정사항", "할 일:", "할일:", "액션:", "액션아이템", "리스크:", "위험:", "action:", "action item", "risk:") &&
		containsAny(lower, "회의록", "회의 메모", "회의메모", "회의 노트", "회의노트", "meeting minutes", "meeting notes") {
		return true
	}
	if containsAny(lower, "회의자료 패키지", "회의 자료 패키지", "회의용 자료", "회의자료", "회의 자료") &&
		containsAny(lower, "ppt", "pptx", "발표자료", "발표 자료", "슬라이드", "deck", "presentation", "패키지") {
		return false
	}
	if containsAny(lower,
		"회의록을 작성", "회의록 작성", "회의록을 만들어", "회의록 만들어", "회의록을 써", "회의록 써",
		"회의 기록", "미팅 기록", "meeting minutes", "minutes",
	) {
		return true
	}
	return !looksLikeMeetingMaterialsRequest(lower) && !looksLikeMarketResearchReportRequest(lower)
}

func looksLikeMeetingMaterialsRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	if containsAny(lower, "회의 자료", "회의자료", "회의용", "미팅 자료", "meeting material", "meeting materials") {
		return true
	}
	if containsAny(lower, "ppt", "pptx", "발표자료", "발표 자료", "슬라이드", "deck", "presentation") &&
		containsAny(lower, "회의", "미팅", "meeting") &&
		containsAny(lower, "문서", "브리프", "요약", "패키지", "자료") {
		return true
	}
	return false
}

func looksLikeMarketResearchReportRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	if looksLikeSpreadsheetArtifactRequest(lower) {
		return false
	}
	if containsAny(lower, "시장조사", "시장 조사", "market research", "research report", "리서치 보고", "산업 조사", "시장 분석", "경쟁사 조사") {
		return true
	}
	if containsAny(lower, "뉴스 분석", "이슈 분석", "회의 토픽", "중요 토픽", "민감 뉴스") &&
		containsAny(lower, "보고서", "리포트", "문서", "작성", "정리", "보내", "회의", "토픽") {
		return true
	}
	if containsAny(lower, "시장 이슈", "산업 이슈", "민감하게 반응", "내일 회의", "회의에서 사용할") &&
		containsAny(lower, "뉴스", "시장", "산업", "화학", "경쟁") &&
		containsAny(lower, "분석", "보고서", "리포트", "토픽", "질문", "정리", "작성") {
		return true
	}
	return false
}

func wantsResearchPresentationPackage(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	if containsAny(lower, "ppt", "pptx", "발표자료", "발표 자료", "슬라이드", "deck", "presentation") {
		return true
	}
	if containsAny(lower, "회의자료", "회의 자료", "회의용", "미팅 자료", "meeting material", "meeting materials") {
		return true
	}
	return containsAny(lower, "회의에서 사용할", "회의에서 쓸", "회의에 쓸", "회의 안건", "회의 토픽") &&
		containsAny(lower, "자료", "패키지", "발표", "슬라이드", "ppt", "deck")
}

func assistantResearchMeetingMaterialsTitle(title string) string {
	title = strings.TrimSpace(title)
	if title == "" {
		return "Argos 시장조사 회의자료"
	}
	for _, suffix := range []string{" 보고서", " 리포트", " 문서"} {
		if strings.HasSuffix(title, suffix) {
			return strings.TrimSpace(strings.TrimSuffix(title, suffix)) + " 회의자료"
		}
	}
	return title + " 회의자료"
}

func assistantCalendarListEarlyReply(opts ListenOptions, text string) (string, bool) {
	action := osauto.ClassifyArgosAction(text)
	if action.Action != "calendar_events_list" {
		return "", false
	}
	return runSignalArgosAction(opts, text, 0)
}

func inferAssistantScheduledDeliverySchedule(text string) string {
	lower := strings.TrimSpace(strings.ToLower(text))
	if lower == "" {
		return ""
	}
	normalized := strings.NewReplacer(
		"내주 ", "매주 ",
		"내주", "매주",
		"금주 ", "매주 ",
		"다음 주 ", "매주 ",
		"다음주 ", "매주 ",
		"화욜", "화요일",
		"수욜", "수요일",
		"목욜", "목요일",
		"금욜", "금요일",
		"토욜", "토요일",
		"일욜", "일요일",
		"월욜", "월요일",
	).Replace(lower)
	lower = normalized
	markerPatterns := []string{"에게", "한테", "에게로", "한테로", "에", "로", "으로", "로써", "로서"}
	timeSuffixes := []string{"시", "분", "시에", "시쯤"}
	actionVerbs := []string{
		"보내줘", "보내", "전송해줘", "전송", "공유해줘", "공유", "알려줘", "알려", "알림줘", "알림해줘", "알림해", "알림", "알람해줘", "알람해", "알람", "전달해줘", "전달",
	}

	for _, verb := range actionVerbs {
		if idx := strings.Index(lower, verb); idx > 0 {
			lower = strings.TrimSpace(lower[:idx])
			break
		}
	}

	trimSuffix := func(value string) string {
		value = strings.TrimSpace(value)
		if value == "" {
			return value
		}
		value = strings.TrimSuffix(value, "하고")
		value = strings.TrimSuffix(value, "로")
		value = strings.TrimSuffix(value, "으로")
		return strings.TrimSpace(value)
	}

	for _, marker := range markerPatterns {
		idx := strings.LastIndex(lower, marker)
		if idx <= 0 {
			continue
		}
		candidate := strings.TrimSpace(lower[:idx])
		if candidate == "" {
			continue
		}
		if !containsAny(candidate, "매일", "매주", "매월", "매년", "매분", "아침마다", "저녁마다", "정기적으로", "정기", "주기적으로", "주기") {
			continue
		}
		timeIdx := -1
		for _, suffix := range timeSuffixes {
			if v := strings.LastIndex(candidate, suffix); v >= 0 {
				timeIdx = v + len(suffix)
				if suffix == "분" {
					timeIdx = v + len(suffix)
				}
			}
		}
		if timeIdx > 0 {
			return trimSuffix(candidate[:timeIdx])
		}
		return trimSuffix(candidate)
	}

	for _, marker := range markerPatterns {
		if idx := strings.Index(lower, marker); idx > 0 {
			candidate := strings.TrimSpace(lower[:idx])
			if candidate != "" && containsAny(candidate, "매일", "매주", "매월", "매년", "매분", "아침마다", "저녁마다", "정기", "정기적으로", "주기적으로", "주기") {
				return strings.TrimSpace(candidate)
			}
		}
	}
	re := regexp.MustCompile(`(?i)(매일|매주|매월|매년|매분|아침마다|저녁마다|정기적으로|정기|주기적으로|주기)[가-힣a-z0-9\\s,:-]+`)
	candidate := strings.TrimSpace(re.FindString(lower))
	if candidate == "" {
		return ""
	}
	return strings.TrimSpace(candidate)
}

func inferAssistantScheduledDeliveryContent(text string) string {
	lower := strings.TrimSpace(strings.ToLower(text))
	if lower == "" {
		return ""
	}
	trimDeliveryAction := func(value string) string {
		value = strings.TrimSpace(value)
		for _, suffix := range []string{
			"보내줘", "보내", "전송해줘", "전송", "발송해줘", "발송", "알려줘", "알려", "공유해줘", "공유", "전달해줘", "전달", "요",
		} {
			value = strings.TrimSpace(strings.TrimSuffix(value, suffix))
		}
		return strings.TrimSpace(value)
	}
	if strings.HasPrefix(lower, "내게 ") {
		return trimDeliveryAction(strings.TrimPrefix(lower, "내게 "))
	}
	if idx := strings.Index(lower, "내게 "); idx >= 0 {
		candidate := strings.TrimSpace(lower[idx+len("내게"):])
		if strings.HasPrefix(candidate, " ") {
			candidate = strings.TrimSpace(candidate)
		}
		return trimDeliveryAction(candidate)
	}
	for _, marker := range []string{
		"보고방에", "보고 방에", "브리핑방에", "브리핑 방에", "비서방에", "비서 방에",
		"보고방으로", "보고 방으로", "브리핑방으로", "브리핑 방으로", "비서방으로", "비서 방으로",
		"to report room", "to briefing room", "to assistant room",
	} {
		if idx := strings.Index(lower, marker); idx >= 0 {
			candidate := strings.TrimSpace(lower[idx+len(marker):])
			if candidate != "" {
				return trimDeliveryAction(candidate)
			}
		}
	}
	for _, marker := range []string{"에게", "한테", "에게로", "한테로", "으로", "로"} {
		if idx := strings.Index(lower, marker); idx > 0 {
			rest := strings.TrimSpace(lower[idx+len(marker):])
			if rest == "" {
				break
			}
			return trimDeliveryAction(rest)
		}
	}
	return strings.TrimSpace(lower)
}

func looksLikeMailSpreadsheetArtifactRequest(lower string) bool {
	if !containsAny(lower, "메일", "email", "mail", "이메일") {
		return false
	}
	if !looksLikeSpreadsheetArtifactRequest(lower) {
		return false
	}
	return containsAny(lower, "찾아", "검색", "최근", "요약", "정리", "find", "search", "summary")
}

func looksLikeBrowserSpreadsheetArtifactRequest(lower string) bool {
	if !containsAny(lower, "브라우저", "웹", "web", "browser") {
		return false
	}
	if !containsAny(lower, "검색", "찾아", "search", "find") {
		return false
	}
	if !looksLikeSpreadsheetArtifactRequest(lower) {
		return false
	}
	return containsAny(lower, "결과", "표로", "정리", "spreadsheet", "xlsx", "csv", "엑셀")
}

func looksLikeBrowserReportArtifactRequest(lower string) bool {
	if looksLikeBrowserSpreadsheetArtifactRequest(lower) {
		return false
	}
	if !containsAny(lower, "브라우저", "웹", "web", "browser") {
		return false
	}
	if !containsAny(lower, "검색", "찾아", "search", "find", "리서치", "research") {
		return false
	}
	return containsAny(lower, "보고서", "리포트", "문서", "출처", "원문", "요약", "정리", "report", "source", "document", "summary")
}

func assistantRecentArtifactFallbackReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" || (!containsAny(lower, "방금", "최근", "아까", "그 문서", "그 파일", "그 ppt", "그 발표", "last", "recent") && !looksLikeRecentSpreadsheetFollowUp(lower)) {
		return "", false
	}
	switch {
	case containsAny(lower, "pdf", "docx", "xlsx", "csv", "excel", "numbers", "export", "내보내", "변환"):
		format := "pdf"
		if containsAny(lower, "csv") {
			format = "csv"
		} else if containsAny(lower, "xlsx", "excel", "numbers", "엑셀") {
			format = "xlsx"
		} else if !containsAny(lower, "pdf") && containsAny(lower, "docx", "word") {
			format = "docx"
		}
		args, _ := json.Marshal(map[string]interface{}{"format": format, "target": inferredRecentArtifactTarget(text)})
		return executeAssistantToolCall(opts, text, "export_recent_artifact", string(args)), true
	case containsAny(lower, "다시 보내", "다시보내", "첨부", "파일 보내", "send again", "resend"):
		target := inferredRecentArtifactTarget(text)
		if target == "auto" {
			target = "all"
		}
		args, _ := json.Marshal(map[string]interface{}{"target": target})
		return executeAssistantToolCall(opts, text, "resend_recent_artifact", string(args)), true
	case containsAny(lower, "열어", "열어줘", "open", "obsidian", "pages", "word", "powerpoint", "keynote", "preview", "numbers", "excel", "엑셀"):
		args, _ := json.Marshal(map[string]interface{}{
			"app":    inferredRecentArtifactApp(text),
			"target": inferredRecentArtifactTarget(text),
		})
		return executeAssistantToolCall(opts, text, "open_recent_artifact", string(args)), true
	case containsAny(lower, "수정", "고쳐", "바꿔", "변경", "적어", "기록", "써", "삭제", "지워", "줄여", "늘려", "추가", "빼", "다듬", "짧게", "길게", "edit", "revise", "update", "delete", "remove"):
		args, _ := json.Marshal(map[string]interface{}{
			"instruction": text,
			"target":      inferredRecentArtifactTarget(text),
			"slide_count": inferSlideCount(text, 0),
		})
		return executeAssistantToolCall(opts, text, "revise_recent_artifact", string(args)), true
	default:
		return "", false
	}
}

func looksLikeRecentSpreadsheetFollowUp(lower string) bool {
	if !containsAny(lower, "다시 보내", "다시보내", "첨부", "보내줘", "열어", "open", "수정", "고쳐", "바꿔", "변경", "적어", "기록", "써", "삭제", "지워", "빼", "update", "edit", "delete", "remove") {
		return false
	}
	return containsAny(lower, "csv", "xlsx", "excel", "numbers", "엑셀", "스프레드시트", "예산표", "비용표", "비용", "예산", "청구서", "인보이스", "트래커", "체크리스트", "항목", "작업", "상태", "담당", "마감", "다음 액션", "다음", "메모", "수량", "단가", "금액", "서비스/제품")
}

func inferredRecentArtifactTarget(text string) string {
	lower := strings.ToLower(strings.TrimSpace(text))
	switch {
	case containsAny(lower, "ppt", "pptx", "발표", "슬라이드", "powerpoint", "keynote", "deck"):
		return "presentation"
	case containsAny(lower, "csv"):
		return "csv"
	case containsAny(lower, "xlsx"):
		return "xlsx"
	case containsAny(lower, "엑셀", "스프레드시트", "spreadsheet", "sheet", "excel", "numbers", "표", "예산표", "비용표", "청구서", "인보이스", "트래커", "체크리스트"):
		return "spreadsheet"
	case containsAny(lower, "문서", "브리프", "보고서", "doc", "docx", "word", "pages", "obsidian", "markdown"):
		return "document"
	default:
		return "auto"
	}
}

func inferredRecentArtifactApp(text string) string {
	lower := strings.ToLower(strings.TrimSpace(text))
	switch {
	case strings.Contains(lower, "obsidian"):
		return "Obsidian"
	case strings.Contains(lower, "pages"):
		return "Pages"
	case strings.Contains(lower, "word"):
		return "Microsoft Word"
	case strings.Contains(lower, "numbers") || strings.Contains(lower, "엑셀"):
		return "Numbers"
	case strings.Contains(lower, "excel"):
		return "Microsoft Excel"
	case strings.Contains(lower, "powerpoint"):
		return "Microsoft PowerPoint"
	case strings.Contains(lower, "keynote"):
		return "Keynote"
	case strings.Contains(lower, "preview"):
		return "Preview"
	default:
		return ""
	}
}

func inferredArtifactTitle(text string) string {
	lower := strings.ToLower(strings.TrimSpace(text))
	switch {
	case containsAny(lower, "회의록", "meeting minutes", "minutes"):
		return "Argos 회의록"
	case containsAny(lower, "내일", "tomorrow") && containsAny(lower, "회의", "meeting"):
		return "내일 회의 자료"
	case containsAny(lower, "회의", "meeting"):
		return "회의 자료"
	case containsAny(lower, "보고서", "리포트", "report"):
		return "Argos 보고서"
	case containsAny(lower, "발표", "ppt", "presentation"):
		return "Argos 발표자료"
	case containsAny(lower, "예산표", "budget"):
		return "Argos 예산표"
	case containsAny(lower, "청구서", "인보이스", "invoice"):
		return "Argos 청구서"
	case containsAny(lower, "트래커", "tracker", "체크리스트"):
		return "Argos 트래커"
	case containsAny(lower, "엑셀", "스프레드시트", "spreadsheet", "xlsx", "csv"):
		return "Argos 표"
	default:
		return "Argos 문서"
	}
}

func assistantScenarioReply(opts ListenOptions, text string) (string, bool) {
	mode := strings.ToLower(strings.TrimSpace(opts.Mode))
	if mode != "assistant" && mode != "briefing" {
		return "", false
	}
	lower := strings.ToLower(strings.TrimSpace(text))
	if reply, handled := assistantMailPriorityReply(opts, text); handled {
		return reply, true
	}
	if isAssistantReportRoomQuietApprovalText(lower) {
		return assistantApplyReportRoomQuietPolicyReply(opts, text), true
	}
	if isAssistantDailyHomeCardRequest(lower) {
		return assistantDailyHomeCardReply(opts, text), true
	}
	if isAssistantReportRoomNoiseControlRequest(lower) {
		return assistantReportRoomNoiseControlReply(text), true
	}
	if reply, handled := assistantChemicalMarketResearchReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantIndustryNewsMeetingMaterialsReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantIndustryLatestNewsReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantMarketResearchMeetingTopicsReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantIndustryScenarioReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantBrowserResearchPackageReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantCalendarTravelPackageReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantCoupangShoppingPackageReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantMeetingMinutesPackageReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantDepartmentWorkflowReply(opts, text); handled {
		return reply, true
	}
	if looksLikeAssistantArtifactRequest(text) {
		return "", false
	}
	if reply, handled := assistantSelfTestReply(opts, text); handled {
		return reply, true
	}
	// Explicit mail draft follow-ups must not fall through to numbered news
	// follow-ups just because both use ordinal words like "첫 번째" or "1번".
	if reply, handled := replyFromRecentSignalMailContext(opts, text); handled {
		return reply, true
	}
	if reply, handled := shoppingCandidateDetailFollowUpReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := pendingShoppingDirectPurchaseCandidateSearchReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := shoppingCandidateCartAddReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := shoppingCandidateCartConfirmReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := shoppingCandidateCartPrepReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := shoppingCandidateCriterionFollowUpReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := shoppingCandidateCompareFollowUpReply(opts, text); handled {
		return reply, true
	}
	// News item follow-ups take priority over stale pending mail/calendar slots.
	if isNewsItemFollowUp(strings.ToLower(strings.TrimSpace(text))) {
		if reply, handled := assistantFollowUpReply(opts, text); handled {
			return reply, true
		}
	}
	if reply, handled := assistantPendingConversationReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := assistantConversationalReply(opts, text); handled {
		return reply, true
	}
	// Model-driven follow-up handling: terse follow-ups must resolve against the
	// previous turn (news item / source / translation) instead of being routed
	// by keyword scenarios into an unrelated tool such as the calendar.
	if reply, handled := assistantFollowUpReply(opts, text); handled {
		return reply, true
	}
	if reply, handled := naturalMailDraftScenarioReply(opts, text); handled {
		return reply, true
	}
	if looksLikeMarketResearchReportRequest(lower) {
		return "", false
	}
	if isNewsVoiceRequest(lower) {
		return newsVoiceReply(opts, text), true
	}
	if isNewsDocumentRequest(lower) {
		return newsDocumentReply(opts, text), true
	}
	if reply, handled := fastNewsScenarioReply(opts, text); handled {
		return reply, true
	}
	if assistantLegacyScenarioFallbackEnabled() {
		if reply, handled := commuteScenarioReply(opts, text); handled {
			return reply, true
		}
		if reply, handled := dailyScenarioReply(opts, text); handled {
			return reply, true
		}
		if reply, handled := lifePlanningScenarioReply(opts, text); handled {
			return reply, true
		}
		if reply, handled := mapsScenarioReply(opts, text); handled {
			return reply, true
		}
		if prefersMacAssistantBeforeBooking(text) {
			if reply, handled := macAssistantScenarioReply(opts, text); handled {
				return reply, true
			}
		}
		if reply, handled := bookingScenarioReply(opts, text); handled {
			return reply, true
		}
		if reply, handled := shoppingScenarioReply(opts, text); handled {
			return reply, true
		}
		if reply, handled := mediaScenarioReply(opts, text); handled {
			return reply, true
		}
	}
	if assistantAllowsMacActionFallback(text) {
		if reply, handled := macAssistantScenarioReply(opts, text); handled {
			return reply, true
		}
	}
	return "", false
}

func assistantLegacyScenarioFallbackEnabled() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_ASSISTANT_LEGACY_SCENARIOS")))
	return value == "1" || value == "true" || value == "on" || value == "yes"
}

func assistantAllowsMacActionFallback(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return false
	}
	if looksLikeAssistantArtifactRequest(lower) ||
		containsAny(lower, "뉴스", "news", "headline", "헤드라인", "브리핑", "유가", "시장", "전망", "지도", "길찾기", "출근길", "이동시간", "주차", "예약 후보", "쿠폰", "쇼핑", "상품", "구매", "결제", "반품", "음악", "유튜브", "넷플릭스") {
		if containsAny(lower, "브라우저에서", "browser search", "search in browser", "웹에서") &&
			containsAny(lower, "검색", "찾아", "search", "look up") {
			return true
		}
		return false
	}
	return containsAny(lower,
		"캘린더", "달력", "일정", "리마인더", "reminder", "reminders", "할 일", "할일",
		"연락처", "contacts", "메모", "노트", "notes",
		"safari", "브라우저에서", "url", "http://", "https://", "열어줘", "열어", "앱",
		"shortcut", "shortcuts", "단축어",
	)
}

func assistantSelfTestReply(opts ListenOptions, text string) (string, bool) {
	if !isAssistantSelfTestRequest(text) {
		return "", false
	}
	reply, _, _ := AssistantSelfTestText(opts.TargetID, opts.Mode)
	return reply, true
}

func assistantEarlyConversationalReply(opts ListenOptions, text string) (string, bool) {
	return assistantConversationalReplyWithMode(opts, text, false)
}

func assistantConversationalReply(opts ListenOptions, text string) (string, bool) {
	return assistantConversationalReplyWithMode(opts, text, true)
}

func assistantConversationalReplyWithMode(opts ListenOptions, text string, allowExtended bool) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return "", false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(lower)
	reply := ""
	switch {
	case isAssistantGreetingText(lower, compact):
		reply = strings.Join([]string{
			lang.T("assistant.conversation.greeting.ready"),
			lang.T("assistant.conversation.greeting.capabilities"),
			lang.T("assistant.conversation.greeting.example"),
			lang.T("assistant.conversation.greeting.next"),
		}, "\n")
	case isAssistantThanksText(lower, compact):
		reply = strings.Join([]string{
			lang.T("assistant.conversation.thanks.ready"),
			lang.T("assistant.conversation.thanks.clarify"),
			lang.T("assistant.conversation.thanks.example"),
		}, "\n")
	case (allowExtended || (isShortAmbiguousApprovalText(lower) && !recentShoppingCheckoutDecisionReady(opts.TargetID))) && isShortAssistantBackchannel(compact):
		reply = strings.Join([]string{
			lang.T("assistant.conversation.backchannel.ready"),
			lang.T("assistant.conversation.backchannel.next"),
			lang.T("assistant.conversation.backchannel.capabilities"),
		}, "\n")
	case allowExtended && isAssistantStarterRecommendationRequest(lower):
		reply = assistantStarterRecommendationReply()
	case allowExtended && isVagueMailSendRequest(lower):
		rememberPendingAssistantConversation(assistantPendingKey(opts.TargetID), pendingAssistantConversation{
			Kind:      "mail_send",
			Intent:    assistantToolIntent{Intent: "mail_send", Confidence: 0.8, Reason: "assistant_slot_fill"},
			Request:   text,
			CreatedAt: time.Now().UTC(),
			ExpiresAt: time.Now().UTC().Add(15 * time.Minute),
		})
		reply = strings.Join([]string{
			"메일을 보내려면 네 가지가 필요합니다.",
			"1. 보낼 계정",
			"2. 받는 사람",
			"3. 제목",
			"4. 본문",
			"예: `101 계정으로 yoon@example.com에게 제목 회의, 본문 내일 3시에 볼까요 라고 메일 초안 만들어줘`",
			"최종 발송은 승인 후 진행합니다.",
		}, "\n")
	case allowExtended && isVagueCalendarEventRequest(lower):
		event, missing := extractSignalCalendarEventSlots(text, time.Now())
		rememberPendingAssistantConversation(assistantPendingKey(opts.TargetID), pendingAssistantConversation{
			Kind:      "calendar_event_create",
			Request:   text,
			CreatedAt: time.Now().UTC(),
			ExpiresAt: time.Now().UTC().Add(15 * time.Minute),
		})
		reply = formatAssistantCalendarMissingSlots(event, missing)
	case allowExtended && isVagueSearchRequest(lower):
		rememberPendingAssistantConversation(assistantPendingKey(opts.TargetID), pendingAssistantConversation{
			Kind:      "browser_search",
			Request:   text,
			CreatedAt: time.Now().UTC(),
			ExpiresAt: time.Now().UTC().Add(15 * time.Minute),
		})
		reply = strings.Join([]string{
			"무엇을 찾아볼까요?",
			"검색 주제와 원하는 결과 형태를 같이 보내면 빠릅니다.",
			"예: `브라우저에서 가나 경제 뉴스 검색해서 5줄로 정리해줘`",
			"필요하면 Mac 브라우저를 열어 근거 링크까지 남기겠습니다.",
		}, "\n")
	}
	if reply == "" {
		return "", false
	}
	reply = appendAssistantConversationalPersonalization(reply)
	_ = appendSignalHistory(opts.TargetID, text, reply)
	return reply, true
}

func isAssistantGreetingText(lower, compact string) bool {
	if containsAny(compact, "안녕", "하이", "ㅎㅇ") {
		return true
	}
	switch strings.TrimSpace(lower) {
	case "hello", "hi", "hey", "hello there", "hi there":
		return true
	default:
		return false
	}
}

func isAssistantThanksText(lower, compact string) bool {
	if containsAny(compact, "고마워", "감사", "땡큐") {
		return true
	}
	switch compact {
	case "thanks", "thankyou", "thx", "ty":
		return true
	default:
		return false
	}
}

func appendAssistantConversationalPersonalization(reply string) string {
	if strings.TrimSpace(reply) == "" {
		return reply
	}
	locale := lang.Current()
	hint := assistantStarterPersonalizationHintLine(locale)
	if hint == "" {
		return reply
	}
	return strings.Join([]string{
		strings.TrimSpace(reply),
		"",
		hint,
		lang.TF(locale, "assistant.capabilities.personalization_boundary"),
	}, "\n")
}

func assistantPendingConversationReply(opts ListenOptions, text string) (string, bool) {
	pending, ok := takePendingAssistantConversation(assistantPendingKey(opts.TargetID), false)
	if !ok {
		return "", false
	}
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return "", false
	}
	if containsAny(lower, "취소", "그만", "cancel", "stop") {
		takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
		return "좋습니다. 방금 이어가던 작업은 취소했습니다.", true
	}
	if pending.Kind == "scheduled_delivery_apply" {
		if isAssistantScheduledDeliveryApprovalText(lower) {
			return continueAssistantScheduledDeliveryApply(opts, pending, text), true
		}
		if looksLikeFreshAssistantRequest(lower) {
			takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
			return "", false
		}
		return lang.T("assistant.scheduled_delivery.approval_needed"), true
	}
	if pending.Kind == "shopping_direct_purchase" && isShoppingDirectPurchaseApprovalFollowUp(lower) {
		if recentShoppingCheckoutDecisionReady(opts.TargetID) &&
			(isPurchaseFinalApprovalText(lower) || isPurchaseShortFinalGoAheadFollowUp(lower) || isPurchaseNaturalFinalGoAheadFollowUp(lower)) {
			locale, explicit := purchaseApprovalLocaleWithEvidence(text)
			return purchaseFinalGoAheadReplyForRequest(opts, locale, explicit, purchaseFinalConfirmationTextFromRequest(lower, text)), true
		}
		return continueShoppingDirectPurchase(opts, pending, text), true
	}
	if looksLikeFreshAssistantRequest(lower) {
		takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
		return "", false
	}
	switch pending.Kind {
	case "mail_send":
		reply := continueAssistantMailSend(opts, pending, text)
		return reply, true
	case "calendar_event_create":
		reply := continueAssistantCalendarEvent(opts, pending, text)
		return reply, true
	case "browser_search":
		query := strings.TrimSpace(text)
		if len([]rune(query)) < 2 {
			return "검색 주제를 조금만 더 구체적으로 보내세요. 예: `가나 경제 뉴스 5줄 요약`", true
		}
		takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
		return runSignalArgosAction(opts, "브라우저에서 "+query+" 검색해서 요약해줘", 0)
	case "shopping_direct_purchase":
		takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
		return "", false
	default:
		takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
		return "", false
	}
}

func isAssistantScheduledDeliveryApprovalText(lower string) bool {
	normalized := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(lower)), " "))
	if normalized == "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(normalized)
	switch compact {
	case "ㅇㅇ", "응", "네", "예", "승인", "등록승인", "예약등록승인", "예약발송승인", "예약전송승인":
		return true
	}
	switch normalized {
	case "yes", "ok", "approve", "approved", "approve schedule", "approve scheduled delivery", "approve schedule registration", "register schedule", "register scheduled delivery":
		return true
	default:
		return false
	}
}

func continueAssistantScheduledDeliveryApply(opts ListenOptions, pending pendingAssistantConversation, text string) string {
	takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
	intent := pending.Intent
	result, err := ApplyScheduledDelivery(ScheduledDeliveryApplyOptions{
		Target:          intent.Target,
		Schedule:        intent.Schedule,
		Content:         intent.Content,
		ContentType:     intent.ContentType,
		Delivery:        intent.Delivery,
		Execute:         true,
		Approve:         true,
		PreviewApproved: true,
	})
	if err != nil {
		return lang.T("assistant.scheduled_delivery.apply_fail", err.Error())
	}
	if result.Status != "registered" || result.Job == nil {
		return lang.T("assistant.scheduled_delivery.apply_fail", firstNonEmpty(result.Status, result.UserMessage, "not registered"))
	}
	job := result.Job
	target := firstNonEmpty(job.TargetLabel, job.TargetID, intent.Target)
	lines := []string{
		lang.T("assistant.scheduled_delivery.registered_title"),
		lang.T("assistant.scheduled_delivery.registered_job", job.ID),
		lang.T("assistant.scheduled_delivery.registered_target", target),
		lang.T("assistant.scheduled_delivery.registered_schedule", job.Schedule),
		lang.T("assistant.scheduled_delivery.registered_content", trimSignalListLine(job.Content, 72)),
		"",
		lang.T("assistant.scheduled_delivery.registered_boundary"),
		lang.T("assistant.scheduled_delivery.registered_next"),
	}
	_ = appendSignalHistory(opts.TargetID, text, strings.Join(lines, "\n"))
	return strings.Join(lines, "\n")
}

func continueAssistantMailSend(opts ListenOptions, pending pendingAssistantConversation, text string) string {
	intent := mergeSignalMailSendSlots(pending.Intent, text)
	missing := missingSignalMailSendSlots(intent)
	if len(missing) > 0 {
		pending.Intent = intent
		pending.Request = strings.TrimSpace(pending.Request + "\n" + text)
		pending.ExpiresAt = time.Now().UTC().Add(15 * time.Minute)
		rememberPendingAssistantConversation(assistantPendingKey(opts.TargetID), pending)
		return formatAssistantMailMissingSlots(intent, missing)
	}
	takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
	return prepareSignalMailSend(opts, intent)
}

func continueAssistantCalendarEvent(opts ListenOptions, pending pendingAssistantConversation, text string) string {
	combined := strings.TrimSpace(pending.Request + "\n" + text)
	event, missing := extractSignalCalendarEventSlots(combined, time.Now())
	if len(missing) > 0 {
		pending.Request = combined
		pending.ExpiresAt = time.Now().UTC().Add(15 * time.Minute)
		rememberPendingAssistantConversation(assistantPendingKey(opts.TargetID), pending)
		return formatAssistantCalendarMissingSlots(event, missing)
	}
	takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
	command := signalCalendarEventCommand(event)
	reply, handled := runSignalArgosAction(opts, command, 0)
	if handled {
		return reply
	}
	return "일정 정보를 모았지만 Calendar 작업으로 변환하지 못했습니다. 예: `내일 오후 6시에 강남역 약속 일정 추가해줘`"
}

func naturalMailDraftScenarioReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" || !containsAny(lower, "메일", "이메일", "email", "mail") {
		return "", false
	}
	if !containsAny(lower, "초안", "보내", "발송", "draft", "send") {
		return "", false
	}
	intent := mergeSignalMailSendSlots(assistantToolIntent{}, text)
	missing := missingSignalMailSendSlots(intent)
	if len(missing) > 0 {
		rememberPendingAssistantConversation(assistantPendingKey(opts.TargetID), pendingAssistantConversation{
			Kind:      "mail_send",
			Intent:    intent,
			Request:   text,
			CreatedAt: time.Now().UTC(),
			ExpiresAt: time.Now().UTC().Add(15 * time.Minute),
		})
		return formatAssistantMailMissingSlots(intent, missing), true
	}
	return prepareSignalMailSend(opts, intent), true
}

func mergeSignalMailSendSlots(intent assistantToolIntent, text string) assistantToolIntent {
	intent.Intent = "mail_send"
	if len(intent.To) == 0 {
		intent.To = cleanSignalMailRecipients(signalMailAddressRE.FindAllString(text, -1))
	}
	if strings.TrimSpace(intent.Subject) == "" {
		if subject, ok := extractKoreanMailField(text, []string{"제목은", "제목:", "제목", "subject:"}, []string{"내용은", "본문은", "내용:", "본문:", "body:", "받는 사람", "수신자"}); ok {
			intent.Subject = subject
		}
	}
	if strings.TrimSpace(intent.Body) == "" {
		if body, ok := extractKoreanMailField(text, []string{"내용은", "본문은", "내용:", "본문:", "body:"}, nil); ok {
			intent.Body = body
		}
	}
	if strings.TrimSpace(intent.Account) == "" {
		if account := extractSignalMailAccountHint(text); account != "" {
			intent.Account = account
		}
	}
	intent.Confidence = 0.9
	intent.Reason = "assistant_slot_fill"
	return intent
}

func missingSignalMailSendSlots(intent assistantToolIntent) []string {
	missing := []string{}
	if strings.TrimSpace(intent.Account) == "" {
		if _, accounts, err := defaultSignalMailAccount(); err == nil && len(accounts) > 1 {
			missing = append(missing, "보낼 계정")
		}
	}
	if len(intent.To) == 0 {
		missing = append(missing, "받는 사람")
	}
	if strings.TrimSpace(intent.Subject) == "" {
		missing = append(missing, "제목")
	}
	if strings.TrimSpace(intent.Body) == "" {
		missing = append(missing, "본문")
	}
	return missing
}

func formatAssistantMailMissingSlots(intent assistantToolIntent, missing []string) string {
	lines := []string{"좋습니다. 아직 필요한 정보가 남았습니다."}
	if len(intent.To) > 0 {
		lines = append(lines, "받는 사람: "+strings.Join(intent.To, ", "))
	}
	if strings.TrimSpace(intent.Subject) != "" {
		lines = append(lines, "제목: "+intent.Subject)
	}
	if strings.TrimSpace(intent.Body) != "" {
		lines = append(lines, "본문: "+trimForContext(intent.Body, 160))
	}
	lines = append(lines,
		"남은 항목: "+strings.Join(missing, ", "),
		"예: `받는 사람은 yoon@example.com 제목은 회의 본문은 내일 3시에 볼까요`",
	)
	return strings.Join(lines, "\n")
}

type signalCalendarEventSlots struct {
	Title       string
	Date        time.Time
	Hour        int
	Minute      int
	HasDate     bool
	HasTime     bool
	Location    string
	VaguePeriod string
}

func extractSignalCalendarEventSlots(text string, now time.Time) (signalCalendarEventSlots, []string) {
	event := signalCalendarEventSlots{Hour: -1}
	lower := strings.ToLower(strings.TrimSpace(text))
	switch {
	case strings.Contains(lower, "내일") || strings.Contains(lower, "tomorrow"):
		event.Date = beginningOfSignalDay(now).AddDate(0, 0, 1)
		event.HasDate = true
	case strings.Contains(lower, "모레"):
		event.Date = beginningOfSignalDay(now).AddDate(0, 0, 2)
		event.HasDate = true
	case strings.Contains(lower, "오늘") || strings.Contains(lower, "today"):
		event.Date = beginningOfSignalDay(now)
		event.HasDate = true
	}
	event.Hour, event.Minute, event.HasTime = signalCalendarHourMinute(lower)
	switch {
	case containsAny(lower, "저녁", "밤", "evening", "tonight"):
		event.VaguePeriod = "저녁"
		if event.HasTime && event.Hour > 0 && event.Hour < 12 {
			event.Hour += 12
		}
	case containsAny(lower, "오후", "pm", "afternoon"):
		event.VaguePeriod = "오후"
		if event.HasTime && event.Hour > 0 && event.Hour < 12 {
			event.Hour += 12
		}
	case containsAny(lower, "점심", "noon", "lunch"):
		event.VaguePeriod = "점심"
		if !event.HasTime {
			event.Hour, event.Minute, event.HasTime = 12, 0, true
		}
	case containsAny(lower, "아침", "오전", "morning", "am"):
		event.VaguePeriod = "오전"
	}
	event.Location = extractSignalCalendarLocation(text)
	event.Title = extractSignalCalendarTitle(text, event)
	missing := []string{}
	if !event.HasDate {
		missing = append(missing, "날짜")
	}
	if !event.HasTime {
		missing = append(missing, "시간")
	}
	if strings.TrimSpace(event.Title) == "" {
		missing = append(missing, "일정 이름")
	}
	return event, missing
}

func beginningOfSignalDay(value time.Time) time.Time {
	return time.Date(value.Year(), value.Month(), value.Day(), 0, 0, 0, 0, value.Location())
}

func signalCalendarHourMinute(lower string) (int, int, bool) {
	re := regexp.MustCompile(`(?i)(오전|오후|am|pm)?\s*([0-9]{1,2})\s*시(?:\s*([0-9]{1,2})\s*분)?`)
	match := re.FindStringSubmatch(lower)
	if len(match) == 0 {
		return -1, 0, false
	}
	hour, _ := strconv.Atoi(match[2])
	minute := 0
	if match[3] != "" {
		minute, _ = strconv.Atoi(match[3])
	}
	ampm := strings.ToLower(strings.TrimSpace(match[1]))
	if (ampm == "오후" || ampm == "pm") && hour < 12 {
		hour += 12
	}
	if (ampm == "오전" || ampm == "am") && hour == 12 {
		hour = 0
	}
	if hour < 0 || hour > 23 || minute < 0 || minute > 59 {
		return -1, 0, false
	}
	return hour, minute, true
}

func extractSignalCalendarLocation(text string) string {
	normalized := strings.Join(strings.Fields(strings.TrimSpace(text)), " ")
	for _, marker := range []string{"장소는", "장소:", "location:"} {
		if idx := strings.Index(strings.ToLower(normalized), strings.ToLower(marker)); idx >= 0 {
			value := strings.TrimSpace(normalized[idx+len(marker):])
			for _, stop := range []string{" 제목", " 일정", " 약속", " event", " meeting"} {
				if stopIdx := strings.Index(strings.ToLower(value), strings.ToLower(stop)); stopIdx >= 0 {
					value = strings.TrimSpace(value[:stopIdx])
				}
			}
			value = strings.Trim(value, " \t\r\n:：.-")
			if value != "" && !containsAny(strings.ToLower(value), "나중") {
				return value
			}
		}
	}
	re := regexp.MustCompile(`([^\s]+(?:역|동|구|카페|식당|회사|학교|공항|터미널|office|station|cafe|restaurant))에서`)
	if match := re.FindStringSubmatch(normalized); len(match) == 2 {
		return strings.TrimSpace(match[1])
	}
	re = regexp.MustCompile(`([^\s]+(?:역|동|구|카페|식당|회사|학교|공항|터미널|office|station|cafe|restaurant))`)
	if match := re.FindStringSubmatch(normalized); len(match) == 2 {
		return strings.TrimSpace(match[1])
	}
	return ""
}

func extractSignalCalendarTitle(text string, event signalCalendarEventSlots) string {
	lower := strings.ToLower(text)
	switch {
	case strings.Contains(lower, "회의") || strings.Contains(lower, "meeting"):
		return "회의"
	case strings.Contains(lower, "예약"):
		return "예약"
	case strings.Contains(lower, "약속") || strings.Contains(lower, "appointment"):
		return "약속"
	}
	return strings.TrimSpace(event.Location)
}

func formatAssistantCalendarMissingSlots(event signalCalendarEventSlots, missing []string) string {
	lines := []string{"좋습니다. 일정에 필요한 정보가 조금 더 필요합니다."}
	if event.HasDate {
		lines = append(lines, "날짜: "+event.Date.Format("2006-01-02"))
	}
	if event.HasTime {
		lines = append(lines, fmt.Sprintf("시간: %02d:%02d", event.Hour, event.Minute))
	} else if event.VaguePeriod != "" {
		lines = append(lines, "시간대: "+event.VaguePeriod)
	}
	if event.Location != "" {
		lines = append(lines, "장소: "+event.Location)
	}
	if event.Title != "" {
		lines = append(lines, "일정: "+event.Title)
	}
	lines = append(lines,
		"남은 항목: "+strings.Join(missing, ", "),
		"예: `6시에 강남역`, `내일 오후 6시에 강남역 약속`",
	)
	return strings.Join(lines, "\n")
}

func signalCalendarEventCommand(event signalCalendarEventSlots) string {
	start := time.Date(event.Date.Year(), event.Date.Month(), event.Date.Day(), event.Hour, event.Minute, 0, 0, event.Date.Location())
	period := "오전"
	hour := event.Hour
	if hour >= 12 {
		period = "오후"
		if hour > 12 {
			hour -= 12
		}
	}
	title := firstNonEmpty(event.Title, "약속")
	if event.Location != "" && !strings.Contains(title, event.Location) {
		title = strings.TrimSpace(event.Location + " " + title)
	}
	return fmt.Sprintf("%s %s %d시에 일정 추가해줘 제목은 %s", signalCalendarDatePhrase(start, time.Now()), period, hour, title)
}

func signalCalendarDatePhrase(start, now time.Time) string {
	startDay := beginningOfSignalDay(start)
	nowDay := beginningOfSignalDay(now)
	switch {
	case startDay.Equal(nowDay):
		return "오늘"
	case startDay.Equal(nowDay.AddDate(0, 0, 1)):
		return "내일"
	case startDay.Equal(nowDay.AddDate(0, 0, 2)):
		return "모레"
	default:
		return start.Format("2006-01-02")
	}
}

func extractSignalMailAccountHint(text string) string {
	lower := strings.ToLower(strings.TrimSpace(text))
	if index, err := strconv.Atoi(strings.Trim(lower, ". ")); err == nil && index > 0 {
		if _, accounts, accountErr := defaultSignalMailAccount(); accountErr == nil && len(accounts) >= index {
			return accounts[index-1].ID
		}
	}
	store, err := mailadapter.ListAccounts()
	if err != nil {
		return ""
	}
	for _, account := range store.Accounts {
		id := strings.ToLower(strings.TrimSpace(account.ID))
		if id != "" && strings.Contains(lower, id) {
			return account.ID
		}
		if account.Email != "" && strings.Contains(lower, strings.ToLower(account.Email)) {
			return account.ID
		}
		if account.Username != "" && strings.Contains(lower, strings.ToLower(account.Username)) {
			return account.ID
		}
		for _, alias := range signalMailAccountAliases(account) {
			if signalMailTextMentionsAccountAlias(lower, alias) {
				return account.ID
			}
		}
	}
	return ""
}

func signalMailAccountAliases(account mailadapter.AccountPublic) []string {
	seen := map[string]bool{}
	aliases := []string{}
	add := func(value string) {
		value = strings.ToLower(strings.TrimSpace(value))
		value = strings.Trim(value, " .,:;()[]{}<>")
		if value == "" || seen[value] {
			return
		}
		seen[value] = true
		aliases = append(aliases, value)
	}
	if id := strings.ToLower(strings.TrimSpace(account.ID)); id != "" {
		if idx := strings.IndexAny(id, "-_./"); idx > 0 {
			add(id[:idx])
		}
	}
	for _, value := range []string{account.Email, account.Username} {
		local := strings.ToLower(strings.TrimSpace(value))
		if idx := strings.Index(local, "@"); idx > 0 {
			add(local[:idx])
		}
	}
	return aliases
}

func signalMailTextMentionsAccountAlias(lowerText, alias string) bool {
	if alias == "" {
		return false
	}
	patterns := []string{
		alias + " 계정",
		alias + "계정",
		alias + " 메일",
		alias + "메일",
		alias + " email",
		alias + " 이메일",
		"account " + alias,
		"from " + alias,
	}
	for _, pattern := range patterns {
		if strings.Contains(lowerText, pattern) {
			return true
		}
	}
	return false
}

func looksLikeFreshAssistantRequest(lower string) bool {
	if isPurchaseShortFinalGoAheadFollowUp(lower) || isPurchaseBareFinalGoAheadFollowUp(lower) || isPurchaseFinalApprovalText(lower) {
		return false
	}
	if isAssistantAutomationListRequest(lower) || isAssistantAutomationStatusRequest(lower) || isAssistantScheduledDeliveryStatusRequest(lower) {
		return true
	}
	if looksLikeAssistantArtifactRequest(lower) {
		return true
	}
	return containsAny(lower,
		"뉴스", "날씨", "지도", "길찾기", "주차", "메일 계정", "새 메일", "중요 메일", "가격 알림",
		"브라우저에서", "검색해줘", "열어줘", "리마인더", "일정", "연락처",
		"구매", "주문", "결제", "쿠팡", "사줘", "사라",
		"다음은", "다음 뭐", "뭐부터", "추천해", "map", "maps", "direction", "show map",
		"buy", "purchase", "order", "checkout", "coupang",
	)
}

func isPurchaseBareFinalGoAheadFollowUp(lower string) bool {
	normalized := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(lower)), " "))
	if normalized == "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "").Replace(normalized)
	exactCompact := map[string]bool{
		"사줘": true, "주문해": true, "주문해줘": true, "구매해": true, "구매해줘": true, "결제해": true, "결제해줘": true,
	}
	if exactCompact[compact] {
		return true
	}
	exact := map[string]bool{
		"buy it": true, "buy now": true, "order it": true, "order now": true, "place it": true,
		"go ahead": true, "proceed": true, "proceed with purchase": true, "complete purchase": true, "complete checkout": true,
	}
	return exact[normalized]
}

func isShoppingDirectPurchaseApprovalFollowUp(lower string) bool {
	return isPurchaseShortFinalGoAheadFollowUp(lower) ||
		isPurchaseBareFinalGoAheadFollowUp(lower) ||
		isShoppingDirectPurchaseNaturalApprovalFollowUp(lower) ||
		isShoppingDirectPurchaseRetryFollowUp(lower) ||
		shoppingDirectPurchaseFollowUpUsesCurrentScreen(lower) ||
		isPurchaseFinalApprovalText(lower)
}

