func looksLikeAssistantArtifactRequest(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return false
	}
	if containsAny(lower, "메일", "이메일", "email", "mail") {
		if looksLikeMailSpreadsheetArtifactRequest(lower) {
			return true
		}
		if containsAny(lower, "회의록", "회의 자료", "회의용", "문서", "보고서", "리포트", "발표자료", "발표 자료", "슬라이드", "ppt", "pptx", "deck", "presentation") &&
			containsAny(lower, "작성", "만들", "준비", "정리", "보내", "공유", "create", "make", "draft", "send") {
			return true
		}
		return false
	}
	return containsAny(lower,
		"자료", "회의 자료", "회의용", "회의록", "문서", "보고서", "리포트", "초안",
		"발표자료", "발표 자료", "슬라이드", "ppt", "pptx", "deck", "presentation",
		"엑셀", "스프레드시트", "spreadsheet", "xlsx", "csv", "예산표", "비용표", "청구서", "인보이스", "트래커", "체크리스트", "대장",
	)
}

func looksLikeSpreadsheetArtifactRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	if containsAny(lower, "엑셀", "스프레드시트", "spreadsheet", "xlsx", "csv", "numbers") {
		return true
	}
	if containsAny(lower, "문서", "보고서", "리포트", "발표", "ppt") {
		return false
	}
	return containsAny(lower, "예산표", "비용표", "청구서", "인보이스", "트래커", "체크리스트", "대장")
}

func isFreshSpreadsheetCreationRequest(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !looksLikeSpreadsheetArtifactRequest(lower) {
		return false
	}
	return containsAny(lower, "만들", "작성", "생성", "준비", "정리해", "정리해서", "create", "make", "draft")
}

func isShortAssistantBackchannel(compact string) bool {
	switch compact {
	case "ㅇㅇ", "응", "네", "그래", "좋아", "오케이", "ok", "okay", "yes", "ㅇㅋ":
		return true
	default:
		return false
	}
}

func isVagueMailSendRequest(lower string) bool {
	if !containsAny(lower, "메일", "이메일", "email", "mail") {
		return false
	}
	if containsAny(lower, "mail please", "email please", "메일 부탁", "메일 좀") {
		return true
	}
	if !containsAny(lower, "보내", "발송", "send") {
		return false
	}
	return !strings.Contains(lower, "@") || !containsAny(lower, "제목", "subject", "본문", "내용")
}

func isVagueSearchRequest(lower string) bool {
	if !containsAny(lower, "찾아봐", "검색해", "검색해봐", "알아봐", "search", "look up") {
		return false
	}
	query := strings.TrimSpace(strings.NewReplacer(
		"찾아봐", "", "검색해봐", "", "검색해", "", "알아봐", "", "search", "", "look up", "",
		"브라우저에서", "", "웹에서", "",
	).Replace(lower))
	return len([]rune(query)) < 4
}

func isVagueCalendarEventRequest(lower string) bool {
	if !containsAny(lower, "일정", "캘린더", "달력", "약속", "회의", "예약", "calendar", "meeting", "appointment") {
		return false
	}
	if containsAny(lower, "뭐 있어", "뭐있어", "있어?", "있지", "보여", "보이는", "조회", "확인", "알려", "list", "show", "check", "what") {
		return false
	}
	if !containsAny(lower, "잡아", "추가", "등록", "만들", "예약", "schedule", "add", "create") {
		return false
	}
	_, missing := extractSignalCalendarEventSlots(lower, time.Now())
	return len(missing) > 0
}

func AssistantSelfTestText(targetID, mode string) (string, evidence.Record, error) {
	opts := ListenOptions{TargetID: strings.TrimSpace(targetID), Mode: strings.TrimSpace(mode)}
	if opts.Mode == "" {
		opts.Mode = "assistant"
	}
	report := runAssistantSelfTest(opts, "")
	record, storeErr := evidence.Store("signal-assistant-self-test", firstNonEmpty(opts.TargetID, "assistant"), "read_only", report)
	lines := []string{formatAssistantSelfTest(report)}
	lines = appendEvidenceLine(lines, record, storeErr)
	return strings.Join(lines, "\n"), record, storeErr
}

func AssistantReplyText(targetID, mode, text string) string {
	return AssistantReplyTextWithOptions(targetID, mode, text, false)
}

func AssistantReplyTextWithOptions(targetID, mode, text string, execute bool) string {
	opts := ListenOptions{TargetID: strings.TrimSpace(targetID), Mode: strings.TrimSpace(mode)}
	if opts.Mode == "" {
		opts.Mode = "assistant"
	}
	opts.Execute = execute
	return assistantReply(opts, text)
}

func isAssistantSelfTestRequest(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if lower == "" {
		return false
	}
	if strings.Contains(lower, "@") || containsAny(lower, "subject:", "body:", "제목", "본문", "내용") {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", "-", "").Replace(lower)
	switch compact {
	case "기능테스트", "비서테스트", "셀프테스트", "자체테스트", "뉴스테스트", "날씨테스트", "지도테스트", "argosdoctor", "assistantselftest", "selftest", "smoketest", "capabilitytest":
		return true
	}
	return lower == "assistant test" || lower == "assistant self test" || lower == "self test" || lower == "smoke test" || lower == "capability test"
}

func runAssistantSelfTest(opts ListenOptions, request string) signalAssistantSelfTest {
	report := signalAssistantSelfTest{
		Kind:      "meshclaw_signal_assistant_self_test",
		Generated: time.Now().UTC(),
		TargetID:  opts.TargetID,
		Mode:      opts.Mode,
		Items:     []signalSelfTestItem{},
	}
	report.Items = append(report.Items, assistantSelfTestNews())
	report.Items = append(report.Items, assistantSelfTestWeather())
	report.Items = append(report.Items, assistantSelfTestMap())
	report.Items = append(report.Items, assistantSelfTestMail())
	report.Items = append(report.Items, assistantSelfTestPriceWatch())
	report.Items = append(report.Items, assistantSelfTestMacPermissions())
	report.Items = append(report.Items, assistantSelfTestProfile())
	report.Items = append(report.Items, assistantSelfTestCapabilityMatrix())
	report.Items = append(report.Items, assistantSelfTestPersonalAssistantBaseline(opts))
	report.Items = append(report.Items, assistantSelfTestSignalReplyContract(opts))
	return report
}

func assistantSelfTestNews() signalSelfTestItem {
	started := time.Now()
	ctx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()
	brief := assistantbrief.News(ctx, assistantbrief.Options{Location: "Seoul", NewsLimit: 2, NoModelSummary: true})
	item := signalSelfTestItem{Name: "뉴스", Status: "ok", DurationMS: time.Since(started).Milliseconds()}
	if len(brief.News) == 0 {
		item.Status = "warn"
		item.Detail = "수집 항목 없음"
		if len(brief.Errors) > 0 {
			item.Detail = strings.Join(brief.Errors, "; ")
		}
		return item
	}
	item.Detail = fmt.Sprintf("%d개 수집: %s", len(brief.News), trimSignalNewsLine(brief.News[0].Title, 46))
	return item
}

func assistantSelfTestWeather() signalSelfTestItem {
	started := time.Now()
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	brief := assistantbrief.WeatherNow(ctx, assistantbrief.Options{Location: "Seoul"})
	item := signalSelfTestItem{Name: "날씨", Status: "ok", DurationMS: time.Since(started).Milliseconds()}
	if brief.Weather == nil {
		item.Status = "warn"
		item.Detail = "weather API 결과 없음"
		if len(brief.Errors) > 0 {
			item.Detail = strings.Join(brief.Errors, "; ")
		}
		return item
	}
	item.Detail = fmt.Sprintf("서울 %s %s°C", koreanSelfTestWeatherCondition(brief.Weather.Condition), firstNonEmpty(brief.Weather.TempC, "?"))
	return item
}

