func mealLocation(text string) string {
	trimmed := strings.TrimSpace(text)
	patterns := []*regexp.Regexp{
		regexp.MustCompile(`^\s*(.+?)\s*에서\s*.*(뭐 먹|점심|저녁|밥)`),
		regexp.MustCompile(`^\s*(.+?)\s*(점심|저녁)\s*추천`),
		regexp.MustCompile(`(?i)\bin\s+(.+?)\s+(?:what should i eat|meal|lunch|dinner)`),
	}
	for _, pattern := range patterns {
		match := pattern.FindStringSubmatch(trimmed)
		if len(match) >= 2 {
			location := mediaQuery(match[1], []string{"오늘", "내일", "지금"})
			if location != "" {
				return location
			}
		}
	}
	return ""
}

type assistantScenarioEvidencePayload struct {
	Kind      string    `json:"kind"`
	Scenario  string    `json:"scenario"`
	TargetID  string    `json:"target_id,omitempty"`
	Request   string    `json:"request"`
	Reply     string    `json:"reply"`
	Links     []string  `json:"links,omitempty"`
	CreatedAt time.Time `json:"created_at"`
}

func mapsScenarioReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !containsAny(lower, "지도", "위치", "길찾기", "길안내", "가는 길", "얼마나 걸", "소요시간", "이동시간", "어디야", "어디에", "주소", "근처", "문 연", "영업", "약국", "병원", "카페", "식당", "주차", "map", "maps", "direction", "directions", "travel time", "eta", "navigate", "navigation", "nearby", "open now", "pharmacy", "hospital", "cafe", "restaurant", "parking") {
		return "", false
	}
	captureRequested := mapCaptureRequested(lower)
	if containsAny(lower, "주차", "parking") {
		query := parkingPlaceQuery(text)
		if query == "" || isVaguePlaceReference(query) {
			reply := strings.Join([]string{
				"주차 가능 여부를 보려면 장소명이 필요합니다.",
				"식당 이름이나 지도 링크를 보내세요.",
				"예: `성수동 난포 주차 되는지 봐줘`, `광화문 교보문고 주차`",
			}, "\n")
			return scenarioReplyWithEvidence(opts, "parking_missing_place", text, reply, nil), true
		}
		link := "https://www.google.com/maps/search/?api=1&query=" + url.QueryEscape(query+" parking")
		reply := strings.Join([]string{
			"주차 정보 확인 링크입니다.",
			link,
			"",
			mapFollowupLine(captureRequested),
		}, "\n")
		return scenarioReplyWithEvidence(opts, "parking_check", text, reply, []string{link}), true
	}
	if containsAny(lower, "내 위치", "현재 위치", "여기서", "where am i") && !containsAny(lower, "까지", "가는 길", "길찾기", "direction", "directions") {
		reply := strings.Join([]string{
			"현재 위치는 Signal만으로 자동 확인하지 않습니다.",
			"위치 공유나 장소명을 보내면 바로 지도 링크와 길찾기 링크를 만들겠습니다.",
			"예: `서울역 지도 보여줘`, `강남역에서 성수역까지 길찾기`",
		}, "\n")
		return scenarioReplyWithEvidence(opts, "maps_location_missing", text, reply, nil), true
	}
	if from, to, ok := directionsQuery(text); ok {
		if isCurrentLocationPhrase(from) {
			reply := strings.Join([]string{
				"현재 위치 기준 길찾기는 위치 공유가 먼저 필요합니다.",
				"Signal에서 위치를 보내거나 출발지를 장소명으로 적어주세요.",
				"예: `강남역에서 서울역까지 얼마나 걸려?`, `분당에서 광화문까지 길찾기`",
			}, "\n")
			return scenarioReplyWithEvidence(opts, "maps_current_location_needed", text, reply, nil), true
		}
		link := "https://www.google.com/maps/dir/?api=1&origin=" + url.QueryEscape(from) + "&destination=" + url.QueryEscape(to) + "&travelmode=transit"
		if containsAny(lower, "얼마나 걸", "소요시간", "이동시간", "travel time", "eta") {
			reply := strings.Join([]string{
				"이동시간 확인 링크입니다.",
				link,
				"",
				mapFollowupLine(captureRequested),
			}, "\n")
			return scenarioReplyWithEvidence(opts, "maps_travel_time", text, reply, []string{link}), true
		}
		reply := strings.Join([]string{
			"길찾기 링크입니다.",
			link,
			"",
			mapFollowupLine(captureRequested),
		}, "\n")
		return scenarioReplyWithEvidence(opts, "maps_directions", text, reply, []string{link}), true
	}
	if containsAny(lower, "얼마나 걸", "소요시간", "이동시간", "travel time", "eta") {
		reply := strings.Join([]string{
			"이동시간을 보려면 출발지와 도착지가 필요합니다.",
			"예: `강남역에서 서울역까지 얼마나 걸려?`, `분당에서 광화문까지 지금 얼마나 걸려?`",
		}, "\n")
		return scenarioReplyWithEvidence(opts, "maps_travel_time_missing_route", text, reply, nil), true
	}
	if query, ok := nearbyPlaceQuery(text); ok {
		if needsExplicitLocationForNearby(lower) {
			reply := strings.Join([]string{
				"근처 장소를 찾으려면 기준 위치가 필요합니다.",
				"현재 Signal에서는 위치를 자동으로 읽지 않습니다.",
				"예: `강남역 근처 문 연 약국`, `성수동 조용한 카페`처럼 보내세요.",
			}, "\n")
			return scenarioReplyWithEvidence(opts, "nearby_missing_location", text, reply, nil), true
		}
		link := "https://www.google.com/maps/search/?api=1&query=" + url.QueryEscape(query)
		reply := strings.Join([]string{
			"장소 검색 링크입니다.",
			link,
			"",
			mapFollowupLine(captureRequested),
		}, "\n")
		return scenarioReplyWithEvidence(opts, "nearby_place_search", text, reply, []string{link}), true
	}
	query := mapsQuery(text)
	if query == "" {
		reply := strings.Join([]string{
			"어느 장소를 지도에서 볼까요?",
			"장소명, 주소, 상호명, 또는 출발지/도착지를 보내세요.",
			"예: `광화문 교보문고 지도 보여줘`, `서울역에서 홍대입구까지 길찾기`",
		}, "\n")
		return scenarioReplyWithEvidence(opts, "maps_missing_place", text, reply, nil), true
	}
	link := "https://www.google.com/maps/search/?api=1&query=" + url.QueryEscape(query)
	reply := strings.Join([]string{
		"지도 링크입니다.",
		link,
		"",
		mapFollowupLine(captureRequested),
	}, "\n")
	return scenarioReplyWithEvidence(opts, "maps_place_link", text, reply, []string{link}), true
}

func mapCaptureRequested(lower string) bool {
	return containsAny(lower, "캡처", "캡쳐", "스크린샷", "사진", "보여줘", "화면", "capture", "screenshot", "photo", "picture", "show me")
}

func mapFollowupLine(captureRequested bool) string {
	if captureRequested {
		return "지도 화면 캡처/증명이 필요하면 MeshClaw가 `maps_proof` 캡처 계획을 만들고, 실제 캡처는 화면 민감정보 확인 후 승인받아 실행합니다."
	}
	return "iPhone에서 바로 열 수 있습니다. 화면 증명이 필요하면 MeshClaw 지도 캡처 계획을 만들고 승인 후 캡처합니다."
}

func bookingScenarioReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !containsAny(lower, "예약", "예매", "식당", "레스토랑", "호텔", "항공권", "비행기", "숙소", "티켓", "콘서트", "restaurant", "booking", "book a table", "hotel", "flight", "ticket", "자리", "인원") {
		return "", false
	}
	if containsAny(lower, "주차", "parking") && !containsAny(lower, "예약", "예매", "booking", "book a table") {
		return "", false
	}
	if containsAny(lower, "취소", "cancel") {
		reply := strings.Join([]string{
			"예약 취소는 외부 서비스 상태를 바꾸는 작업이라 바로 실행하지 않습니다.",
			"예약 확인 문자/메일/링크를 보내면 제가 취소 화면을 열고, 최종 취소 버튼 직전에서 멈춘 뒤 다시 승인받겠습니다.",
		}, "\n")
		return scenarioReplyWithEvidence(opts, "booking_cancel_guard", text, reply, nil), true
	}
	query := bookingPlaceQuery(text)
	if query == "" {
		reply := strings.Join([]string{
			"예약하려면 정보가 더 필요합니다.",
			"장소 또는 지역, 날짜, 시간, 인원, 예약자 이름/전화번호를 보내세요.",
			"예: `내일 저녁 7시에 강남 파스타 식당 2명 예약 후보 찾아줘`",
		}, "\n")
		return scenarioReplyWithEvidence(opts, "booking_missing_slots", text, reply, nil), true
	}
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	reply, links := assistantBookingPrepareReply(ctx, query)
	return scenarioReplyWithEvidence(opts, "booking_prepare", text, reply, links), true
}

