func latestBookingDraftForBriefing(targetID string) (string, bool) {
	history := loadSignalHistory(targetID, 20)
	for i := len(history) - 1; i >= 0; i-- {
		msg := history[i]
		if msg.Role != "assistant" {
			continue
		}
		visible := signalReplyVisibleText(msg.Content)
		if !strings.Contains(visible, "예약") || !containsAny(visible, "전화/메시지 초안:", "전화 문장:") {
			continue
		}
		body := bookingDraftBriefingBody(visible)
		if strings.TrimSpace(body) != "" {
			return body, true
		}
	}
	return "", false
}

func bookingDraftBriefingBody(draft string) string {
	lines := []string{"예약 문의 문구입니다.", ""}
	for _, line := range strings.Split(strings.TrimSpace(draft), "\n") {
		trimmed := strings.TrimSpace(line)
		if trimmed == "" {
			lines = append(lines, "")
			continue
		}
		if strings.HasPrefix(trimmed, "다음에 말할 것:") || strings.HasPrefix(trimmed, "아직 예약을 제출") {
			break
		}
		lines = append(lines, trimmed)
	}
	return strings.TrimSpace(strings.Join(compactBlankLines(lines), "\n"))
}

func compactBlankLines(lines []string) []string {
	out := make([]string, 0, len(lines))
	blank := false
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			if blank {
				continue
			}
			blank = true
			out = append(out, "")
			continue
		}
		blank = false
		out = append(out, line)
	}
	for len(out) > 0 && strings.TrimSpace(out[len(out)-1]) == "" {
		out = out[:len(out)-1]
	}
	return out
}

func isBookingDraftRevisionRequest(lower string) bool {
	lower = strings.TrimSpace(lower)
	if lower == "" {
		return false
	}
	if containsAny(lower, "예약자명", "예약자 이름", "예약자", "booking name") {
		return true
	}
	if bookingRevisionPhone(lower) != "" {
		return true
	}
	if containsAny(lower, "연락처", "전화번호", "휴대폰 번호", "phone number") && containsAny(lower, "넣어", "추가", "반영", "수정") {
		return true
	}
	if containsAny(lower, "전화용", "전화 버전", "전화로 말할") {
		return true
	}
	if containsAny(lower, "예약 문구", "예약 초안", "예약 메시지", "예약 문자") && containsAny(lower, "정중", "공손", "짧게", "수정", "다듬", "넣어", "추가") {
		return true
	}
	if containsAny(lower, "이 문구", "이 초안", "그 문구") && containsAny(lower, "정중", "공손", "짧게", "수정", "다듬") {
		return true
	}
	return lower == "더 짧게" || lower == "더 정중하게"
}

func bookingRevisionName(text string) string {
	patterns := []*regexp.Regexp{
		regexp.MustCompile(`예약자\s*명(?:은|는|:|：)?\s*([^\s,，.。]+)`),
		regexp.MustCompile(`예약자\s*이름(?:은|는|:|：)?\s*([^\s,，.。]+)`),
		regexp.MustCompile(`이름(?:은|는|:|：)?\s*([^\s,，.。]+)`),
	}
	for _, pattern := range patterns {
		match := pattern.FindStringSubmatch(text)
		if len(match) < 2 {
			continue
		}
		name := strings.TrimSpace(match[1])
		name = strings.TrimSuffix(name, "으로")
		name = strings.TrimSuffix(name, "로")
		name = strings.Trim(name, " :：,，.。")
		if name != "" && !containsAny(strings.ToLower(name), "넣어줘", "추가", "반영") {
			return name
		}
	}
	return ""
}

func bookingRevisionPhone(text string) string {
	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?:연락처|전화번호|휴대폰\s*번호|핸드폰\s*번호|phone(?:\s*number)?)(?:은|는|:|：)?\s*(01[016789][-\s]?\d{3,4}[-\s]?\d{4})`),
		regexp.MustCompile(`(01[016789][-\s]?\d{3,4}[-\s]?\d{4})`),
	}
	for _, pattern := range patterns {
		match := pattern.FindStringSubmatch(text)
		if len(match) < 2 {
			continue
		}
		phone := strings.Join(strings.Fields(strings.TrimSpace(match[1])), "-")
		phone = strings.Trim(phone, " :：,，.。")
		if phone != "" {
			return phone
		}
	}
	return ""
}

func bookingRevisionApplied(name, phone string) string {
	parts := []string{}
	if name != "" {
		parts = append(parts, "예약자명 "+name)
	}
	if phone != "" {
		parts = append(parts, "연락처 "+phone)
	}
	if len(parts) == 0 {
		return "요청한 내용을 반영"
	}
	return strings.Join(parts, ", ")
}

