func isAssistantChemicalMarketResearchRequest(lower string) bool {
	lower = strings.TrimSpace(lower)
	if lower == "" {
		return false
	}
	return containsAny(lower, "화학회사", "화학 회사", "화학업계", "화학 업계", "chemical company", "chemical industry") &&
		containsAny(lower, "민감", "뉴스", "시장조사", "시장 조사", "분석", "보고서", "회의", "토픽", "topic", "research")
}

func assistantChemicalMarketResearchQuery(text string) string {
	lower := strings.ToLower(text)
	query := "chemical industry news PFAS regulation petrochemical supply chain battery materials sanctions tariffs safety 2026"
	if containsAny(lower, "한국", "국내", "korea", "korean") {
		query += " Korea"
	}
	if containsAny(lower, "중국", "china") {
		query += " China overcapacity exports"
	}
	if containsAny(lower, "배터리", "battery", "양극재", "전해액") {
		query += " battery materials EV demand"
	}
	return query
}

