func assistantTravelPlanQuery(text string) string {
	lower := strings.ToLower(text)
	destination := "Jeju"
	if containsAny(lower, "부산", "busan") {
		destination = "Busan"
	} else if containsAny(lower, "도쿄", "tokyo") {
		destination = "Tokyo"
	} else if containsAny(lower, "오사카", "osaka") {
		destination = "Osaka"
	} else if containsAny(lower, "제주", "jeju") {
		destination = "Jeju"
	}
	return "Seoul " + destination + " flight hotel 2 nights next week fare hotel booking"
}

