func isPurchaseNaturalFinalGoAheadRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" || isPurchaseFinalApprovalText(lower) {
		return false
	}
	if containsAny(lower, "가격 알림", "가격알림", "가격 감시", "가격감시", "price alert", "price watch", "반품", "환불", "교환", "return", "refund", "exchange") {
		return false
	}
	if containsAny(lower, "중지", "멈춰", "멈추", "취소", "그만", "진행하지 마", "하지마", "하지 마", "stop", "cancel", "abort", "do not proceed", "don't proceed", "dont proceed") {
		return false
	}
	if !containsAny(lower,
		"구매", "주문", "결제", "사줘", "쿠팡", "coupang",
		"사지게", "사게 해", "사게해", "구매되게", "주문되게", "결제되게",
		"buy", "purchase", "order", "checkout",
	) {
		return false
	}
	return containsAny(lower,
		"이대로", "그대로", "최종 주문", "최종 결제", "주문 버튼", "구매 버튼",
		"결제 진행", "주문 진행", "구매 진행", "계속 진행", "진행해", "진행해줘",
		"사도 돼", "사도돼",
		"사지게", "사게 해", "사게해", "구매되게", "주문되게", "결제되게",
		"go ahead", "place the order", "complete the purchase", "complete checkout",
		"buy it now", "order it now", "proceed with purchase", "proceed with the purchase",
		"proceed to purchase", "proceed to checkout", "click purchase", "click the order", "final order",
	)
}

