func purchaseExecutionFieldsFromCurrentCheckoutScreen(opts ListenOptions, locale, confirmation string) (purchaseExecutionFields, bool) {
	candidate, recentLocale, _ := shoppingCandidateForCartPrepWithLocale(opts.TargetID, "")
	if strings.TrimSpace(recentLocale) != "" {
		locale = recentLocale
	}
	capturePath := filepath.Join(os.TempDir(), fmt.Sprintf("meshclaw-checkout-final-%d.png", time.Now().UnixNano()))
	capture := shoppingCheckoutScreenCapture(context.Background(), capturePath)
	payload := map[string]interface{}{
		"kind":       "assistant_purchase_final_current_screen",
		"capture":    capture,
		"capture_at": capturePath,
		"created_at": time.Now().UTC(),
	}
	if !capture.OK {
		_, _ = evidence.Store("assistant-purchase-final-current-screen", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "purchase"), payload)
		return purchaseExecutionFields{}, false
	}
	ocrText, ocrErr := shoppingCheckoutScreenOCR(capturePath)
	payload["ocr_text"] = ocrText
	payload["ocr_error"] = ocrErr
	fields := inferCheckoutScreenFieldsFromOCRText(ocrText, candidate, capturePath)
	if checkoutScreenFieldCount(fields) == 0 {
		_, _ = evidence.Store("assistant-purchase-final-current-screen", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "purchase"), payload)
		return purchaseExecutionFields{}, false
	}
	item := checkoutProductOptionLine(fields)
	x, y, _ := parsePurchaseExecutionCoordinates(fields.Button)
	proof := purchaseButtonProofFor(locale)
	if strings.TrimSpace(capturePath) != "" {
		proof = firstNonEmpty(proof, capturePath)
	}
	purchaseFields := purchaseExecutionFields{
		Merchant:     lang.TF(locale, "assistant.shopping.service.coupang"),
		Item:         item,
		Total:        fields.Total,
		Delivery:     fields.Delivery,
		Shipping:     fields.Address,
		Payment:      fields.Payment,
		URL:          coupangCartURL(),
		Coordinate:   fields.Button,
		Proof:        proof,
		X:            x,
		Y:            y,
		Confirmation: purchaseCanonicalConfirmationFor(locale, confirmation),
	}
	payload["checkout_fields"] = fields
	payload["purchase_fields"] = purchaseFields
	_, _ = evidence.Store("assistant-purchase-final-current-screen", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, item, "purchase"), payload)
	return purchaseFields, true
}

func rememberPendingShoppingDirectPurchase(opts ListenOptions, request, query string) {
	rememberPendingShoppingDirectPurchaseWithBlocker(opts, request, query, "")
}

const directPurchasePendingReasonOneApproval = "direct_purchase_one_approval"
const directPurchasePendingReasonBlockedPrefix = "direct_purchase_blocked:"
const directPurchasePendingReasonEvidenceSep = "|evidence:"

func rememberPendingShoppingDirectPurchaseWithBlocker(opts ListenOptions, request, query, blocker string) {
	rememberPendingShoppingDirectPurchaseWithURLAndBlocker(opts, request, query, "", blocker)
}

func rememberPendingShoppingDirectPurchaseWithURLAndBlocker(opts ListenOptions, request, query, candidateURL, blocker string) {
	rememberPendingShoppingDirectPurchaseWithURLBlockerEvidence(opts, request, query, candidateURL, blocker, "")
}

func rememberPendingShoppingDirectPurchaseWithURLBlockerEvidence(opts ListenOptions, request, query, candidateURL, blocker, evidenceID string) {
	reason := directPurchasePendingReasonFor(blocker, evidenceID)
	candidateURL = strings.TrimSpace(candidateURL)
	if !isCoupangProductURL(candidateURL) {
		candidateURL = ""
	}
	rememberPendingAssistantConversation(assistantPendingKey(opts.TargetID), pendingAssistantConversation{
		Kind: "shopping_direct_purchase",
		Intent: assistantToolIntent{
			Intent:     "shopping_direct_purchase",
			Query:      strings.TrimSpace(query),
			URL:        candidateURL,
			Confidence: 0.95,
			Reason:     reason,
		},
		Request:   request,
		CreatedAt: time.Now().UTC(),
		ExpiresAt: time.Now().UTC().Add(20 * time.Minute),
	})
}

func directPurchasePendingReasonFor(blocker, evidenceID string) string {
	reason := directPurchasePendingReasonOneApproval
	if strings.TrimSpace(blocker) != "" {
		reason = directPurchasePendingReasonBlockedPrefix + strings.TrimSpace(blocker)
	}
	if id := assistantRecentReportsRequestedEvidenceID(evidenceID); id != "" {
		reason += directPurchasePendingReasonEvidenceSep + id
	}
	return reason
}

func pendingShoppingDirectPurchaseExists(targetID string) bool {
	pending, ok := takePendingAssistantConversation(assistantPendingKey(targetID), false)
	return ok && pending.Kind == "shopping_direct_purchase"
}

func clearPendingShoppingDirectPurchase(targetID string) bool {
	pending, ok := takePendingAssistantConversation(assistantPendingKey(targetID), false)
	if !ok || pending.Kind != "shopping_direct_purchase" {
		return false
	}
	takePendingAssistantConversation(assistantPendingKey(targetID), true)
	return true
}

func pendingShoppingDirectPurchaseBlocker(pending pendingAssistantConversation) string {
	reason, _ := pendingShoppingDirectPurchaseReasonParts(pending)
	if strings.HasPrefix(reason, directPurchasePendingReasonBlockedPrefix) {
		return strings.TrimSpace(strings.TrimPrefix(reason, directPurchasePendingReasonBlockedPrefix))
	}
	return ""
}

func pendingShoppingDirectPurchaseEvidenceID(pending pendingAssistantConversation) string {
	_, evidenceID := pendingShoppingDirectPurchaseReasonParts(pending)
	return evidenceID
}

func pendingShoppingDirectPurchaseReasonParts(pending pendingAssistantConversation) (string, string) {
	reason := strings.TrimSpace(pending.Intent.Reason)
	if reason == "" {
		return "", ""
	}
	base, evidenceID, ok := strings.Cut(reason, directPurchasePendingReasonEvidenceSep)
	if !ok {
		return reason, ""
	}
	return strings.TrimSpace(base), assistantRecentReportsRequestedEvidenceID(evidenceID)
}

func alignPendingShoppingDirectPurchaseToCandidate(targetID, request string, candidate browserauto.Link) bool {
	request = strings.TrimSpace(request)
	product := shoppingCandidatePurchaseQueryTitle(candidate)
	if product == "" {
		return false
	}
	key := assistantPendingKey(targetID)
	pending, ok := takePendingAssistantConversation(key, false)
	if !ok || pending.Kind != "shopping_direct_purchase" {
		return false
	}
	pending.Intent.Query = product
	pending.Intent.URL = ""
	if candidateURL := strings.TrimSpace(candidate.URL); isCoupangProductURL(candidateURL) {
		pending.Intent.URL = candidateURL
	}
	pending.Request = strings.TrimSpace(firstNonEmpty(pending.Request, request))
	if request != "" && !strings.Contains(pending.Request, request) {
		pending.Request = strings.TrimSpace(pending.Request + "\n" + request)
	}
	pending.ExpiresAt = time.Now().UTC().Add(20 * time.Minute)
	rememberPendingAssistantConversation(key, pending)
	return true
}

func shoppingCandidatePurchaseQueryTitle(candidate browserauto.Link) string {
	title := strings.TrimSpace(candidate.Text)
	if title == "" {
		return ""
	}
	if host := assistantURLHost(candidate.URL); host != "" {
		for _, suffix := range []string{
			" (" + host + ")",
			" (" + strings.TrimPrefix(host, "www.") + ")",
		} {
			title = strings.TrimSpace(strings.TrimSuffix(title, suffix))
		}
	}
	return title
}

func continueShoppingDirectPurchase(opts ListenOptions, pending pendingAssistantConversation, approvalText string) string {
	takePendingAssistantConversation(assistantPendingKey(opts.TargetID), true)
	query := strings.TrimSpace(firstNonEmpty(pending.Intent.Query, coupangShoppingQuery(pending.Request)))
	locale := shoppingSearchLocale(pending.Request)
	if normalized := lang.Normalize(locale); normalized != "" {
		locale = normalized
	}
	if query == "" {
		return coupangPurchasePrepReply()
	}
	preferredProductURL := pending.Intent.URL
	if shoppingDirectPurchaseFollowUpUsesCurrentScreen(approvalText) {
		query = directPurchaseCurrentVisibleProductSentinel
	} else if pendingShoppingDirectPurchaseShouldRetryCurrentScreen(pending) {
		preferredProductURL = directPurchaseCurrentVisibleProductSentinel
	}
	if !opts.Execute {
		return formatShoppingDirectPurchaseApprovedDryRunReplyFor(locale, query)
	}
	reply := executeShoppingDirectPurchaseApprovedReplyFor(opts, locale, query, approvalText, preferredProductURL)
	if isShoppingDirectPurchaseBlockedReply(locale, query, reply) && !pendingShoppingDirectPurchaseExists(opts.TargetID) {
		rememberPendingShoppingDirectPurchaseWithURLAndBlocker(opts, firstNonEmpty(pending.Request, query), query, pending.Intent.URL, "")
	}
	return reply
}

func pendingShoppingDirectPurchaseShouldRetryCurrentScreen(pending pendingAssistantConversation) bool {
	return strings.TrimSpace(pending.Intent.URL) == "" && strings.TrimSpace(pendingShoppingDirectPurchaseBlocker(pending)) != ""
}

func isShoppingDirectPurchaseBlockedReply(locale, query, reply string) bool {
	title := lang.TF(locale, "assistant.shopping.direct_purchase.blocked.title", directPurchaseDisplayQueryFor(locale, query))
	if strings.Contains(reply, title) {
		return true
	}
	return shoppingDirectPurchaseBlockedReplyTitlePresent(reply)
}

func shoppingDirectPurchaseBlockedReplyTitlePresent(reply string) bool {
	reply = strings.TrimSpace(reply)
	if reply == "" {
		return false
	}
	for _, locale := range []string{"ko", "en"} {
		prefix, suffix, ok := strings.Cut(lang.TF(locale, "assistant.shopping.direct_purchase.blocked.title", "__meshclaw_blocked_query__"), "__meshclaw_blocked_query__")
		if !ok || strings.TrimSpace(suffix) == "" {
			continue
		}
		if (strings.TrimSpace(prefix) == "" || strings.Contains(reply, prefix)) && strings.Contains(reply, suffix) {
			return true
		}
	}
	return false
}

const directPurchaseCurrentVisibleProductSentinel = "__meshclaw_current_visible_product__"

func isDirectPurchaseCurrentVisibleProductQuery(query string) bool {
	return strings.TrimSpace(query) == directPurchaseCurrentVisibleProductSentinel
}

func directPurchaseDisplayQueryFor(locale, query string) string {
	if isDirectPurchaseCurrentVisibleProductQuery(query) {
		return lang.TF(locale, "assistant.shopping.direct_purchase.current_visible_item")
	}
	return strings.TrimSpace(query)
}

func shoppingDirectPurchaseFollowUpUsesCurrentScreen(text string) bool {
	lower := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(text)), " "))
	if lower == "" {
		return false
	}
	compact := strings.NewReplacer(" ", "", "\t", "", "\n", "", ".", "", "!", "", "?", "", ",", "", ";", "", ":", "").Replace(lower)
	if containsAny(lower, "do not", "don't", "dont", "stop", "cancel", "abort") ||
		containsAny(compact, "하지마", "진행하지마", "진행하지말", "하지말", "중지", "멈춰", "멈추", "취소", "그만") {
		return false
	}
	koreanScreen := containsAny(compact, "현재화면", "이화면", "지금화면", "열린화면", "보이는화면", "보고있는화면", "현재상품", "이상품", "이제품", "이거", "이걸", "이것")
	koreanResume := containsAny(compact, "다시", "재시도", "계속", "이어", "이어서", "진행")
	if koreanScreen && koreanResume {
		return true
	}
	englishScreen := containsAny(lower, "current screen", "this screen", "open screen", "visible screen", "current item", "current product", "this item", "this product", "this one")
	englishResume := containsAny(lower, "try again", "retry", "continue", "resume", "go again")
	return englishScreen && englishResume
}

func executeShoppingDirectPurchaseApprovedReplyFor(opts ListenOptions, locale, query, approvalText string, preferredProductURL ...string) string {
	confirmation := purchaseCanonicalConfirmationFor(locale, approvalText)
	initialMissingLine := ""
	if fields, ok := purchaseExecutionFieldsFromCurrentCheckoutScreen(opts, locale, confirmation); ok {
		fields.Confirmation = confirmation
		if len(purchaseExecutionMissingFieldsFor(locale, fields)) == 0 {
			return executePurchaseFinalClickReplyFor(locale, fields, opts.TargetID)
		}
		initialMissingLine = purchaseExecutionMissingFieldsLineFor(locale, fields)
	}
	searchURL := ""
	actionReply := ""
	var openResult osauto.Result
	var tabCleanup osauto.Result
	var productCandidate browserauto.Link
	productCandidateSource := ""
	preferredURL := ""
	useCurrentScreen := isDirectPurchaseCurrentVisibleProductQuery(query)
	for _, rawPreferredURL := range preferredProductURL {
		if strings.TrimSpace(rawPreferredURL) == directPurchaseCurrentVisibleProductSentinel {
			useCurrentScreen = true
			continue
		}
		if preferredURL == "" && isCoupangProductURL(rawPreferredURL) {
			preferredURL = strings.TrimSpace(rawPreferredURL)
		}
	}
	if useCurrentScreen {
		actionReply = lang.TF(locale, "assistant.shopping.direct_purchase.execute.current_screen")
	} else {
		tabCleanup = cleanupCoupangTabsForNewWork(opts)
		if preferredURL != "" {
			productCandidate = browserauto.Link{Text: query, URL: preferredURL}
			productCandidateSource = "pending_selected_candidate"
		} else if recentCandidate, ok := recentShoppingProductCandidateForDirectPurchase(opts.TargetID, query); ok {
			productCandidate = recentCandidate
			productCandidateSource = "recent_signal_history"
		} else if candidates := shoppingDirectPurchaseProductCandidates(context.Background(), query, 1); len(candidates) > 0 && strings.TrimSpace(candidates[0].URL) != "" {
			productCandidate = candidates[0]
			productCandidateSource = "live_product_search"
		}
		if strings.TrimSpace(productCandidate.URL) != "" {
			searchURL = strings.TrimSpace(productCandidate.URL)
			openResult = shoppingDirectPurchaseOpenURL(context.Background(), searchURL)
			if openResult.OK {
				if productCandidateSource == "pending_selected_candidate" {
					actionReply = lang.TF(locale, "assistant.shopping.direct_purchase.execute.opened_selected_product", searchURL)
				} else {
					actionReply = lang.TF(locale, "assistant.shopping.direct_purchase.execute.opened_product", searchURL)
				}
			} else {
				if strings.TrimSpace(openResult.Error) != "" {
					actionReply = lang.TF(locale, "assistant.shopping.direct_purchase.execute.open_failed", openResult.Error)
				}
				searchURL = ""
			}
		}
		if searchURL == "" {
			searchURL = coupangSearchURL(query)
			openResult = shoppingDirectPurchaseOpenURL(context.Background(), searchURL)
			if openResult.OK {
				actionReply = lang.TF(locale, "assistant.shopping.direct_purchase.execute.opened", searchURL)
			} else if strings.TrimSpace(openResult.Error) != "" {
				actionReply = lang.TF(locale, "assistant.shopping.direct_purchase.execute.open_failed", openResult.Error)
			}
		}
	}
	payload := map[string]interface{}{
		"kind":        "assistant_direct_purchase_approved",
		"query":       query,
		"search_url":  searchURL,
		"approval":    confirmation,
		"action":      actionReply,
		"open_result": openResult,
		"created_at":  time.Now().UTC(),
		"target_id":   opts.TargetID,
		"max_steps":   5,
		"final_click": false,
	}
	if tabCleanup.Kind != "" {
		payload["tab_cleanup"] = tabCleanup
	}
	if strings.TrimSpace(productCandidate.URL) != "" || strings.TrimSpace(productCandidate.Text) != "" {
		payload["product_candidate"] = productCandidate
		payload["product_candidate_source"] = productCandidateSource
	}
	record, storeErr := evidence.Store("assistant-direct-purchase-approved-start", firstNonEmpty(opts.TargetID, "assistant"), query, payload)
	displayQuery := directPurchaseDisplayQueryFor(locale, query)
	stepLines := []string{lang.TF(locale, "assistant.shopping.direct_purchase.execute.title", displayQuery)}
	if strings.TrimSpace(actionReply) != "" {
		stepLines = append(stepLines, "", lang.TF(locale, "assistant.shopping.coupang.action_title"), strings.TrimSpace(actionReply))
	}
	evidenceRef := signalEvidenceRef(record)
	if evidenceRef != "" {
		stepLines = append(stepLines, lang.TF(locale, "assistant.shopping.direct_purchase.execute.evidence", evidenceRef))
	}
	if storeErr != nil {
		stepLines = append(stepLines, lang.TF(locale, "assistant.shopping.final_execution.executed.evidence_error", storeErr.Error()))
	}
	stepLines = appendDirectPurchaseUniqueStepLine(stepLines, initialMissingLine)
	for step := 0; step < 5; step++ {
		time.Sleep(1 * time.Second)
		if fields, ok := purchaseExecutionFieldsFromCurrentCheckoutScreen(opts, locale, confirmation); ok {
			fields.Confirmation = confirmation
			missingLine := purchaseExecutionMissingFieldsLineFor(locale, fields)
			if missingLine == "" {
				if len(stepLines) > 0 {
					_, _ = evidence.Store("assistant-direct-purchase-approved-steps", firstNonEmpty(opts.TargetID, "assistant"), query, map[string]interface{}{
						"query": query,
						"steps": stepLines,
					})
				}
				return formatShoppingDirectPurchaseFinalReplyFor(locale, stepLines, executePurchaseFinalClickReplyFor(locale, fields, opts.TargetID))
			}
			stepLines = appendDirectPurchaseUniqueStepLine(stepLines, missingLine)
		}
		advance, ok := directPurchaseAdvanceCurrentScreen(opts, locale, query, step)
		if !ok {
			stepLines = appendDirectPurchaseStepLine(stepLines, lang.TF(locale, "assistant.shopping.direct_purchase.execute.waiting"))
			continue
		}
		stepLines = appendDirectPurchaseStepLine(stepLines, advance.Line)
		if advance.Blocked {
			rememberPendingShoppingDirectPurchaseWithURLBlockerEvidence(opts, firstNonEmpty(query, approvalText), query, firstNonEmpty(preferredURL, productCandidate.URL), advance.Blocker, evidenceRef)
			return formatShoppingDirectPurchaseBlockedReplyFor(locale, query, stepLines, advance.Blocker)
		}
	}
	rememberPendingShoppingDirectPurchaseWithURLBlockerEvidence(opts, firstNonEmpty(query, approvalText), query, firstNonEmpty(preferredURL, productCandidate.URL), directPurchaseBlockerNotReady, evidenceRef)
	return formatShoppingDirectPurchaseBlockedReplyFor(locale, query, stepLines, lang.TF(locale, "assistant.shopping.direct_purchase.blocker.not_ready"))
}

func purchaseExecutionMissingFieldsLineFor(locale string, fields purchaseExecutionFields) string {
	missing := purchaseExecutionMissingFieldsFor(locale, fields)
	if len(missing) == 0 {
		return ""
	}
	return lang.TF(locale, "assistant.shopping.final_execution.missing.fields", strings.Join(missing, ", "))
}

func appendDirectPurchaseUniqueStepLine(lines []string, line string) []string {
	line = strings.TrimSpace(line)
	if line == "" {
		return lines
	}
	for _, existing := range lines {
		if strings.TrimSpace(existing) == line {
			return lines
		}
	}
	return appendDirectPurchaseStepLine(lines, line)
}

func appendDirectPurchaseStepLine(lines []string, line string) []string {
	line = strings.TrimSpace(line)
	if line == "" {
		return lines
	}
	for i := len(lines) - 1; i >= 0; i-- {
		if strings.TrimSpace(lines[i]) == "" {
			continue
		}
		if strings.TrimSpace(lines[i]) == line {
			return lines
		}
		break
	}
	return append(lines, line)
}

type directPurchaseAdvance struct {
	Line    string
	Blocker string
	Blocked bool
}

func directPurchaseAdvanceCurrentScreen(opts ListenOptions, locale, query string, step int) (directPurchaseAdvance, bool) {
	capturePath := filepath.Join(os.TempDir(), fmt.Sprintf("meshclaw-direct-purchase-%d-%d.png", time.Now().UnixNano(), step))
	capture := shoppingCheckoutScreenCapture(context.Background(), capturePath)
	payload := map[string]interface{}{
		"kind":       "assistant_direct_purchase_advance_screen",
		"query":      query,
		"step":       step,
		"capture":    capture,
		"capture_at": capturePath,
		"created_at": time.Now().UTC(),
	}
	if !capture.OK {
		payload["blocker"] = firstNonEmpty(capture.Error, "screen capture failed")
		_, _ = evidence.Store("assistant-direct-purchase-advance-screen", firstNonEmpty(opts.TargetID, "assistant"), query, payload)
		return directPurchaseAdvance{Line: lang.TF(locale, "assistant.shopping.direct_purchase.execute.capture_failed", firstNonEmpty(capture.Error, "unknown error")), Blocker: firstNonEmpty(capture.Error, "screen capture failed"), Blocked: true}, true
	}
	ocrText, ocrErr := shoppingCheckoutScreenOCR(capturePath)
	payload["ocr_text"] = ocrText
	payload["ocr_error"] = strings.TrimSpace(ocrErr)
	action, ok := inferDirectPurchaseScreenAction(ocrText, capturePath)
	payload["screen_action"] = action
	_, _ = evidence.Store("assistant-direct-purchase-advance-screen", firstNonEmpty(opts.TargetID, "assistant"), query, payload)
	if !ok {
		return directPurchaseAdvance{Line: lang.TF(locale, "assistant.shopping.direct_purchase.execute.screen_unknown")}, true
	}
	if action.Blocker != "" {
		displayBlocker := directPurchaseBlockerDisplayFor(locale, action.Blocker)
		return directPurchaseAdvance{Line: lang.TF(locale, "assistant.shopping.direct_purchase.execute.blocked", displayBlocker), Blocker: action.Blocker, Blocked: true}, true
	}
	actionLabel := directPurchaseScreenActionLabelFor(locale, action)
	if action.Kind == "cart_added_open_cart" {
		openResult := shoppingDirectPurchaseOpenURL(context.Background(), coupangCartURL())
		openPayload := map[string]interface{}{
			"kind":        "assistant_direct_purchase_advance_open_cart",
			"query":       query,
			"step":        step,
			"label":       actionLabel,
			"action":      action.Kind,
			"open_result": openResult,
			"created_at":  time.Now().UTC(),
		}
		_, _ = evidence.Store("assistant-direct-purchase-advance-open-cart", firstNonEmpty(opts.TargetID, "assistant"), query, openPayload)
		if !openResult.OK {
			blocker := firstNonEmpty(openResult.Error, "open cart failed")
			return directPurchaseAdvance{Line: lang.TF(locale, "assistant.shopping.direct_purchase.execute.open_cart_failed", blocker), Blocker: blocker, Blocked: true}, true
		}
		return directPurchaseAdvance{Line: lang.TF(locale, "assistant.shopping.direct_purchase.execute.opened_cart", coupangCartURL())}, true
	}
	click := shoppingMouseClick(context.Background(), directPurchaseRunnerURL(), float64(action.X), float64(action.Y))
	clickPayload := map[string]interface{}{
		"kind":       "assistant_direct_purchase_advance_click",
		"query":      query,
		"step":       step,
		"label":      actionLabel,
		"action":     action.Kind,
		"x":          action.X,
		"y":          action.Y,
		"click":      click,
		"created_at": time.Now().UTC(),
	}
	_, _ = evidence.Store("assistant-direct-purchase-advance-click", firstNonEmpty(opts.TargetID, "assistant"), query, clickPayload)
	if !click.OK {
		blocker := firstNonEmpty(click.Error, "mouse click failed")
		return directPurchaseAdvance{Line: lang.TF(locale, "assistant.shopping.direct_purchase.execute.click_failed", actionLabel, blocker), Blocker: blocker, Blocked: true}, true
	}
	return directPurchaseAdvance{Line: lang.TF(locale, "assistant.shopping.direct_purchase.execute.clicked", actionLabel)}, true
}

type directPurchaseScreenAction struct {
	Kind    string `json:"kind"`
	Label   string `json:"label"`
	X       int    `json:"x"`
	Y       int    `json:"y"`
	Blocker string `json:"blocker,omitempty"`
}

const directPurchaseBlockerMacOSPermission = "macos_permission_prompt"
const directPurchaseBlockerNotReady = "not_ready"
const directPurchaseBlockerCaptcha = "captcha"
const directPurchaseBlockerIdentity = "identity_verification"
const directPurchaseBlockerLogin = "login_required"
const directPurchaseBlockerPaymentAuth = "payment_authentication"

func directPurchaseScreenActionLabelFor(locale string, action directPurchaseScreenAction) string {
	switch action.Kind {
	case "search_result", "reorder_buy_again", "cart_added_open_cart", "product_cart_add", "cart_checkout", "product_buy":
		return lang.TF(locale, "assistant.shopping.direct_purchase.action."+action.Kind)
	default:
		return strings.TrimSpace(action.Label)
	}
}

func inferDirectPurchaseScreenAction(ocrText, capturePath string) (directPurchaseScreenAction, bool) {
	normalized := strings.ToLower(strings.Join(strings.Fields(ocrText), " "))
	if normalized == "" {
		return directPurchaseScreenAction{}, false
	}
	if blocker := directPurchaseScreenBlocker(normalized); blocker != "" {
		return directPurchaseScreenAction{Kind: "blocked", Label: "blocked", Blocker: blocker}, true
	}
	width, height := checkoutScreenPointSize(capturePath)
	if directPurchaseOCRShowsSearchResults(normalized) {
		x, y := estimateDirectPurchaseFirstResultCoordinate(width, height)
		return directPurchaseScreenAction{Kind: "search_result", Label: "첫 번째 상품", X: x, Y: y}, true
	}
	if directPurchaseOCRShowsReorderCTA(normalized) {
		x, y := estimateDirectPurchaseReorderCoordinate(width, height)
		return directPurchaseScreenAction{Kind: "reorder_buy_again", Label: "재구매/다시 구매 버튼", X: x, Y: y}, true
	}
	if shoppingCartAddOCRShowsAdded(normalized) {
		return directPurchaseScreenAction{Kind: "cart_added_open_cart", Label: "장바구니 페이지"}, true
	}
	if shoppingCartAddOCRShowsAddToCartCTA(normalized) {
		x, y := estimateShoppingCartAddCoordinate(width, height)
		return directPurchaseScreenAction{Kind: "product_cart_add", Label: "장바구니 담기", X: x, Y: y}, true
	}
	if directPurchaseOCRShowsCartCheckoutCTA(normalized) {
		x, y := estimateDirectPurchaseCartCheckoutCoordinate(width, height)
		return directPurchaseScreenAction{Kind: "cart_checkout", Label: "주문/결제 진행 버튼", X: x, Y: y}, true
	}
	if directPurchaseOCRShowsProductBuyCTA(normalized) {
		x, y := estimateDirectPurchaseProductBuyCoordinate(width, height)
		return directPurchaseScreenAction{Kind: "product_buy", Label: "바로구매/구매 버튼", X: x, Y: y}, true
	}
	return directPurchaseScreenAction{}, false
}

func directPurchaseScreenBlocker(normalized string) string {
	switch {
	case directPurchaseMacOSPermissionPrompt(normalized):
		return directPurchaseBlockerMacOSPermission
	case containsAny(normalized, "captcha", "자동입력", "보안문자", "로봇이 아닙니다"):
		return directPurchaseBlockerCaptcha
	case containsAny(normalized, "본인인증", "휴대폰 인증", "인증번호", "identity verification", "verification code"):
		return directPurchaseBlockerIdentity
	case directPurchaseLoginRequired(normalized):
		return directPurchaseBlockerLogin
	case containsAny(normalized, "cvc", "보안코드", "결제 비밀번호", "payment password", "security code"):
		return directPurchaseBlockerPaymentAuth
	default:
		return ""
	}
}

func directPurchaseMacOSPermissionPrompt(normalized string) bool {
	if normalized == "" {
		return false
	}
	controlPrompt := containsAny(normalized,
		"제어하려고 합니다", "제어를 허용", "제어 권한", "컴퓨터를 제어",
		"would like to control", "wants to control", "access to control", "control your computer",
	)
	permissionChoice := containsAny(normalized,
		"허용 안 함", "허용하지 않음", "허용", "don't allow", "dont allow", "allow",
	)
	if controlPrompt && permissionChoice {
		return true
	}
	systemPrivacyPrompt := containsAny(normalized,
		"손쉬운 사용", "화면 기록", "시스템 설정", "개인정보 보호",
		"accessibility", "screen recording", "system settings", "privacy & security",
	)
	return systemPrivacyPrompt && containsAny(normalized, "meshclaw", "terminal", "finder", "osascript")
}

func directPurchaseBlockerDisplayFor(locale, blocker string) string {
	switch blocker {
	case directPurchaseBlockerMacOSPermission:
		return lang.TF(locale, "assistant.shopping.direct_purchase.blocker.macos_permission")
	case directPurchaseBlockerNotReady:
		return lang.TF(locale, "assistant.shopping.direct_purchase.blocker.not_ready")
	case directPurchaseBlockerCaptcha, "CAPTCHA/보안문자":
		return lang.TF(locale, "assistant.shopping.direct_purchase.blocker.captcha")
	case directPurchaseBlockerIdentity, "본인인증":
		return lang.TF(locale, "assistant.shopping.direct_purchase.blocker.identity")
	case directPurchaseBlockerLogin, "로그인/비밀번호":
		return lang.TF(locale, "assistant.shopping.direct_purchase.blocker.login")
	case directPurchaseBlockerPaymentAuth, "결제 인증":
		return lang.TF(locale, "assistant.shopping.direct_purchase.blocker.payment_auth")
	default:
		return blocker
	}
}

