func executeShoppingCandidateCartAddClick(opts ListenOptions, locale string, candidate browserauto.Link) ([]string, []string) {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	time.Sleep(1 * time.Second)
	capturePath := filepath.Join(os.TempDir(), fmt.Sprintf("meshclaw-cart-add-%d.png", time.Now().UnixNano()))
	capture := shoppingCheckoutScreenCapture(context.Background(), capturePath)
	payload := map[string]interface{}{
		"kind":       "assistant_shopping_cart_add_execute",
		"candidate":  candidate,
		"capture":    capture,
		"capture_at": capturePath,
		"created_at": time.Now().UTC(),
		"target_id":  opts.TargetID,
	}
	proofs := []string{}
	if capture.OK && strings.TrimSpace(capturePath) != "" {
		proofs = append(proofs, capturePath)
	}
	if !capture.OK {
		payload["blocker"] = firstNonEmpty(capture.Error, "screen capture failed")
		_, _ = evidence.Store("assistant-shopping-cart-add-execute", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "cart-add"), payload)
		return []string{t("assistant.shopping.cart_add.capture_failed", firstNonEmpty(capture.Error, "screen capture failed"))}, proofs
	}
	ocrText, ocrErr := shoppingCheckoutScreenOCR(capturePath)
	payload["ocr_text"] = ocrText
	payload["ocr_error"] = strings.TrimSpace(ocrErr)
	action, ok := inferShoppingCartAddScreenAction(ocrText, capturePath)
	payload["screen_action"] = action
	if !ok {
		_, _ = evidence.Store("assistant-shopping-cart-add-execute", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "cart-add"), payload)
		return []string{t("assistant.shopping.cart_add.not_found")}, proofs
	}
	if action.Blocker != "" {
		payload["blocker"] = action.Blocker
		_, _ = evidence.Store("assistant-shopping-cart-add-execute", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "cart-add"), payload)
		return []string{t("assistant.shopping.cart_add.blocked", action.Blocker)}, proofs
	}
	if action.Kind == "cart_added" {
		payload["already_added"] = true
		record, _ := evidence.Store("assistant-shopping-cart-add-execute", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "cart-add"), payload)
		lines := []string{t("assistant.shopping.cart_add.already_added")}
		return appendShoppingCartAddEvidenceLines(locale, lines, record), proofs
	}
	click := shoppingMouseClick(context.Background(), directPurchaseRunnerURL(), float64(action.X), float64(action.Y))
	payload["click"] = click
	payload["click_action"] = action.Kind
	payload["click_label"] = action.Label
	payload["click_x"] = action.X
	payload["click_y"] = action.Y
	if !click.OK {
		payload["blocker"] = firstNonEmpty(click.Error, "mouse click failed")
		record, _ := evidence.Store("assistant-shopping-cart-add-execute", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "cart-add"), payload)
		lines := []string{t("assistant.shopping.cart_add.click_failed", firstNonEmpty(click.Error, "mouse click failed"))}
		return appendShoppingCartAddEvidenceLines(locale, lines, record), proofs
	}
	time.Sleep(1 * time.Second)
	proofPath := filepath.Join(os.TempDir(), fmt.Sprintf("meshclaw-cart-add-proof-%d.png", time.Now().UnixNano()))
	proofCapture := shoppingCheckoutScreenCapture(context.Background(), proofPath)
	payload["proof_capture"] = proofCapture
	payload["proof_capture_at"] = proofPath
	if proofCapture.OK && strings.TrimSpace(proofPath) != "" {
		proofs = append(proofs, proofPath)
		proofOCR, proofOCRErr := shoppingCheckoutScreenOCR(proofPath)
		payload["proof_ocr_text"] = proofOCR
		payload["proof_ocr_error"] = strings.TrimSpace(proofOCRErr)
		if shoppingCartAddOCRShowsAdded(strings.ToLower(strings.Join(strings.Fields(proofOCR), " "))) {
			record, _ := evidence.Store("assistant-shopping-cart-add-execute", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "cart-add"), payload)
			lines := []string{
				t("assistant.shopping.cart_add.clicked"),
				t("assistant.shopping.cart_add.confirmed"),
			}
			return appendShoppingCartAddEvidenceLines(locale, lines, record), proofs
		}
	}
	record, _ := evidence.Store("assistant-shopping-cart-add-execute", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "cart-add"), payload)
	lines := []string{
		t("assistant.shopping.cart_add.clicked"),
		t("assistant.shopping.cart_add.confirmation_unknown"),
	}
	return appendShoppingCartAddEvidenceLines(locale, lines, record), proofs
}

func appendShoppingCartAddEvidenceLines(locale string, lines []string, record evidence.Record) []string {
	return appendShoppingEvidenceDashboardLines(locale, lines, record, "assistant.shopping.cart_add.evidence", "assistant.shopping.cart_add.evidence_dashboard")
}

func appendShoppingEvidenceDashboardLines(locale string, lines []string, record evidence.Record, evidenceKey, dashboardKey string) []string {
	evidenceRef := signalEvidenceRef(record)
	if evidenceRef == "" {
		return lines
	}
	lines = append(lines, lang.TF(locale, evidenceKey, evidenceRef))
	lines = append(lines, lang.TF(locale, dashboardKey, assistantDashboardEvidenceURL(evidenceRef)))
	return lines
}

func inferShoppingCartAddScreenAction(ocrText, capturePath string) (directPurchaseScreenAction, bool) {
	normalized := strings.ToLower(strings.Join(strings.Fields(ocrText), " "))
	if normalized == "" {
		return directPurchaseScreenAction{}, false
	}
	if blocker := directPurchaseScreenBlocker(normalized); blocker != "" {
		return directPurchaseScreenAction{Kind: "blocked", Label: "blocked", Blocker: blocker}, true
	}
	if shoppingCartAddOCRShowsAdded(normalized) {
		return directPurchaseScreenAction{Kind: "cart_added", Label: "cart_added"}, true
	}
	if !shoppingCartAddOCRShowsAddToCartCTA(normalized) {
		return directPurchaseScreenAction{}, false
	}
	width, height := checkoutScreenPointSize(capturePath)
	x, y := estimateShoppingCartAddCoordinate(width, height)
	return directPurchaseScreenAction{Kind: "cart_add", Label: "장바구니 담기", X: x, Y: y}, true
}

