func formatShoppingDirectPurchaseOneApprovalReplyFor(locale, query, actionReply string) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	displayQuery := directPurchaseDisplayQueryFor(locale, query)
	lines := []string{
		t("assistant.shopping.direct_purchase.confirm.title"),
		t("assistant.shopping.direct_purchase.confirm.item", displayQuery),
		t("assistant.shopping.direct_purchase.confirm.one"),
		t("assistant.shopping.direct_purchase.confirm.execute"),
	}
	if strings.TrimSpace(actionReply) != "" {
		lines = append(lines, "", t("assistant.shopping.coupang.action_title"), strings.TrimSpace(actionReply))
	}
	return strings.Join(lines, "\n")
}

func formatShoppingDirectPurchaseApprovedDryRunReplyFor(locale, query string) string {
	displayQuery := directPurchaseDisplayQueryFor(locale, query)
	return strings.Join([]string{
		lang.TF(locale, "assistant.shopping.direct_purchase.approved.title", displayQuery),
		lang.TF(locale, "assistant.shopping.direct_purchase.approved.dry_run"),
	}, "\n")
}

func formatShoppingDirectPurchaseFinalReplyFor(locale string, stepLines []string, finalReply string) string {
	finalReply = strings.TrimSpace(finalReply)
	if len(stepLines) == 0 {
		return finalReply
	}
	lines := []string{}
	if finalReply != "" {
		lines = append(lines, finalReply, "")
	}
	lines = append(lines, lang.TF(locale, "assistant.shopping.direct_purchase.blocked.steps"))
	lines = append(lines, stepLines...)
	return strings.Join(lines, "\n")
}

func formatShoppingDirectPurchaseBlockedReplyFor(locale, query string, stepLines []string, blocker string) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	displayQuery := directPurchaseDisplayQueryFor(locale, query)
	lines := []string{
		t("assistant.shopping.direct_purchase.blocked.title", displayQuery),
		t("assistant.shopping.direct_purchase.blocked.reason", firstNonEmpty(directPurchaseBlockerDisplayFor(locale, blocker), t("assistant.shopping.direct_purchase.blocker.not_ready"))),
	}
	if hint := directPurchaseBlockerUserHintFor(locale, blocker); hint != "" {
		lines = append(lines, t("assistant.shopping.direct_purchase.blocked.user_hint", hint))
	}
	if len(stepLines) > 0 {
		lines = append(lines, "", t("assistant.shopping.direct_purchase.blocked.steps"))
		lines = append(lines, stepLines...)
	}
	evidenceCheck := t("assistant.shopping.direct_purchase.blocked.evidence_check")
	if evidenceID := assistantRecentReportsRequestedEvidenceID(strings.Join(stepLines, "\n")); evidenceID != "" {
		evidenceCheck = t("assistant.shopping.direct_purchase.blocked.evidence_check_with_id", evidenceID, evidenceID)
	}
	lines = append(lines,
		"",
		t("assistant.shopping.direct_purchase.blocked.one_approval"),
		t("assistant.shopping.direct_purchase.blocked.retry_plan"),
		evidenceCheck,
		t("assistant.shopping.direct_purchase.blocked.next"),
	)
	return strings.Join(lines, "\n")
}

