func recentCoupangShoppingContext(targetID string) bool {
	targetID = strings.TrimSpace(targetID)
	if targetID == "" {
		return false
	}
	for _, msg := range loadSignalHistory(targetID, 8) {
		visible := strings.ToLower(signalReplyVisibleText(msg.Content))
		if containsAny(visible, "쿠팡", "coupang") &&
			containsAny(visible,
				"구매", "주문", "결제", "장바구니", "배송지", "주소지",
				"purchase", "order", "checkout", "cart", "shipping address", "payment method",
			) {
			return true
		}
	}
	return false
}

