func directPurchaseKoreanImperativeQuery(text string) string {
	cleaned := strings.NewReplacer("\t", " ", "\n", " ", ".", "", "!", "", "?", "", "。", "", "！", "", "？", "").Replace(strings.TrimSpace(text))
	cleaned = strings.Join(strings.Fields(cleaned), " ")
	if cleaned == "" || !assistantCheckoutPrepContainsHangul(cleaned) {
		return ""
	}
	if directPurchaseKoreanCurrentVisibleProductRequest(cleaned) {
		return directPurchaseCurrentVisibleProductSentinel
	}
	for _, suffix := range []string{
		"주문 넣어 주세요", "주문 넣어주세요", "주문 넣어 줘요", "주문 넣어줘요", "주문 넣어 줘", "주문 넣어줘",
		"구매되게 해 주세요", "구매되게 해주세요", "구매되게 해줘요", "구매되게 해줘", "구매되게 해", "구매되게해줘", "구매되게해",
		"구입되게 해 주세요", "구입되게 해주세요", "구입되게 해줘요", "구입되게 해줘", "구입되게 해", "구입되게해줘", "구입되게해",
		"주문되게 해 주세요", "주문되게 해주세요", "주문되게 해줘요", "주문되게 해줘", "주문되게 해", "주문되게해줘", "주문되게해",
		"결제되게 해 주세요", "결제되게 해주세요", "결제되게 해줘요", "결제되게 해줘", "결제되게 해", "결제되게해줘", "결제되게해",
		"사지게 해 주세요", "사지게 해주세요", "사지게 해줘요", "사지게 해줘", "사지게 해", "사지게해줘", "사지게해",
		"사게 해 주세요", "사게 해주세요", "사게 해줘요", "사게 해줘", "사게 해", "사게해줘", "사게해",
		"구매해 주세요", "구매해주세요", "구매 해줘요", "구매해줘요", "구매 해줘", "구매해줘", "구매 해", "구매해",
		"구입해 주세요", "구입해주세요", "구입 해줘요", "구입해줘요", "구입 해줘", "구입해줘", "구입 해", "구입해",
		"주문해 주세요", "주문해주세요", "주문 해줘요", "주문해줘요", "주문 해줘", "주문해줘", "주문 해", "주문해",
		"사다 주세요", "사다주세요", "사다 줘요", "사다줘요", "사다 줘", "사다줘",
		"사 주세요", "사주세요", "사 줘요", "사줘요", "사 줘", "사줘", "사라", "사",
	} {
		if !strings.HasSuffix(cleaned, suffix) {
			continue
		}
		query := cleanDirectPurchaseKoreanQuery(strings.TrimSpace(strings.TrimSuffix(cleaned, suffix)))
		if len([]rune(strings.ReplaceAll(query, " ", ""))) < 2 {
			return ""
		}
		if containsAny(query, "회사", "의사", "검사", "기사", "역사") {
			return ""
		}
		return query
	}
	return ""
}

