func coupangShoppingPrepReplyFor(locale, actionReply, query string, candidates ...browserauto.Link) string {
	query = strings.TrimSpace(query)
	searchURL := coupangSearchURL(query)
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	lines := []string{
		t("assistant.shopping.coupang.title"),
		t("assistant.shopping.coupang.query", firstNonEmpty(query, t("assistant.shopping.coupang.query_missing"))),
		t("assistant.shopping.coupang.link", searchURL),
		"",
		t("assistant.shopping.coupang.candidates_title"),
	}
	candidates = assistantShoppingCandidateLines(candidates, 3)
	if len(candidates) == 0 {
		lines = append(lines, "- "+t("assistant.shopping.coupang.candidate_unavailable"))
	} else {
		for i, candidate := range candidates {
			lines = append(lines, t("assistant.shopping.coupang.candidate_line", i+1, firstNonEmpty(strings.TrimSpace(candidate.Text), t("assistant.shopping.product_fallback.candidate"))))
			if strings.TrimSpace(candidate.URL) != "" {
				lines = append(lines, t("assistant.shopping.coupang.candidate_link", strings.TrimSpace(candidate.URL)))
			}
			lines = append(lines, t("assistant.shopping.coupang.candidate_note"))
		}
	}
	lines = append(lines,
		"",
		t("assistant.shopping.coupang.checklist_title"),
		"1. "+t("assistant.shopping.coupang.check.rocket"),
		"2. "+t("assistant.shopping.coupang.check.unit_price"),
		"3. "+t("assistant.shopping.coupang.check.review"),
		"4. "+t("assistant.shopping.coupang.check.option"),
		"",
		t("assistant.shopping.coupang.next_title"),
		"- "+t("assistant.shopping.coupang.next.compare"),
		"- "+t("assistant.shopping.coupang.next.detail"),
		"- "+t("assistant.shopping.coupang.next.cart"),
		"",
		t("assistant.shopping.coupang.boundary"),
	)
	if strings.TrimSpace(actionReply) != "" {
		lines = append(lines, "", t("assistant.shopping.coupang.action_title"), strings.TrimSpace(actionReply))
	}
	return strings.Join(lines, "\n")
}

func coupangShoppingCandidates(ctx context.Context, query string, limit int) []browserauto.Link {
	query = strings.TrimSpace(query)
	if query == "" || assistantEnvTruthy(os.Getenv("MESHCLAW_SHOPPING_SEARCH_DISABLE")) {
		return nil
	}
	if limit <= 0 {
		limit = 3
	}
	search, err := browserauto.Search(ctx, browserauto.SearchOptions{
		Query:   "site:coupang.com " + query + " 쿠팡 로켓배송 가격 리뷰",
		Limit:   limit * 3,
		Timeout: 8,
	})
	if err != nil {
		return nil
	}
	if productCandidates := assistantShoppingProductCandidateLines(search.Results, limit); len(productCandidates) > 0 {
		return productCandidates
	}
	return assistantShoppingCandidateLines(search.Results, limit)
}

func assistantShoppingCandidateLines(candidates []browserauto.Link, limit int) []browserauto.Link {
	if limit <= 0 {
		limit = 3
	}
	out := []browserauto.Link{}
	seen := map[string]bool{}
	for _, candidate := range candidates {
		title := strings.TrimSpace(candidate.Text)
		link := strings.TrimSpace(candidate.URL)
		if title == "" {
			continue
		}
		key := strings.ToLower(title + " " + link)
		if seen[key] {
			continue
		}
		seen[key] = true
		if link != "" {
			if host := assistantURLHost(link); host != "" && !strings.Contains(strings.ToLower(title), strings.ToLower(host)) {
				title += " (" + host + ")"
			}
		}
		out = append(out, browserauto.Link{Text: trimForContext(title, 120), URL: link})
		if len(out) >= limit {
			break
		}
	}
	return out
}

func coupangShoppingProductCandidates(ctx context.Context, query string, limit int) []browserauto.Link {
	query = strings.TrimSpace(query)
	if query == "" || assistantEnvTruthy(os.Getenv("MESHCLAW_SHOPPING_SEARCH_DISABLE")) {
		return nil
	}
	if limit <= 0 {
		limit = 1
	}
	search, err := browserauto.Search(ctx, browserauto.SearchOptions{
		Query:   "site:coupang.com/vp/products " + query + " 쿠팡 로켓배송 가격 리뷰",
		Limit:   limit * 6,
		Timeout: 8,
	})
	if err != nil {
		return nil
	}
	return assistantShoppingProductCandidateLines(search.Results, limit)
}

func assistantShoppingProductCandidateLines(candidates []browserauto.Link, limit int) []browserauto.Link {
	if limit <= 0 {
		limit = 3
	}
	filtered := []browserauto.Link{}
	for _, candidate := range candidates {
		if !isCoupangProductURL(candidate.URL) {
			continue
		}
		filtered = append(filtered, candidate)
	}
	return assistantShoppingCandidateLines(filtered, limit)
}

func isCoupangProductURL(rawURL string) bool {
	rawURL = strings.TrimSpace(rawURL)
	if rawURL == "" {
		return false
	}
	parsed, err := url.Parse(rawURL)
	if err != nil {
		return false
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return false
	}
	host := strings.ToLower(parsed.Hostname())
	if host == "" || (host != "coupang.com" && host != "www.coupang.com" && !strings.HasSuffix(host, ".coupang.com")) {
		return false
	}
	path := strings.ToLower(parsed.EscapedPath())
	if strings.Contains(path, "/np/search") || strings.Contains(path, "/np/campaign") || strings.Contains(path, "/np/categories") {
		return false
	}
	if strings.Contains(path, "/vp/products/") || strings.Contains(path, "/np/products/") || strings.Contains(path, "/products/") {
		return true
	}
	query := parsed.Query()
	return query.Get("itemId") != "" && query.Get("vendorItemId") != ""
}

func recentShoppingProductCandidateForDirectPurchase(targetID, query string) (browserauto.Link, bool) {
	query = strings.TrimSpace(query)
	if targetID == "" || query == "" || isDirectPurchaseCurrentVisibleProductQuery(query) {
		return browserauto.Link{}, false
	}
	if candidate, _, ok := latestShoppingSelectionFromHistoryWithLocale(targetID); ok &&
		isCoupangProductURL(candidate.URL) &&
		shoppingDirectPurchaseCandidateMatchesQuery(query, "", candidate) {
		return candidate, true
	}
	if candidate, _, ok := latestShoppingDetailFromHistoryWithLocale(targetID); ok &&
		isCoupangProductURL(candidate.URL) &&
		shoppingDirectPurchaseCandidateMatchesQuery(query, "", candidate) {
		return candidate, true
	}
	recentQuery, candidates, _, ok := latestShoppingCandidatesFromHistoryWithLocale(targetID)
	if !ok || !shoppingDirectPurchaseQueryTokensMatch(query, recentQuery) {
		return browserauto.Link{}, false
	}
	for _, candidate := range candidates {
		if isCoupangProductURL(candidate.URL) && shoppingDirectPurchaseCandidateMatchesQuery(query, recentQuery, candidate) {
			return candidate, true
		}
	}
	return browserauto.Link{}, false
}

func shoppingDirectPurchaseCandidateMatchesQuery(query, recentQuery string, candidate browserauto.Link) bool {
	haystack := strings.Join([]string{recentQuery, candidate.Text}, " ")
	return shoppingDirectPurchaseQueryTokensMatch(query, haystack)
}

func shoppingDirectPurchaseQueryTokensMatch(query, haystack string) bool {
	tokens := shoppingDirectPurchaseMatchTokens(query)
	if len(tokens) == 0 {
		return false
	}
	normalizedHaystack := strings.Join(shoppingDirectPurchaseMatchTokens(haystack), " ")
	if normalizedHaystack == "" {
		return false
	}
	for _, token := range tokens {
		if !strings.Contains(normalizedHaystack, token) {
			return false
		}
	}
	return true
}

func shoppingDirectPurchaseMatchTokens(value string) []string {
	value = strings.ToLower(strings.TrimSpace(value))
	if value == "" {
		return nil
	}
	replacer := strings.NewReplacer(
		"\t", " ", "\n", " ", "\r", " ",
		",", " ", ".", " ", "!", " ", "?", " ", ":", " ", ";", " ",
		"(", " ", ")", " ", "[", " ", "]", " ", "{", " ", "}", " ",
		"/", " ", "|", " ", "-", " ", "_", " ",
	)
	value = replacer.Replace(value)
	skip := map[string]bool{
		"쿠팡": true, "로켓": true, "로켓배송": true, "배송": true, "상품": true, "제품": true,
		"구매": true, "구입": true, "주문": true, "추천": true, "후보": true, "비교": true,
		"coupang": true, "rocket": true, "delivery": true, "product": true, "item": true,
		"buy": true, "purchase": true, "order": true, "candidate": true,
	}
	out := []string{}
	seen := map[string]bool{}
	for _, token := range strings.Fields(value) {
		token = strings.TrimSpace(token)
		if token == "" || skip[token] {
			continue
		}
		if len([]rune(token)) < 2 && !regexp.MustCompile(`^\d+$`).MatchString(token) {
			continue
		}
		if !seen[token] {
			seen[token] = true
			out = append(out, token)
		}
	}
	return out
}

func shoppingCandidateCompareFollowUpReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !isShoppingCandidateCompareFollowUp(lower) {
		return "", false
	}
	query, candidates, recentLocale, ok := latestShoppingCandidatesFromHistoryWithLocale(opts.TargetID)
	locale := shoppingFollowUpLocale(text, recentLocale)
	if !ok || len(candidates) == 0 {
		return lang.TF(locale, "assistant.shopping.compare.no_recent"), true
	}
	reply := formatShoppingCandidateCompareReplyFor(locale, query, candidates)
	_ = appendSignalHistory(opts.TargetID, text, reply)
	return reply, true
}

func isShoppingCandidateCompareFollowUp(lower string) bool {
	if lower == "" {
		return false
	}
	if containsAny(lower, "쿠팡", "coupang", "쇼핑", "상품", "가격", "배송", "로켓", "리뷰", "후기", "검색", "찾아", "최저가", "만원", "ml") {
		return false
	}
	return containsAny(lower, "후보 비교표", "상위 3개 후보", "상위 후보", "3개 후보 비교", "세 개 후보 비교", "비교표 만들어", "비교표로", "top 3 candidates", "candidate comparison", "comparison table") ||
		(containsAny(lower, "후보", "candidate") && containsAny(lower, "비교표", "비교", "compare", "table"))
}

func shoppingCandidateDetailFollowUpReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !isShoppingCandidateDetailFollowUp(lower) {
		return "", false
	}
	_, candidates, recentLocale, ok := latestShoppingCandidatesFromHistoryWithLocale(opts.TargetID)
	locale := shoppingFollowUpLocale(text, recentLocale)
	if !ok || len(candidates) == 0 {
		return lang.TF(locale, "assistant.shopping.detail.no_recent"), true
	}
	index := shoppingCandidateFollowUpIndex(lower)
	if index < 0 {
		index = 0
	}
	if index >= len(candidates) {
		return lang.TF(locale, "assistant.shopping.detail.out_of_range", index+1, len(candidates)), true
	}
	candidate := candidates[index]
	if strings.TrimSpace(candidate.URL) == "" {
		return lang.TF(locale, "assistant.shopping.detail.no_link"), true
	}
	pendingAligned := alignPendingShoppingDirectPurchaseToCandidate(opts.TargetID, text, candidate)
	actionReply, handled := runSignalArgosAction(opts, strings.TrimSpace(candidate.URL)+" 열어줘", 0)
	if !handled {
		actionReply = ""
	}
	reply := formatShoppingCandidateDetailReplyFor(locale, index, candidate, localizeCoupangOpenURLActionReply(locale, actionReply, candidate.URL))
	if pendingAligned {
		reply = strings.TrimSpace(reply) + "\n\n" + lang.TF(locale, "assistant.shopping.direct_purchase.pending_selected")
	}
	return scenarioReplyWithEvidence(opts, "shopping_candidate_detail", text, reply, []string{candidate.URL}), true
}

func isShoppingCandidateDetailFollowUp(lower string) bool {
	if lower == "" {
		return false
	}
	if containsAny(lower, "쿠팡에서", "coupang에서", "검색해서", "검색해줘", "찾아줘", "좋은 후보", "후보 3개") {
		return false
	}
	if !containsAny(lower, "첫", "1번", "1 번째", "첫 번째", "첫번째", "두", "2번", "2 번째", "두 번째", "두번째", "세", "3번", "3 번째", "세 번째", "세번째", "first", "second", "third", "#1", "#2", "#3", "candidate 1", "candidate 2", "candidate 3", "product 1", "product 2", "product 3") {
		return false
	}
	return containsAny(lower, "상품 상세", "상세 열", "상세 페이지", "총액 확인", "상품도 열", "상품 열", "후보 열", "open candidate", "open product", "detail page", "final total")
}

func shoppingCandidateFollowUpIndex(lower string) int {
	switch {
	case containsAny(lower, "세 번째", "세번째", "3번", "3 번째", "#3", "third", "candidate 3", "product 3"):
		return 2
	case containsAny(lower, "두 번째", "두번째", "2번", "2 번째", "#2", "second", "candidate 2", "product 2"):
		return 1
	case containsAny(lower, "첫 번째", "첫번째", "첫", "1번", "1 번째", "#1", "first", "candidate 1", "product 1"):
		return 0
	default:
		for _, pattern := range []string{
			`(?i)(\d+)\s*(?:번|번째)`,
			`(?i)#\s*(\d+)`,
			`(?i)\bcandidate\s+#?\s*(\d+)\b`,
			`(?i)\bproduct\s+#?\s*(\d+)\b`,
		} {
			re := regexp.MustCompile(pattern)
			match := re.FindStringSubmatch(lower)
			if len(match) < 2 {
				continue
			}
			n, err := strconv.Atoi(match[1])
			if err == nil && n > 0 {
				return n - 1
			}
		}
		return -1
	}
}

func formatShoppingCandidateDetailReply(index int, candidate browserauto.Link, actionReply string) string {
	return formatShoppingCandidateDetailReplyFor(lang.Current(), index, candidate, actionReply)
}

func formatShoppingCandidateDetailReplyFor(locale string, index int, candidate browserauto.Link, actionReply string) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	product := firstNonEmpty(strings.TrimSpace(candidate.Text), t("assistant.shopping.product_fallback.candidate"))
	link := strings.TrimSpace(candidate.URL)
	lines := []string{
		t("assistant.shopping.detail.title"),
		t("assistant.shopping.detail.selected", index+1),
		t("assistant.shopping.detail.product", product),
		t("assistant.shopping.detail.link", link),
		"",
		t("assistant.shopping.detail.checklist_title"),
		"1. " + t("assistant.shopping.detail.check.option"),
		"2. " + t("assistant.shopping.detail.check.total"),
		"3. " + t("assistant.shopping.detail.check.delivery"),
		"4. " + t("assistant.shopping.detail.check.seller"),
		"5. " + t("assistant.shopping.detail.check.review"),
		"",
		t("assistant.shopping.detail.next"),
		t("assistant.shopping.detail.boundary"),
	}
	if strings.TrimSpace(actionReply) != "" {
		lines = append(lines, "", t("assistant.shopping.coupang.action_title"), strings.TrimSpace(actionReply))
	}
	return strings.Join(lines, "\n")
}

func shoppingCandidateSelectionFollowUpReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !isShoppingCandidateSelectionFollowUp(lower) {
		return "", false
	}
	query, candidates, ok := latestShoppingCandidatesFromHistory(opts.TargetID)
	if !ok || len(candidates) == 0 {
		if containsAny(lower, "후보", "상품", "쿠팡", "쇼핑", "candidate", "product", "coupang", "shopping") {
			return lang.T("assistant.shopping.selection.no_recent"), true
		}
		return "", false
	}
	index := shoppingCandidateFollowUpIndex(lower)
	if index < 0 {
		reply := formatShoppingCandidateSelectionNeedNumberReply(query, candidates)
		_ = appendSignalHistory(opts.TargetID, text, reply)
		return reply, true
	}
	if index >= len(candidates) {
		reply := formatShoppingCandidateSelectionOutOfRangeReply(query, candidates, index)
		_ = appendSignalHistory(opts.TargetID, text, reply)
		return reply, true
	}
	candidate := candidates[index]
	if strings.TrimSpace(candidate.URL) == "" {
		return lang.T("assistant.shopping.selection.no_link"), true
	}
	reply := formatShoppingCandidateSelectionReply(query, index, candidate)
	if alignPendingShoppingDirectPurchaseToCandidate(opts.TargetID, text, candidate) {
		reply = strings.TrimSpace(reply) + "\n\n" + lang.T("assistant.shopping.direct_purchase.pending_selected")
	}
	_ = appendSignalHistory(opts.TargetID, text, reply)
	return reply, true
}

func isShoppingCandidateSelectionFollowUp(lower string) bool {
	if lower == "" {
		return false
	}
	if directPurchaseKoreanCurrentVisibleProductRequest(lower) ||
		isDirectPurchaseCurrentVisibleProductQuery(directPurchaseEnglishImperativeQuery(lower)) {
		return false
	}
	if containsAny(lower, "쿠팡에서", "coupang에서", "검색해서", "검색해줘", "찾아줘", "좋은 후보", "후보 3개") {
		return false
	}
	if containsAny(lower,
		"옵션", "색상", "색깔", "컬러", "사이즈", "수량", "용량", "개수", "묶음",
		"option", "variant", "color", "size", "quantity", "qty", "volume", "pack",
	) {
		return false
	}
	if shoppingCandidateFollowUpIndex(lower) < 0 &&
		!containsAny(lower, "이걸로", "이거로", "이 상품", "이 후보", "this one", "go with this", "use this") {
		return false
	}
	return containsAny(lower,
		"선택", "고를", "고르", "골랐", "이걸로", "이거로", "이 상품", "이 후보", "으로 할게", "로 할게", "으로 진행", "로 진행", "후보로", "상품으로",
		"choose", "select", "selected", "go with", "use candidate", "use product", "this one", "pick",
	)
}

