func shoppingCandidateCartAddReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !isShoppingCandidateCartAddRequest(lower) {
		return "", false
	}
	candidate, recentLocale, ok := shoppingCandidateForCartPrepWithLocale(opts.TargetID, lower)
	locale := shoppingFollowUpLocale(text, recentLocale)
	if !ok || strings.TrimSpace(candidate.URL) == "" {
		return lang.TF(locale, "assistant.shopping.cart_add.no_recent"), true
	}
	actionReply := ""
	executionLines := []string{}
	attachments := []string{candidate.URL}
	if opts.Execute {
		openResult := shoppingCartAddOpenURL(context.Background(), strings.TrimSpace(candidate.URL))
		if openResult.OK {
			actionReply = lang.TF(locale, "assistant.shopping.cart_add.opened", strings.TrimSpace(candidate.URL))
			lines, proofs := executeShoppingCandidateCartAddClick(opts, locale, candidate)
			executionLines = append(executionLines, lines...)
			attachments = append(attachments, proofs...)
		} else {
			actionReply = lang.TF(locale, "assistant.shopping.cart_add.open_failed", firstNonEmpty(openResult.Error, "open failed"))
		}
	} else {
		var handled bool
		actionReply, handled = runSignalArgosAction(opts, strings.TrimSpace(candidate.URL)+" 열어줘", 0)
		if !handled {
			actionReply = ""
		}
	}
	reply := formatShoppingCandidateCartAddReplyFor(locale, candidate, localizeCoupangOpenURLActionReply(locale, actionReply, candidate.URL), executionLines...)
	if alignPendingShoppingDirectPurchaseToCandidate(opts.TargetID, text, candidate) {
		reply = strings.TrimSpace(reply) + "\n\n" + lang.TF(locale, "assistant.shopping.direct_purchase.pending_selected")
	}
	return scenarioReplyWithEvidence(opts, "shopping_candidate_cart_add", text, reply, attachments), true
}

