func isCoupangTabCleanupRequest(lower string) bool {
	if !containsAny(lower, "쿠팡", "coupang") {
		return false
	}
	if strings.Contains(lower, "탭") && containsAny(lower, "정리", "닫", "제거", "지워", "없애", "줄여") {
		return true
	}
	return containsAny(lower, "탭 정리", "탭정리", "탭 닫", "탭닫", "탭 제거", "탭제거", "탭 지워", "탭지워", "브라우저 정리", "browser tab", "close tab", "close coupang", "cleanup coupang", "clean up coupang")
}

func cleanupCoupangTabsForNewWork(opts ListenOptions) osauto.Result {
	if !opts.Execute || !allowCoupangTabCleanup() {
		return osauto.Result{}
	}
	return shoppingBrowserTabCleanup(context.Background(), []string{"coupang.com"})
}

func allowCoupangTabCleanup() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_COUPANG_TAB_CLEANUP")))
	return value != "0" && value != "false" && value != "no" && value != "off"
}

func coupangTabCleanupReply(opts ListenOptions, text string) string {
	locale := shoppingGuideLocale(text)
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	if !opts.Execute {
		return strings.Join([]string{
			t("assistant.shopping.tab_cleanup.title"),
			t("assistant.shopping.tab_cleanup.dry_run"),
			t("assistant.shopping.tab_cleanup.scope"),
		}, "\n")
	}
	result := shoppingBrowserTabCleanup(context.Background(), []string{"coupang.com"})
	record, storeErr := evidence.Store("assistant-coupang-tab-cleanup", firstNonEmpty(opts.TargetID, "assistant"), "coupang.com", result)
	lines := []string{t("assistant.shopping.tab_cleanup.title")}
	if result.OK {
		lines = append(lines, t("assistant.shopping.tab_cleanup.done", browserTabCleanupClosedCount(result)))
	} else {
		lines = append(lines, t("assistant.shopping.tab_cleanup.failed", firstNonEmpty(result.Error, result.Stderr, "unknown error")))
	}
	lines = append(lines, t("assistant.shopping.tab_cleanup.scope"))
	lines = appendShoppingEvidenceDashboardLines(locale, lines, record, "assistant.shopping.tab_cleanup.evidence", "assistant.shopping.tab_cleanup.evidence_dashboard")
	if storeErr != nil {
		lines = append(lines, t("assistant.shopping.tab_cleanup.evidence_error", storeErr.Error()))
	}
	return strings.Join(lines, "\n")
}

func browserTabCleanupClosedCount(result osauto.Result) string {
	matches := regexp.MustCompile(`closed_tabs=([0-9]+)`).FindStringSubmatch(result.Stdout)
	if len(matches) == 2 {
		return matches[1]
	}
	return "0"
}

func shoppingCheckoutDecisionReply(opts ListenOptions, text string) (string, bool) {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !isShoppingCheckoutDecisionRequest(lower, text) {
		return "", false
	}
	fields := parseCheckoutScreenFields(text)
	candidate, recentLocale, _ := shoppingCandidateForCartPrepWithLocale(opts.TargetID, lower)
	locale := shoppingFollowUpLocale(text, recentLocale)
	reply := formatShoppingCheckoutDecisionReplyFor(locale, candidate, fields)
	attachments := []string{}
	cardPath, cardErr := writeShoppingCheckoutDecisionSVGFor(locale, candidate, fields)
	if cardErr == nil && strings.TrimSpace(cardPath) != "" {
		attachments = append(attachments, cardPath)
	}
	if targetRef := inferAssistantSignalTargetRef(text); targetRef != "" {
		return formatShoppingCheckoutDecisionSendResult(opts, targetRef, reply, attachments, cardErr), true
	}
	if len(attachments) > 0 {
		lines := []string{reply, "", lang.TF(locale, "assistant.shopping.decision.file.svg")}
		reply = strings.Join(appendVoiceReportAttachmentMarkers(lines, []string{cardPath}), "\n")
	} else if cardErr != nil {
		reply = strings.Join([]string{reply, "", lang.TF(locale, "assistant.shopping.decision.file.svg_failed", cardErr.Error())}, "\n")
	}
	return scenarioReplyWithEvidence(opts, "shopping_checkout_decision", text, reply, nil), true
}

func isShoppingCheckoutDecisionRequest(lower, text string) bool {
	if lower == "" {
		return false
	}
	if isPurchaseFinalApprovalText(lower) || isCoupangCheckoutReviewRequest(lower) && !strings.Contains(text, ":") && !strings.Contains(text, "：") {
		return false
	}
	count := checkoutScreenLabelCount(text)
	if count >= 5 {
		return true
	}
	if count >= 3 && containsAny(lower, "구매 가능", "판정", "맞아", "맞는지", "확인해", "진행해도", "이대로", "go ahead", "ready to buy") {
		return true
	}
	return false
}

func checkoutScreenLabelCount(text string) int {
	seen := map[string]bool{}
	for _, line := range strings.Split(text, "\n") {
		label, _, ok := splitCheckoutFieldLine(line)
		if ok {
			seen[label] = true
		}
	}
	return len(seen)
}

func parseCheckoutScreenFields(text string) checkoutScreenFields {
	fields := checkoutScreenFields{}
	for _, line := range strings.Split(text, "\n") {
		label, value, ok := splitCheckoutFieldLine(line)
		if !ok || strings.TrimSpace(value) == "" {
			continue
		}
		switch label {
		case "product":
			fields.Product = firstNonEmpty(fields.Product, value)
		case "option_quantity":
			option, quantity := splitCheckoutOptionQuantityValue(value)
			fields.Option = firstNonEmpty(fields.Option, option)
			fields.Quantity = firstNonEmpty(fields.Quantity, quantity)
		case "option":
			fields.Option = firstNonEmpty(fields.Option, value)
		case "quantity":
			fields.Quantity = firstNonEmpty(fields.Quantity, value)
		case "total":
			fields.Total = firstNonEmpty(fields.Total, value)
		case "address":
			fields.Address = firstNonEmpty(fields.Address, value)
		case "payment":
			fields.Payment = firstNonEmpty(fields.Payment, value)
		case "delivery":
			fields.Delivery = firstNonEmpty(fields.Delivery, value)
		case "button":
			fields.Button = firstNonEmpty(fields.Button, value)
		}
	}
	return fields
}

func shoppingCheckoutAutoDecisionReplyFor(locale string, opts ListenOptions, request string, candidate browserauto.Link) (string, []string, bool) {
	capturePath := filepath.Join(os.TempDir(), fmt.Sprintf("meshclaw-checkout-screen-%d.png", time.Now().UnixNano()))
	capture := shoppingCheckoutScreenCapture(context.Background(), capturePath)
	payload := map[string]interface{}{
		"kind":       "assistant_coupang_checkout_auto_decision",
		"request":    request,
		"capture":    capture,
		"capture_at": capturePath,
		"created_at": time.Now().UTC(),
	}
	record, storeErr := evidence.Store("assistant-coupang-checkout-auto-decision", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "checkout"), payload)
	if !capture.OK {
		return "", nil, false
	}
	ocrText, ocrErr := shoppingCheckoutScreenOCR(capturePath)
	payload["ocr_text"] = ocrText
	payload["ocr_error"] = ocrErr
	_, _ = evidence.Store("assistant-coupang-checkout-auto-decision-ocr", firstNonEmpty(opts.TargetID, "assistant"), firstNonEmpty(candidate.Text, "checkout"), payload)
	fields := inferCheckoutScreenFieldsFromOCRText(ocrText, candidate, capturePath)
	if checkoutScreenFieldCount(fields) == 0 {
		return "", []string{capturePath}, false
	}
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	lines := []string{
		t("assistant.shopping.checkout.auto.title"),
		t("assistant.shopping.checkout.auto.capture", capturePath),
	}
	if strings.TrimSpace(ocrErr) != "" {
		lines = append(lines, t("assistant.shopping.checkout.auto.ocr_failed", strings.TrimSpace(ocrErr)))
	} else {
		lines = append(lines, t("assistant.shopping.checkout.auto.ocr_ok"))
	}
	lines = appendShoppingEvidenceDashboardLines(locale, lines, record, "assistant.shopping.checkout.auto.evidence", "assistant.shopping.checkout.auto.evidence_dashboard")
	if storeErr != nil {
		lines = append(lines, t("assistant.shopping.checkout.auto.evidence_error", storeErr.Error()))
	}
	lines = append(lines, "", formatShoppingCheckoutDecisionReplyFor(locale, candidate, fields))
	return strings.Join(lines, "\n"), []string{capturePath}, true
}

func inferCheckoutScreenFieldsFromOCRText(ocrText string, candidate browserauto.Link, capturePath string) checkoutScreenFields {
	width, height := checkoutScreenPointSize(capturePath)
	return inferCheckoutScreenFieldsFromOCRTextWithSize(ocrText, candidate, width, height)
}

func inferCheckoutScreenFieldsFromOCRTextWithSize(ocrText string, candidate browserauto.Link, width, height int) checkoutScreenFields {
	fields := parseCheckoutScreenFields(ocrText)
	normalized := strings.ToLower(strings.Join(strings.Fields(ocrText), " "))
	if strings.TrimSpace(fields.Product) == "" {
		fields.Product = inferCheckoutOCRProduct(ocrText, candidate)
	}
	if strings.TrimSpace(fields.Quantity) == "" {
		fields.Quantity = inferCheckoutOCRQuantity(ocrText)
	}
	if strings.TrimSpace(fields.Total) == "" {
		fields.Total = inferCheckoutOCRTotal(ocrText)
	}
	if strings.TrimSpace(fields.Delivery) == "" {
		fields.Delivery = inferCheckoutOCRDelivery(ocrText)
	}
	if strings.TrimSpace(fields.Address) == "" && checkoutOCRShowsAddress(normalized) {
		fields.Address = "yes"
	}
	if strings.TrimSpace(fields.Payment) == "" && checkoutOCRShowsPayment(normalized) {
		fields.Payment = "yes"
	}
	if strings.TrimSpace(fields.Button) == "" && checkoutOCRShowsFinalOrderButton(normalized) {
		x, y := estimateCheckoutFinalButtonCoordinate(width, height)
		fields.Button = fmt.Sprintf("OCR final order button visible; x=%d, y=%d", x, y)
	}
	return fields
}

func inferCheckoutOCRProduct(ocrText string, candidate browserauto.Link) string {
	if text := strings.TrimSpace(candidate.Text); text != "" {
		return text
	}
	pricePattern := regexp.MustCompile(`[0-9][0-9,]*(?:원|krw|₩)`)
	for _, line := range strings.Split(ocrText, "\n") {
		line = strings.TrimSpace(line)
		if len([]rune(line)) < 4 {
			continue
		}
		lower := strings.ToLower(line)
		if containsAny(lower,
			"주문서", "주문/결제", "주문 상품", "주문상품", "주문", "배송", "결제", "총액", "합계", "도착", "수량",
			"받는사람", "받는 사람", "수령인", "주소", "카드", "쿠페이", "계좌", "할인", "쿠폰", "적립",
			"order", "payment", "delivery", "total", "quantity", "address", "card", "coupon", "discount",
		) {
			continue
		}
		if pricePattern.MatchString(lower) {
			continue
		}
		return line
	}
	return ""
}

func inferCheckoutOCRQuantity(ocrText string) string {
	re := regexp.MustCompile(`(?i)(?:수량|quantity|qty)\s*[:：]?\s*([0-9]{1,3})(?:\s*개)?`)
	if match := re.FindStringSubmatch(ocrText); len(match) >= 2 {
		return strings.TrimSpace(match[1])
	}
	lineOnlyEach := regexp.MustCompile(`^([0-9]{1,3})\s*개$`)
	for _, line := range strings.Split(ocrText, "\n") {
		clean := strings.Join(strings.Fields(strings.TrimSpace(line)), " ")
		if match := lineOnlyEach.FindStringSubmatch(clean); len(match) >= 2 {
			return strings.TrimSpace(match[1])
		}
	}
	reEach := regexp.MustCompile(`(?m)([0-9]{1,3})\s*개(?:\s|$)`)
	if match := reEach.FindStringSubmatch(ocrText); len(match) >= 2 {
		return strings.TrimSpace(match[1])
	}
	return ""
}

func inferCheckoutOCRTotal(ocrText string) string {
	labeled := regexp.MustCompile(`(?i)(?:총\s*결제\s*금액|최종\s*결제\s*금액|결제\s*예정\s*금액|총\s*주문\s*금액|주문\s*총액|총액|합계|결제\s*금액|주문\s*금액|order\s*total|payment\s*amount|total)[^\n0-9₩]{0,32}(₩?\s*[0-9][0-9,\.]*\s*(?:원|krw)?)`)
	for _, line := range strings.Split(ocrText, "\n") {
		if match := labeled.FindStringSubmatch(line); len(match) >= 2 {
			return strings.Join(strings.Fields(match[1]), " ")
		}
	}
	all := regexp.MustCompile(`₩?\s*[0-9][0-9,\.]*\s*(?:원|krw)`).FindAllString(ocrText, -1)
	if len(all) == 0 {
		return ""
	}
	return strings.Join(strings.Fields(all[len(all)-1]), " ")
}

func inferCheckoutOCRDelivery(ocrText string) string {
	for _, line := range strings.Split(ocrText, "\n") {
		clean := strings.Join(strings.Fields(strings.TrimSpace(line)), " ")
		lower := strings.ToLower(clean)
		if clean == "" {
			continue
		}
		if containsAny(lower, "도착", "배송 예정", "배송예정", "arrival", "arrives", "delivery") ||
			containsAny(lower, "오늘", "내일", "모레", "새벽도착", "새벽 도착", "로켓배송", "월요일", "화요일", "수요일", "목요일", "금요일", "토요일", "일요일") {
			if !containsAny(lower, "배송지", "address", "배송비", "shipping fee", "배송 요청", "delivery memo") {
				return clean
			}
		}
	}
	return ""
}

func checkoutOCRShowsAddress(normalized string) bool {
	if normalized == "" || checkoutAddressMultipleValue(normalized) {
		return false
	}
	return containsAny(normalized, "배송지", "받는 사람", "받는사람", "수령인", "수취인", "받으시는 분", "address", "shipping address", "recipient")
}

func checkoutOCRShowsPayment(normalized string) bool {
	if normalized == "" || checkoutPaymentMultipleValue(normalized) {
		return false
	}
	return containsAny(normalized,
		"결제수단", "결제 수단", "카드", "신용", "체크카드", "쿠페이", "coupay", "계좌", "원터치결제", "원터치 결제",
		"payment method", "card", "credit", "debit", "bank account",
	)
}

func checkoutOCRShowsFinalOrderButton(normalized string) bool {
	if normalized == "" {
		return false
	}
	return containsAny(normalized,
		"결제하기", "주문하기", "구매하기", "바로구매", "바로 구매", "place order", "buy now", "complete purchase", "complete checkout",
	)
}

func estimateCheckoutFinalButtonCoordinate(width, height int) (int, int) {
	if width <= 0 {
		width = 1440
	}
	if height <= 0 {
		height = 900
	}
	x := int(float64(width) * 0.82)
	y := int(float64(height) * 0.88)
	if x < 1 {
		x = 1
	}
	if y < 1 {
		y = 1
	}
	return x, y
}

func checkoutScreenPointSize(capturePath string) (int, int) {
	if width, height, ok := imagePixelSize(capturePath); ok {
		if width >= 2400 && height >= 1400 {
			return width / 2, height / 2
		}
		return width, height
	}
	if allowFinderDesktopBoundsForCheckout() {
		if width, height, ok := desktopPointSize(); ok {
			return width, height
		}
	}
	return 1440, 900
}

func allowFinderDesktopBoundsForCheckout() bool {
	value := strings.ToLower(strings.TrimSpace(os.Getenv("MESHCLAW_CHECKOUT_FINDER_BOUNDS")))
	return value == "1" || value == "true" || value == "yes" || value == "on"
}

func desktopPointSize() (int, int, bool) {
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()
	cmd := exec.CommandContext(ctx, "osascript", "-e", `tell application "Finder" to get bounds of window of desktop`)
	out, err := cmd.Output()
	if err != nil || ctx.Err() != nil {
		return 0, 0, false
	}
	nums := regexp.MustCompile(`-?[0-9]+`).FindAllString(string(out), -1)
	if len(nums) < 4 {
		return 0, 0, false
	}
	left, _ := strconv.Atoi(nums[0])
	top, _ := strconv.Atoi(nums[1])
	right, _ := strconv.Atoi(nums[2])
	bottom, _ := strconv.Atoi(nums[3])
	width := right - left
	height := bottom - top
	return width, height, width > 0 && height > 0
}

func imagePixelSize(path string) (int, int, bool) {
	f, err := os.Open(strings.TrimSpace(path))
	if err != nil {
		return 0, 0, false
	}
	defer f.Close()
	cfg, _, err := image.DecodeConfig(f)
	if err != nil {
		return 0, 0, false
	}
	return cfg.Width, cfg.Height, cfg.Width > 0 && cfg.Height > 0
}

func splitCheckoutFieldLine(line string) (string, string, bool) {
	trimmed := strings.TrimSpace(strings.TrimLeft(line, "-*•0123456789. "))
	if trimmed == "" {
		return "", "", false
	}
	parts := strings.SplitN(trimmed, ":", 2)
	if len(parts) < 2 {
		parts = strings.SplitN(trimmed, "：", 2)
	}
	if len(parts) < 2 {
		return "", "", false
	}
	label := strings.ToLower(strings.TrimSpace(parts[0]))
	value := cleanCheckoutTemplateValue(parts[1])
	switch {
	case containsAny(label, "옵션/수량", "옵션 수량", "option/quantity", "option quantity") ||
		(containsAny(label, "옵션", "option") && containsAny(label, "수량", "quantity", "qty")):
		return "option_quantity", value, true
	case containsAny(label, "상품명", "상품", "product"):
		return "product", value, true
	case containsAny(label, "옵션", "option"):
		return "option", value, true
	case containsAny(label, "수량", "quantity", "qty"):
		return "quantity", value, true
	case containsAny(label, "총액", "합계", "금액", "total", "price"):
		return "total", value, true
	case containsAny(label, "배송지", "주소", "address"):
		return "address", value, true
	case containsAny(label, "결제수단", "결제 수단", "카드", "payment", "card"):
		return "payment", value, true
	case containsAny(label, "도착", "배송예정", "배송 예정", "arrival", "delivery"):
		return "delivery", value, true
	case containsAny(label, "버튼", "주문 버튼", "최종 주문", "button"):
		return "button", value, true
	default:
		return "", "", false
	}
}

func cleanCheckoutTemplateValue(value string) string {
	clean := strings.TrimSpace(value)
	normalized := strings.ToLower(strings.Join(strings.Fields(clean), " "))
	placeholder := map[string]bool{
		"화면 그대로":                          true,
		"화면 그대로 복사":                       true,
		"최종 결제 금액":                        true,
		"맞음/아님":                           true,
		"맞음 / 아님":                         true,
		"보임/안 보임":                         true,
		"보임 / 안 보임":                       true,
		"copy exactly as shown":           true,
		"final payment amount":            true,
		"yes/no":                          true,
		"yes / no":                        true,
		"visible/not visible":             true,
		"visible / not visible":           true,
		"copy exactly as shown on screen": true,
	}
	if placeholder[normalized] {
		return ""
	}
	return clean
}

func splitCheckoutOptionQuantityValue(value string) (string, string) {
	clean := strings.TrimSpace(value)
	if clean == "" {
		return "", ""
	}
	if strings.Contains(clean, "/") {
		parts := strings.SplitN(clean, "/", 2)
		return strings.TrimSpace(parts[0]), strings.TrimSpace(parts[1])
	}
	re := regexp.MustCompile(`(?i)(?:수량|quantity|qty)\s*[:：]?\s*([0-9]+(?:\s*개)?)`)
	match := re.FindStringSubmatch(clean)
	if len(match) >= 2 {
		option := strings.TrimSpace(re.ReplaceAllString(clean, ""))
		option = strings.Trim(option, " ,，/;-")
		return option, strings.TrimSpace(match[1])
	}
	return clean, ""
}

func checkoutScreenFieldCount(fields checkoutScreenFields) int {
	count := 0
	for _, value := range []string{fields.Product, fields.Option, fields.Quantity, fields.Total, fields.Address, fields.Payment, fields.Delivery, fields.Button} {
		if strings.TrimSpace(value) != "" {
			count++
		}
	}
	return count
}

func formatShoppingCheckoutDecisionReply(candidate browserauto.Link, fields checkoutScreenFields) string {
	return formatShoppingCheckoutDecisionReplyFor(lang.Current(), candidate, fields)
}

func formatShoppingCheckoutDecisionReplyFor(locale string, candidate browserauto.Link, fields checkoutScreenFields) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	product := checkoutDecisionDisplayProductFor(locale, candidate, fields)
	missing := checkoutDecisionMissingFieldsFor(locale, fields)
	problems := checkoutDecisionProblemsFor(locale, fields)
	mismatch := checkoutProductMismatch(fields.Product, candidate.Text)
	ready := len(missing) == 0 && len(problems) == 0 && !mismatch
	lines := []string{
		t("assistant.shopping.decision.title"),
		t("assistant.shopping.decision.product", product),
	}
	if ready {
		lines = append(lines, t("assistant.shopping.decision.ready"))
		lines = append(lines, t("assistant.shopping.decision.primary_action.ready", t("assistant.shopping.decision.approval_phrase")))
	} else {
		lines = append(lines, t("assistant.shopping.decision.hold"))
		if len(problems) > 0 {
			lines = append(lines, t("assistant.shopping.decision.primary_action.problem"))
		} else {
			lines = append(lines, t("assistant.shopping.decision.primary_action.hold"))
		}
	}
	lines = append(lines, "", t("assistant.shopping.decision.confirmed_title"))
	if productLine := checkoutProductOptionLine(fields); productLine != "" {
		lines = append(lines, "- "+t("assistant.shopping.decision.field.product", productLine))
	}
	if strings.TrimSpace(fields.Quantity) != "" {
		lines = append(lines, "- "+t("assistant.shopping.decision.field.quantity", strings.TrimSpace(fields.Quantity)))
	}
	if strings.TrimSpace(fields.Total) != "" {
		lines = append(lines, "- "+t("assistant.shopping.decision.field.total", strings.TrimSpace(fields.Total)))
	}
	if strings.TrimSpace(fields.Address) != "" {
		if checkoutScreenNegativeValue(fields.Address) {
			lines = append(lines, "- "+t("assistant.shopping.decision.field.address_problem", strings.TrimSpace(fields.Address)))
		} else if checkoutAddressMultipleValue(fields.Address) {
			lines = append(lines, "- "+t("assistant.shopping.decision.field.address_multiple"))
		} else if !checkoutScreenVisibilityAffirmative(fields.Address) {
			lines = append(lines, "- "+t("assistant.shopping.decision.field.address_needs_flag"))
		} else {
			lines = append(lines, "- "+t("assistant.shopping.decision.field.address"))
		}
	}
	if strings.TrimSpace(fields.Payment) != "" {
		if checkoutScreenNegativeValue(fields.Payment) {
			lines = append(lines, "- "+t("assistant.shopping.decision.field.payment_problem", strings.TrimSpace(fields.Payment)))
		} else if checkoutPaymentMultipleValue(fields.Payment) {
			lines = append(lines, "- "+t("assistant.shopping.decision.field.payment_multiple"))
		} else if !checkoutScreenVisibilityAffirmative(fields.Payment) {
			lines = append(lines, "- "+t("assistant.shopping.decision.field.payment_needs_flag"))
		} else {
			lines = append(lines, "- "+t("assistant.shopping.decision.field.payment"))
		}
	}
	if strings.TrimSpace(fields.Delivery) != "" {
		lines = append(lines, "- "+t("assistant.shopping.decision.field.delivery", strings.TrimSpace(fields.Delivery)))
	}
	if strings.TrimSpace(fields.Button) != "" {
		lines = append(lines, "- "+t("assistant.shopping.decision.field.button", strings.TrimSpace(fields.Button)))
	}
	if len(missing) > 0 {
		lines = append(lines, "", t("assistant.shopping.decision.missing", strings.Join(missing, ", ")))
	}
	for _, problem := range problems {
		lines = append(lines, t("assistant.shopping.decision.stop_reason", problem.Reason))
	}
	if mismatch {
		lines = append(lines, t("assistant.shopping.decision.mismatch"))
	}
	if ready {
		lines = append(lines, "", t("assistant.shopping.decision.next_ready"))
		lines = appendCheckoutDecisionNextSignalLinesFor(locale, lines, true, nil, nil)
	} else {
		if len(problems) > 0 {
			lines = append(lines, "", t("assistant.shopping.decision.next_problem"))
		} else {
			lines = append(lines, "", t("assistant.shopping.decision.next_hold"))
		}
		lines = appendCheckoutDecisionNextSignalLinesFor(locale, lines, false, checkoutDecisionBlockingFields(missing, problems), problems)
	}
	lines = append(lines, t("assistant.shopping.decision.boundary"))
	return strings.Join(lines, "\n")
}

func checkoutDecisionDisplayProduct(candidate browserauto.Link, fields checkoutScreenFields) string {
	return checkoutDecisionDisplayProductFor(lang.Current(), candidate, fields)
}

func checkoutDecisionDisplayProductFor(locale string, candidate browserauto.Link, fields checkoutScreenFields) string {
	candidateText := strings.TrimSpace(candidate.Text)
	screenProduct := strings.TrimSpace(fields.Product)
	if lang.Normalize(locale) != "ko" {
		return firstNonEmpty(screenProduct, candidateText, lang.TF(locale, "assistant.shopping.product_fallback.recent"))
	}
	return firstNonEmpty(candidateText, screenProduct, lang.TF(locale, "assistant.shopping.product_fallback.recent"))
}

type checkoutDecisionProblem struct {
	Field  string
	Reason string
}

func checkoutDecisionProblems(fields checkoutScreenFields) []checkoutDecisionProblem {
	return checkoutDecisionProblemsFor(lang.Current(), fields)
}

func checkoutDecisionProblemsFor(locale string, fields checkoutScreenFields) []checkoutDecisionProblem {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	problems := []checkoutDecisionProblem{}
	add := func(value, field, reason string) {
		if checkoutScreenNegativeValue(value) {
			problems = append(problems, checkoutDecisionProblem{Field: field, Reason: reason})
		}
	}
	add(checkoutProductOptionLine(fields), t("assistant.shopping.checkout.check.product"), t("assistant.shopping.decision.problem.product"))
	add(fields.Quantity, t("assistant.shopping.checkout.check.quantity"), t("assistant.shopping.decision.problem.quantity"))
	add(fields.Total, t("assistant.shopping.checkout.check.total"), t("assistant.shopping.decision.problem.total"))
	add(fields.Delivery, t("assistant.shopping.checkout.check.delivery"), t("assistant.shopping.decision.problem.delivery"))
	add(fields.Address, t("assistant.shopping.checkout.check.address"), t("assistant.shopping.decision.problem.address"))
	add(fields.Payment, t("assistant.shopping.checkout.check.payment"), t("assistant.shopping.decision.problem.payment"))
	add(fields.Button, t("assistant.shopping.checkout.check.button"), t("assistant.shopping.decision.problem.button"))
	if strings.TrimSpace(fields.Delivery) != "" && !checkoutScreenNegativeValue(fields.Delivery) && checkoutDeliveryUnclearValue(fields.Delivery) {
		problems = append(problems, checkoutDecisionProblem{Field: t("assistant.shopping.checkout.check.delivery"), Reason: t("assistant.shopping.decision.problem.delivery_unclear")})
	}
	if strings.TrimSpace(fields.Address) != "" && !checkoutScreenNegativeValue(fields.Address) && checkoutAddressMultipleValue(fields.Address) {
		problems = append(problems, checkoutDecisionProblem{Field: t("assistant.shopping.checkout.check.address"), Reason: t("assistant.shopping.decision.problem.address_multiple")})
	} else if strings.TrimSpace(fields.Address) != "" && !checkoutScreenNegativeValue(fields.Address) && !checkoutScreenVisibilityAffirmative(fields.Address) {
		problems = append(problems, checkoutDecisionProblem{Field: t("assistant.shopping.checkout.check.address"), Reason: t("assistant.shopping.decision.problem.address_raw")})
	}
	if strings.TrimSpace(fields.Payment) != "" && !checkoutScreenNegativeValue(fields.Payment) && checkoutPaymentMultipleValue(fields.Payment) {
		problems = append(problems, checkoutDecisionProblem{Field: t("assistant.shopping.checkout.check.payment"), Reason: t("assistant.shopping.decision.problem.payment_multiple")})
	} else if strings.TrimSpace(fields.Payment) != "" && !checkoutScreenNegativeValue(fields.Payment) && !checkoutScreenVisibilityAffirmative(fields.Payment) {
		problems = append(problems, checkoutDecisionProblem{Field: t("assistant.shopping.checkout.check.payment"), Reason: t("assistant.shopping.decision.problem.payment_raw")})
	}
	return problems
}

func checkoutDecisionBlockingFields(missing []string, problems []checkoutDecisionProblem) []string {
	blocking := append([]string{}, missing...)
	for _, problem := range problems {
		if strings.TrimSpace(problem.Field) != "" {
			blocking = append(blocking, problem.Field)
		}
	}
	return blocking
}

func checkoutScreenNegativeValue(value string) bool {
	normalized := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(value)), " "))
	if normalized == "" {
		return false
	}
	exact := map[string]bool{
		"아님":           true,
		"아니오":          true,
		"아니요":          true,
		"틀림":           true,
		"다름":           true,
		"불일치":          true,
		"안 보임":         true,
		"안보임":          true,
		"보이지 않음":       true,
		"없음":           true,
		"no":           true,
		"false":        true,
		"wrong":        true,
		"different":    true,
		"mismatch":     true,
		"incorrect":    true,
		"not visible":  true,
		"not shown":    true,
		"not provided": true,
	}
	if exact[normalized] {
		return true
	}
	return containsAny(normalized,
		"맞지 않", "안 맞", "표시 안", "보이지 않", "확인 안", "확인되지 않",
		"not correct", "not visible", "not shown", "does not match", "do not match", "not confirmed",
	)
}

func checkoutScreenVisibilityAffirmative(value string) bool {
	normalized := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(value)), " "))
	if normalized == "" {
		return false
	}
	exact := map[string]bool{
		"맞음":        true,
		"맞습니다":      true,
		"맞다":        true,
		"확인":        true,
		"확인됨":       true,
		"표시됨":       true,
		"보임":        true,
		"예":         true,
		"네":         true,
		"yes":       true,
		"y":         true,
		"true":      true,
		"ok":        true,
		"correct":   true,
		"confirmed": true,
		"visible":   true,
		"shown":     true,
		"provided":  true,
	}
	if exact[normalized] {
		return true
	}
	return containsAny(normalized,
		"맞게 표시", "정상 표시", "화면에 보임", "보이는 것 맞",
		"visible yes", "shown yes", "confirmed yes", "looks correct", "is correct",
	)
}

func checkoutAddressMultipleValue(value string) bool {
	normalized := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(value)), " "))
	if normalized == "" {
		return false
	}
	return containsAny(normalized,
		"2개", "두개", "두 개", "둘", "여러", "복수", "여러 개", "여러개",
		"two address", "two shipping address", "2 address", "multiple address", "multiple shipping address", "more than one address",
	)
}

func checkoutPaymentMultipleValue(value string) bool {
	normalized := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(value)), " "))
	if normalized == "" {
		return false
	}
	return containsAny(normalized,
		"2개", "두개", "두 개", "둘", "여러", "복수", "여러 개", "여러개",
		"카드 2", "카드 두", "카드 여러", "결제수단 2", "결제수단 두", "결제수단 여러",
		"two payment", "two cards", "2 payment", "2 cards", "multiple payment", "multiple cards", "more than one payment",
	)
}

func checkoutDeliveryUnclearValue(value string) bool {
	normalized := strings.ToLower(strings.Join(strings.Fields(strings.TrimSpace(value)), " "))
	if normalized == "" {
		return false
	}
	return containsAny(normalized,
		"2개", "두개", "두 개", "둘", "여러", "복수", "여러 개", "여러개",
		"옵션", "선택 필요", "확정 필요", "변경", "바뀜", "지연", "늦어", "미정", "불확실", "확인 필요", "확정 안",
		"multiple", "two", "more than one", "option", "choice needed", "needs choice", "not selected",
		"changed", "delayed", "delay", "uncertain", "unknown", "not confirmed", "needs confirmation",
	)
}

func appendCheckoutDecisionNextSignalLines(lines []string, ready bool, missing []string, problems []checkoutDecisionProblem) []string {
	return appendCheckoutDecisionNextSignalLinesFor(lang.Current(), lines, ready, missing, problems)
}

func appendCheckoutDecisionNextSignalLinesFor(locale string, lines []string, ready bool, missing []string, problems []checkoutDecisionProblem) []string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	lines = append(lines, "", t("assistant.shopping.decision.next_signal_title"))
	if ready {
		return append(lines,
			"- "+t("assistant.shopping.decision.next_signal.ready", t("assistant.shopping.decision.approval_phrase")),
			"- "+t("assistant.shopping.decision.next_signal.warning"),
		)
	}
	if len(missing) == 0 {
		missing = checkoutDecisionMissingFieldsFor(locale, checkoutScreenFields{})
	}
	skipGeneric := map[string]bool{}
	for _, problem := range problems {
		switch strings.TrimSpace(problem.Reason) {
		case t("assistant.shopping.decision.problem.address_multiple"):
			lines = append(lines, "- "+t("assistant.shopping.decision.next_signal.address_choice"))
			skipGeneric[t("assistant.shopping.checkout.check.address")] = true
		case t("assistant.shopping.decision.problem.payment_multiple"):
			lines = append(lines, "- "+t("assistant.shopping.decision.next_signal.payment_choice"))
			skipGeneric[t("assistant.shopping.checkout.check.payment")] = true
		case t("assistant.shopping.decision.problem.delivery_unclear"):
			lines = append(lines, "- "+t("assistant.shopping.decision.next_signal.delivery_choice"))
			skipGeneric[t("assistant.shopping.checkout.check.delivery")] = true
		}
	}
	for _, field := range missing {
		if skipGeneric[strings.TrimSpace(field)] {
			continue
		}
		lines = append(lines, "- "+t("assistant.shopping.decision.next_signal.value", field))
	}
	return lines
}

func formatShoppingCheckoutDecisionSendResult(opts ListenOptions, targetRef, summary string, attachments []string, cardErr error) string {
	target, candidates, targetErr := resolveAssistantVoiceTarget(targetRef)
	if targetErr != nil {
		lines := []string{lang.T("assistant.shopping.decision.send_target_failed")}
		lines = append(lines, formatAssistantVoiceTargetCandidates(candidates)...)
		lines = append(lines, "", lang.T("assistant.shopping.decision.attach_here"), summary)
		lines = appendVoiceReportAttachmentMarkers(lines, attachments)
		return strings.Join(lines, "\n")
	}
	targetLabel := assistantScheduleLocalizedTarget(target.ID, target.Label)
	lines := []string{}
	if cardErr == nil && len(attachments) > 0 {
		lines = append(lines, lang.T("assistant.shopping.decision.file.svg"))
	} else if cardErr != nil {
		lines = append(lines, lang.T("assistant.shopping.decision.file.svg_failed", cardErr.Error()))
	}
	if !opts.Execute {
		preview := []string{
			lang.T("assistant.shopping.decision.send_ready"),
			lang.T("assistant.shopping.decision.target", targetLabel),
		}
		if OneWayReportTarget(target) {
			preview = append(preview, lang.T("assistant.shopping.decision.one_way"))
		}
		preview = append(preview, "", lang.T("assistant.shopping.decision.to_send"), summary)
		if len(lines) > 0 {
			preview = append(preview, "")
			preview = append(preview, lines...)
		}
		preview = appendVoiceReportAttachmentMarkers(preview, attachments)
		return strings.Join(preview, "\n")
	}
	sendText := strings.Join(compactBlankLines(strings.Split(summary, "\n")), "\n")
	send, sendErr := Send(SendOptions{TargetID: target.ID, Kind: "text", Text: sendText, Attachments: attachments, Execute: true})
	payload := map[string]interface{}{
		"kind":             "assistant_coupang_checkout_decision_send",
		"target":           targetRef,
		"resolved_target":  target,
		"attachment_count": len(attachments),
		"send":             send,
		"send_error":       errorString(sendErr),
		"created_at":       time.Now().UTC(),
	}
	sendRecord, sendStoreErr := evidence.Store("assistant-coupang-checkout-decision-send", firstNonEmpty(opts.TargetID, "assistant"), target.ID, payload)
	if sendErr != nil {
		failed := []string{
			lang.T("assistant.shopping.decision.send_failed"),
			lang.T("assistant.shopping.decision.target", targetLabel),
			lang.T("assistant.shopping.decision.problem", sendErr.Error()),
			"",
			lang.T("assistant.shopping.decision.attach_here"),
			summary,
		}
		failed = appendVoiceReportAttachmentMarkers(failed, attachments)
		return strings.Join(appendAssistantEvidenceNote(failed, sendRecord, sendStoreErr), "\n")
	}
	sent := []string{
		lang.T("assistant.shopping.decision.sent"),
		lang.T("assistant.shopping.decision.target", targetLabel),
	}
	if id := strings.TrimSpace(send.Stdout); id != "" {
		sent = append(sent, lang.T("assistant.workflow.signal_id", id))
	}
	return strings.Join(appendAssistantEvidenceNote(sent, sendRecord, sendStoreErr), "\n")
}

func writeShoppingCheckoutDecisionSVG(candidate browserauto.Link, fields checkoutScreenFields) (string, error) {
	return writeShoppingCheckoutDecisionSVGFor(lang.Current(), candidate, fields)
}

func writeShoppingCheckoutDecisionSVGFor(locale string, candidate browserauto.Link, fields checkoutScreenFields) (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}
	dir := filepath.Join(home, "Documents", "Argos Vault", "Charts")
	if err := os.MkdirAll(dir, 0700); err != nil {
		return "", err
	}
	path := filepath.Join(dir, safeAssistantDepartmentFilename(lang.TF(locale, "assistant.shopping.decision.title"))+"-"+time.Now().Format("20060102-150405")+"-decision.svg")
	content := renderShoppingCheckoutDecisionSVGFor(locale, candidate, fields)
	if err := os.WriteFile(path, []byte(content), 0600); err != nil {
		return "", err
	}
	return path, nil
}

func renderShoppingCheckoutDecisionSVG(candidate browserauto.Link, fields checkoutScreenFields) string {
	return renderShoppingCheckoutDecisionSVGFor(lang.Current(), candidate, fields)
}

func renderShoppingCheckoutDecisionSVGFor(locale string, candidate browserauto.Link, fields checkoutScreenFields) string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	product := checkoutDecisionDisplayProductFor(locale, candidate, fields)
	missing := checkoutDecisionMissingFieldsFor(locale, fields)
	problems := checkoutDecisionProblemsFor(locale, fields)
	mismatch := checkoutProductMismatch(fields.Product, candidate.Text)
	ready := len(missing) == 0 && len(problems) == 0 && !mismatch
	status := t("assistant.shopping.decision.hold")
	statusColor := "#dc2626"
	statusFill := "#fef2f2"
	if ready {
		status = t("assistant.shopping.decision.ready")
		statusColor = "#0f766e"
		statusFill = "#ecfdf5"
	}
	values := []struct {
		Label string
		Value string
		OK    bool
	}{
		{t("assistant.shopping.checkout.check.product"), checkoutProductOptionLine(fields), checkoutProductOptionLine(fields) != "" && !checkoutScreenNegativeValue(checkoutProductOptionLine(fields))},
		{t("assistant.shopping.checkout.check.quantity"), strings.TrimSpace(fields.Quantity), strings.TrimSpace(fields.Quantity) != "" && !checkoutScreenNegativeValue(fields.Quantity)},
		{t("assistant.shopping.checkout.check.total"), strings.TrimSpace(fields.Total), strings.TrimSpace(fields.Total) != "" && !checkoutScreenNegativeValue(fields.Total)},
		{t("assistant.shopping.checkout.check.delivery"), strings.TrimSpace(fields.Delivery), strings.TrimSpace(fields.Delivery) != "" && !checkoutScreenNegativeValue(fields.Delivery) && !checkoutDeliveryUnclearValue(fields.Delivery)},
		{t("assistant.shopping.checkout.check.address"), t("assistant.shopping.decision.svg.provided"), strings.TrimSpace(fields.Address) != "" && !checkoutScreenNegativeValue(fields.Address) && checkoutScreenVisibilityAffirmative(fields.Address)},
		{t("assistant.shopping.checkout.check.payment"), t("assistant.shopping.decision.svg.provided"), strings.TrimSpace(fields.Payment) != "" && !checkoutScreenNegativeValue(fields.Payment) && checkoutScreenVisibilityAffirmative(fields.Payment)},
		{t("assistant.shopping.checkout.check.button"), strings.TrimSpace(fields.Button), strings.TrimSpace(fields.Button) != "" && !checkoutScreenNegativeValue(fields.Button)},
	}
	var b strings.Builder
	b.WriteString(`<?xml version="1.0" encoding="UTF-8"?>` + "\n")
	b.WriteString(`<svg xmlns="http://www.w3.org/2000/svg" width="840" height="660" viewBox="0 0 840 660">` + "\n")
	b.WriteString(`<rect width="840" height="660" fill="#f8fafc"/>` + "\n")
	b.WriteString(`<rect x="24" y="24" width="792" height="612" rx="20" fill="#ffffff" stroke="#d9e2ef"/>` + "\n")
	b.WriteString(fmt.Sprintf(`<text x="48" y="66" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="27" font-weight="850" fill="#0f172a">%s</text>`, html.EscapeString(t("assistant.shopping.decision.title"))))
	b.WriteString("\n")
	b.WriteString(fmt.Sprintf(`<text x="48" y="96" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="15" fill="#64748b">%s</text>`, html.EscapeString(t("assistant.shopping.decision.svg.subtitle"))))
	b.WriteString("\n")
	b.WriteString(fmt.Sprintf(`<rect x="48" y="124" width="744" height="78" rx="16" fill="%s" stroke="%s"/>`, statusFill, statusColor))
	b.WriteString("\n")
	b.WriteString(fmt.Sprintf(`<text x="72" y="160" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="20" font-weight="850" fill="%s">%s</text>`, statusColor, html.EscapeString(status)))
	b.WriteString("\n")
	b.WriteString(fmt.Sprintf(`<text x="72" y="184" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="14" fill="#334155">%s</text>`, html.EscapeString(shortenSVGText(product, 72))))
	b.WriteString("\n")
	b.WriteString(fmt.Sprintf(`<text x="48" y="238" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="17" font-weight="850" fill="#0f172a">%s</text>`, html.EscapeString(t("assistant.shopping.decision.confirmed_title"))))
	b.WriteString("\n")
	for i, item := range values {
		y := 262 + i*42
		color := "#0f766e"
		mark := "OK"
		value := strings.TrimSpace(item.Value)
		if !item.OK {
			color = "#dc2626"
			mark = "MISS"
			value = t("assistant.shopping.decision.svg.missing")
		}
		b.WriteString(fmt.Sprintf(`<rect x="48" y="%d" width="744" height="32" rx="10" fill="#f8fafc" stroke="#e2e8f0"/>`, y))
		b.WriteString("\n")
		b.WriteString(fmt.Sprintf(`<text x="70" y="%d" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="13" font-weight="850" fill="%s">%s</text>`, y+21, color, mark))
		b.WriteString("\n")
		b.WriteString(fmt.Sprintf(`<text x="128" y="%d" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="14" font-weight="800" fill="#334155">%s</text>`, y+21, html.EscapeString(item.Label)))
		b.WriteString("\n")
		b.WriteString(fmt.Sprintf(`<text x="756" y="%d" text-anchor="end" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="14" fill="#0f172a">%s</text>`, y+21, html.EscapeString(shortenSVGText(value, 48))))
		b.WriteString("\n")
	}
	if len(missing) > 0 || len(problems) > 0 || mismatch {
		reasons := append([]string{}, missing...)
		for _, problem := range problems {
			reasons = append(reasons, problem.Reason)
		}
		reason := strings.Join(reasons, ", ")
		if mismatch {
			if reason != "" {
				reason += ", "
			}
			reason += t("assistant.shopping.decision.mismatch")
		}
		b.WriteString(fmt.Sprintf(`<text x="48" y="582" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="14" font-weight="750" fill="#dc2626">%s</text>`, html.EscapeString(shortenSVGText(t("assistant.shopping.decision.missing", reason), 86))))
		b.WriteString("\n")
	}
	b.WriteString(fmt.Sprintf(`<text x="48" y="626" font-family="-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif" font-size="14" fill="#64748b">%s</text>`, html.EscapeString(t("assistant.shopping.decision.svg.footer"))))
	b.WriteString("\n</svg>\n")
	return b.String()
}

func checkoutProductOptionLine(fields checkoutScreenFields) string {
	product := strings.TrimSpace(fields.Product)
	option := strings.TrimSpace(fields.Option)
	switch {
	case product != "" && option != "":
		return product + " / " + option
	case product != "":
		return product
	default:
		return option
	}
}

func checkoutDecisionMissingFields(fields checkoutScreenFields) []string {
	return checkoutDecisionMissingFieldsFor(lang.Current(), fields)
}

func checkoutDecisionMissingFieldsFor(locale string, fields checkoutScreenFields) []string {
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	missing := []string{}
	if checkoutProductOptionLine(fields) == "" {
		missing = append(missing, t("assistant.shopping.checkout.check.product"))
	}
	if strings.TrimSpace(fields.Quantity) == "" {
		missing = append(missing, t("assistant.shopping.checkout.check.quantity"))
	}
	if strings.TrimSpace(fields.Total) == "" {
		missing = append(missing, t("assistant.shopping.checkout.check.total"))
	}
	if strings.TrimSpace(fields.Delivery) == "" {
		missing = append(missing, t("assistant.shopping.checkout.check.delivery"))
	}
	if strings.TrimSpace(fields.Address) == "" {
		missing = append(missing, t("assistant.shopping.checkout.check.address"))
	}
	if strings.TrimSpace(fields.Payment) == "" {
		missing = append(missing, t("assistant.shopping.checkout.check.payment"))
	}
	if strings.TrimSpace(fields.Button) == "" {
		missing = append(missing, t("assistant.shopping.checkout.check.button"))
	}
	return missing
}

func checkoutProductMismatch(screenProduct, candidate string) bool {
	screen := normalizeCheckoutProduct(screenProduct)
	reference := normalizeCheckoutProduct(candidate)
	if screen == "" || reference == "" {
		return false
	}
	if strings.Contains(reference, screen) || strings.Contains(screen, reference) {
		return false
	}
	matches := 0
	for _, token := range strings.Fields(reference) {
		if len([]rune(token)) < 2 {
			continue
		}
		if strings.Contains(screen, token) {
			matches++
		}
	}
	return matches == 0
}

func normalizeCheckoutProduct(value string) string {
	replacer := strings.NewReplacer("|", " ", "/", " ", ",", " ", ".", " ", "(", " ", ")", " ", "[", " ", "]", " ", "-", " ")
	return strings.Join(strings.Fields(strings.ToLower(replacer.Replace(strings.TrimSpace(value)))), " ")
}

func isShoppingCandidateCartAddRequest(lower string) bool {
	if lower == "" {
		return false
	}
	return containsAny(lower, "장바구니 담기 실행", "장바구니에 담기 실행", "장바구니 넣기 실행", "add to cart", "add it to cart") ||
		(containsAny(lower, "장바구니", "cart") && containsAny(lower, "실행", "담기", "넣기", "add") && !containsAny(lower, "준비", "prep", "prepare", "결제", "pay", "checkout"))
}

func isShoppingCandidateCartConfirmRequest(lower string) bool {
	if lower == "" {
		return false
	}
	return containsAny(lower,
		"장바구니 확인 완료", "장바구니 확인했", "장바구니 담겼", "장바구니에 담겼",
		"cart confirmed", "cart confirmation complete", "cart confirmation completed", "cart confirmation done", "cart is confirmed", "cart ready", "added to cart",
	)
}

func isShoppingCandidateCartPrepFollowUp(lower string) bool {
	if lower == "" {
		return false
	}
	if containsAny(lower, "가격 알림", "가격알림", "price alert", "return", "refund", "exchange", "반품", "환불", "교환") {
		return false
	}
	return containsAny(lower, "장바구니", "구매 직전", "cart", "checkout prep", "prepare the cart") &&
		containsAny(lower, "준비", "담", "넣", "결제는 하지", "결제 하지", "결제 없이", "do not pay", "but do not pay", "prepare", "add")
}

func shoppingCandidateForCartPrep(targetID, lower string) (browserauto.Link, bool) {
	candidate, _, ok := shoppingCandidateForCartPrepWithLocale(targetID, lower)
	return candidate, ok
}

func shoppingCandidateForCartPrepWithLocale(targetID, lower string) (browserauto.Link, string, bool) {
	index := shoppingCandidateFollowUpIndex(lower)
	if index >= 0 {
		_, candidates, recentLocale, ok := latestShoppingCandidatesFromHistoryWithLocale(targetID)
		if !ok || index >= len(candidates) {
			return browserauto.Link{}, recentLocale, false
		}
		return candidates[index], recentLocale, true
	}
	if candidate, recentLocale, ok := latestShoppingDetailFromHistoryWithLocale(targetID); ok {
		return candidate, recentLocale, true
	}
	if candidate, recentLocale, ok := latestShoppingSelectionFromHistoryWithLocale(targetID); ok {
		return candidate, recentLocale, true
	}
	_, candidates, recentLocale, ok := latestShoppingCandidatesFromHistoryWithLocale(targetID)
	if !ok || len(candidates) == 0 {
		return browserauto.Link{}, recentLocale, false
	}
	return candidates[0], recentLocale, true
}

