func parseShoppingSelectionFromReply(reply string) browserauto.Link {
	candidate := browserauto.Link{}
	for _, line := range strings.Split(reply, "\n") {
		trimmed := strings.TrimSpace(line)
		lower := strings.ToLower(trimmed)
		switch {
		case strings.HasPrefix(trimmed, "선택 상품:"):
			candidate.Text = strings.TrimSpace(strings.TrimPrefix(trimmed, "선택 상품:"))
		case strings.HasPrefix(lower, "selected product:"):
			candidate.Text = strings.TrimSpace(trimmed[len("Selected product:"):])
		case strings.HasPrefix(trimmed, "상품 링크:"):
			candidate.URL = strings.TrimSpace(strings.TrimPrefix(trimmed, "상품 링크:"))
		case strings.HasPrefix(lower, "product link:"):
			candidate.URL = strings.TrimSpace(trimmed[len("Product link:"):])
		}
	}
	return candidate
}

func parseShoppingDetailFromReply(reply string) browserauto.Link {
	candidate := browserauto.Link{}
	for _, line := range strings.Split(reply, "\n") {
		trimmed := strings.TrimSpace(line)
		lower := strings.ToLower(trimmed)
		switch {
		case strings.HasPrefix(trimmed, "상품:"):
			candidate.Text = strings.TrimSpace(strings.TrimPrefix(trimmed, "상품:"))
		case strings.HasPrefix(lower, "product:"):
			candidate.Text = strings.TrimSpace(trimmed[len("Product:"):])
		case strings.HasPrefix(trimmed, "열린 링크:"):
			candidate.URL = strings.TrimSpace(strings.TrimPrefix(trimmed, "열린 링크:"))
		case strings.HasPrefix(lower, "opened link:"):
			candidate.URL = strings.TrimSpace(trimmed[len("Opened link:"):])
		}
	}
	return candidate
}

