func parseShoppingCandidatesFromReply(reply string) (string, []browserauto.Link) {
	query := ""
	if match := regexp.MustCompile(`(?m)^(?:검색어|기준 검색어|Search query|Query):\s*(.+)$`).FindStringSubmatch(reply); len(match) > 1 {
		query = strings.TrimSpace(match[1])
	}
	section := reply
	for _, marker := range []string{"검색 결과 후보:", "Search-result candidates:"} {
		if idx := strings.Index(section, marker); idx >= 0 {
			section = section[idx+len(marker):]
			break
		}
	}
	for _, marker := range []string{"\n\n바로 확인할 항목:", "\n\nCheck next:"} {
		if idx := strings.Index(section, marker); idx >= 0 {
			section = section[:idx]
			break
		}
	}
	lines := strings.Split(section, "\n")
	out := []browserauto.Link{}
	for i := 0; i < len(lines); i++ {
		line := strings.TrimSpace(lines[i])
		match := regexp.MustCompile(`^(\d+)\.\s+(.+)$`).FindStringSubmatch(line)
		if len(match) < 3 {
			continue
		}
		title := strings.TrimSpace(match[2])
		link := ""
		for j := i + 1; j < len(lines) && j <= i+3; j++ {
			next := strings.TrimSpace(lines[j])
			if strings.HasPrefix(next, "링크:") || strings.HasPrefix(strings.ToLower(next), "link:") {
				link = strings.TrimSpace(strings.TrimPrefix(strings.TrimPrefix(next, "링크:"), "Link:"))
				break
			}
			if regexp.MustCompile(`^\d+\.\s+`).MatchString(next) {
				break
			}
		}
		out = append(out, browserauto.Link{Text: title, URL: link})
	}
	return query, assistantShoppingCandidateLines(out, 3)
}

