func formatShoppingCandidateCompareReplyFor(locale, query string, candidates []browserauto.Link) string {
	candidates = assistantShoppingCandidateLines(candidates, 3)
	t := func(key string, args ...interface{}) string {
		return lang.TF(locale, key, args...)
	}
	lines := []string{t("assistant.shopping.compare.title")}
	if strings.TrimSpace(query) != "" {
		lines = append(lines, t("assistant.shopping.compare.query", strings.TrimSpace(query)))
	}
	lines = append(lines, "", t("assistant.shopping.compare.header"), t("assistant.shopping.compare.separator"))
	for i, candidate := range candidates {
		label := firstNonEmpty(strings.TrimSpace(candidate.Text), t("assistant.shopping.product_fallback.candidate"))
		if strings.TrimSpace(candidate.URL) != "" {
			label += "<br>" + strings.TrimSpace(candidate.URL)
		}
		lines = append(lines, t("assistant.shopping.compare.row", i+1, shoppingCompareTableCell(label)))
	}
	lines = append(lines, "", t("assistant.shopping.compare.next"), t("assistant.shopping.compare.boundary"))
	return strings.Join(lines, "\n")
}

func shoppingCompareTableCell(value string) string {
	value = strings.ReplaceAll(value, "|", "/")
	value = strings.ReplaceAll(value, "\n", " ")
	return strings.Join(strings.Fields(value), " ")
}

func coupangShoppingQuery(text string) string {
	if query := directPurchaseKoreanImperativeQuery(text); query != "" {
		return query
	}
	if query := directPurchaseEnglishImperativeQuery(text); query != "" {
		return query
	}
	query := shoppingQuery(text)
	replacements := []string{
		"쿠팡에서", "쿠팡", "coupang에서", "coupang", "에서", "로켓배송으로", "로켓 배송으로", "로켓배송", "로켓 배송", "로켓",
		"실제", "진짜", "구매 테스트", "구매 준비", "구매할거야", "구매할 거야",
		"가격", "리뷰", "후기", "좋은 후보 3개", "후보 3개", "좋은 후보", "후보", "비교해줘", "비교", "검색해서", "검색해줘", "찾아줘",
		"으로", "좋은", "개",
		"search coupang for", "search coupang", "coupang",
		"search for", "search", "find on", "find", "look for", "look up",
		"and compare", "compare three good", "compare three", "compare",
		"three good", "three", "good",
		"rocket-delivery", "rocket delivery", "rocket", "delivery",
		"candidates", "candidate",
		"by price and reviews", "by prices and reviews", "by price", "by prices",
		"and reviews", "and review", "reviews", "review", "prices", "price",
		"by", "and", "for", "on", "please", "pls",
	}
	for _, old := range replacements {
		query = replaceShoppingDirective(query, old)
	}
	query = strings.NewReplacer(",", " ", "，", " ", ".", " ", "!", " ", "?", " ").Replace(query)
	query = strings.Join(strings.Fields(strings.TrimSpace(query)), " ")
	return query
}

func replaceShoppingDirective(query, token string) string {
	token = strings.TrimSpace(token)
	if token == "" {
		return query
	}
	if isASCIIText(token) {
		pattern := regexp.MustCompile(`(?i)(^|[^[:alnum:]])` + regexp.QuoteMeta(token) + `([^[:alnum:]]|$)`)
		return pattern.ReplaceAllString(query, "$1 $2")
	}
	return strings.ReplaceAll(query, token, " ")
}

func isASCIIText(value string) bool {
	for _, r := range value {
		if r > 127 {
			return false
		}
	}
	return true
}

func coupangSearchURL(query string) string {
	query = strings.TrimSpace(query)
	if query == "" {
		return "https://www.coupang.com/"
	}
	return "https://www.coupang.com/np/search?q=" + url.QueryEscape(query)
}

func priceAlertListReply(opts ListenOptions, request string) string {
	watches, err := assistantwatch.ListWatches("price_alert", false)
	if err != nil {
		return scenarioReplyWithEvidence(opts, "price_alert_list_error", request, "가격 알림 목록을 읽지 못했습니다: "+err.Error(), nil)
	}
	if len(watches) == 0 {
		return scenarioReplyWithEvidence(opts, "price_alert_list_empty", request, "등록된 가격 알림이 없습니다.", nil)
	}
	lines := []string{"등록된 가격 알림입니다."}
	links := []string{}
	for i, watch := range watches {
		link := assistantwatch.SearchLink(watch)
		links = append(links, signalEvidenceLinks(link)...)
		lines = append(lines, fmt.Sprintf("%d. %s / %s / %s", i+1, watch.Query, watch.ThresholdText, watch.Cadence))
		lines = append(lines, "   id: "+watch.ID)
		lines = append(lines, "   link: "+signalVisibleAssistantWatchLink(link))
	}
	return scenarioReplyWithEvidence(opts, "price_alert_list", request, strings.Join(lines, "\n"), links)
}

func signalVisibleAssistantWatchLink(link string) string {
	link = strings.TrimSpace(link)
	if link == "" {
		return "없음"
	}
	if isLoopbackHTTPURL(link) {
		return "로컬 테스트 링크라 iPhone에서 열 수 없습니다. 실제 상품 URL이나 검색어로 다시 등록하세요."
	}
	return link
}

func signalEvidenceLinks(link string) []string {
	link = strings.TrimSpace(link)
	if link == "" || isLoopbackHTTPURL(link) {
		return nil
	}
	return []string{link}
}

func isLoopbackHTTPURL(value string) bool {
	u, err := url.Parse(strings.TrimSpace(value))
	if err != nil {
		return false
	}
	host := strings.ToLower(strings.Trim(u.Hostname(), "[]"))
	return host == "127.0.0.1" || host == "localhost" || host == "::1"
}

func priceAlertDisableReply(opts ListenOptions, request string) string {
	query := priceAlertDisableQuery(request)
	watch, ok, err := assistantwatch.DisableWatch(query, time.Now().UTC())
	if err != nil {
		return scenarioReplyWithEvidence(opts, "price_alert_disable_error", request, "가격 알림 중지에 실패했습니다: "+err.Error(), nil)
	}
	if !ok {
		reply := "중지할 가격 알림을 찾지 못했습니다. `가격 알림 목록`을 먼저 확인하세요."
		return scenarioReplyWithEvidence(opts, "price_alert_disable_missing", request, reply, nil)
	}
	reply := strings.Join([]string{
		"가격 알림을 중지했습니다.",
		"상품/조건: " + watch.Query,
		"watch id: " + watch.ID,
	}, "\n")
	return scenarioReplyWithEvidence(opts, "price_alert_disabled", request, reply, nil)
}

