func mediaQuery(text string, remove []string) string {
	query := strings.TrimSpace(text)
	for _, token := range remove {
		query = strings.ReplaceAll(query, token, " ")
		query = strings.ReplaceAll(query, strings.ToUpper(token), " ")
	}
	return strings.Trim(strings.Join(strings.Fields(query), " "), " :：,，.。")
}

