func scenarioReplyWithEvidence(opts ListenOptions, scenario, request, reply string, links []string) string {
	evidenceRequest := strings.TrimSpace(firstNonEmpty(opts.EvidenceText, request))
	payload := assistantScenarioEvidencePayload{
		Kind:      "signal_assistant_scenario",
		Scenario:  scenario,
		TargetID:  opts.TargetID,
		Request:   evidenceRequest,
		Reply:     reply,
		Links:     links,
		CreatedAt: time.Now().UTC(),
	}
	_, err := evidence.Store("signal-assistant-scenario", firstNonEmpty(opts.TargetID, "signal"), scenario, payload)
	lines := []string{reply}
	if err != nil {
		lines = append(lines, "", "작업 기록 저장 경고: "+err.Error())
	}
	_ = appendSignalHistory(opts.TargetID, evidenceRequest, reply)
	return strings.Join(lines, "\n")
}

