func maybeStartAsyncPreparedNewsReply(opts ListenOptions, target Target, text string) (string, bool) {
	mode := strings.ToLower(strings.TrimSpace(opts.Mode))
	if mode != "assistant" && mode != "briefing" && mode != "ops" {
		return "", false
	}
	if !isFreshNewsRequest(text) {
		return "", false
	}
	targetID := strings.TrimSpace(firstNonEmpty(opts.TargetID, target.ID))
	if targetID == "" {
		return "", false
	}
	binary := meshclawBinary()
	if binary == "" {
		return "뉴스를 새로 정리하려면 MeshClaw 실행 파일 경로가 필요합니다.", true
	}
	limit := assistantbrief.NewsLimitFromText(text, 10)
	args := []string{"assistant", "news-prepare", "--news-limit", strconv.Itoa(limit), "--target", targetID, "--execute", "--json"}
	cmd := exec.Command(binary, args...)
	cmd.Env = os.Environ()
	cmd.Stdout, cmd.Stderr = asyncPreparedNewsLogWriters()
	if err := cmd.Start(); err != nil {
		return "뉴스 새 정리를 시작하지 못했습니다: " + err.Error(), true
	}
	return strings.Join([]string{
		"뉴스를 새로 정리하기 시작했습니다.",
		"로컬 모델이 한국어 브리핑을 만들고, 완료되면 이 방으로 다시 보내겠습니다.",
		"기존 준비 뉴스가 필요하면 그냥 '뉴스'라고 보내세요.",
	}, "\n"), true
}

func isFreshNewsRequest(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !containsAny(lower, "뉴스", "news", "headline", "headlines", "브리핑", "briefing") {
		return false
	}
	return containsAny(lower, "새로", "갱신", "다시 수집", "새 뉴스", "refresh", "fresh")
}

func asyncPreparedNewsLogWriters() (*os.File, *os.File) {
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return nil, nil
	}
	dir := filepath.Join(home, ".meshclaw", "logs")
	_ = os.MkdirAll(dir, 0700)
	stdout, _ := os.OpenFile(filepath.Join(dir, "argos-news-prepare.log"), os.O_CREATE|os.O_APPEND|os.O_WRONLY, 0600)
	stderr, _ := os.OpenFile(filepath.Join(dir, "argos-news-prepare.err.log"), os.O_CREATE|os.O_APPEND|os.O_WRONLY, 0600)
	return stdout, stderr
}

func meshclawBinary() string {
	if configured := strings.TrimSpace(os.Getenv("MESHCLAW_BIN")); configured != "" && fileNonEmptyLocal(configured) {
		return configured
	}
	if path, err := exec.LookPath("meshclaw"); err == nil && path != "" {
		return path
	}
	home, err := os.UserHomeDir()
	if err == nil && home != "" {
		candidate := filepath.Join(home, "bin", "meshclaw")
		if fileNonEmptyLocal(candidate) {
			return candidate
		}
	}
	return ""
}

