func assistantFleetStatusReply(request string) string {
	m, err := monitor.New(monitor.DefaultConfig())
	if err != nil {
		return "노드 상태를 확인하지 못했습니다: " + err.Error()
	}
	states := m.CheckAll()
	alerts := m.DetectAlerts()
	nodes := inventory.DefaultNodes()
	online := 0
	for _, node := range nodes {
		if state := states[node.Name]; state != nil && state.Online {
			online++
		}
	}
	record, storeErr := evidence.Store("signal-fleet-status", "fleet", fmt.Sprintf("online=%d total=%d alerts=%d", online, len(nodes), len(alerts)), map[string]interface{}{
		"request": request,
		"states":  states,
		"alerts":  alerts,
	})

	lines := []string{
		fmt.Sprintf("🖥️ 노드 상태 — 전체 %d대 중 %d대 온라인", len(nodes), online),
	}
	if len(alerts) > 0 {
		lines = append(lines, "", "주의/긴급:")
		for _, alert := range alerts {
			lines = append(lines, fmt.Sprintf("- [%s] %s: %s", alert.Level, alert.Node, alert.Message))
		}
	} else {
		lines = append(lines, "", "현재 감지된 경고는 없습니다.")
	}
	lines = append(lines, "", "노드별:")
	for _, node := range nodes {
		state := states[node.Name]
		if state == nil {
			lines = append(lines, fmt.Sprintf("- %s: 상태 없음", node.Name))
			continue
		}
		if !state.Online {
			reason := firstNonEmpty(state.Error, "offline")
			lines = append(lines, fmt.Sprintf("- %s: 오프라인 (%s)", state.Name, reason))
			continue
		}
		extra := ""
		if state.GPUUsage > 0 || state.GPUMemory > 0 {
			extra = fmt.Sprintf(" · GPU %.0f%%", state.GPUUsage)
		}
		lines = append(lines, fmt.Sprintf("- %s: 온라인 · CPU %.0f%% · 메모리 %.0f%% · 디스크 %.0f%%%s", state.Name, state.CPU, state.Memory, state.Disk, extra))
	}
	lines = appendEvidenceLine(lines, record, storeErr)
	return strings.Join(lines, "\n")
}

func requestedArgosRecording(lower string) (int, bool) {
	if !containsAny(lower, "녹화", "동영상", "영상으로", "화면 기록", "화면녹화", "record screen", "screen record", "recording", "video") {
		return 0, false
	}
	return signalArgosRecordingSeconds(), true
}

func signalArgosRecordingSeconds() int {
	seconds := 5
	if raw := strings.TrimSpace(os.Getenv("MESHCLAW_ARGOS_SIGNAL_RECORD_SECONDS")); raw != "" {
		if parsed, err := strconv.Atoi(raw); err == nil && parsed > 0 {
			seconds = parsed
		}
	}
	if seconds > 30 {
		seconds = 30
	}
	return seconds
}

func runSignalArgosAction(opts ListenOptions, text string, recordSeconds int) (string, bool) {
	actionText := stripArgosRecordingWords(text)
	action := osauto.ClassifyArgosAction(actionText)
	if action.Action == "none" || action.Error != "" {
		return "", false
	}
	if assistantShoppingBrowserDisabled() && assistantShoppingBrowserAction(action, actionText) {
		return formatSignalShoppingBrowserDisabledAction(), true
	}
	decision := osauto.CheckArgosPermission(action)
	if !decision.Allowed {
		if signalLocalAutoGrantEnabled() && decision.Grantable {
			if _, err := osauto.GrantArgosPermission(action, "signal:"+opts.TargetID, "signal-auto"); err == nil {
				decision = osauto.CheckArgosPermission(action)
			}
		}
	}
	if !decision.Allowed {
		rememberPendingArgosAction(argosPendingKey(opts.TargetID), pendingArgosAction{
			Action:        action,
			Decision:      decision,
			RecordSeconds: recordSeconds,
			CreatedAt:     time.Now().UTC(),
			ExpiresAt:     time.Now().UTC().Add(10 * time.Minute),
		})
		return formatSignalArgosApprovalRequest(action, decision), true
	}
	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()
	action = osauto.ArgosDo(ctx, osauto.ArgosRequest{Text: actionText, Execute: true, RecordSeconds: recordSeconds})
	record, storeErr := evidence.Store(action.Action, "argos", action.Text, action)
	return formatSignalArgosAction(action, record, storeErr), true
}

