func isAssistantPurchaseAutomationRequest(lower string) bool {
	lower = strings.ToLower(strings.TrimSpace(lower))
	if lower == "" {
		return false
	}
	if containsAny(lower, "쿠팡플레이", "coupang play") &&
		!containsAny(lower, "구매", "주문", "장바구니", "결제", "상품", "쇼핑", "물건", "사줘", "buy", "purchase", "cart", "checkout", "payment") {
		return false
	}
	if containsAny(lower, "리마인더", "reminder", "할 일", "할일", "todo", "일정", "calendar", "캘린더") &&
		!containsAny(lower, "쿠팡", "coupang", "쇼핑", "shopping", "장바구니", "cart", "checkout", "payment", "결제", "주문", "order", "구매해", "구매 해", "구입해", "주문해", "사줘", "사다줘", "buy ", "buy it", "buy this", "purchase", "price alert") {
		return false
	}
	if isShoppingDirectPurchaseStartRequest(lower) ||
		isShoppingPurchaseWorkflowQuestion(lower) ||
		isCoupangPurchasePrepRequest(lower) ||
		isCoupangCheckoutReviewRequest(lower) ||
		isCoupangPaymentAuthRequest(lower) ||
		isPurchaseFinalApprovalText(lower) ||
		isPurchaseNaturalFinalGoAheadRequest(lower) {
		return true
	}
	return containsAny(lower,
		"쿠팡", "쇼핑", "장바구니", "체크아웃", "결제", "결제수단", "결제 비밀번호", "cvc", "보안코드",
		"상품 찾아", "상품 검색", "상품 비교", "가격 알림", "가격 감시", "최저가", "구매 승인", "구매 실행", "구매 플로우",
		"coupang", "shopping", "shop for", "cart", "checkout", "payment", "payment method", "security code",
		"product search", "find products", "compare products", "price alert", "purchase approved", "purchase execution", "stop the purchase flow",
	)
}

