func assistantShoppingBrowserAction(action osauto.ArgosAction, actionText string) bool {
	switch action.Action {
	case "open_url", "browser_fetch":
		if isCoupangOpenURL(action.URL) {
			return true
		}
		lowerURL := strings.ToLower(action.URL)
		if strings.Contains(lowerURL, "tbm=shop") || strings.Contains(lowerURL, "google.com/search") && strings.Contains(lowerURL, "shopping") {
			return true
		}
	case "browser_search", "visible_browser_search":
		// fall through to target text checks below
	default:
		return false
	}
	target := strings.ToLower(action.URL + " " + action.Query + " " + actionText)
	if containsAny(target, "coupang.com", "coupang", "쿠팡", "tbm=shop") {
		return true
	}
	return containsAny(target, "장바구니", "결제", "구매", "주문", "배송", "상품", "쇼핑", "쿠폰", "리뷰 비교",
		"shopping", "checkout", "purchase", "buy", "cart", "coupon discount")
}

