func stripArgosRecordingWords(text string) string {
	out := strings.TrimSpace(text)
	for _, marker := range []string{"녹화하면서", "녹화해서", "녹화해줘", "화면 기록하면서", "화면녹화하면서", "동영상으로", "영상으로", "record screen while", "screen record while", "recording", "record screen", "screen record", "record"} {
		out = strings.ReplaceAll(out, marker, " ")
	}
	return strings.Join(strings.Fields(out), " ")
}

