	if resultTitle, resultDue := parseReminderCreateResult(action); resultTitle != "" || resultDue != "" {
		if title == "" {
			title = resultTitle
		}
		if due == "" {
			due = resultDue
		}
	}
	if title == "" {
		title = lang.T("assistant.argos_action.reminder_create.untitled")
	}
	lines := []string{
		lang.T("assistant.argos_action.reminder_create.title"),
		lang.T("assistant.argos_action.reminder_create.item", title),
	}
	if due != "" {
		lines = append(lines, lang.T("assistant.argos_action.reminder_create.due", formatSignalKoreanTimeRange(due, "")))
	}
	if notes != "" {
		lines = append(lines, lang.T("assistant.argos_action.reminder_create.notes", trimForContext(notes, 180)))
	}
	lines = append(lines, "", lang.T("assistant.argos_action.reminder_create.next"))
