func parseReminderCreateResult(action osauto.ArgosAction) (string, string) {
	if action.Result == nil || strings.TrimSpace(action.Result.Stdout) == "" {
		return "", ""
	}
	payload := strings.TrimSpace(action.Result.Stdout)
	var outer struct {
		Stdout string `json:"stdout"`
		Title  string `json:"title"`
		Due    string `json:"due"`
	}
	if err := json.Unmarshal([]byte(payload), &outer); err == nil {
		title := strings.TrimSpace(outer.Title)
		due := strings.TrimSpace(outer.Due)
		if strings.TrimSpace(outer.Stdout) != "" {
			nestedTitle, nestedDue := parseReminderCreatePayload(strings.TrimSpace(outer.Stdout))
			if title == "" {
				title = nestedTitle
			}
			if due == "" {
				due = nestedDue
			}
		}
		if title != "" || due != "" {
			return title, due
		}
	}
	return parseReminderCreatePayload(payload)
}

func parseReminderCreatePayload(payload string) (string, string) {
	var created struct {
		Title    string `json:"title"`
		Due      string `json:"due"`
		DueDate  string `json:"due_date"`
		DueISO   string `json:"due_iso"`
		Reminder struct {
			Title   string `json:"title"`
			Due     string `json:"due"`
			DueDate string `json:"due_date"`
			DueISO  string `json:"due_iso"`
		} `json:"reminder"`
	}
	if err := json.Unmarshal([]byte(payload), &created); err != nil {
		return "", ""
	}
	title := firstNonEmpty(created.Title, created.Reminder.Title)
	due := firstNonEmpty(created.Due, created.DueDate, created.DueISO, created.Reminder.Due, created.Reminder.DueDate, created.Reminder.DueISO)
	return strings.TrimSpace(title), strings.TrimSpace(due)
}

