func parseCalendarCreateResult(action osauto.ArgosAction) string {
	if action.Result == nil || strings.TrimSpace(action.Result.Stdout) == "" {
		return ""
	}
	payload := strings.TrimSpace(action.Result.Stdout)
	var outer struct {
		Stdout string `json:"stdout"`
		Title  string `json:"title"`
	}
	if err := json.Unmarshal([]byte(payload), &outer); err == nil {
		if strings.TrimSpace(outer.Title) != "" {
			return strings.TrimSpace(outer.Title)
		}
		if strings.TrimSpace(outer.Stdout) != "" {
			return parseCalendarCreatePayload(strings.TrimSpace(outer.Stdout))
		}
	}
	return parseCalendarCreatePayload(payload)
}

func parseCalendarCreatePayload(payload string) string {
	var created struct {
		Title string `json:"title"`
		Event struct {
			Title string `json:"title"`
		} `json:"event"`
	}
	if err := json.Unmarshal([]byte(payload), &created); err != nil {
		return ""
	}
	return strings.TrimSpace(firstNonEmpty(created.Title, created.Event.Title))
}

func formatSignalCalendarList(action osauto.ArgosAction) []string {
	if action.Result == nil || strings.TrimSpace(action.Result.Stdout) == "" {
		return []string{"일정 결과를 읽을 수 없습니다."}
	}
	payload := strings.TrimSpace(action.Result.Stdout)
	var outer struct {
		Stdout string `json:"stdout"`
	}
	if err := json.Unmarshal([]byte(payload), &outer); err == nil && strings.TrimSpace(outer.Stdout) != "" {
		payload = strings.TrimSpace(outer.Stdout)
	}
	var list struct {
		Count  int                 `json:"count"`
		Events []calendarListEvent `json:"events"`
	}
	if err := json.Unmarshal([]byte(payload), &list); err != nil {
		return []string{"일정 결과 원문: " + trimForContext(payload, 700)}
	}
	list.Events = filterUpcomingCalendarEvents(list.Events, time.Now())
	if list.Count > len(list.Events) {
		list.Count = len(list.Events)
	}
	if list.Count == 0 || len(list.Events) == 0 {
		return []string{"해당 기간에 표시할 일정이 없습니다."}
	}
	lines := []string{fmt.Sprintf("일정 %d개:", list.Count)}
	for i, event := range list.Events {
		if i >= 10 {
			lines = append(lines, fmt.Sprintf("- ...외 %d개", len(list.Events)-i))
			break
		}
		when := formatSignalKoreanTimeRange(event.Start, event.End)
		title := firstNonEmpty(event.Title, "(제목 없음)")
		line := fmt.Sprintf("%d. %s | %s", i+1, title, when)
		if event.Location != "" {
			line += " | " + event.Location
		}
		lines = append(lines, line)
	}
	return lines
}

type calendarListEvent struct {
	Title    string `json:"title"`
	Start    string `json:"start"`
	End      string `json:"end"`
	Calendar string `json:"calendar"`
	Location string `json:"location"`
}

func filterUpcomingCalendarEvents(events []calendarListEvent, now time.Time) []calendarListEvent {
	if len(events) == 0 {
		return events
	}
	filtered := make([]calendarListEvent, 0, len(events))
	for _, event := range events {
		if calendarEventStillRelevant(event.Start, event.End, now) {
			filtered = append(filtered, event)
		}
	}
	return filtered
}

func calendarEventStillRelevant(startISO, endISO string, now time.Time) bool {
	end := parseCalendarEventTime(endISO)
	start := parseCalendarEventTime(startISO)
	if !end.IsZero() {
		return end.After(now)
	}
	if !start.IsZero() {
		return start.After(now.Add(-15 * time.Minute))
	}
	return false
}

func parseCalendarEventTime(value string) time.Time {
	value = strings.TrimSpace(value)
	if value == "" {
		return time.Time{}
	}
	layouts := []string{time.RFC3339, "2006-01-02T15:04:05", "2006-01-02 15:04:05", "2006-01-02"}
	for _, layout := range layouts {
		if parsed, err := time.Parse(layout, value); err == nil {
			return parsed
		}
	}
	return time.Time{}
}

func formatSignalKoreanTimeRange(startValue, endValue string) string {
	start := parseCalendarEventTime(startValue)
	end := parseCalendarEventTime(endValue)
	if start.IsZero() && end.IsZero() {
		return strings.TrimSpace(strings.TrimSpace(startValue) + " ~ " + strings.TrimSpace(endValue))
	}
	loc, err := time.LoadLocation("Asia/Seoul")
	if err != nil {
		loc = time.FixedZone("KST", 9*60*60)
	}
	if !start.IsZero() {
		start = start.In(loc)
	}
	if !end.IsZero() {
		end = end.In(loc)
	}
	if !start.IsZero() && !end.IsZero() {
		if start.Format("2006-01-02") == end.Format("2006-01-02") {
			return start.Format("2006-01-02 15:04") + " ~ " + end.Format("15:04")
		}
		return start.Format("2006-01-02 15:04") + " ~ " + end.Format("2006-01-02 15:04")
	}
	if !start.IsZero() {
		return start.Format("2006-01-02 15:04")
	}
	return end.Format("2006-01-02 15:04") + "까지"
}

