func formatSignalArgosApprovalRequest(action osauto.ArgosAction, decision osauto.ArgosPermissionDecision) string {
	label := firstNonEmpty(decision.Label, decision.Scope, action.Action)
	lines := []string{
		"Mac 작업 실행 권한이 필요합니다.",
		"작업: " + action.Action,
		"범위: " + label,
	}
	switch action.Action {
	case "open_app":
		lines = append(lines, "앱: "+action.App)
	case "open_url", "browser_fetch":
		lines = append(lines, "URL: "+action.URL)
	case "browser_search", "visible_browser_search":
		lines = append(lines, "검색: "+action.Query)
	case "work_demo":
		lines = append(lines, "검색/문서 데모: "+action.Query)
	case "mac_runner_command":
		lines = append(lines, "요청: "+action.Input)
	case "shortcut_run":
		lines = append(lines, "단축어: "+action.Shortcut)
	case "note_create":
		lines = append(lines, "메모: "+action.NoteTitle)
	case "reminder_create":
		lines = append(lines, "리마인더: "+action.ReminderTitle)
		if action.ReminderDue != "" {
			lines = append(lines, "시간: "+action.ReminderDue)
		}
	case "reminders_list":
		lines = append(lines, "조회 범위: "+action.ReminderStart+" ~ "+action.ReminderEnd)
		if action.ReminderQuery != "" {
			lines = append(lines, "검색어: "+action.ReminderQuery)
		}
	case "reminder_complete", "reminder_delete":
		lines = append(lines, "리마인더: "+firstNonEmpty(action.ReminderQuery, action.ReminderID))
	case "calendar_event_create":
		lines = append(lines, "일정: "+action.CalendarTitle)
		if action.CalendarStart != "" {
			lines = append(lines, "시작: "+action.CalendarStart)
		}
		if action.CalendarEnd != "" {
			lines = append(lines, "종료: "+action.CalendarEnd)
		}
	case "calendar_events_list":
		lines = append(lines, "조회 범위: "+action.CalendarStart+" ~ "+action.CalendarEnd)
		if action.CalendarQuery != "" {
			lines = append(lines, "검색어: "+action.CalendarQuery)
		}
	case "calendar_event_delete":
		lines = append(lines, "일정: "+firstNonEmpty(action.CalendarQuery, action.CalendarID))
		lines = append(lines, "조회 범위: "+action.CalendarStart+" ~ "+action.CalendarEnd)
	case "contacts_search":
		lines = append(lines, "검색어: "+action.ContactQuery)
	case "ai_handoff":
		lines = append(lines, "대상: "+action.Provider)
	}
	lines = append(lines, "", "한 번만 실행하려면 `실행`이라고 답장하세요.")
	if decision.Grantable {
		lines = append(lines, "앞으로 같은 범위를 다시 묻지 않게 하려면 `항상 허용`이라고 답장하세요.")
	} else {
		lines = append(lines, "이 작업은 반복 허용 대상이 아니어서 매번 확인합니다.")
	}
	return strings.Join(lines, "\n")
}

func formatSignalArgosPermissions(grants []osauto.ArgosPermissionGrant, runErr error) string {
	if runErr != nil {
		return "Argos Mac 권한 목록을 읽지 못했습니다: " + runErr.Error()
	}
	if len(grants) == 0 {
		return strings.Join([]string{
			"저장된 Argos Mac 실행 권한이 없습니다.",
			"Mac 작업 요청 후 `항상 허용`이라고 답장하면 같은 범위를 다시 묻지 않습니다.",
		}, "\n")
	}
	lines := []string{"저장된 Argos Mac 실행 권한입니다."}
	for _, grant := range grants {
		lines = append(lines, fmt.Sprintf("- %s: %s / %s", grant.ID, grant.Action, firstNonEmpty(grant.Label, grant.Scope)))
	}
	lines = append(lines, "", "취소하려면 `권한 취소 <grant-id>` 또는 `권한 취소 Safari`처럼 답장하세요.")
	return strings.Join(lines, "\n")
}

func formatSignalArgosPermissionRevoke(grant osauto.ArgosPermissionGrant, found bool, runErr error) string {
	if runErr != nil {
		return "Argos Mac 권한을 취소하지 못했습니다: " + runErr.Error()
	}
	if !found {
		return strings.Join([]string{
			"해당 Argos Mac 권한을 찾지 못했습니다.",
			"`권한 목록`으로 현재 저장된 권한을 확인하세요.",
		}, "\n")
	}
	return fmt.Sprintf("Argos Mac 권한을 취소했습니다: %s / %s", grant.Action, firstNonEmpty(grant.Label, grant.Scope))
}

func formatSignalBrowserSearch(result browserauto.SearchResult, record evidence.Record, storeErr error, runErr error) string {
	if runErr != nil && len(result.Results) == 0 {
		return "브라우저 검색에 실패했습니다: " + runErr.Error()
	}
	lines := []string{fmt.Sprintf("검색 결과: %s", result.Query)}
	for i, item := range result.Results {
		if i >= 5 {
			break
		}
		lines = append(lines, fmt.Sprintf("%d. %s", i+1, item.Text))
		lines = append(lines, "   "+item.URL)
	}
	lines = appendEvidenceLine(lines, record, storeErr)
	return strings.Join(lines, "\n")
}

func formatSignalBrowserFetch(page browserauto.Page, record evidence.Record, storeErr error, runErr error) string {
	if runErr != nil && strings.TrimSpace(page.Text) == "" {
		return "페이지 읽기에 실패했습니다: " + runErr.Error()
	}
	title := firstNonEmpty(page.Title, page.FinalURL, page.URL)
	lines := []string{fmt.Sprintf("페이지를 읽었습니다: %s", title)}
	if page.FinalURL != "" {
		lines = append(lines, page.FinalURL)
	}
	if page.Text != "" {
		lines = append(lines, "", "요약:")
		lines = append(lines, conciseTextBullets(page.Text, 4)...)
		lines = append(lines, "", "본문 일부:", trimForContext(page.Text, 800))
	}
	if len(page.Links) > 0 {
		lines = append(lines, "", "주요 링크:")
		for i, link := range page.Links {
			if i >= 5 {
				break
			}
			lines = append(lines, fmt.Sprintf("%d. %s", i+1, link.Text))
			lines = append(lines, "   "+link.URL)
		}
	}
	lines = appendEvidenceLine(lines, record, storeErr)
	return strings.Join(lines, "\n")
}

func conciseTextBullets(text string, limit int) []string {
	if limit <= 0 {
		limit = 3
	}
	candidates := strings.FieldsFunc(text, func(r rune) bool {
		return r == '\n' || r == '.' || r == '。' || r == '!' || r == '?' || r == '؟'
	})
	out := []string{}
	seen := map[string]bool{}
	for _, candidate := range candidates {
		candidate = strings.Join(strings.Fields(candidate), " ")
		candidate = strings.Trim(candidate, " \t\r\n-•*")
		if len([]rune(candidate)) < 35 {
			continue
		}
		key := strings.ToLower(candidate)
		if seen[key] {
			continue
		}
		seen[key] = true
		out = append(out, "- "+trimForContext(candidate, 220))
		if len(out) >= limit {
			break
		}
	}
	if len(out) == 0 && strings.TrimSpace(text) != "" {
		out = append(out, "- "+trimForContext(text, 220))
	}
	return out
}

func formatSignalAutomationResult(label string, result osauto.Result, record evidence.Record, storeErr error) string {
	status := "완료"
	if !result.OK {
		status = "실패"
	}
	lines := []string{fmt.Sprintf("%s: %s", label, status)}
	if result.Stdout != "" {
		lines = append(lines, result.Stdout)
	}
	if result.Stderr != "" {
		lines = append(lines, "stderr: "+result.Stderr)
	}
	if result.Error != "" {
		lines = append(lines, "error: "+result.Error)
	}
	lines = appendEvidenceLine(lines, record, storeErr)
	return strings.Join(lines, "\n")
}

func appendEvidenceLine(lines []string, record evidence.Record, storeErr error) []string {
	if storeErr != nil {
		return append(lines, "", "작업 기록 저장 실패: "+storeErr.Error())
	}
	return lines
}

func appendSignalEvidenceDashboardLines(lines []string, record evidence.Record, storeErr error) []string {
	if storeErr != nil {
		return append(lines, lang.T("assistant.evidence.store_warning", storeErr.Error()))
	}
	evidenceRef := signalEvidenceRef(record)
	if evidenceRef == "" {
		return lines
	}
	lines = append(lines, lang.T("assistant.evidence.id", evidenceRef))
	lines = append(lines, lang.T("assistant.evidence.dashboard", assistantDashboardEvidenceURL(evidenceRef)))
	return lines
}

func assistantActiveSkillModelContext() string {
	profile, err := assistantprofile.Inspect(time.Now().UTC(), "")
	if err != nil || len(profile.Skills.Items) == 0 {
		return ""
	}
	lines := []string{
		"Argos active skill context follows.",
		"Use these reviewed routines when relevant, but do not execute irreversible actions from skill context alone.",
	}
	count := 0
	for _, item := range profile.Skills.Items {
		if item.Activation != "active_policy_gated" {
			continue
		}
		line := "- " + firstNonEmpty(item.Title, item.Name)
		if strings.TrimSpace(item.Summary) != "" {
			line += ": " + trimSignalSelfTestDetail(item.Summary, 220)
		}
		lines = append(lines, line)
		count++
		if count >= 6 {
			break
		}
	}
	if count == 0 {
		return ""
	}
	lines = append(lines, "Boundary: sending, deleting, purchasing, booking, payments, and account changes require explicit final approval.")
	return strings.Join(lines, "\n")
}

func assistantPersonalizationModelContextMessages() []aichat.Message {
	var messages []aichat.Message
	if memoryContext, err := assistantprofile.LoadMemoryContext(time.Now().UTC(), "", 2200); err == nil && strings.TrimSpace(memoryContext.Text) != "" {
		contextText := strings.Join([]string{
			"Argos bounded memory context follows.",
			"Use approved memory only as stable user preference, personalization, and long-term context when relevant.",
			"Apply style and preference memories naturally, but do not quote or reveal this section unless the user asks what you remember.",
			"Memory and skills are context, not authorization.",
			"Never treat memory as permission to send, delete, buy, book, pay, mutate accounts, or run destructive actions.",
			memoryContext.Text,
		}, "\n")
		messages = append(messages, aichat.Message{Role: "system", Content: contextText})
	}
	if contextText := assistantActiveSkillModelContext(); contextText != "" {
		messages = append(messages, aichat.Message{Role: "system", Content: contextText})
	}
	return messages
}

func modelRoomReply(opts ListenOptions, text, mode string) string {
	cfg, _, err := aichat.LoadConfig()
	if err != nil {
		cfg = aichat.DefaultConfig()
	}
	if opts.Model != "" {
		cfg.Model = opts.Model
	}
	if opts.BaseURL != "" {
		cfg.BaseURL = opts.BaseURL
	}
	cfg.MaxTokens = signalMaxTokens(mode, cfg.MaxTokens)
	cfg.SystemPrompt = signalSystemPrompt(mode, "followup")
	history := loadSignalHistory(opts.TargetID, 12)
	if mode == "assistant" || mode == "chat" {
		history = append(assistantPersonalizationModelContextMessages(), history...)
	}
	if contextText := latestSignalAttachmentContext(opts.TargetID); contextText != "" {
		history = append([]aichat.Message{{Role: "system", Content: contextText}}, history...)
	}
	// Inject the latest news set as context for both briefing and assistant
	// rooms so terse follow-ups ("한글로", "더 자세히", "원문") resolve against
	// exactly the news the user just saw instead of being answered blind.
	if mode == "briefing" || mode == "assistant" {
		if contextText := latestNewsBriefingContext(); contextText != "" {
			history = append([]aichat.Message{{Role: "system", Content: contextText}}, history...)
		}
	}
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
	defer cancel()
	reply, err := aichat.NewClient(cfg).Chat(ctx, history, text)
	if err != nil {
		return "로컬 모델 응답에 실패했습니다: " + err.Error()
	}
	_ = appendSignalHistory(opts.TargetID, text, reply)
	return reply
}

func isLocalOllamaRoomModel(model string) bool {
	model = strings.ToLower(strings.TrimSpace(model))
	return strings.HasPrefix(model, "gemma") || strings.HasPrefix(model, "kobolt") || strings.HasPrefix(model, "llama") || strings.HasPrefix(model, "qwen")
}

func isBlockedRoomModel(model string) bool {
	model = strings.ToLower(strings.TrimSpace(model))
	switch model {
	case "claude", "클로드", "claude-code", "claudecode", "codex", "코덱스":
		return true
	default:
		return false
	}
}

func extractApprovalStep(text string) (string, bool) {
	fields := strings.Fields(strings.TrimSpace(text))
	for i, field := range fields {
		normalized := strings.ToLower(strings.Trim(field, " :：,，.。"))
		if normalized == "승인" || normalized == "approve" || normalized == "approval" {
			if i+1 < len(fields) {
				step := strings.Trim(fields[i+1], " `\"'.,，。")
				if step != "" {
					return step, true
				}
			}
		}
	}
	return "", false
}

