func loadSignalHistory(targetID string, turns int) []aichat.Message {
	if turns <= 0 {
		return nil
	}
	data, err := os.ReadFile(signalHistoryPath(targetID))
	if err != nil {
		return nil
	}
	lines := strings.Split(strings.TrimSpace(string(data)), "\n")
	start := 0
	if len(lines) > turns*2 {
		start = len(lines) - turns*2
	}
	out := make([]aichat.Message, 0, len(lines)-start)
	for _, line := range lines[start:] {
		var msg aichat.Message
		if err := json.Unmarshal([]byte(line), &msg); err == nil && msg.Role != "" && msg.Content != "" {
			out = append(out, msg)
		}
	}
	return out
}

func appendSignalHistory(targetID, userText, reply string) error {
	path := signalHistoryPath(targetID)
	if err := os.MkdirAll(filepath.Dir(path), 0700); err != nil {
		return err
	}
	f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0600)
	if err != nil {
		return err
	}
	defer f.Close()
	for _, msg := range []aichat.Message{
		{Role: "user", Content: userText},
		{Role: "assistant", Content: reply},
	} {
		data, err := json.Marshal(msg)
		if err != nil {
			return err
		}
		if _, err := f.Write(append(data, '\n')); err != nil {
			return err
		}
	}
	return nil
}

func signalHistoryPath(targetID string) string {
	home, err := os.UserHomeDir()
	if err != nil {
		home = "."
	}
	id := sanitizeID(targetID)
	if id == "" {
		id = "default"
	}
	return filepath.Join(home, ".meshclaw", "messenger-history", id+".jsonl")
}

func latestNewsBriefingContext() string {
	record, latest, ok := loadLatestNewsRecord()
	if !ok {
		return ""
	}
	lines := []string{
		"최근 브리핑 context입니다. 사용자의 후속 질문은 이 내용을 기준으로 답하세요.",
		"브리핑 evidence: " + latest,
	}
	if strings.TrimSpace(record.Payload.Text) != "" {
		lines = append(lines, "브리핑 본문:", trimForContext(record.Payload.Text, 4000))
	}
	if len(record.Payload.Items) > 0 {
		lines = append(lines, "브리핑 출처:")
		for i, item := range record.Payload.Items {
			if i >= 12 {
				break
			}
			line := fmt.Sprintf("%d. %s", i+1, strings.TrimSpace(item.Title))
			if item.Feed != "" {
				line += " (" + item.Feed + ")"
			}
			if item.Link != "" {
				line += " - " + item.Link
			}
			lines = append(lines, line)
		}
	}
	return strings.Join(lines, "\n")
}

func latestNewsSourcesReply() string {
	record, _, ok := loadLatestNewsRecord()
	if !ok || len(record.Payload.Items) == 0 {
		return ""
	}
	lines := []string{"최근 주요뉴스 원문 링크입니다."}
	for i, item := range record.Payload.Items {
		if i >= 12 {
			break
		}
		title := strings.TrimSpace(item.Title)
		if title == "" {
			title = "원문"
		}
		lines = append(lines, fmt.Sprintf("%d. %s", i+1, title))
		if item.Link != "" {
			lines = append(lines, "   "+item.Link)
		}
	}
	lines = append(lines, "", "원하시면 '3번 자세히'처럼 번호를 보내세요. 현재는 RSS 제목/요약 기준으로 먼저 풀어 설명합니다.")
	return strings.Join(lines, "\n")
}

func latestNewsDetailReply(index int) string {
	record, _, ok := loadLatestNewsRecord()
	if !ok || index <= 0 || index > len(record.Payload.Items) {
		return ""
	}
	item := record.Payload.Items[index-1]
	title := strings.TrimSpace(item.Title)
	if title == "" {
		title = "해당 뉴스"
	}
	lines := []string{
		fmt.Sprintf("%d번 뉴스입니다.", index),
		"",
		title,
	}
	if strings.TrimSpace(item.Summary) != "" {
		lines = append(lines, "", item.Summary)
	}
	if item.Link != "" {
		lines = append(lines, "", "원문: "+item.Link)
	}
	lines = append(lines, "", "본문까지 읽어 요약하는 기능은 다음 단계에서 브라우저/본문 fetch adapter로 붙이겠습니다.")
	return strings.Join(lines, "\n")
}

type latestNewsRecord struct {
	Payload struct {
		Text  string `json:"text"`
		Items []struct {
			Title   string `json:"title"`
			Link    string `json:"link"`
			Feed    string `json:"feed"`
			Summary string `json:"description"`
		} `json:"items"`
	} `json:"payload"`
}

func loadLatestNewsRecord() (latestNewsRecord, string, bool) {
	home, err := os.UserHomeDir()
	if err != nil {
		return latestNewsRecord{}, "", false
	}
	patterns := []string{
		filepath.Join(home, ".meshclaw", "evidence", "*", "*news-brief-rss.json"),
		filepath.Join(home, ".meshclaw", "evidence", "*", "*assistant-news*.json"),
	}
	var latestPath string
	var latestTime time.Time
	for _, pattern := range patterns {
		matches, _ := filepath.Glob(pattern)
		for _, match := range matches {
			info, statErr := os.Stat(match)
			if statErr != nil {
				continue
			}
			if latestPath == "" || info.ModTime().After(latestTime) {
				latestPath = match
				latestTime = info.ModTime()
			}
		}
	}
	if latestPath == "" {
		return latestNewsRecord{}, "", false
	}
	data, err := os.ReadFile(latestPath)
	if err != nil {
		return latestNewsRecord{}, "", false
	}
	var record latestNewsRecord
	if err := json.Unmarshal(data, &record); err != nil {
		return latestNewsRecord{}, "", false
	}
	if len(record.Payload.Items) == 0 {
		var assistant struct {
			Payload struct {
				Text string `json:"text"`
				News []struct {
					Title       string `json:"title"`
					Link        string `json:"link"`
					FeedTitle   string `json:"feed_title"`
					FeedID      string `json:"feed_id"`
					Description string `json:"description"`
				} `json:"news"`
			} `json:"payload"`
		}
		if err := json.Unmarshal(data, &assistant); err == nil && len(assistant.Payload.News) > 0 {
			record.Payload.Text = assistant.Payload.Text
			for _, item := range assistant.Payload.News {
				record.Payload.Items = append(record.Payload.Items, struct {
					Title   string `json:"title"`
					Link    string `json:"link"`
					Feed    string `json:"feed"`
					Summary string `json:"description"`
				}{
					Title:   item.Title,
					Link:    item.Link,
					Feed:    firstNonEmpty(item.FeedTitle, item.FeedID),
					Summary: item.Description,
				})
			}
		}
	}
	if len(record.Payload.Items) == 0 {
		return latestNewsRecord{}, "", false
	}
	return record, latestPath, true
}

func trimForContext(text string, max int) string {
	text = strings.TrimSpace(text)
	if max <= 0 {
		return text
	}
	runes := []rune(text)
	if len(runes) <= max {
		return text
	}
	return string(runes[:max]) + "\n..."
}

func isGuardScope(text, intent string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	switch intent {
	case "vault_import", "vault_list", "vault_metadata", "vault_delete", "vault_rotate_plan", "vault_clip_plan", "guard_posture", "guard_vuln":
		return true
	}
	return strings.Contains(lower, "[redacted:") || containsAny(lower,
		"비번", "비밀번호", "패스워드", "암호", "토큰", "키", "api key", "apikey", "secret", "password", "passwd", "token",
		"vault", "볼트", "handle", "핸들", "keychain", "키체인", "pass ", "1password", "bitwarden",
		"승인", "approval", "메모리", "memory", "rag", "기록", "history", "삭제", "정리", "clean",
	)
}

func asksForExternalAI(text string) bool {
	lower := strings.ToLower(strings.TrimSpace(text))
	if !containsAny(lower, "클로드", "claude", "코덱스", "codex", "지피티", "gpt", "chatgpt") {
		return false
	}
	return containsAny(lower, "확인", "물어", "물어봐", "시켜", "요청", "ask", "check", "verify")
}

func firstNonEmpty(values ...string) string {
	for _, value := range values {
		if strings.TrimSpace(value) != "" {
			return strings.TrimSpace(value)
		}
	}
	return ""
}

func firstNonZeroInt64(values ...int64) int64 {
	for _, value := range values {
		if value != 0 {
			return value
		}
	}
	return 0
}

func containsAny(text string, needles ...string) bool {
	for _, needle := range needles {
		if strings.Contains(text, needle) {
			return true
		}
	}
	return false
}
